private func nativePixelAccentFont(size: CGFloat) -> Font {
    .custom("BBHBartle-Regular", size: size)
}

private func nativeAppFontName(for weight: Font.Weight) -> String {
    switch weight {
    case .ultraLight, .thin, .light, .regular:
        return "PlusJakartaSans-Regular"
    case .medium:
        return "PlusJakartaSans-Medium"
    case .semibold:
        return "PlusJakartaSans-SemiBold"
    case .bold:
        return "PlusJakartaSans-Bold"
    case .heavy, .black:
        return "PlusJakartaSans-ExtraBold"
    default:
        return "PlusJakartaSans-Regular"
    }
}

private func nativeAppUIFontName(for weight: UIFont.Weight) -> String {
    if weight.rawValue <= UIFont.Weight.regular.rawValue {
        return "PlusJakartaSans-Regular"
    }
    if weight.rawValue < UIFont.Weight.semibold.rawValue {
        return "PlusJakartaSans-Medium"
    }
    if weight.rawValue < UIFont.Weight.bold.rawValue {
        return "PlusJakartaSans-SemiBold"
    }
    if weight.rawValue < UIFont.Weight.heavy.rawValue {
        return "PlusJakartaSans-Bold"
    }
    return "PlusJakartaSans-ExtraBold"
}

private func nativeAppFont(size: CGFloat, weight: Font.Weight = .regular, design: Font.Design = .default) -> Font {
    .custom(nativeAppFontName(for: weight), size: size)
}

private func nativeAppUIFont(size: CGFloat, weight: UIFont.Weight = .regular) -> UIFont {
    UIFont(name: nativeAppUIFontName(for: weight), size: size)
        ?? UIFont.systemFont(ofSize: size, weight: weight)
}

private func nativeResolvedAPIBaseURL() -> URL {
    let environmentOverride = ProcessInfo.processInfo.environment["VIBINN_NATIVE_API_BASE_URL"]?
        .trimmingCharacters(in: .whitespacesAndNewlines)
    let userDefaultsOverride = UserDefaults.standard.string(forKey: nativeAPIBaseURLUserDefaultsKey)?
        .trimmingCharacters(in: .whitespacesAndNewlines)

    let explicitOverride = ([environmentOverride, userDefaultsOverride] as [String?])
        .compactMap { value -> String? in
            guard let value, !value.isEmpty else { return nil }
            return value
        }
        .first

    if let explicitOverride, let url = URL(string: explicitOverride) {
        return url
    }

    return URL(string: "https://vibinn-api-staging.onrender.com")!
}

private func nativeNearestSupportedLocation(
    to coordinate: CLLocationCoordinate2D?
) -> NativeLocationOption? {
    guard let coordinate else { return nil }
    let userLocation = CLLocation(latitude: coordinate.latitude, longitude: coordinate.longitude)
    return nativeLocationOptions.min { lhs, rhs in
        guard
            let lhsCoordinate = nativeSupportedLocationCoordinates[lhs.id],
            let rhsCoordinate = nativeSupportedLocationCoordinates[rhs.id]
        else {
            return false
        }
        let lhsDistance = userLocation.distance(
            from: CLLocation(latitude: lhsCoordinate.latitude, longitude: lhsCoordinate.longitude)
        )
        let rhsDistance = userLocation.distance(
            from: CLLocation(latitude: rhsCoordinate.latitude, longitude: rhsCoordinate.longitude)
        )
        return lhsDistance < rhsDistance
    }
}

private func nativeSupportedLocation(
    for coordinate: CLLocationCoordinate2D?
) -> NativeLocationOption? {
    guard let coordinate else { return nil }
    let userLocation = CLLocation(latitude: coordinate.latitude, longitude: coordinate.longitude)

    let ranked = nativeLocationOptions.compactMap { option -> (NativeLocationOption, Double, Double)? in
        guard
            let center = nativeSupportedLocationCoordinates[option.id],
            let radiusMiles = nativeSupportedLocationRadiusMiles[option.id]
        else {
            return nil
        }

        let distanceMiles = userLocation.distance(
            from: CLLocation(latitude: center.latitude, longitude: center.longitude)
        ) / 1609.344

        return (option, distanceMiles, radiusMiles)
    }
    .sorted { $0.1 < $1.1 }

    guard let closest = ranked.first, closest.1 <= closest.2 else { return nil }
    return closest.0
}

private func nativeDecisionHistoryDateLabel(_ raw: String?) -> String {
    guard let raw, !raw.isEmpty else { return "Recently" }
    let isoFormatter = ISO8601DateFormatter()
    isoFormatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
    let fallbackFormatter = DateFormatter()
    fallbackFormatter.locale = Locale(identifier: "en_US_POSIX")
    fallbackFormatter.dateFormat = "yyyy-MM-dd"
    fallbackFormatter.timeZone = TimeZone(secondsFromGMT: 0)

    let date =
        isoFormatter.date(from: raw)
        ?? {
            isoFormatter.formatOptions = [.withInternetDateTime]
            return isoFormatter.date(from: raw)
        }()
        ?? fallbackFormatter.date(from: raw)

    guard let date else { return raw }

    let now = Date()
    let diff = Int(now.timeIntervalSince(date))
    if diff < 60 {
        return "just now"
    }
    if diff < 24 * 60 * 60 {
        return "\(max(1, diff / 3600))h ago"
    }
    if diff < 7 * 24 * 60 * 60 {
        return "\(max(1, diff / 86400))d ago"
    }

    let formatter = DateFormatter()
    formatter.locale = Locale(identifier: "en_US_POSIX")
    formatter.timeZone = .current
    formatter.dateFormat = "MMM dd, yyyy"
    return formatter.string(from: date)
}

