final class AppDelegate: NSObject, UIApplicationDelegate, UNUserNotificationCenterDelegate, NativeMessagingDelegateProtocol {
    fileprivate weak var appState: NativeAppState?

    func application(
        _ application: UIApplication,
        didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]? = nil
    ) -> Bool {
        #if canImport(FirebaseCore)
        if FirebaseApp.app() == nil {
            FirebaseApp.configure()
        }
        #endif
        UNUserNotificationCenter.current().delegate = self
        #if canImport(FirebaseMessaging)
        Messaging.messaging().delegate = self
        #endif
        application.setMinimumBackgroundFetchInterval(UIApplication.backgroundFetchIntervalMinimum)
        return true
    }

    func application(_ application: UIApplication, didRegisterForRemoteNotificationsWithDeviceToken deviceToken: Data) {
        #if canImport(FirebaseMessaging)
        Messaging.messaging().apnsToken = deviceToken
        nativeLogger.log("apns token received")
        Messaging.messaging().token { token, error in
            if let error {
                nativeLogger.error("firebase messaging token after apns failed: \(error.localizedDescription, privacy: .public)")
                return
            }
            guard let token, !token.isEmpty else { return }
            nativeLogger.log("firebase token received after apns")
            UserDefaults.standard.set(token, forKey: nativePushTokenUserDefaultsKey)
            NotificationCenter.default.post(name: nativePushTokenNotification, object: token)
        }
        #endif
    }

    func application(_ application: UIApplication, didFailToRegisterForRemoteNotificationsWithError error: Error) {
        nativeLogger.error("remote notification registration failed: \(error.localizedDescription, privacy: .public)")
    }

    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey: Any] = [:]) -> Bool {
        #if canImport(GoogleSignIn)
        if GIDSignIn.sharedInstance.handle(url) {
            return true
        }
        #endif
        if url.scheme?.caseInsensitiveCompare("vibinn") == .orderedSame {
            UserDefaults.standard.set(url.absoluteString, forKey: nativePendingWidgetDeepLinkUserDefaultsKey)
            NotificationCenter.default.post(name: nativeWidgetDeepLinkNotification, object: url)
            return true
        }
        #if canImport(Capacitor)
        return ApplicationDelegateProxy.shared.application(app, open: url, options: options)
        #else
        return false
        #endif
    }

    func application(
        _ application: UIApplication,
        continue userActivity: NSUserActivity,
        restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void
    ) -> Bool {
        #if canImport(Capacitor)
        return ApplicationDelegateProxy.shared.application(
            application,
            continue: userActivity,
            restorationHandler: restorationHandler
        )
        #else
        return false
        #endif
    }

    #if canImport(FirebaseMessaging)
    func messaging(_ messaging: Messaging, didReceiveRegistrationToken fcmToken: String?) {
        guard let fcmToken, !fcmToken.isEmpty else { return }
        nativeLogger.log("firebase messaging delegate token received")
        UserDefaults.standard.set(fcmToken, forKey: nativePushTokenUserDefaultsKey)
        NotificationCenter.default.post(name: nativePushTokenNotification, object: fcmToken)
    }
    #endif

    func userNotificationCenter(
        _ center: UNUserNotificationCenter,
        willPresent notification: UNNotification,
        withCompletionHandler completionHandler: @escaping (UNNotificationPresentationOptions) -> Void
    ) {
        completionHandler([.banner, .badge, .sound])
    }

    func application(
        _ application: UIApplication,
        performFetchWithCompletionHandler completionHandler: @escaping (UIBackgroundFetchResult) -> Void
    ) {
        guard let appState else {
            completionHandler(.noData)
            return
        }

        Task { @MainActor in
            let result = await appState.performWidgetBackgroundRefresh()
            completionHandler(result)
        }
    }
}

@MainActor
private func nativeKeyWindow() -> UIWindow? {
    UIApplication.shared.connectedScenes
        .compactMap { $0 as? UIWindowScene }
        .flatMap { $0.windows }
        .first { $0.isKeyWindow }
}

@MainActor
private func nativeTopViewController(
    base: UIViewController? = nil
) -> UIViewController? {
    let resolvedBase = base ?? nativeKeyWindow()?.rootViewController
    if let navigationController = resolvedBase as? UINavigationController {
        return nativeTopViewController(base: navigationController.visibleViewController)
    }
    if let tabBarController = resolvedBase as? UITabBarController {
        return nativeTopViewController(base: tabBarController.selectedViewController)
    }
    if let presentedViewController = resolvedBase?.presentedViewController {
        return nativeTopViewController(base: presentedViewController)
    }
    return resolvedBase
}

private func nativeAppVersionString() -> String? {
    let info = Bundle.main.infoDictionary
    let shortVersion = info?["CFBundleShortVersionString"] as? String
    let buildNumber = info?["CFBundleVersion"] as? String
    if let shortVersion, let buildNumber {
        return "\(shortVersion) (\(buildNumber))"
    }
    return shortVersion ?? buildNumber
}

