private func nativeLocalDayString(from date: Date = Date()) -> String {
    let formatter = DateFormatter()
    formatter.locale = Locale(identifier: "en_US_POSIX")
    formatter.timeZone = .current
    formatter.dateFormat = "yyyy-MM-dd"
    return formatter.string(from: date)
}

private func nativeParseDate(_ raw: String?) -> Date? {
    guard let raw, !raw.isEmpty else { return nil }
    let isoFormatter = ISO8601DateFormatter()
    isoFormatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
    if let value = isoFormatter.date(from: raw) {
        return value
    }
    isoFormatter.formatOptions = [.withInternetDateTime]
    if let value = isoFormatter.date(from: raw) {
        return value
    }
    let formatter = DateFormatter()
    formatter.locale = Locale(identifier: "en_US_POSIX")
    formatter.dateFormat = "yyyy-MM-dd"
    formatter.timeZone = TimeZone(secondsFromGMT: 0)
    return formatter.date(from: raw)
}

private func nativeIsMomentToday(visitedAtIso: String?, visitedDate: String?) -> Bool {
    let localDay = nativeLocalDayString()

    if let visitedDate, !visitedDate.isEmpty {
        let normalizedVisitedDate = String(visitedDate.prefix(10))
        if normalizedVisitedDate == localDay {
            return true
        }
    }

    if let visitedAtIso,
       let date = nativeParseDate(visitedAtIso) {
        return Calendar.current.isDateInToday(date)
    }

    return false
}

private struct NativeAppleSignInPayload {
    let idToken: String
    let email: String?
    let givenName: String?
    let familyName: String?
}

@MainActor
private enum NativeGoogleSignInCoordinator {
    private static func resolvePresentingViewController() async -> UIViewController? {
        for attempt in 0..<8 {
            if let controller = nativeTopViewController() {
                nativeLogger.log("google sign-in presenting controller resolved attempt=\(attempt + 1, privacy: .public) type=\(String(describing: type(of: controller)), privacy: .public)")
                return controller
            }
            if attempt < 7 {
                nativeLogger.log("google sign-in waiting for presenting controller attempt=\(attempt + 1, privacy: .public)")
                try? await Task.sleep(nanoseconds: 150_000_000)
            }
        }
        nativeLogger.error("google sign-in presenting controller unavailable after retries")
        return nil
    }

    static func signIn(clientID: String) async throws -> String {
        #if canImport(GoogleSignIn)
        guard let presentingViewController = await resolvePresentingViewController() else {
            throw NSError(domain: "NativeGoogleSignIn", code: 1, userInfo: [NSLocalizedDescriptionKey: "No presenting view controller available."])
        }

        nativeLogger.log("google sign-in starting oauth clientID_present=\(!clientID.isEmpty, privacy: .public)")
        GIDSignIn.sharedInstance.configuration = GIDConfiguration(clientID: clientID)
        let result: GIDSignInResult
        do {
            result = try await GIDSignIn.sharedInstance.signIn(withPresenting: presentingViewController)
        } catch {
            nativeLogger.error("google sign-in sdk failed \(nativeDescribeError(error), privacy: .public)")
            throw error
        }

        guard let idToken = result.user.idToken?.tokenString, !idToken.isEmpty else {
            nativeLogger.error("google sign-in missing id token after sdk success")
            throw NSError(domain: "NativeGoogleSignIn", code: 2, userInfo: [NSLocalizedDescriptionKey: "Google did not return an ID token."])
        }

        nativeLogger.log("google sign-in sdk success token_length=\(idToken.count, privacy: .public)")
        return idToken
        #else
        throw NSError(
            domain: "NativeGoogleSignIn",
            code: 99,
            userInfo: [NSLocalizedDescriptionKey: "Google Sign-In is unavailable in this build."]
        )
        #endif
    }

    static func signOut() {
        #if canImport(GoogleSignIn)
        GIDSignIn.sharedInstance.signOut()
        #endif
    }
}

private final class NativeAppleSignInCoordinator: NSObject {
    private var continuation: CheckedContinuation<NativeAppleSignInPayload, Error>?
    private weak var presentationAnchor: ASPresentationAnchor?

    @MainActor
    func signIn() async throws -> NativeAppleSignInPayload {
        guard let presentingViewController = nativeTopViewController(),
              let window = presentingViewController.view.window ?? nativeKeyWindow() else {
            nativeLogger.error("apple sign-in presenting controller unavailable")
            throw NSError(domain: "NativeAppleSignIn", code: 1, userInfo: [NSLocalizedDescriptionKey: "No presenting view controller available."])
        }

        presentationAnchor = window
        nativeLogger.log("apple sign-in starting anchor_ready=true")

        return try await withCheckedThrowingContinuation { continuation in
            self.continuation = continuation
            let provider = ASAuthorizationAppleIDProvider()
            let request = provider.createRequest()
            request.requestedScopes = [.fullName, .email]

            let controller = ASAuthorizationController(authorizationRequests: [request])
            controller.delegate = self
            controller.presentationContextProvider = self
            controller.performRequests()
        }
    }
}

extension NativeAppleSignInCoordinator: ASAuthorizationControllerDelegate {
    func authorizationController(controller: ASAuthorizationController, didCompleteWithAuthorization authorization: ASAuthorization) {
        guard let credential = authorization.credential as? ASAuthorizationAppleIDCredential else {
            nativeLogger.error("apple sign-in invalid credential returned")
            continuation?.resume(throwing: NSError(domain: "NativeAppleSignIn", code: 2, userInfo: [NSLocalizedDescriptionKey: "Apple did not return a valid credential."]))
            continuation = nil
            return
        }

        guard
            let tokenData = credential.identityToken,
            let token = String(data: tokenData, encoding: .utf8),
            !token.isEmpty
        else {
            nativeLogger.error("apple sign-in missing identity token")
            continuation?.resume(throwing: NSError(domain: "NativeAppleSignIn", code: 3, userInfo: [NSLocalizedDescriptionKey: "Apple did not return an identity token."]))
            continuation = nil
            return
        }

        nativeLogger.log("apple sign-in sdk success token_length=\(token.count, privacy: .public) email_present=\(credential.email != nil, privacy: .public)")
        continuation?.resume(returning: NativeAppleSignInPayload(
            idToken: token,
            email: credential.email,
            givenName: credential.fullName?.givenName,
            familyName: credential.fullName?.familyName
        ))
        continuation = nil
    }

    func authorizationController(controller: ASAuthorizationController, didCompleteWithError error: Error) {
        nativeLogger.error("apple sign-in sdk failed \(nativeDescribeError(error), privacy: .public)")
        continuation?.resume(throwing: error)
        continuation = nil
    }
}

extension NativeAppleSignInCoordinator: ASAuthorizationControllerPresentationContextProviding {
    func presentationAnchor(for controller: ASAuthorizationController) -> ASPresentationAnchor {
        presentationAnchor ?? ASPresentationAnchor()
    }
}

