private struct NativeHomepageChallenge: Decodable, Identifiable {
    let id: String
    let icon: String
    let title: String
    let subtitle: String
    let cta: String
    let action: String
    let current: Int
    let target: Int

    private enum CodingKeys: String, CodingKey {
        case id
        case icon
        case title
        case subtitle
        case cta
        case action
        case current
        case target
    }

    init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        id = try container.decode(String.self, forKey: .id)
        icon = try container.decode(String.self, forKey: .icon)
        title = try container.decode(String.self, forKey: .title)
        subtitle = try container.decode(String.self, forKey: .subtitle)
        cta = try container.decode(String.self, forKey: .cta)
        action = try container.decode(String.self, forKey: .action)
        current = try container.decodeIfPresent(Int.self, forKey: .current) ?? 0
        target = max(try container.decodeIfPresent(Int.self, forKey: .target) ?? 1, 1)
    }

    var progressValue: Double {
        guard target > 0 else { return 0 }
        return min(max(Double(current) / Double(target), 0), 1)
    }
}

