private func nativeDecisionDerivedIntentId(withId: String, feelId: String, stateId: String) -> String {
    "\(withId)_\(feelId)_\(stateId)"
}

private func nativeDecisionIntentForSelection(
    withId: String,
    feelId: String,
    stateId: String
) -> NativeDecisionIntent {
    let icon: String = {
        switch feelId {
        case "quiet":
            return "moon.stars.fill"
        case "social":
            return "person.2.fill"
        case "lowkey":
            return "sparkles"
        case "great":
            return "sparkles.rectangle.stack.fill"
        default:
            return "cup.and.saucer.fill"
        }
    }()
    let title: String = {
        switch feelId {
        case "quiet":
            return "Quiet pick"
        case "social":
            return "Social pick"
        case "lowkey":
            return "Lowkey pick"
        case "great":
            return "Great pick"
        default:
            return "Chill pick"
        }
    }()
    let subtitle = "\(withId.replacingOccurrences(of: "_", with: " ")) + \(stateId.replacingOccurrences(of: "_", with: " "))"
    let categories: [String] = {
        switch feelId {
        case "great":
            return ["good_coffee", "aesthetic_cafes", "desserts_sweet_treats"]
        case "social":
            return ["good_coffee", "aesthetic_cafes"]
        case "quiet":
            return ["good_coffee"]
        default:
            return ["good_coffee", "aesthetic_cafes"]
        }
    }()
    return .init(
        id: nativeDecisionDerivedIntentId(withId: withId, feelId: feelId, stateId: stateId),
        title: title,
        subtitle: subtitle,
        icon: icon,
        primaryPreferenceCategories: categories
    )
}

private func nativeDecisionPreviewAssetNames(
    withId: String,
    feelId: String,
    stateId: String
) -> [String] {
    switch feelId {
    case "quiet":
        return stateId == "stay"
            ? ["good_coffee", "aesthetic_cafes", "asian_comfort_food"]
            : ["good_coffee", "parks_outdoor", "aesthetic_cafes"]
    case "social":
        return withId == "dating"
            ? ["aesthetic_cafes", "desserts_sweet_treats", "good_coffee"]
            : ["aesthetic_cafes", "good_coffee", "shop_stroll"]
    case "great":
        return ["good_coffee", "aesthetic_cafes", "desserts_sweet_treats"]
    case "lowkey":
        return stateId == "near"
            ? ["good_coffee", "street_food_casual_eats", "aesthetic_cafes"]
            : ["good_coffee", "aesthetic_cafes", "parks_outdoor"]
    default:
        return ["good_coffee", "aesthetic_cafes", "asian_comfort_food"]
    }
}

