    let previewAssets = nativeDecisionPreviewAssetNames(withId: withId, feelId: feelId, stateId: stateId)
    let templates: [(name: String, neighborhood: String, vibe: String, price: String, reason: String)] = {
        switch (withId, feelId, stateId) {
        case (_, _, "quick"):
            return [
                ("Circuit Coffee", "Back Bay", "Fast espresso", "$4-6", "Closest coffee stop with a no-fuss flow."),
                ("Corner Window Cafe", "South End", "Quick caffeine", "$5-7", "Easy in, easy out, still feels cute."),
                ("Early Shift Coffee", "Beacon Hill", "Grab-and-go", "$4-6", "Best pick when you want to keep moving."),
            ]
        case (_, "quiet", _), (_, "chill", "stay"):
            return [
                ("Velvet Roast", "South End", "Cozy cafe", "$6-9", "Warm lighting and a slower pace for a reset."),
                ("Soft Hour Coffee", "Cambridge", "Quiet corner", "$5-8", "Feels tucked away without being dead."),
                ("Candle Table Cafe", "Back Bay", "Soft vibe", "$6-8", "A calmer backup if you want to stay awhile."),
            ]
        case ("friends", "social", _), ("dating", "social", _):
            return [
                ("Second Sip Cafe", "Cambridge", "Social cafe", "$6-9", "Easy seating and better talk energy."),
                ("Meet Me At Noon", "Back Bay", "Catch-up spot", "$6-8", "Balanced enough for coffee and conversation."),
                ("Sidewalk Table Coffee", "South End", "People-watch coffee", "$5-8", "Good if you want a more lively backup."),
            ]
        case ("work", _, _), (_, "quiet", "stay"):
            return [
                ("Open Tabs Coffee", "Cambridge", "Work-friendly", "$5-8", "Best bet if you want to lock in for a bit."),
                ("Signal Roast", "Back Bay", "Laptop cafe", "$5-7", "Reliable for a solo work block."),
                ("Study Hall Espresso", "Fenway", "Quiet productivity", "$4-7", "Lower-friction focus option."),
            ]
        case ("dating", _, _), (_, "great", _):
            return [
                ("Butter Crumb Cafe", "Back Bay", "Coffee + pastry", "$7-10", "Strong dessert payoff without losing the coffee."),
                ("Sugar Window", "South End", "Sweet treat cafe", "$6-9", "Best if you want a softer indulgent stop."),
                ("Cloud Bakery Coffee", "Cambridge", "Pastry run", "$6-10", "Backup with a stronger bakery vibe."),
            ]
        default:
            return [
                ("Third Wave Room", "Back Bay", "Specialty coffee", "$5-8", "Strongest cup-first pick for today."),
                ("Dialed Espresso", "Cambridge", "Coffee-forward", "$5-7", "Balanced backup with a sharper coffee lean."),
                ("Roast Theory", "South End", "Worth the cup", "$6-9", "Good if you want a slightly more vibey option."),
            ]
        }
    }()

    let options = templates.enumerated().map { index, template in
        NativeDecisionSessionOption(
            id: "preview-\(profile.id)-\(index + 1)",
            rank: index + 1,
            sourceType: "preview",
            isSelected: false,
            isSkipped: false,
            isVisible: true,
            score: Double(86 - (index * 6)),
            reasonLabel: template.reason,
            place: NativeDecisionSessionPlace(
                id: "preview-place-\(profile.id)-\(index + 1)",
                googlePlaceId: nil,
                name: template.name,
                thumbnailUrl: "asset://\(previewAssets[safe: index] ?? "good_coffee")",
                distanceMiles: [0.6, 1.1, 1.7][safe: index] ?? 1.2,
                travelTimeLabel: ["4 mins away", "8 mins away", "11 mins away"][safe: index] ?? "7 mins away",
                neighborhood: template.neighborhood,
                city: city.label,
                vibeLabel: template.vibe,
                feelEvidenceLabel: template.reason,
                priceRangeLabel: template.price,
                topBadge: index == 0 ? "Preview pick" : nil,
                timeToVisit: stateId == "quick" ? ["Morning", "Afternoon"] : ["Anytime"],
                traitSource: "preview",
                archetype: nil,
                traitConfidence: nil
            )
        )
    }

    return NativeDecisionSessionResponse(
        session: NativeDecisionSessionMeta(
            id: "preview-session-\(profile.id)-\(city.id)",
            status: "active",
            cityKey: city.id.replacingOccurrences(of: "-", with: "_"),
            cityLabel: city.label,
            entryMode: "preview",
            intentId: profile.id,
            swapCount: 0,
            skipCount: 0,
            expiresAt: nil
        ),
        options: options,
        debug: NativeDecisionSessionDebug(
            requestedIntentId: profile.id,
            normalizedIntentId: profile.id,
            resolvedIntentId: profile.id
        )
    )
}

private func nativeDecisionSessionPlaceAsPlace(_ place: NativeDecisionSessionPlace) -> NativePlace {
    NativePlace(
        id: place.id,
        googlePlaceId: place.googlePlaceId,
        autocompleteSessionToken: nil,
        name: place.name,
        location: [place.neighborhood, place.city].compactMap { value in
            guard let value, !value.isEmpty else { return nil }
            return value
        }.joined(separator: ", ").isEmpty ? (place.city ?? "Unknown") : [place.neighborhood, place.city].compactMap { value in
            guard let value, !value.isEmpty else { return nil }
            return value
        }.joined(separator: ", "),
        address: nil,
        neighborhood: place.neighborhood,
        category: place.vibeLabel,
        description: nil,
        hook: nil,
        image: place.thumbnailUrl,
        images: place.thumbnailUrl.map { [$0] },
        momentMedia: nil,
        placeMediaUrls: place.thumbnailUrl.map { [$0] },
        userMediaUrls: nil,
        tags: place.vibeLabel.map { [$0] },
        attitudeLabel: nil,
        bestTime: place.timeToVisit?.joined(separator: ", "),
        similarityStat: nil,
        whyYoullLikeIt: nil,
        recommendationReason: nil,
        rating: nil,
        priceLevel: nil,
        openingHours: nil,
        servesBreakfast: nil,
        servesLunch: nil,
        servesDinner: nil,
        servesBeer: nil,
        servesWine: nil,
        servesBrunch: nil,
        servesDessert: nil,
        servesCoffee: true,
        servesCocktails: nil,
        goodForGroups: nil,
        goodForWatchingSports: nil,
        timeZone: nil,
        utcOffsetMinutes: nil,
        outdoors: nil,
        outdoorSeating: nil,
        mapsUrl: nil,
        latitude: nil,
        longitude: nil,
        priceRange: nil,
        priceRangeLabel: place.priceRangeLabel,
        discoverySignals: nil,
        discoveryTopRank: nil,
        topBadgeLabel: place.topBadge,
        tabIds: nil,
        momentId: nil,
        ownerUserId: nil,
        visitedDate: nil,
        visitedAtIso: nil,
        momentCaption: nil,
        momentWouldRevisit: nil,
        momentRating: nil,
        momentRatingLabel: nil,
        traitSource: place.traitSource,
        archetype: place.archetype,
        traitConfidence: place.traitConfidence
    )
}

private func nativeDecisionDirectionsURL(for place: NativeDecisionSessionPlace) -> URL? {
    let query = [place.name, place.neighborhood, place.city]
        .compactMap { value -> String? in
            guard let value, !value.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { return nil }
            return value
        }
        .joined(separator: ", ")

    guard !query.isEmpty else { return nil }
    let encoded = query.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? query
    return URL(string: "http://maps.apple.com/?q=\(encoded)")
}

