private enum NativeWidgetSnapshotStore {
    private static var fileURL: URL? {
        FileManager.default
            .containerURL(forSecurityApplicationGroupIdentifier: nativeWidgetAppGroupIdentifier)?
            .appendingPathComponent(nativeWidgetSnapshotFileName)
    }

    static func load() -> NativeWidgetSnapshot? {
        guard let fileURL else { return nil }
        guard let data = try? Data(contentsOf: fileURL) else { return nil }
        return try? JSONDecoder().decode(NativeWidgetSnapshot.self, from: data)
    }

    static func save(_ snapshot: NativeWidgetSnapshot) {
        guard let fileURL else { return }
        guard let data = try? JSONEncoder().encode(snapshot) else { return }
        try? data.write(to: fileURL, options: [.atomic])
    }

    static func clear() {
        guard let fileURL else { return }
        try? FileManager.default.removeItem(at: fileURL)
    }
}

private enum NativeWidgetImageCacheStore {
    private static var containerURL: URL? {
        FileManager.default.containerURL(forSecurityApplicationGroupIdentifier: nativeWidgetAppGroupIdentifier)
    }

    private static var directoryURL: URL? {
        containerURL?.appendingPathComponent(nativeWidgetImageCacheDirectoryName, isDirectory: true)
    }

    private static func ensureDirectoryIfNeeded() throws -> URL {
        guard let directoryURL else {
            throw NSError(
                domain: "NativeWidgetImageCache",
                code: 1,
                userInfo: [NSLocalizedDescriptionKey: "App Group container is unavailable."]
            )
        }
        try FileManager.default.createDirectory(at: directoryURL, withIntermediateDirectories: true)
        return directoryURL
    }

    private static func fileName(for cacheKey: String, fileExtension: String) -> String {
        let sanitizedKey = cacheKey.replacingOccurrences(
            of: "[^a-zA-Z0-9_-]+",
            with: "-",
            options: .regularExpression
        )
        return "\(sanitizedKey).\(fileExtension)"
    }

    static func fileURL(forRelativePath relativePath: String?) -> URL? {
        guard let relativePath, let containerURL else { return nil }
        return containerURL.appendingPathComponent(relativePath)
    }

    static func cacheImage(from remoteURLString: String?, cacheKey: String) async -> String? {
        guard let resolved = nativeResolvedImageURL(remoteURLString) else { return nil }
        guard let url = URL(string: resolved) else { return nil }

        do {
            let directoryURL = try ensureDirectoryIfNeeded()
            let (data, response) = try await URLSession.shared.data(from: url)
            guard let httpResponse = response as? HTTPURLResponse,
                  (200..<300).contains(httpResponse.statusCode),
                  !data.isEmpty else {
                return nil
            }

            guard let image = UIImage(data: data) else {
                nativeLogger.error("widget image cache decode failed for: \(resolved, privacy: .public)")
                return nil
            }

            let hasAlpha = image.cgImage?.alphaInfo == .premultipliedFirst
                || image.cgImage?.alphaInfo == .premultipliedLast
                || image.cgImage?.alphaInfo == .first
                || image.cgImage?.alphaInfo == .last

            let encodedData: Data?
            let fileExtension: String
            if hasAlpha {
                encodedData = image.pngData()
                fileExtension = "png"
            } else {
                encodedData = image.jpegData(compressionQuality: 0.92)
                fileExtension = "jpg"
            }

            guard let encodedData, !encodedData.isEmpty else {
                nativeLogger.error("widget image cache encode failed for: \(resolved, privacy: .public)")
                return nil
            }

            let fileName = fileName(for: cacheKey, fileExtension: fileExtension)
            let destinationURL = directoryURL.appendingPathComponent(fileName)
            let relativePath = "\(nativeWidgetImageCacheDirectoryName)/\(fileName)"

            if FileManager.default.fileExists(atPath: destinationURL.path) {
                try? FileManager.default.removeItem(at: destinationURL)
            }

            try encodedData.write(to: destinationURL, options: [.atomic])
            return relativePath
        } catch {
            nativeLogger.error("widget image cache failed: \(error.localizedDescription, privacy: .public)")
            return nil
        }
    }

    static func clear() {
        guard let directoryURL else { return }
        try? FileManager.default.removeItem(at: directoryURL)
    }
}

@MainActor
private final class NativeAppState: NSObject, ObservableObject, CLLocationManagerDelegate {
    private enum NativeSessionFlavor: String {
        case legacy
        case v2
    }

    @Published var isBootstrapping = true
    @Published var currentUser: NativeAuthUser?
    @Published var activeTab: NativeTab = .discover
    @Published var selectedLocation = NativeLocationOption(id: "boston", label: "Boston")
    @Published var selectedInterests: [String] = []
    @Published var selectedVibe: String?
    @Published var hasCompletedOnboarding = false
    @Published var hasCompletedInviteOnboarding = false
    @Published var isDiscoveryLoading = false
    @Published var isDiscoveryLoadingMore = false
    @Published var discoveryPlaces: [NativePlace] = []
    @Published var decisionIntents: [NativeDecisionIntent] = []
    @Published var selectedDecisionIntentId: String?
    @Published var selectedDecisionWithValue: String = nativeDecisionWithOptions[0].id
    @Published var selectedDecisionFeelValue: String = nativeDecisionFeelOptions[0].id
    @Published var selectedDecisionStateValue: String = nativeDecisionStateOptions[0].id
    @Published var decisionSession: NativeDecisionSessionResponse?
    @Published var isDecisionLoading = false
    @Published var decisionErrorMessage: String?
    @Published var discoveryInspirationMedia: [NativeDiscoveryInspirationMedia] = []
    @Published var discoveryPage = 1
    @Published var discoveryHasMore = false
    @Published var todayRecommendation: NativeTodayRecommendationResponse?
    @Published var isTodayRecommendationLoading = false
    @Published var todayRecommendationErrorMessage: String?
    @Published var savedEntries: [NativeSavedEntry] = []
    @Published var savedPlaces: [NativePlace] = []
    @Published var collections: [NativeCollection] = []
    @Published var myMoments: [NativeMoment] = []
    @Published var homepageOverview: NativeHomepageOverview?
    @Published var homepageRecentMemories: [NativeMoment] = []
    @Published var diaryMoments: [NativeMoment] = []
    @Published var ownFeedItemsCache: [NativeFeedItem] = []
    @Published var followedTravelers: [NativeTravelerSummary] = []
    @Published var suggestedTravelers: [NativeTravelerSummary] = []
    @Published var feedItems: [NativeFeedItem] = []
    @Published var fallbackFeedItems: [NativeFeedItem] = []
    @Published var suggestedFeedItems: [NativeFeedItem] = []
    @Published var blockedTravelerIds: Set<String> = []
    @Published var showFloatingTabBar = true
    @Published var chatUnreadCount = 0
    @Published var notificationUnreadCount = 0
    @Published var currentCoordinate: CLLocationCoordinate2D?
    @Published var detectedLocationCityName: String?
    @Published var locationPermissionState: NativeLocationPermissionState = .notDetermined
    @Published var notificationPermissionState: NativeNotificationPermissionState = .notDetermined
    @Published var profileErrorMessage: String?
    @Published var discoveryErrorMessage: String?
    @Published var homepageOverviewErrorMessage: String?
    @Published var homepageRecentMemoriesErrorMessage: String?
    @Published var diaryMomentsErrorMessage: String?
    @Published var feedErrorMessage: String?
    @Published var savedErrorMessage: String?
    @Published var activeToast: NativeToastState?
    @Published var showAuthSheet = false
    @Published var authSheetReason: String?
    @Published var showPreferenceSetupSheet = false
    @Published var showCheckInSheet = false
    @Published var showDecisionLocationPermissionSheet = false
    @Published var checkInPrefilledPlace: NativePlace?
    @Published var checkInPrefilledPhotoAsset: NativePickedPhotoAsset?
    @Published var checkInPrefilledImage: UIImage?
    @Published var checkInPrefilledVisitedDate: String?
    @Published var unsupportedCityGateEnabled = true

    private let api = NativeAPIClient()
    private let authTokenKey = "vibinn_native_auth_token"
    private let cachedUserKey = "vibinn_native_cached_user"
    private let onboardingKey = "vibinn_native_onboarding_completed"
    private let inviteOnboardingKey = "vibinn_native_invite_onboarding_completed"
    private let sessionFlavorKey = "vibinn_native_session_flavor"
    private let locationKey = "vibinn_native_location_label"
    private let selectedInterestsKey = "vibinn_native_selected_interests"
    private let selectedVibeKey = "vibinn_native_selected_vibe"
    private let decisionSessionCacheKey = "vibinn_native_decision_session"
    private let syncedPushTokenKey = "vibinn_native_synced_push_token"
    private let hasPromptedForPushAfterContentActionKeyPrefix = "vibinn_native_push_prompt_after_content_action"
    private let locationManager = CLLocationManager()
    private let geocoder = CLGeocoder()
    private var floatingTabBarHideDepth = 0
    private var followStateOverrides: [String: Bool] = [:]
    private var pendingPostAuthAction: NativePostAuthAction?
    private var placeDetailCache: [String: NativeCachedPlaceDetail] = [:]
    private let placeDetailCacheTTL: TimeInterval = 120
    private var hasStartedBootstrap = false
    private var lastGeocodedCoordinate: CLLocationCoordinate2D?
    private var toastDismissWorkItem: DispatchWorkItem?

    var fallbackLocationWhenGateDisabled: NativeLocationOption? {
        guard unsupportedCityGateEnabled == false else { return nil }
        return nativeLocationOptions.first(where: { $0.id == "boston" }) ?? nativeLocationOptions.first
    }

    var effectiveDecisionLocation: NativeLocationOption {
        nativeSupportedLocation(for: currentCoordinate)
            ?? fallbackLocationWhenGateDisabled
            ?? selectedLocation
    }

    var trackedSupportedLocation: NativeLocationOption? {
        nativeSupportedLocation(for: currentCoordinate)
    }

    var shouldShowCityComingSoonGate: Bool {
        unsupportedCityGateEnabled
            &&
        locationPermissionState == .authorized
            && currentCoordinate != nil
            && trackedSupportedLocation == nil
    }

    var currentLocationLabelForUI: String {
        if let resolvedLocation = trackedSupportedLocation ?? fallbackLocationWhenGateDisabled {
            return resolvedLocation.label
        }
        guard locationPermissionState == .authorized else { return "Vibinn" }
        if let detectedLocationCityName, !detectedLocationCityName.isEmpty {
            return detectedLocationCityName
        }
        return "Vibinn"
    }

    var currentUnsupportedCityLabel: String {
        if let detectedLocationCityName, !detectedLocationCityName.isEmpty {
            return detectedLocationCityName
        }
        return "your city"
    }

    var hasActiveDecisionDeck: Bool {
        guard let session = decisionSession, session.session.status == "active" else { return false }
        return session.options.contains { $0.isVisible && !$0.isSkipped && !$0.isSelected }
    }

    var shouldShowUnlockVibeCTA: Bool {
        if let currentUser {
            return currentUser.hasCompletedTastePreferences != true
        }
        return true
    }

    var debugCurrentPushToken: String? {
        currentPushToken
    }

    var debugLastSyncedPushToken: String? {
        lastSyncedPushToken
    }

    var hasSyncedCurrentPushToken: Bool {
        guard let currentPushToken else { return false }
        return currentPushToken == lastSyncedPushToken
    }

    override init() {
        super.init()
        let storedLocation = UserDefaults.standard.string(forKey: locationKey) ?? "Boston"
        self.selectedLocation = nativeLocationOptions.first {
            $0.label.caseInsensitiveCompare(storedLocation) == .orderedSame
                || $0.id.caseInsensitiveCompare(storedLocation) == .orderedSame
        } ?? nativeLocationOptions[0]
        UserDefaults.standard.set(self.selectedLocation.label, forKey: locationKey)
        self.hasCompletedOnboarding = UserDefaults.standard.bool(forKey: onboardingKey)
        if let storedInviteOnboarding = UserDefaults.standard.object(forKey: inviteOnboardingKey) as? Bool {
            self.hasCompletedInviteOnboarding = storedInviteOnboarding
        } else {
            self.hasCompletedInviteOnboarding = self.hasCompletedOnboarding
            UserDefaults.standard.set(self.hasCompletedInviteOnboarding, forKey: inviteOnboardingKey)
        }
        self.selectedInterests = UserDefaults.standard.stringArray(forKey: selectedInterestsKey) ?? []
        self.selectedVibe = UserDefaults.standard.string(forKey: selectedVibeKey)
        self.decisionSession = loadPersistedDecisionSession()
        if authToken == nil {
            self.isBootstrapping = false
        } else if let cachedUser = cachedAuthUser {
            self.currentUser = cachedUser
            self.isBootstrapping = false
        }
        locationManager.delegate = self
        locationManager.desiredAccuracy = kCLLocationAccuracyHundredMeters
        syncLocationPermissionState(with: locationManager.authorizationStatus)
        if locationPermissionState == .authorized {
            locationManager.startUpdatingLocation()
        }
        Task { [weak self] in
            await self?.refreshClientConfig()
        }
        Task { [weak self] in
            await self?.refreshNotificationPermissionState()
        }
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handlePushTokenUpdated(_:)),
            name: nativePushTokenNotification,
            object: nil
        )
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handleWidgetDeepLinkNotification(_:)),
            name: nativeWidgetDeepLinkNotification,
            object: nil
        )
        handlePendingWidgetDeepLinkIfNeeded()
        nativeLogger.log("NativeAppState init. location=\(self.selectedLocation.label, privacy: .public) onboarding=\(self.hasCompletedOnboarding, privacy: .public)")
    }

    deinit {
        NotificationCenter.default.removeObserver(self)
    }

    nonisolated func locationManagerDidChangeAuthorization(_ manager: CLLocationManager) {
        Task { @MainActor in
            self.syncLocationPermissionState(with: manager.authorizationStatus)
            if self.locationPermissionState == .authorized {
                manager.startUpdatingLocation()
            }
        }
    }

    nonisolated func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        guard let coordinate = locations.last?.coordinate else { return }
        Task { @MainActor in
            self.currentCoordinate = coordinate
            if let resolvedLocation = self.trackedSupportedLocation ?? self.fallbackLocationWhenGateDisabled,
               self.selectedLocation != resolvedLocation {
                self.selectedLocation = resolvedLocation
                UserDefaults.standard.set(resolvedLocation.label, forKey: self.locationKey)
            }
            self.reverseGeocodeCityIfNeeded(for: coordinate)
        }
    }

    func refreshClientConfig() async {
        do {
            let config = try await api.getClientConfig()
            let resolvedGateEnabled = nativeForceDisableUnsupportedCityGate ? false : config.unsupportedCityGateEnabled
            unsupportedCityGateEnabled = resolvedGateEnabled
            nativeLogger.log("client config loaded unsupportedCityGateEnabled=\(config.unsupportedCityGateEnabled, privacy: .public) resolvedUnsupportedCityGateEnabled=\(resolvedGateEnabled, privacy: .public)")
            if let resolvedLocation = trackedSupportedLocation ?? fallbackLocationWhenGateDisabled,
               selectedLocation != resolvedLocation {
                selectedLocation = resolvedLocation
                UserDefaults.standard.set(resolvedLocation.label, forKey: locationKey)
            }
        } catch {
            nativeLogger.error("client config failed: \(error.localizedDescription, privacy: .public)")
        }
    }

    private func syncLocationPermissionState(with status: CLAuthorizationStatus) {
        switch status {
        case .authorizedAlways, .authorizedWhenInUse:
            locationPermissionState = .authorized
        case .denied, .restricted:
            locationPermissionState = .denied
            currentCoordinate = nil
            detectedLocationCityName = nil
        case .notDetermined:
            locationPermissionState = .notDetermined
            currentCoordinate = nil
            detectedLocationCityName = nil
        @unknown default:
            locationPermissionState = .denied
            currentCoordinate = nil
            detectedLocationCityName = nil
        }
    }

    private func reverseGeocodeCityIfNeeded(for coordinate: CLLocationCoordinate2D) {
        if let lastGeocodedCoordinate {
            let last = CLLocation(latitude: lastGeocodedCoordinate.latitude, longitude: lastGeocodedCoordinate.longitude)
            let current = CLLocation(latitude: coordinate.latitude, longitude: coordinate.longitude)
            if current.distance(from: last) < 800 {
                return
            }
        }

        lastGeocodedCoordinate = coordinate
        geocoder.cancelGeocode()
        let location = CLLocation(latitude: coordinate.latitude, longitude: coordinate.longitude)
        geocoder.reverseGeocodeLocation(location) { [weak self] placemarks, _ in
            guard let self else { return }
            let resolvedCity = placemarks?
                .first
                .flatMap { placemark in
                    placemark.locality
                        ?? placemark.subAdministrativeArea
                        ?? placemark.administrativeArea
                        ?? placemark.name
                }?
                .trimmingCharacters(in: .whitespacesAndNewlines)

            DispatchQueue.main.async {
                self.detectedLocationCityName = resolvedCity
            }
        }
    }

    private func syncNotificationPermissionState(with status: UNAuthorizationStatus) {
        switch status {
        case .authorized, .provisional, .ephemeral:
            notificationPermissionState = .authorized
        case .denied:
            notificationPermissionState = .denied
        case .notDetermined:
            notificationPermissionState = .notDetermined
        @unknown default:
            notificationPermissionState = .denied
        }
    }

    func refreshNotificationPermissionState() async {
        let settings: UNNotificationSettings = await withCheckedContinuation { continuation in
            UNUserNotificationCenter.current().getNotificationSettings { settings in
                continuation.resume(returning: settings)
            }
        }
        syncNotificationPermissionState(with: settings.authorizationStatus)
    }

    var shouldShowLocationAccessCTA: Bool {
        locationPermissionState != .authorized
    }

    var canGenerateDecisionWithCurrentLocation: Bool {
        locationPermissionState == .authorized && currentCoordinate != nil
    }

    func trackAnalytics(_ event: NativeAnalyticsEvent, properties: [String: Any] = [:]) {
        var merged: [String: Any] = [
            "platform": "ios",
            "device_type": UIDevice.current.userInterfaceIdiom == .pad ? "ipad" : "iphone",
            "os_version": UIDevice.current.systemVersion,
            "app_version": nativeAppVersionString() ?? "unknown",
            "city": selectedLocation.label,
            "is_logged_in": currentUser != nil,
        ]
        if let currentUser {
            merged["user_id"] = currentUser.id
            merged["username"] = currentUser.username
        }
        properties.forEach { key, value in
            merged[key] = value
        }
        NativeMixpanelTracker.shared.track(event, properties: merged)
    }

    func placeAnalyticsProperties(
        _ place: NativePlace,
        source: String? = nil,
        extra: [String: Any] = [:]
    ) -> [String: Any] {
        var properties: [String: Any] = [
            "place_id": place.id,
            "place_name": place.name,
            "place_city": nativePrimaryCity(from: place.location) ?? place.location,
        ]
        if let source {
            properties["source"] = source
        }
        if let googlePlaceId = place.googlePlaceId {
            properties["google_place_id"] = googlePlaceId
        }
        if let neighborhood = place.neighborhood {
            properties["neighborhood"] = neighborhood
        }
        if let category = place.category {
            properties["category"] = category
        }
        if let score = place.similarityStat {
            properties["compatibility_score"] = score
        }
        if let rank = place.discoveryTopRank {
            properties["top_rank"] = rank
        }
        extra.forEach { key, value in
            properties[key] = value
        }
        return properties
    }

