    func requestLocationAccessOrOpenSettings() {
        switch locationPermissionState {
        case .authorized:
            locationManager.startUpdatingLocation()
        case .notDetermined:
            locationManager.requestWhenInUseAuthorization()
        case .denied:
            guard let url = URL(string: UIApplication.openSettingsURLString) else { return }
            UIApplication.shared.open(url)
        }
    }

    func openSystemSettings() {
        guard let url = URL(string: UIApplication.openSettingsURLString) else { return }
        UIApplication.shared.open(url)
    }

    /// Only triggers the native permission dialog when the user hasn't decided yet.
    /// (Used in onboarding so we don't bounce users to Settings.)
    func requestLocationAuthorizationIfNeeded() {
        guard locationPermissionState == .notDetermined else { return }
        locationManager.requestWhenInUseAuthorization()
    }

    func pushFloatingTabBarHidden() {
        floatingTabBarHideDepth += 1
        showFloatingTabBar = floatingTabBarHideDepth <= 0
    }

    func popFloatingTabBarHidden() {
        floatingTabBarHideDepth = max(0, floatingTabBarHideDepth - 1)
        showFloatingTabBar = floatingTabBarHideDepth <= 0
    }

    func bootstrap() async {
        nativeLogger.log("bootstrap start")
        guard !hasStartedBootstrap else { return }
        hasStartedBootstrap = true
        guard let token = authToken else {
            isBootstrapping = false
            return
        }

        if let cachedUser = cachedAuthUser {
            currentUser = cachedUser
            isBootstrapping = false
            nativeLogger.log("bootstrap cached user=\(cachedUser.username, privacy: .public)")
            Task { [weak self] in
                await self?.validateSessionAndRunStartupMaintenance(token: token)
            }
            return
        }

        do {
            let session = try await api.getAuthSession(token: token)
            currentUser = session.user
            cachedAuthUser = session.user
            if session.user.hasCompletedTastePreferences != true {
                markOnboardingRequiredAfterAuth()
            }
            isBootstrapping = false
            Task { [weak self] in
                await self?.runStartupMaintenance()
            }
            nativeLogger.log("bootstrap session ok user=\(session.user.username, privacy: .public)")
        } catch {
            nativeLogger.error("bootstrap legacy session failed: \(error.localizedDescription, privacy: .public)")
            if shouldClearSession(for: error) {
                do {
                    let v2Session = try await api.getV2AuthSession(token: token)
                    syncCurrentUserFromV2Payload(v2Session.user)
                    if v2Session.user.onboardingCompleted == true {
                        markInviteOnboardingCompletedAfterAuth()
                    }
                    isBootstrapping = false
                    Task { [weak self] in
                        await self?.runStartupMaintenance()
                    }
                    nativeLogger.log("bootstrap v2 session ok user=\(self.currentUser?.username ?? "unknown", privacy: .public)")
                } catch {
                    nativeLogger.error("bootstrap v2 session failed: \(error.localizedDescription, privacy: .public)")
                    if shouldClearSession(for: error) {
                        clearSession()
                    }
                    isBootstrapping = false
                }
            } else {
                isBootstrapping = false
            }
        }
    }

    private func validateSessionAndRunStartupMaintenance(token: String) async {
        do {
            let session = try await api.getAuthSession(token: token)
            guard authToken == token else { return }
            sessionFlavor = .legacy
            currentUser = session.user
            cachedAuthUser = session.user
            if session.user.hasCompletedTastePreferences != true {
                markOnboardingRequiredAfterAuth()
            }
            await runStartupMaintenance()
            nativeLogger.log("bootstrap session revalidated user=\(session.user.username, privacy: .public)")
        } catch {
            guard authToken == token else { return }
            nativeLogger.error("bootstrap legacy revalidate failed: \(error.localizedDescription, privacy: .public)")
            if shouldClearSession(for: error) {
                do {
                    let v2Session = try await api.getV2AuthSession(token: token)
                    guard authToken == token else { return }
                    sessionFlavor = .v2
                    syncCurrentUserFromV2Payload(v2Session.user)
                    if v2Session.user.onboardingCompleted == true {
                        markInviteOnboardingCompletedAfterAuth()
                    }
                    await runStartupMaintenance()
                    nativeLogger.log("bootstrap v2 revalidated user=\(self.currentUser?.username ?? "unknown", privacy: .public)")
                } catch {
                    guard authToken == token else { return }
                    nativeLogger.error("bootstrap v2 revalidate failed: \(error.localizedDescription, privacy: .public)")
                    if shouldClearSession(for: error) {
                        clearSession()
                    }
                }
            }
        }
    }

    private func runStartupMaintenance() async {
        await syncLocalTastePreferencesIfNeeded()
        await refreshCurrentPushTokenFromFirebase()
        await refreshHomepageOverview()
        await refreshHomepageRecentMemories()
        guard usesV2Session == false else {
            chatUnreadCount = 0
            notificationUnreadCount = 0
            return
        }
        await syncPushTokenIfPossible()
        await refreshChatUnreadCount()
    }

    private func shouldClearSession(for error: Error) -> Bool {
        let nsError = error as NSError
        return nsError.domain == "NativeAPI" && nsError.code == 401
    }

    private func unsupportedLegacyFeatureError(_ featureName: String) -> NSError {
        NSError(
            domain: "NativeFeatureUnavailable",
            code: 1,
            userInfo: [NSLocalizedDescriptionKey: "\(featureName) isn't available in the new app yet."]
        )
    }

