    func presentCheckInFlow(
        prefilledPlace: NativePlace? = nil,
        prefilledPhotoAsset: NativePickedPhotoAsset? = nil,
        prefilledImage: UIImage? = nil,
        prefilledVisitedDate: String? = nil
    ) {
        guard currentUser != nil else {
            nativeHaptic(.warning)
            presentAuthGate(
                reason: "Log in to save your check-ins.",
                postAuthAction: .openCheckIn(place: prefilledPlace)
            )
            return
        }
        nativeHaptic(.medium)
        checkInPrefilledPlace = prefilledPlace
        checkInPrefilledPhotoAsset = prefilledPhotoAsset
        checkInPrefilledImage = prefilledImage ?? prefilledPhotoAsset?.image
        checkInPrefilledVisitedDate = prefilledVisitedDate ?? prefilledPhotoAsset?.capturedAt.map { NativeCheckInScreen.isoDayString(from: $0) }
        showCheckInSheet = true
    }

    func dismissCheckInFlow() {
        showCheckInSheet = false
        checkInPrefilledPlace = nil
        checkInPrefilledPhotoAsset = nil
        checkInPrefilledImage = nil
        checkInPrefilledVisitedDate = nil
    }

    func performPendingPostAuthActionIfNeeded() {
        guard let action = pendingPostAuthAction else { return }
        pendingPostAuthAction = nil
        switch action {
        case .openPreferenceSetup:
            showPreferenceSetupSheet = true
        case .openTodayRecommendation:
            Task { await loadTodayRecommendation() }
        case .openCheckIn(let place):
            checkInPrefilledPlace = place
            showCheckInSheet = true
        }
    }

    func updateTastePreferences(selectedInterests: [String], selectedVibe: String?) async {
        self.selectedInterests = selectedInterests
        self.selectedVibe = selectedVibe
        UserDefaults.standard.set(selectedInterests, forKey: selectedInterestsKey)
        UserDefaults.standard.set(selectedVibe, forKey: selectedVibeKey)

        guard let token = authToken else { return }

        do {
            try await api.savePreferences(
                token: token,
                selectedInterests: selectedInterests,
                selectedVibe: selectedVibe,
                skippedPreferences: selectedInterests.isEmpty && selectedVibe == nil,
                onboardingCompleted: true
            )
            if let currentUser {
                let updatedUser = NativeAuthUser(
                    id: currentUser.id,
                    displayName: currentUser.displayName,
                    username: currentUser.username,
                    email: currentUser.email,
                    bio: currentUser.bio,
                    avatarUrl: currentUser.avatarUrl,
                    hasCompletedTastePreferences: true
                )
                self.currentUser = updatedUser
                cachedAuthUser = updatedUser
            }
        } catch {
            nativeLogger.error("savePreferences failed: \(error.localizedDescription, privacy: .public)")
        }
    }

    func completeOnboarding(
        with location: NativeLocationOption,
        selectedInterests: [String] = [],
        selectedVibe: String? = nil,
        preserveExistingPreferences: Bool = false
    ) async {
        selectedLocation = location
        UserDefaults.standard.set(true, forKey: onboardingKey)
        UserDefaults.standard.set(true, forKey: inviteOnboardingKey)
        UserDefaults.standard.set(location.label, forKey: locationKey)
        hasCompletedOnboarding = true
        hasCompletedInviteOnboarding = true
        if preserveExistingPreferences {
            if currentUser?.hasCompletedTastePreferences != true {
                await updateTastePreferences(selectedInterests: selectedInterests, selectedVibe: selectedVibe)
            }
        } else {
            await updateTastePreferences(selectedInterests: selectedInterests, selectedVibe: selectedVibe)
        }
        Task { await self.refreshDiscovery() }
        Task { await self.refreshFeed() }
    }

    func updateLocation(to location: NativeLocationOption) async {
        let supportedLocation = nativeLocationOptions.first { $0.id == location.id || $0.label == location.label } ?? nativeLocationOptions[0]
        guard selectedLocation != supportedLocation else { return }
        selectedLocation = supportedLocation
        UserDefaults.standard.set(supportedLocation.label, forKey: locationKey)
        discoveryPlaces = []
        discoveryInspirationMedia = []
        discoveryPage = 1
        discoveryHasMore = false
        todayRecommendation = nil
        todayRecommendationErrorMessage = nil
        decisionSession = nil
        decisionErrorMessage = nil
        clearPersistedDecisionSession()
        await refreshDiscovery()
    }

    func joinCityWaitlist(email: String, cityLabel: String) async throws {
        let normalizedEmail = email.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        guard !normalizedEmail.isEmpty else {
            throw NSError(
                domain: "NativeWaitlist",
                code: 1,
                userInfo: [NSLocalizedDescriptionKey: "Please enter a valid email address."]
            )
        }

        _ = try await api.joinWaitlist(
            email: normalizedEmail,
            source: "ios-coming-soon:\(cityLabel.lowercased())"
        )
    }

    func loadTodayRecommendation(focus: String? = nil) async {
        guard let token = authToken else {
            presentAuthGate(
                reason: "Log in to get today's recommendation.",
                postAuthAction: .openTodayRecommendation
            )
            return
        }

        guard locationPermissionState == .authorized else {
            todayRecommendation = nil
            todayRecommendationErrorMessage = "Enable location to get today's pick."
            refreshWidgetSnapshot()
            return
        }

        guard let currentCoordinate else {
            todayRecommendation = nil
            todayRecommendationErrorMessage = "Enable location to get today's pick."
            refreshWidgetSnapshot()
            return
        }

        isTodayRecommendationLoading = true
        todayRecommendationErrorMessage = nil
        defer { isTodayRecommendationLoading = false }

        do {
            let recommendation = try await api.getTodayRecommendation(
                token: token,
                location: selectedLocation.label,
                latitude: currentCoordinate.latitude,
                longitude: currentCoordinate.longitude,
                focus: focus
            )
            todayRecommendation = recommendation
            refreshWidgetSnapshot()
        } catch {
            if error is CancellationError {
                return
            }
            let nsError = error as NSError
            if nsError.domain == NSURLErrorDomain && nsError.code == NSURLErrorCancelled {
                return
            }
            nativeLogger.error("loadTodayRecommendation failed: \(error.localizedDescription, privacy: .public)")
            todayRecommendation = nil
            todayRecommendationErrorMessage = "Could not get today's recommendation right now."
            refreshWidgetSnapshot()
        }
    }

    func loadDecisionCatalogIfNeeded() async {
        guard decisionIntents.isEmpty else { return }
        decisionIntents = nativeFallbackDecisionIntents
        if selectedDecisionIntentId == nil {
            selectedDecisionIntentId = nativeDecisionDerivedIntentId(
                withId: selectedDecisionWithValue,
                feelId: selectedDecisionFeelValue,
                stateId: selectedDecisionStateValue
            )
        }
    }

    func generateDecisionSession(
        withValue: String,
        feelValue: String,
        stateValue: String
    ) async {
        guard canGenerateDecisionWithCurrentLocation else {
            nativeHaptic(.warning)
            clearDecisionSessionState()
            showDecisionLocationPermissionSheet = true
            return
        }

        await loadDecisionCatalogIfNeeded()
        let decisionLocation = effectiveDecisionLocation
        let profile = nativeDecisionIntentForSelection(
            withId: withValue,
            feelId: feelValue,
            stateId: stateValue
        )
        selectedDecisionWithValue = withValue
        selectedDecisionFeelValue = feelValue
        selectedDecisionStateValue = stateValue
        selectedDecisionIntentId = profile.id

        isDecisionLoading = true
        decisionErrorMessage = nil
        defer { isDecisionLoading = false }

        do {
            let response = try await api.createDecisionSession(
                cityKey: decisionLocation.id.replacingOccurrences(of: "-", with: "_"),
                intentId: profile.id,
                withValue: withValue,
                feelValue: feelValue,
                stateValue: stateValue,
                latitude: currentCoordinate?.latitude,
                longitude: currentCoordinate?.longitude,
                token: authToken
            )
            decisionSession = response
            persistDecisionSessionIfNeeded()
            refreshWidgetSnapshot()
        } catch {
            if error is CancellationError { return }
            let nsError = error as NSError
            if nsError.domain == NSURLErrorDomain && nsError.code == NSURLErrorCancelled { return }
            nativeLogger.error("generateDecisionSession failed: \(error.localizedDescription, privacy: .public)")
            if nativeDecisionPreviewFallbackEnabled {
                decisionSession = nativeMockDecisionSession(
                    city: decisionLocation,
                    profile: profile,
                    withId: withValue,
                    feelId: feelValue,
                    stateId: stateValue
                )
                decisionErrorMessage = "Preview mode: generated local sample picks."
                clearPersistedDecisionSession()
                refreshWidgetSnapshot()
            } else {
                decisionSession = nil
                decisionErrorMessage = "Could not generate live recommendations right now. \(error.localizedDescription)"
                clearPersistedDecisionSession()
                refreshWidgetSnapshot()
            }
        }
    }

    func swipeDecisionOption(_ option: NativeDecisionSessionOption, direction: String) async {
        guard let sessionId = decisionSession?.session.id else { return }
        let normalizedDirection = direction == "right" ? "right" : "left"

        if decisionSession?.session.entryMode == "preview" {
            applyPreviewDecisionSwipe(option: option, direction: normalizedDirection)
            return
        }

        isDecisionLoading = true
        defer { isDecisionLoading = false }

        do {
            let response = try await api.swipeDecisionSession(
                sessionId: sessionId,
                placeId: option.place.id,
                direction: normalizedDirection,
                token: authToken
            )
            decisionSession = response
            persistDecisionSessionIfNeeded()
            refreshWidgetSnapshot()
        } catch {
            nativeLogger.error("swipeDecisionOption failed: \(error.localizedDescription, privacy: .public)")
            decisionErrorMessage = "Could not update this card right now."
        }
    }

    private func applyPreviewDecisionSwipe(option: NativeDecisionSessionOption, direction: String) {
        guard let current = decisionSession else { return }

        let updatedOptions = current.options.map { existing -> NativeDecisionSessionOption in
            guard existing.id == option.id else { return existing }
            return NativeDecisionSessionOption(
                id: existing.id,
                rank: existing.rank,
                sourceType: existing.sourceType,
                isSelected: direction == "right",
                isSkipped: direction != "right",
                isVisible: direction == "right",
                score: existing.score,
                reasonLabel: existing.reasonLabel,
                place: existing.place
            )
        }

        let sessionStatus = direction == "right" ? "chosen" : "active"
        let allSkipped = updatedOptions.allSatisfy { $0.isSkipped || $0.isSelected == true }
        let finalStatus = allSkipped ? "completed" : sessionStatus

        decisionSession = NativeDecisionSessionResponse(
            session: NativeDecisionSessionMeta(
                id: current.session.id,
                status: finalStatus,
                cityKey: current.session.cityKey,
                cityLabel: current.session.cityLabel,
                entryMode: current.session.entryMode,
                intentId: current.session.intentId,
                swapCount: current.session.swapCount,
                skipCount: direction == "right" ? current.session.skipCount : current.session.skipCount + 1,
                expiresAt: current.session.expiresAt
            ),
            options: updatedOptions,
            debug: current.debug
        )
        clearPersistedDecisionSession()
    }

    func refreshDiscovery() async {
        nativeLogger.log("refreshDiscovery start location=\(self.selectedLocation.label, privacy: .public)")
        isDiscoveryLoading = true
        discoveryErrorMessage = nil
        defer { isDiscoveryLoading = false }
        do {
            let response = try await api.getDiscoveryPlaces(
                location: selectedLocation.label,
                page: 1,
                limit: 18,
                refresh: true,
                selectedInterests: selectedInterests,
                selectedVibe: selectedVibe,
                token: authToken
            )
            discoveryPlaces = response.places
            discoveryInspirationMedia = response.inspirationMedia ?? []
            discoveryPage = response.pagination?.page ?? 1
            discoveryHasMore = response.pagination?.hasMore ?? false
            nativeLogger.log("refreshDiscovery success count=\(self.discoveryPlaces.count, privacy: .public)")
        } catch {
            if error is CancellationError {
                nativeLogger.log("refreshDiscovery cancelled")
                return
            }
            let nsError = error as NSError
            if nsError.domain == NSURLErrorDomain && nsError.code == NSURLErrorCancelled {
                nativeLogger.log("refreshDiscovery cancelled")
                return
            }
            nativeLogger.error("refreshDiscovery failed: \(error.localizedDescription, privacy: .public)")
            if discoveryPlaces.isEmpty {
                discoveryPlaces = nativeFallbackDiscoveryPlaces(for: selectedLocation.label)
                discoveryInspirationMedia = []
                discoveryPage = 1
                discoveryHasMore = false
            }
            discoveryErrorMessage = "Could not refresh discovery right now."
        }
    }

    func loadMoreDiscoveryIfNeeded(currentPlaceId: String) async {
        guard discoveryHasMore, !isDiscoveryLoading, !isDiscoveryLoadingMore else { return }
        guard discoveryPlaces.last?.id == currentPlaceId else { return }

        isDiscoveryLoadingMore = true
        defer { isDiscoveryLoadingMore = false }

        do {
            let nextPage = discoveryPage + 1
            let response = try await api.getDiscoveryPlaces(
                location: selectedLocation.label,
                page: nextPage,
                limit: 18,
                selectedInterests: selectedInterests,
                selectedVibe: selectedVibe,
                token: authToken
            )
            let existingIds = Set(discoveryPlaces.map(\.id))
            let nextPlaces = response.places.filter { !existingIds.contains($0.id) }
            discoveryPlaces.append(contentsOf: nextPlaces)
            discoveryPage = response.pagination?.page ?? nextPage
            discoveryHasMore = response.pagination?.hasMore ?? false
        } catch {
            if error is CancellationError {
                nativeLogger.log("loadMoreDiscovery cancelled")
                return
            }
            let nsError = error as NSError
            if nsError.domain == NSURLErrorDomain && nsError.code == NSURLErrorCancelled {
                nativeLogger.log("loadMoreDiscovery cancelled")
                return
            }
            nativeLogger.error("loadMoreDiscovery failed: \(error.localizedDescription, privacy: .public)")
        }
    }

    private func nativeFallbackDiscoveryPlaces(for location: String) -> [NativePlace] {
        let matchingSaved = savedPlaces.filter { $0.location.localizedCaseInsensitiveContains(location) }
        let matchingMoments = myMoments
            .map(\.place)
            .filter { $0.location.localizedCaseInsensitiveContains(location) }
        let seededPlaces = matchingSaved + matchingMoments
        var seen = Set<String>()
        return seededPlaces.filter { place in
            if seen.contains(place.id) { return false }
            seen.insert(place.id)
            return true
        }
    }

    private func nativeAuthUsersMatch(_ lhs: NativeAuthUser?, _ rhs: NativeAuthUser) -> Bool {
        guard let lhs else { return false }
        return lhs.id == rhs.id
            && lhs.displayName == rhs.displayName
            && lhs.username == rhs.username
            && lhs.email == rhs.email
            && lhs.bio == rhs.bio
            && lhs.avatarUrl == rhs.avatarUrl
            && lhs.hasCompletedTastePreferences == rhs.hasCompletedTastePreferences
    }

    func refreshProfile() async {
        nativeLogger.log("refreshProfile start")
        profileErrorMessage = nil
        guard let token = authToken else { return }

        do {
            let response = try await api.getProfile(token: token)
            let uniqueBookmarks = Array(
                Dictionary(response.bookmarks.map { ($0.id, $0) }, uniquingKeysWith: { first, _ in first }).values
            )
            let uniqueCollections = Array(
                Dictionary(response.collections.map { ($0.id, $0) }, uniquingKeysWith: { first, _ in first }).values
            )
            let uniqueMoments = Array(
                Dictionary(response.moments.map { ($0.id, $0) }, uniquingKeysWith: { first, _ in first }).values
            )
            if !nativeAuthUsersMatch(currentUser, response.user) {
                currentUser = response.user
                cachedAuthUser = response.user
            }
            savedPlaces = uniqueBookmarks
            collections = uniqueCollections
            myMoments = uniqueMoments
            rebuildOwnFeedItems()
            nativeLogger.log("refreshProfile success bookmarks=\(self.savedPlaces.count, privacy: .public) collections=\(self.collections.count, privacy: .public) moments=\(self.myMoments.count, privacy: .public)")
        } catch {
            nativeLogger.error("refreshProfile failed: \(error.localizedDescription, privacy: .public)")
            profileErrorMessage = "Could not load your profile right now."
        }
    }

