    func showToast(message: String, icon: String = "checkmark.circle.fill") {
        toastDismissWorkItem?.cancel()
        let nextToast = NativeToastState(message: message, icon: icon)
        activeToast = nextToast

        let workItem = DispatchWorkItem { [weak self] in
            guard let self else { return }
            if self.activeToast?.id == nextToast.id {
                self.activeToast = nil
            }
        }
        toastDismissWorkItem = workItem
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.8, execute: workItem)
    }

    func savePlace(_ place: NativePlace, source: String? = nil) async throws {
        guard let token = authToken else {
            presentAuthGate(reason: "Log in to save places.")
            throw URLError(.userAuthenticationRequired)
        }

        guard !isBookmarked(place.id) else { return }

        let response = try await api.bookmarkPlace(token: token, place: place, source: source)
        applySavedMutationResponse(response)
        rebuildOwnFeedItems()
        showToast(message: "Place saved", icon: "heart.fill")
        await requestPushNotificationsAfterFirstContentActionIfNeeded()
    }

    func toggleBookmark(for place: NativePlace, source: String? = nil) async throws {
        guard let token = authToken else {
            presentAuthGate(reason: "Log in to save places.")
            throw URLError(.userAuthenticationRequired)
        }

        if isBookmarked(place.id) {
            let response = try await api.removeBookmarkPlace(token: token, placeId: place.id)
            applySavedMutationResponse(response)
        } else {
            let response = try await api.bookmarkPlace(token: token, place: place, source: source)
            applySavedMutationResponse(response)
            showToast(message: "Place saved", icon: "heart.fill")
            await requestPushNotificationsAfterFirstContentActionIfNeeded()
        }
        nativeHaptic(.success)
        rebuildOwnFeedItems()
    }

    private func applySavedMutationResponse(_ response: NativeBookmarkedPlacesMutationResponse) {
        let uniqueBookmarks = Array(
            Dictionary(response.bookmarks.map { ($0.id, $0) }, uniquingKeysWith: { first, _ in first }).values
        )
        let uniqueEntries = Array(
            Dictionary((response.entries ?? []).map { ($0.id, $0) }, uniquingKeysWith: { first, _ in first }).values
        )
        savedPlaces = uniqueBookmarks
        savedEntries = uniqueEntries.sorted {
            (NativeAppState.date(from: $0.expiresAtIso) ?? .distantFuture) < (NativeAppState.date(from: $1.expiresAtIso) ?? .distantFuture)
        }
        savedErrorMessage = nil
    }

