                guard existing.id == itemId else { return existing }
                return NativeFeedItem(
                    id: existing.id,
                    type: existing.type,
                    traveler: existing.traveler,
                    title: existing.title,
                    timestampLabel: existing.timestampLabel,
                    sortTimestamp: existing.sortTimestamp,
                    place: existing.place,
                    collection: existing.collection,
                    caption: existing.caption,
                    isVibed: isVibed,
                    vibinCount: vibinCount,
                    uploadedMediaUrls: existing.uploadedMediaUrls
                )
            }
        }

        feedItems = updated(feedItems)
        fallbackFeedItems = updated(fallbackFeedItems)
        suggestedFeedItems = updated(suggestedFeedItems)
        ownFeedItemsCache = updated(ownFeedItemsCache)
    }

