    func updateMomentInteractionState(
        momentId: String,
        commentCount: Int? = nil,
        likeCount: Int? = nil,
        latestComment: NativeComment? = nil
    ) {
        func updatedMoment(_ moment: NativeMoment) -> NativeMoment {
            guard moment.id == momentId else { return moment }
            return NativeMoment(
                id: moment.id,
                visitedDate: moment.visitedDate,
                visitedAtIso: moment.visitedAtIso,
                caption: moment.caption,
                uploadedMedia: moment.uploadedMedia,
                rating: moment.rating,
                ratingLabel: moment.ratingLabel,
                wouldRevisit: moment.wouldRevisit,
                visibility: moment.visibility,
                commentCount: commentCount ?? moment.commentCount,
                likeCount: likeCount ?? moment.likeCount,
                latestComment: latestComment ?? moment.latestComment,
                place: moment.place
            )
        }

        homepageRecentMemories = homepageRecentMemories.map(updatedMoment)
        diaryMoments = diaryMoments.map(updatedMoment)
        myMoments = myMoments.map(updatedMoment)
    }

    private func buildFeedItems(
        followedTravelers: [NativeTravelerSummary],
        savedDrops: [NativeFeedSavedDrop]
    ) -> [NativeFeedItem] {
        var items: [NativeFeedItem] = []
        let travelerMap = Dictionary(uniqueKeysWithValues: followedTravelers.map { ($0.id, $0) })

        for drop in savedDrops {
            guard let traveler = travelerMap[drop.travelerId] else { continue }
            items.append(
                NativeFeedItem(
                    id: drop.id,
                    type: .saved,
                    traveler: traveler,
                    title: "\(traveler.displayName ?? traveler.username) saved a place",
                    timestampLabel: drop.savedAtLabel,
                    sortTimestamp: Self.feedSortDate(iso: drop.savedAtIso, label: drop.savedAtLabel) ?? .distantPast,
                    place: drop.place,
                    collection: nil,
                    caption: nil
                )
            )
        }

        for traveler in followedTravelers {
            for history in traveler.travelHistory {
                for place in history.places where place.visitedDate != nil {
                    items.append(
                        NativeFeedItem(
                            id: "visited-\(traveler.id)-\(place.momentId ?? place.id)",
                            type: .visited,
                            traveler: traveler,
                            title: "\(traveler.displayName ?? traveler.username) visited a place",
                            timestampLabel: Self.relativeLabel(from: place.visitedDate),
                            sortTimestamp: Self.feedSortDate(iso: place.visitedAtIso ?? place.visitedDate, label: Self.relativeLabel(from: place.visitedDate)) ?? .distantPast,
                            place: place,
                            collection: nil,
                            caption: place.momentCaption
                        )
                    )
                }
            }

            for collection in traveler.recentCollections ?? [] {
                items.append(
                    NativeFeedItem(
                        id: "collection-\(traveler.id)-\(collection.id)",
                        type: .collection,
                        traveler: traveler,
                        title: "\(traveler.displayName ?? traveler.username) created a collection",
                        timestampLabel: Self.relativeLabel(from: collection.createdAt),
                        sortTimestamp: Self.date(from: collection.createdAt) ?? .distantPast,
                        place: nil,
                        collection: collection,
                        caption: nil
                    )
                )
            }
        }

        return items.sorted { $0.sortTimestamp > $1.sortTimestamp }
    }

    private static var todayString: String {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyy-MM-dd"
        formatter.timeZone = TimeZone(secondsFromGMT: 0)
        return formatter.string(from: Date())
    }

    static func date(from raw: String?) -> Date? {
        guard let raw, !raw.isEmpty else { return nil }
        let isoFormatter = ISO8601DateFormatter()
        isoFormatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        if let value = isoFormatter.date(from: raw) {
            return value
        }
        isoFormatter.formatOptions = [.withInternetDateTime]
        if let value = isoFormatter.date(from: raw) {
            return value
        }
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.dateFormat = "yyyy-MM-dd"
        formatter.timeZone = TimeZone.current
        return formatter.date(from: raw)
    }

    private static func nextLocalMidnight(from date: Date = Date()) -> Date {
        let calendar = Calendar.current
        return calendar.startOfDay(for: calendar.date(byAdding: .day, value: 1, to: date) ?? date)
    }

    private func persistDecisionSessionIfNeeded() {
        guard let session = decisionSession else {
            clearPersistedDecisionSession()
            return
        }
        guard session.session.entryMode != "preview" else {
            clearPersistedDecisionSession()
            return
        }
        let persisted = NativePersistedDecisionSession(
            session: session,
            validUntilIso: ISO8601DateFormatter().string(from: NativeAppState.nextLocalMidnight())
        )
        guard let data = try? JSONEncoder().encode(persisted) else { return }
        UserDefaults.standard.set(data, forKey: decisionSessionCacheKey)
    }

    private func clearPersistedDecisionSession() {
        UserDefaults.standard.removeObject(forKey: decisionSessionCacheKey)
    }

    func clearDecisionSessionState() {
        decisionSession = nil
        decisionErrorMessage = nil
        clearPersistedDecisionSession()
    }

    private func loadPersistedDecisionSession() -> NativeDecisionSessionResponse? {
        guard let data = UserDefaults.standard.data(forKey: decisionSessionCacheKey) else {
            return nil
        }
        guard let persisted = try? JSONDecoder().decode(NativePersistedDecisionSession.self, from: data) else {
            UserDefaults.standard.removeObject(forKey: decisionSessionCacheKey)
            return nil
        }
        if let validUntil = NativeAppState.date(from: persisted.validUntilIso),
           validUntil <= Date() {
            UserDefaults.standard.removeObject(forKey: decisionSessionCacheKey)
            return nil
        }
        return persisted.session
    }

	    static func relativeLabel(from raw: String?) -> String {
	        guard let date = date(from: raw) else { return "Recently" }
	        let now = Date()
	        let diff = Int(now.timeIntervalSince(date))
	        if diff < 60 { return "just now" }
	        let hour = 60 * 60
	        let day = 24 * hour
	        let week = 7 * day
	        _ = 30 * day
	        _ = 365 * day

	        if diff < day {
	            let hours = max(1, diff / hour)
	            return "\(hours)h ago"
	        }
	        if diff < week {
	            let days = max(1, diff / day)
	            return "\(days)d ago"
	        }
	        // Older than 7 days: show a concrete date.
	        let formatter = DateFormatter()
	        formatter.locale = Locale(identifier: "en_US_POSIX")
	        formatter.timeZone = .current
	        formatter.dateFormat = "MMM dd, yyyy"
	        return formatter.string(from: date)
	    }

	    static func feedSortDate(iso: String?, label: String?) -> Date? {
	        if let direct = date(from: iso) {
	            return direct
	        }
	        guard let label else { return nil }
	        let normalized = label
	            .lowercased()
	            .replacingOccurrences(of: ".", with: "")
	            .trimmingCharacters(in: .whitespacesAndNewlines)
	
	        // Supports concrete date labels (MMM dd, yyyy) produced by `relativeLabel`.
	        do {
	            let formatter = DateFormatter()
	            formatter.locale = Locale(identifier: "en_US_POSIX")
	            formatter.timeZone = .current
	            formatter.dateFormat = "MMM dd, yyyy"
	            if let parsed = formatter.date(from: label.trimmingCharacters(in: .whitespacesAndNewlines)) {
	                return parsed
	            }
	        }
	        if normalized == "just now" { return Date() }
	        if normalized == "recently" { return Date().addingTimeInterval(-60) }
	        let match = normalized.range(of: #"^(\d+)\s*(h|d|wk|w|mo|y)\s*ago$"#, options: .regularExpression)
	        guard let match else { return nil }
	        let token = String(normalized[match])
        let parts = token.split(separator: " ")
        guard let first = parts.first, let value = Int(first) else { return nil }
        if token.contains("wk") || token.contains(" w") {
            return Date().addingTimeInterval(TimeInterval(-value * 7 * 24 * 60 * 60))
        }
        if token.contains("mo") {
            return Date().addingTimeInterval(TimeInterval(-value * 30 * 24 * 60 * 60))
        }
        if token.contains("y") {
            return Date().addingTimeInterval(TimeInterval(-value * 365 * 24 * 60 * 60))
        }
        if token.contains("d") {
            return Date().addingTimeInterval(TimeInterval(-value * 24 * 60 * 60))
        }
        if token.contains("h") {
            return Date().addingTimeInterval(TimeInterval(-value * 60 * 60))
        }
        return nil
    }

    private var authToken: String? {
        get { UserDefaults.standard.string(forKey: authTokenKey) }
        set {
            if let newValue {
                UserDefaults.standard.set(newValue, forKey: authTokenKey)
            } else {
                UserDefaults.standard.removeObject(forKey: authTokenKey)
            }
        }
    }

    private var cachedAuthUser: NativeAuthUser? {
        get {
            guard let data = UserDefaults.standard.data(forKey: cachedUserKey) else { return nil }
            return try? JSONDecoder().decode(NativeAuthUser.self, from: data)
        }
        set {
            guard let newValue, let data = try? JSONEncoder().encode(newValue) else {
                UserDefaults.standard.removeObject(forKey: cachedUserKey)
                return
            }
            UserDefaults.standard.set(data, forKey: cachedUserKey)
        }
    }

    private var currentPushToken: String? {
        get { UserDefaults.standard.string(forKey: nativePushTokenUserDefaultsKey) }
        set { UserDefaults.standard.set(newValue, forKey: nativePushTokenUserDefaultsKey) }
    }

    private var sessionFlavor: NativeSessionFlavor {
        get {
            guard
                let rawValue = UserDefaults.standard.string(forKey: sessionFlavorKey),
                let flavor = NativeSessionFlavor(rawValue: rawValue)
            else {
                return .legacy
            }
            return flavor
        }
        set {
            UserDefaults.standard.set(newValue.rawValue, forKey: sessionFlavorKey)
        }
    }

    private var usesV2Session: Bool {
        sessionFlavor == .v2
    }

    private var lastSyncedPushToken: String? {
        get { UserDefaults.standard.string(forKey: syncedPushTokenKey) }
        set { UserDefaults.standard.set(newValue, forKey: syncedPushTokenKey) }
    }

    private func clearSession() {
        authToken = nil
        currentUser = nil
        cachedAuthUser = nil
        sessionFlavor = .legacy
        lastSyncedPushToken = nil
        notificationUnreadCount = 0
        clearPersistedDecisionSession()
        decisionSession = nil
        placeDetailCache.removeAll()
    }

    @objc
    private func handlePushTokenUpdated(_ notification: Notification) {
        guard let token = notification.object as? String, !token.isEmpty else { return }
        currentPushToken = token
        Task { [weak self] in
            await self?.syncPushTokenIfPossible()
        }
    }

    @objc
    private func handleWidgetDeepLinkNotification(_ notification: Notification) {
        handleWidgetDeepLink(notification.object as? URL)
    }

    private func handlePendingWidgetDeepLinkIfNeeded() {
        guard let rawValue = UserDefaults.standard.string(forKey: nativePendingWidgetDeepLinkUserDefaultsKey),
              let url = URL(string: rawValue) else { return }
        UserDefaults.standard.removeObject(forKey: nativePendingWidgetDeepLinkUserDefaultsKey)
        handleWidgetDeepLink(url)
    }

    private func handleWidgetDeepLink(_ url: URL?) {
        guard let url else { return }
        switch url.host?.lowercased() {
        case "feed":
            if currentUser == nil {
                presentAuthGate(reason: "Log in to open your today feed.")
                return
            }
            activeTab = .feed
        case "discover":
            activeTab = .discover
        case "today-recommendation":
            if currentUser == nil {
                presentAuthGate(
                    reason: "Log in to get today's recommendation.",
                    postAuthAction: .openTodayRecommendation
                )
                return
            }
            activeTab = .discover
            Task { [weak self] in
                await self?.loadTodayRecommendation()
            }
        default:
            activeTab = .discover
        }
    }

    private func refreshCurrentPushTokenFromFirebase() async {
        #if canImport(FirebaseMessaging)
        guard Messaging.messaging().apnsToken != nil else {
            nativeLogger.log("skip firebase token refresh: apns token not ready")
            return
        }

        let token: String? = await withCheckedContinuation { continuation in
            Messaging.messaging().token { token, error in
                if let error {
                    nativeLogger.error("firebase messaging token refresh failed: \(error.localizedDescription, privacy: .public)")
                    continuation.resume(returning: nil)
                    return
                }
                continuation.resume(returning: token)
            }
        }

        guard let token, !token.isEmpty else { return }
        currentPushToken = token
        UserDefaults.standard.set(token, forKey: nativePushTokenUserDefaultsKey)
        #endif
    }

    private func syncPushTokenIfPossible(force: Bool = false) async {
        guard usesV2Session == false, let authToken, currentUser != nil, let currentPushToken, !currentPushToken.isEmpty else { return }
        if !force && lastSyncedPushToken == currentPushToken {
            return
        }

        do {
            try await api.registerPushDevice(
                fcmToken: currentPushToken,
                platform: "ios",
                appVersion: nativeAppVersionString(),
                token: authToken
            )
            lastSyncedPushToken = currentPushToken
            nativeLogger.log("push token sync success")
        } catch {
            nativeLogger.error("push token sync failed: \(error.localizedDescription, privacy: .public)")
        }
    }

    func refreshWidgetSnapshot() {
        Task { [weak self] in
            await self?.refreshWidgetSnapshotAsync()
        }
    }

    private func refreshWidgetSnapshotSync(_ snapshot: NativeWidgetSnapshot) {
        NativeWidgetSnapshotStore.save(snapshot)
#if canImport(WidgetKit)
        WidgetCenter.shared.reloadTimelines(ofKind: "VibinnGalleryWidget")
        WidgetCenter.shared.reloadTimelines(ofKind: "VibinnRecommendationWidget")
        WidgetCenter.shared.reloadTimelines(ofKind: "VibinnComboWidget")
        WidgetCenter.shared.reloadAllTimelines()
#endif
    }

    private func refreshWidgetSnapshotAsync() async {
        let gallerySnapshot = await nativeWidgetGallerySnapshot
        let recommendationSnapshot = await nativeWidgetRecommendationSnapshot

        nativeLogger.log(
            "widget snapshot build galleryURL=\(gallerySnapshot?.mediaURL ?? "nil", privacy: .public) galleryLocal=\(gallerySnapshot?.localMediaPath ?? "nil", privacy: .public) recoURL=\(recommendationSnapshot?.backgroundImageURL ?? "nil", privacy: .public) recoLocal=\(recommendationSnapshot?.localBackgroundImagePath ?? "nil", privacy: .public)"
        )

        let snapshot = NativeWidgetSnapshot(
            generatedAt: Date(),
            hasFriends: !followedTravelers.isEmpty,
            gallery: gallerySnapshot,
            recommendation: recommendationSnapshot
        )
        refreshWidgetSnapshotSync(snapshot)
    }

    func clearWidgetSnapshot() {
        NativeWidgetSnapshotStore.clear()
        NativeWidgetImageCacheStore.clear()
#if canImport(WidgetKit)
        WidgetCenter.shared.reloadTimelines(ofKind: "VibinnGalleryWidget")
        WidgetCenter.shared.reloadTimelines(ofKind: "VibinnRecommendationWidget")
        WidgetCenter.shared.reloadTimelines(ofKind: "VibinnComboWidget")
        WidgetCenter.shared.reloadAllTimelines()
#endif
    }

    private var nativeWidgetGallerySnapshot: NativeWidgetGallerySnapshot? {
        get async {
            let sourceItem: NativeFeedItem?
            if !followedTravelers.isEmpty {
                sourceItem = feedItems.first ?? fallbackFeedItems.first
            } else {
                sourceItem = suggestedFeedItems.first
            }

            guard let item = sourceItem else { return nil }
            let mediaURL =
                item.uploadedMediaUrls?.first(where: { !$0.isEmpty })
                ?? item.place?.userMediaUrls?.first(where: { !$0.isEmpty })
                ?? item.place?.momentMedia?.first?.url
                ?? item.place?.image
                ?? item.place?.images?.first
            let localMediaPath = await NativeWidgetImageCacheStore.cacheImage(
                from: mediaURL,
                cacheKey: "gallery-\(item.id)"
            )

            return NativeWidgetGallerySnapshot(
                id: item.id,
                username: item.traveler.username,
                displayName: item.traveler.displayName,
                avatarURL: item.traveler.avatar,
                mediaURL: mediaURL,
                localMediaPath: localMediaPath,
                postedLabel: item.timestampLabel
            )
        }
    }

    private var nativeWidgetRecommendationSnapshot: NativeWidgetRecommendationSnapshot? {
        get async {
            if let recommendation = todayRecommendation {
                let imageURL =
                    recommendation.place.image
                    ?? recommendation.place.images?.first
                    ?? recommendation.place.userMediaUrls?.first
                    ?? recommendation.place.momentMedia?.first?.url
                let localBackgroundImagePath = await NativeWidgetImageCacheStore.cacheImage(
                    from: imageURL,
                    cacheKey: "recommendation-\(recommendation.place.id)"
                )

                let distanceLabel: String
                if recommendation.distanceMiles < 0.2 {
                    distanceLabel = "Nearby"
                } else {
                    distanceLabel = String(format: "%.1f mi away", recommendation.distanceMiles)
                }

                return NativeWidgetRecommendationSnapshot(
                    placeId: recommendation.place.id,
                    placeName: recommendation.place.name,
                    backgroundImageURL: imageURL,
                    localBackgroundImagePath: localBackgroundImagePath,
                    distanceLabel: distanceLabel,
                    hasGeneratedRecommendation: true
                )
            }

            if let option = nativeWidgetDecisionRecommendationOption {
                let imageURL = option.place.thumbnailUrl
                let localBackgroundImagePath = await NativeWidgetImageCacheStore.cacheImage(
                    from: imageURL,
                    cacheKey: "decision-\(option.place.id)"
                )
                let distanceLabel = option.place.travelTimeLabel?.trimmingCharacters(in: CharacterSet.whitespacesAndNewlines)
                return NativeWidgetRecommendationSnapshot(
                    placeId: option.place.id,
                    placeName: option.place.name,
                    backgroundImageURL: imageURL,
                    localBackgroundImagePath: localBackgroundImagePath,
                    distanceLabel: (distanceLabel?.isEmpty == false ? distanceLabel! : "Open your picks"),
                    hasGeneratedRecommendation: true
                )
            }

            return NativeWidgetRecommendationSnapshot(
                placeId: "",
                placeName: "Pick for me",
                backgroundImageURL: nil,
                localBackgroundImagePath: nil,
                distanceLabel: "Generate today’s pick",
                hasGeneratedRecommendation: false
            )
        }
    }

    private var nativeWidgetDecisionRecommendationOption: NativeDecisionSessionOption? {
        guard let session = decisionSession else { return nil }
        if let selected = session.options.first(where: { $0.isSelected }) {
            return selected
        }
        let rankedVisible = session.options
            .filter { $0.isVisible && !$0.isSkipped }
            .sorted { $0.rank < $1.rank }
        if let firstVisible = rankedVisible.first {
            return firstVisible
        }
        return session.options.sorted { $0.rank < $1.rank }.first
    }

    func performWidgetBackgroundRefresh() async -> UIBackgroundFetchResult {
        guard currentUser != nil, authToken != nil else {
            clearWidgetSnapshot()
            return .noData
        }

        let previousSnapshot = NativeWidgetSnapshotStore.load()
        await refreshFeed()

        if locationPermissionState == .authorized, currentCoordinate != nil {
            await loadTodayRecommendation()
        }
        await refreshWidgetSnapshotAsync()

        let nextSnapshot = NativeWidgetSnapshotStore.load()
        let previousData = try? JSONEncoder().encode(previousSnapshot)
        let nextData = try? JSONEncoder().encode(nextSnapshot)
        return previousData == nextData ? .noData : .newData
    }

    func forceSyncPushTokenForDebug() async {
        await refreshCurrentPushTokenFromFirebase()
        await syncPushTokenIfPossible(force: true)
    }

    private func rebuildOwnFeedItems() {
        guard let user = currentUser else {
            ownFeedItemsCache = []
            return
        }
        let traveler = NativeTravelerSummary(
            id: user.id,
            username: user.username,
            displayName: user.displayName,
            avatar: nil,
            bio: nil,
            descriptor: nil,
            matchScore: nil,
            followersCount: nil,
            followingCount: nil,
            recentSavedPlaces: savedPlaces.prefix(4).map { place in
                NativeTravelerSavedEntry(
                    place: place,
                    savedAtLabel: "Saved",
                    savedAtIso: nil
                )
            },
            recentCollections: collections,
            travelHistory: [],
            visitedPlacesCount: myMoments.count,
            savedPlacesCount: savedPlaces.count,
            collectionsCount: collections.count
        )

        let savedBaseDate = Date()

        var items: [NativeFeedItem] = savedPlaces.prefix(4).enumerated().map { index, place in
            NativeFeedItem(
                id: "own-saved-\(place.id)",
                type: .saved,
                traveler: traveler,
                title: "",
                timestampLabel: "Saved",
                sortTimestamp: savedBaseDate.addingTimeInterval(TimeInterval(-(index * 90))),
                place: place,
                collection: nil,
                caption: nil
            )
        }

        items.append(contentsOf: myMoments.map { moment in
            let momentMedia = (moment.uploadedMedia ?? []).filter { !$0.isEmpty }
            return NativeFeedItem(
                id: "own-visited-\(moment.id)",
                type: .visited,
                traveler: traveler,
                title: "",
                timestampLabel: Self.relativeLabel(from: moment.visitedDate),
                sortTimestamp: Self.feedSortDate(iso: moment.visitedAtIso ?? moment.visitedDate, label: Self.relativeLabel(from: moment.visitedDate)) ?? .distantPast,
	                place: NativePlace(
	                    id: moment.place.id,
	                    name: moment.place.name,
	                    location: moment.place.location,
	                    address: moment.place.address,
	                    neighborhood: moment.place.neighborhood,
	                    category: moment.place.category,
	                    description: moment.place.description,
	                    hook: moment.place.hook,
	                    image: momentMedia.first ?? moment.place.image,
	                    images: moment.place.images,
	                    momentMedia: momentMedia.isEmpty ? moment.place.momentMedia : momentMedia.map {
                            NativeMomentMediaItem(url: $0, mediaType: "image")
                        },
	                    placeMediaUrls: moment.place.placeMediaUrls ?? moment.place.images,
	                    userMediaUrls: momentMedia.isEmpty ? moment.place.userMediaUrls : momentMedia,
	                    tags: moment.place.tags,
	                    attitudeLabel: moment.place.attitudeLabel,
	                    bestTime: moment.place.bestTime,
	                    similarityStat: moment.place.similarityStat,
                    whyYoullLikeIt: moment.place.whyYoullLikeIt,
                    recommendationReason: moment.place.recommendationReason,
                    rating: moment.place.rating,
                    priceLevel: moment.place.priceLevel,
                    openingHours: moment.place.openingHours,
                    servesBreakfast: moment.place.servesBreakfast,
                    servesLunch: moment.place.servesLunch,
                    servesDinner: moment.place.servesDinner,
                    servesBeer: moment.place.servesBeer,
                    servesWine: moment.place.servesWine,
                    servesBrunch: moment.place.servesBrunch,
                    servesDessert: moment.place.servesDessert,
                    servesCoffee: moment.place.servesCoffee,
                    servesCocktails: moment.place.servesCocktails,
                    goodForGroups: moment.place.goodForGroups,
                    goodForWatchingSports: moment.place.goodForWatchingSports,
                    timeZone: moment.place.timeZone,
                    utcOffsetMinutes: moment.place.utcOffsetMinutes,
                    outdoors: moment.place.outdoors,
                    outdoorSeating: moment.place.outdoorSeating,
                    mapsUrl: moment.place.mapsUrl,
                    latitude: moment.place.latitude,
                    longitude: moment.place.longitude,
                    priceRange: moment.place.priceRange,
                    priceRangeLabel: moment.place.priceRangeLabel,
                    discoverySignals: moment.place.discoverySignals,
                    discoveryTopRank: moment.place.discoveryTopRank,
                    momentId: moment.id,
                    ownerUserId: moment.place.ownerUserId,
                    visitedDate: moment.visitedDate,
                    visitedAtIso: moment.visitedAtIso,
                    momentCaption: moment.caption,
                    momentWouldRevisit: moment.wouldRevisit,
                    momentRating: moment.rating,
                    momentRatingLabel: moment.ratingLabel
                ),
                collection: nil,
                caption: moment.caption,
                uploadedMediaUrls: momentMedia.isEmpty ? nil : momentMedia
            )
        })

        items.append(contentsOf: collections.map { collection in
            NativeFeedItem(
                id: "own-collection-\(collection.id)",
                type: .collection,
                traveler: traveler,
                title: "",
                timestampLabel: Self.relativeLabel(from: collection.createdAt),
                sortTimestamp: Self.date(from: collection.createdAt) ?? .distantPast,
                place: nil,
                collection: collection,
                caption: nil
            )
        })

        ownFeedItemsCache = items.sorted { $0.sortTimestamp > $1.sortTimestamp }
    }
}

