    func getDiscoveryPlaces(
        location: String,
        page: Int,
        limit: Int,
        refresh: Bool = false,
        selectedInterests: [String],
        selectedVibe: String?,
        token: String?
    ) async throws -> NativeDiscoveryPlacesResponse {
        let encodedLocation = location.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? location
        let encodedInterests = selectedInterests
            .map { $0.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? $0 }
            .joined(separator: ",")
        let encodedVibe = selectedVibe?.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? ""
        var path = "/api/discovery/places?location=\(encodedLocation)&type=city&page=\(page)&limit=\(limit)"
        if !encodedInterests.isEmpty {
            path += "&interests=\(encodedInterests)"
        }
        if !encodedVibe.isEmpty {
            path += "&vibe=\(encodedVibe)"
        }
        if refresh {
            path += "&refresh=1"
        }
        return try await request(
            path: path,
            method: "GET",
            token: token
        )
    }

    func getTodayRecommendation(
        token: String,
        location: String,
        latitude: Double,
        longitude: Double,
        focus: String? = nil
    ) async throws -> NativeTodayRecommendationResponse {
        let encodedLocation = location.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? location
        let encodedFocus = focus?.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed)
        var path = "/api/recommendations/today?location=\(encodedLocation)&type=city&latitude=\(latitude)&longitude=\(longitude)"
        if let encodedFocus, !encodedFocus.isEmpty {
            path += "&focus=\(encodedFocus)"
        }
        return try await request(
            path: path,
            method: "GET",
            token: token
        )
    }

