        }
        return uploadedURL
    }

    private func request<T: Decodable, B: Encodable>(
        path: String,
        method: String,
        token: String?,
        body: B?
    ) async throws -> T {
        guard let url = URL(string: path, relativeTo: baseURL) else {
            throw URLError(.badURL)
        }
        var request = URLRequest(url: url)
        request.httpMethod = method
        let isInviteValidation = path.hasPrefix("/api/v2/invite-codes/validate")
        request.timeoutInterval = isInviteValidation ? 40 : (method == "GET" ? 30 : 25)
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        if let token {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        if let body {
            request.httpBody = try JSONEncoder().encode(body)
        }

        let dataAndResponse: (Data, URLResponse)
        do {
            dataAndResponse = try await URLSession.shared.data(for: request)
        } catch {
            let nsError = error as NSError
            let shouldRetry = method == "GET" && (nsError.domain == NSURLErrorDomain && nsError.code == NSURLErrorTimedOut)
            if shouldRetry {
                nativeLogger.error("API request timed out, retrying path=\(path, privacy: .public)")
                dataAndResponse = try await URLSession.shared.data(for: request)
            } else {
                throw error
            }
        }
        let (data, response) = dataAndResponse
        guard let httpResponse = response as? HTTPURLResponse else {
            throw URLError(.badServerResponse)
        }

        guard (200...299).contains(httpResponse.statusCode) else {
            let responseText = String(data: data, encoding: .utf8)?
                .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            nativeLogger.error("API request failed path=\(path, privacy: .public) status=\(httpResponse.statusCode, privacy: .public) body=\(responseText, privacy: .public)")
            let sanitizedMessage: String
            if responseText.lowercased().contains("<!doctype html") || responseText.lowercased().contains("<html") {
                sanitizedMessage = "Request failed (\(httpResponse.statusCode))"
            } else {
                sanitizedMessage = responseText.isEmpty
                    ? "Request failed (\(httpResponse.statusCode))"
                    : responseText
            }
            throw NSError(
                domain: "NativeAPI",
                code: httpResponse.statusCode,
                userInfo: [
                    NSLocalizedDescriptionKey: sanitizedMessage,
                ]
            )
        }

        if data.isEmpty, T.self == NativeEmptyResponse.self {
            return NativeEmptyResponse() as! T
        }

        return try JSONDecoder().decode(T.self, from: data)
    }

    private func request<T: Decodable>(
        path: String,
        method: String,
        token: String?
    ) async throws -> T {
        try await request(path: path, method: method, token: token, body: Optional<String>.none)
    }
}

private struct NativeVibinnRootView: View {
    @StateObject private var appState = NativeAppState()

    var body: some View {
        Group {
            if appState.isBootstrapping {
                NativeLoadingScreen()
            } else if appState.currentUser == nil || !appState.hasCompletedInviteOnboarding {
                NativeAuthScreen(
                    allowsDismissal: false,
                    promptReason: appState.currentUser == nil ? "Sign in or create an account to continue." : nil
                )
                    .environmentObject(appState)
            } else if appState.shouldShowCityComingSoonGate {
                NativeComingSoonScreen()
                    .environmentObject(appState)
            } else {
                NativeMainTabView()
                    .environmentObject(appState)
            }
        }
        .preferredColorScheme(.dark)
        .fullScreenCover(isPresented: $appState.showAuthSheet) {
            NativeAuthScreen(allowsDismissal: true, promptReason: appState.authSheetReason)
                .environmentObject(appState)
        }
        .sheet(isPresented: $appState.showPreferenceSetupSheet) {
            NativePreferenceSetupScreen()
                .environmentObject(appState)
        }
        .sheet(isPresented: $appState.showCheckInSheet, onDismiss: {
            appState.dismissCheckInFlow()
        }) {
            NativeCheckInScreen(
                prefilledPlace: appState.checkInPrefilledPlace,
                prefilledPhotoAsset: appState.checkInPrefilledPhotoAsset,
                prefilledImage: appState.checkInPrefilledImage,
                prefilledVisitedDate: appState.checkInPrefilledVisitedDate
            )
                .environmentObject(appState)
        }
        .overlay(alignment: .bottom) {
            if let toast = appState.activeToast {
                NativeToastView(toast: toast)
                    .padding(.horizontal, 18)
                    .padding(.bottom, max(18, appState.showFloatingTabBar ? 108 : 28))
                    .transition(.move(edge: .bottom).combined(with: .opacity))
            }
        }
        .task {
            nativeLogger.log("RootView task bootstrap")
            (UIApplication.shared.delegate as? AppDelegate)?.appState = appState
            await appState.bootstrap()
        }
        .onAppear {
            (UIApplication.shared.delegate as? AppDelegate)?.appState = appState
        }
        .onChange(of: appState.isBootstrapping) { value in
            nativeLogger.log("RootView isBootstrapping changed=\(value, privacy: .public)")
        }
        .onChange(of: appState.currentUser?.id) { value in
            nativeLogger.log("RootView currentUser changed hasUser=\(value != nil, privacy: .public)")
            if value != nil, appState.showAuthSheet {
                appState.dismissAuthGate()
            }
        }
        .onChange(of: appState.hasCompletedOnboarding) { value in
            nativeLogger.log("RootView onboarding changed=\(value, privacy: .public)")
            if value, appState.currentUser != nil {
                appState.performPendingPostAuthActionIfNeeded()
            }
        }
    }
}

