    private func diaryTimelineCard(_ moment: NativeMoment) -> some View {
        let dateLabel = NativeAppState.relativeLabel(from: moment.visitedAtIso ?? moment.visitedDate)
        let shortAddress = nativeShortAddress(for: moment.place)
        let ratingMeta = nativeMomentRatingMeta(label: moment.ratingLabel, fallbackRating: moment.rating)
        return NativeVisitedMomentPostCard(
            displayName: appState.currentUser?.displayName ?? "You",
            username: appState.currentUser?.username,
            avatarURL: appState.currentUser?.avatarUrl,
            avatarFallback: appState.currentUser?.displayName ?? appState.currentUser?.username ?? "You",
            ratingMeta: ratingMeta,
            wouldRevisit: moment.wouldRevisit,
            reviewText: moment.caption?.trimmingCharacters(in: .whitespacesAndNewlines),
            mediaURL: nativeDiaryMediaURL(for: moment),
            placeName: moment.place.name,
            placeMetaLine: nativePlaceMetaLine(for: moment.place, shortAddress: shortAddress)
        ) {
            Text(dateLabel)
                .font(nativeAppFont(size: 12, weight: .bold))
                .foregroundStyle(.white.opacity(0.58))
        } placeSection: {
            NativeMomentPlaceInfoCard(
                placeName: moment.place.name,
                metaLine: nativePlaceMetaLine(for: moment.place, shortAddress: shortAddress)
            )
        } actions: {
            NativeMomentEngagementRow(
                commentCount: moment.commentCount ?? 0,
                likeCount: moment.likeCount ?? 0
            )
        } commentPreview: {
            if let latestComment = moment.latestComment,
               !latestComment.body.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                VStack(alignment: .leading, spacing: 6) {
                    Text("Latest comment")
                        .font(nativeAppFont(size: 11, weight: .black))
                        .foregroundStyle(.white.opacity(0.42))
                        .textCase(.uppercase)

                    HStack(alignment: .top, spacing: 10) {
                        Image(systemName: "bubble.left.and.bubble.right.fill")
                            .font(nativeAppFont(size: 12, weight: .black))
                            .foregroundStyle(nativeAccent)
                            .padding(.top, 1)

                        VStack(alignment: .leading, spacing: 4) {
                            Text("@\(latestComment.user)")
                                .font(nativeAppFont(size: 12, weight: .black))
                                .foregroundStyle(.white)
                                .lineLimit(1)

                            Text(latestComment.body)
                                .font(nativeAppFont(size: 13, weight: .medium))
                                .foregroundStyle(.white.opacity(0.72))
                                .lineLimit(2)
                        }

                        Spacer(minLength: 0)

                        Image(systemName: "chevron.right")
                            .font(nativeAppFont(size: 11, weight: .black))
                            .foregroundStyle(.white.opacity(0.28))
                            .padding(.top, 2)
                    }
                    .frame(maxWidth: .infinity, alignment: .leading)
                    .padding(.horizontal, 14)
                    .padding(.vertical, 12)
                    .background(Color.white.opacity(0.05))
                    .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
                }
            }
        }
    }

    private func diaryEmptyState(_ message: String) -> some View {
        NativeSurfaceCard {
            VStack(alignment: .leading, spacing: 10) {
                Text(message)
                    .font(nativeAppFont(size: 16, weight: .black))
                    .foregroundStyle(.white)
                Text("Add more logs and your diary will start to fill up here.")
                    .font(nativeAppFont(size: 13, weight: .medium))
                    .foregroundStyle(.white.opacity(0.62))
                    .fixedSize(horizontal: false, vertical: true)
            }
            .frame(maxWidth: .infinity, alignment: .leading)
        }
    }

    private func filteredMomentsByTime(_ filter: NativeDiaryTimeFilter) -> [NativeMoment] {
        let calendar = Calendar.current
        let now = Date()

        return allMoments.filter { moment in
            let date = nativeDiaryDate(for: moment)
            switch filter {
            case .thisWeek:
                return calendar.isDate(date, equalTo: now, toGranularity: .weekOfYear)
                    && calendar.isDate(date, equalTo: now, toGranularity: .yearForWeekOfYear)
            case .thisMonth:
                return calendar.isDate(date, equalTo: now, toGranularity: .month)
                    && calendar.isDate(date, equalTo: now, toGranularity: .year)
            case .lastMonth:
                guard let lastMonth = calendar.date(byAdding: .month, value: -1, to: now) else { return false }
                return calendar.isDate(date, equalTo: lastMonth, toGranularity: .month)
                    && calendar.isDate(date, equalTo: lastMonth, toGranularity: .year)
            case .last3Months:
                guard let start = calendar.date(byAdding: .month, value: -3, to: now) else { return true }
                return date >= start && date <= now
            }
        }
    }

    private func gallerySectionsByDate() -> [GallerySection] {
        let calendar = Calendar.current
        let now = Date()
        let startOfThisWeek = calendar.dateInterval(of: .weekOfYear, for: now)?.start ?? now
        let startOfLastWeek = calendar.date(byAdding: .weekOfYear, value: -1, to: startOfThisWeek) ?? startOfThisWeek
        let startOfThisMonth = calendar.dateInterval(of: .month, for: now)?.start ?? now
        let startOfLastMonth = calendar.date(byAdding: .month, value: -1, to: startOfThisMonth) ?? startOfThisMonth

        let grouped = Dictionary(grouping: galleryMoments) { moment -> String in
            let date = nativeDiaryDate(for: moment)
            if date >= startOfThisWeek {
                return "This week"
            }
            if date >= startOfLastWeek && date < startOfThisWeek {
                return "Last week"
            }
            if date >= startOfLastMonth && date < startOfThisMonth {
                return "Last month"
            }

            let formatter = DateFormatter()
            formatter.locale = Locale(identifier: "en_US_POSIX")
            formatter.timeZone = .current
            formatter.dateFormat = calendar.component(.year, from: date) == calendar.component(.year, from: now)
                ? "MMMM"
                : "MMMM yyyy"
            return formatter.string(from: date)
        }

        let orderedTitles = grouped.keys.sorted { lhs, rhs in
            dateClusterSortKey(for: lhs, now: now) > dateClusterSortKey(for: rhs, now: now)
        }

        return orderedTitles.compactMap { title in
            guard let moments = grouped[title], !moments.isEmpty else { return nil }
            return GallerySection(
                id: "date-\(title)",
                title: title,
                moments: moments.sorted { nativeDiaryDate(for: $0) > nativeDiaryDate(for: $1) }
            )
        }
    }

    private func gallerySectionsByCity() -> [GallerySection] {
        let grouped = Dictionary(grouping: galleryMoments) { moment in
            nativeCityKey(for: moment) ?? "Unknown location"
        }

        return grouped.keys.sorted().compactMap { city in
            guard let moments = grouped[city], !moments.isEmpty else { return nil }
            return GallerySection(
                id: "city-\(city)",
                title: city,
                moments: moments.sorted { nativeDiaryDate(for: $0) > nativeDiaryDate(for: $1) }
            )
        }
    }

    private func dateClusterSortKey(for title: String, now: Date) -> Date {
        let calendar = Calendar.current
        switch title {
        case "This week":
            return calendar.dateInterval(of: .weekOfYear, for: now)?.start ?? now
        case "Last week":
            let startOfThisWeek = calendar.dateInterval(of: .weekOfYear, for: now)?.start ?? now
            return calendar.date(byAdding: .weekOfYear, value: -1, to: startOfThisWeek) ?? now
        case "Last month":
            let startOfThisMonth = calendar.dateInterval(of: .month, for: now)?.start ?? now
            return calendar.date(byAdding: .month, value: -1, to: startOfThisMonth) ?? now
        default:
            let formatter = DateFormatter()
            formatter.locale = Locale(identifier: "en_US_POSIX")
            formatter.timeZone = .current
            formatter.dateFormat = "MMMM yyyy"
            if let fullDate = formatter.date(from: title) {
                return fullDate
            }
            formatter.dateFormat = "MMMM"
            if let monthOnly = formatter.date(from: title) {
                let month = calendar.component(.month, from: monthOnly)
                var components = calendar.dateComponents([.year], from: now)
                components.month = month
                components.day = 1
                return calendar.date(from: components) ?? .distantPast
            }
            return .distantPast
        }
    }

    private func nativeDiaryDate(for moment: NativeMoment) -> Date {
        NativeAppState.date(from: moment.visitedAtIso ?? moment.visitedDate) ?? Date.distantPast
    }

    private func nativeDiaryMediaURL(for moment: NativeMoment) -> String? {
        if let uploaded = moment.uploadedMedia?.first(where: { !$0.isEmpty }) {
            return uploaded
        }
        if let image = moment.place.image, !image.isEmpty {
            return image
        }
        return moment.place.images?.first(where: { !$0.isEmpty })
    }

    private func updateMapRegion() {
        let coordinates = mapMoments.compactMap { moment -> CLLocationCoordinate2D? in
            guard let latitude = moment.place.latitude, let longitude = moment.place.longitude else { return nil }
            return CLLocationCoordinate2D(latitude: latitude, longitude: longitude)
        }
        guard !coordinates.isEmpty else { return }

        let latitudes = coordinates.map(\.latitude)
        let longitudes = coordinates.map(\.longitude)
        let minLat = latitudes.min() ?? 0
        let maxLat = latitudes.max() ?? 0
        let minLon = longitudes.min() ?? 0
        let maxLon = longitudes.max() ?? 0

        mapRegion = MKCoordinateRegion(
            center: CLLocationCoordinate2D(
                latitude: (minLat + maxLat) / 2,
                longitude: (minLon + maxLon) / 2
            ),
            span: MKCoordinateSpan(
                latitudeDelta: max((maxLat - minLat) * 1.6, 0.05),
                longitudeDelta: max((maxLon - minLon) * 1.6, 0.05)
            )
        )
    }
}

private struct NativeHomepageShellScreen: View {
    @EnvironmentObject private var appState: NativeAppState
    @State private var photoAuthorizationStatus: PHAuthorizationStatus = PHPhotoLibrary.authorizationStatus(for: .readWrite)
    @State private var recentPhotoPreviews: [UIImage] = []
    @State private var showHeroPhotoPicker = false
    @State private var showAllChallenges = false
    @State private var showNotificationsSheet = false
    @State private var selectedHeroPhoto: NativePickedPhotoAsset?
    @State private var selectedHomepageMoment: NativeMoment?

    private var greetingName: String {
        let username = appState.currentUser?.username.trimmingCharacters(in: .whitespacesAndNewlines)
        if let username, !username.isEmpty {
            return username
        }
        let candidate = appState.currentUser?.displayName?.trimmingCharacters(in: .whitespacesAndNewlines)
        if let candidate, !candidate.isEmpty {
            return candidate
        }
        return "there"
    }

    private var greetingPrefix: String {
        let hour = Calendar.current.component(.hour, from: Date())
        switch hour {
        case 5..<12:
            return "Good morning"
        case 12..<17:
            return "Good afternoon"
        default:
            return "Good evening"
        }
    }

    var body: some View {
        ScrollView(showsIndicators: false) {
            VStack(alignment: .leading, spacing: 22) {
                homepageHeader
                heroActionCard
                statsAndChallengesSection
                recentMemoriesSection
                feedPreview
            }
            .padding(.horizontal, 20)
            .padding(.top, 18)
            .padding(.bottom, 120)
        }
        .background(Color.black.ignoresSafeArea())
        .navigationBarHidden(true)
        .sheet(isPresented: $showHeroPhotoPicker) {
            NativeSingleMetadataImagePicker(selection: $selectedHeroPhoto)
        }
        .sheet(isPresented: $showAllChallenges) {
            NativeHomepageChallengesSheet(
                challenges: appState.homepageOverview?.challenges ?? [],
                onAction: handleHomepageChallengeAction
            )
        }
        .sheet(isPresented: $showNotificationsSheet) {
            NavigationView {
                NativeNotificationsSheet()
            }
            .navigationViewStyle(.stack)
            .environmentObject(appState)
        }
        .fullScreenCover(item: $selectedHomepageMoment) { moment in
            NativeDecisionHistoryMomentFullscreen(moment: moment)
                .environmentObject(appState)
        }
        .onAppear {
            refreshHomepagePhotoPreviewIfNeeded()
            Task {
                await appState.refreshHomepageOverview()
                await appState.refreshHomepageRecentMemories()
                await appState.refreshFeed()
                await appState.refreshNotificationUnreadCount()
            }
        }
        .onChange(of: photoAuthorizationStatus) { _ in
            refreshHomepagePhotoPreviewIfNeeded()
        }
        .onChange(of: selectedHeroPhoto) { newValue in
            guard let newValue else { return }
            Task { @MainActor in
                try? await Task.sleep(nanoseconds: 180_000_000)
                appState.presentCheckInFlow(prefilledPhotoAsset: newValue)
                selectedHeroPhoto = nil
            }
        }
    }

