    private func homepageShortAddress(for place: NativePlace) -> String {
        let raw = place.address?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if raw.isEmpty {
            return place.location
        }
        let parts = raw
            .split(separator: ",")
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        guard let first = parts.first else { return place.location }
        if CharacterSet.decimalDigits.isSuperset(of: CharacterSet(charactersIn: first)),
           parts.count > 1 {
            return "\(first) \(parts[1])"
        }
        return first
    }

    private func homepagePlaceMetaLine(for place: NativePlace, shortAddress: String) -> String {
        let segments = [place.category?.trimmingCharacters(in: .whitespacesAndNewlines), shortAddress]
            .compactMap { value -> String? in
                guard let value, !value.isEmpty else { return nil }
                return value
            }
        return segments.joined(separator: " • ")
    }

    private func homepageDisplayUsername() -> String? {
        guard let currentUser = appState.currentUser else {
            return nil
        }
        let raw = currentUser.username.trimmingCharacters(in: .whitespacesAndNewlines)
        guard
              !raw.isEmpty,
              raw.lowercased() != "vibinn" else {
            return nil
        }
        return "@\(raw)"
    }

    private func handleHomepageChallengeAction(_ challenge: NativeHomepageChallenge) {
        switch challenge.action {
        case "add_log":
            appState.presentCheckInFlow()
        case "invite_friends":
            appState.showToast(message: "Invite flow is coming next.", icon: "paperplane.fill")
        default:
            break
        }
    }
}

private func nativePrimaryCity(from location: String) -> String? {
    let city = location
        .split(separator: ",")
        .first
        .map { String($0).trimmingCharacters(in: .whitespacesAndNewlines) }
    guard let city, !city.isEmpty else { return nil }
    return city
}

private func nativeCityKey(for place: NativePlace) -> String? {
    nativePrimaryCity(from: place.location)
}

private func nativeCityKey(for moment: NativeMoment) -> String? {
    nativeCityKey(for: moment.place)
}

private func nativeCityKey(for feedItem: NativeFeedItem) -> String? {
    if let place = feedItem.place {
        return nativeCityKey(for: place)
    }
    if let collection = feedItem.collection {
        let cities = Set(collection.places.compactMap(nativeCityKey(for:)))
        if cities.count == 1 {
            return cities.first
        }
    }
    return nil
}

private struct NativeCityFilterPills: View {
    @Binding var selectedCity: String? // nil means "All"
    let cities: [String]

    private struct PillItem: Identifiable {
        let id: String
        let label: String
        let icon: String?
        let cityValue: String? // nil means "All"
    }

    private var items: [PillItem] {
        var result: [PillItem] = [
            PillItem(id: "__all__", label: "All", icon: "globe", cityValue: nil)
        ]
        result.append(contentsOf: cities.map { city in
            PillItem(id: city, label: city, icon: nil, cityValue: city)
        })
        return result
    }

    var body: some View {
        ScrollViewReader { proxy in
            ScrollView(.horizontal, showsIndicators: false) {
                HStack(spacing: 10) {
                    ForEach(items) { item in
                        let isActive = selectedCity == item.cityValue
                        Button {
                            selectedCity = item.cityValue
                        } label: {
                            HStack(spacing: 8) {
                                if let icon = item.icon {
                                    Image(systemName: icon)
                                        .font(nativeAppFont(size: 12, weight: .black))
                                        .foregroundStyle(isActive ? .black : .white.opacity(0.84))
                                }
                                Text(item.label)
                                    .font(nativeAppFont(size: 13, weight: .black))
                                    .foregroundStyle(isActive ? .black : .white.opacity(0.84))
                                    .lineLimit(1)
                            }
                            .padding(.horizontal, 14)
                            .padding(.vertical, 10)
                            .background(isActive ? nativeAccent : Color.white.opacity(0.06))
                            .overlay(
                                Capsule()
                                    .stroke(Color.white.opacity(isActive ? 0.0 : 0.12), lineWidth: 1)
                            )
                            .clipShape(Capsule())
                        }
                        .buttonStyle(.plain)
                        .id(item.id)
                    }
                }
                .padding(.horizontal, 2)
            }
            // Helps avoid taps "falling through" into the content below when embedded in a vertical ScrollView.
            .contentShape(Rectangle())
            .background(Color.black.opacity(0.001))
            .onChange(of: selectedCity) { newValue in
                withAnimation(.easeInOut(duration: 0.22)) {
                    proxy.scrollTo(newValue ?? "__all__", anchor: .center)
                }
            }
        }
    }

}

