private struct NativeBottomSheetPresentationModifier: ViewModifier {
    @ViewBuilder
    func body(content: Content) -> some View {
        if #available(iOS 16.4, *) {
            content
                .presentationDetents([.height(320)])
                .presentationDragIndicator(.visible)
                .presentationCornerRadius(28)
        } else if #available(iOS 16.0, *) {
            content
                .presentationDetents([.height(320)])
                .presentationDragIndicator(.visible)
        } else {
            content
        }
    }
}

private struct NativeTallBottomSheetPresentationModifier: ViewModifier {
    @ViewBuilder
    func body(content: Content) -> some View {
        if #available(iOS 16.4, *) {
            content
                .presentationDetents([.fraction(0.8)])
                .presentationDragIndicator(.visible)
                .presentationCornerRadius(28)
        } else if #available(iOS 16.0, *) {
            content
                .presentationDetents([.fraction(0.8)])
                .presentationDragIndicator(.visible)
        } else {
            content
        }
    }
}

private struct NativeDiscoverySearchSheet: View {
    @EnvironmentObject private var appState: NativeAppState
    @Environment(\.dismiss) private var dismiss
    @State private var query = ""
    @State private var results: [NativePlace] = []
    @State private var isSearching = false
    @State private var errorMessage: String?

    var body: some View {
        ScrollView(showsIndicators: false) {
            VStack(alignment: .leading, spacing: 18) {
                NativeScreenHeader(
                    title: "Search places",
                    subtitle: "Search within the current city, just like discovery on the web."
                )

                NativeSurfaceCard {
                    VStack(spacing: 14) {
                        HStack(spacing: 12) {
                            TextField("Search places", text: $query)
                                .textInputAutocapitalization(.words)
                                .autocorrectionDisabled()
                                .font(nativeAppFont(size: 17, weight: .medium))
                                .foregroundStyle(.white)

                            Button {
                                Task { await performSearch() }
                            } label: {
                                if isSearching {
                                    ProgressView()
                                        .tint(.black)
                                        .frame(width: 18, height: 18)
                                } else {
                                    Image(systemName: "magnifyingglass")
                                        .font(nativeAppFont(size: 16, weight: .black))
                                        .foregroundStyle(.black)
                                }
                            }
                            .buttonStyle(.plain)
                            .frame(width: 40, height: 40)
                            .background(nativeAccent)
                            .clipShape(Circle())
                            .disabled(query.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || isSearching)
                        }
                        .padding(.horizontal, 16)
                        .padding(.vertical, 16)
                        .background(nativeSurfaceStrong)
                        .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))

                        if let errorMessage {
                            NativeInlineError(message: errorMessage)
                        }

                        if !query.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty && !isSearching && results.isEmpty && errorMessage == nil {
                            Text("No places found.")
                                .font(nativeAppFont(size: 14, weight: .medium))
                                .foregroundStyle(.white.opacity(0.58))
                        }

                        if !results.isEmpty {
                            VStack(spacing: 12) {
                                ForEach(results) { place in
                                    NavigationLink {
                                        NativePlaceDetailScreen(initialPlace: place, source: "search")
                                    } label: {
                                        HStack(spacing: 12) {
                                            NativeRemoteImage(url: place.image)
                                                .frame(width: 72, height: 72)
                                                .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))

                                            VStack(alignment: .leading, spacing: 6) {
                                                Text(place.name)
                                                    .font(nativeAppFont(size: 16, weight: .black))
                                                    .foregroundStyle(.white)
                                                    .multilineTextAlignment(.leading)
                                                Text(place.location)
                                                    .font(nativeAppFont(size: 13, weight: .medium))
                                                    .foregroundStyle(.white.opacity(0.58))
                                                    .lineLimit(2)
                                                if let category = place.category, !category.isEmpty {
                                                    Text(category.uppercased())
                                                        .font(nativeAppFont(size: 10, weight: .black))
                                                        .foregroundStyle(.white.opacity(0.45))
                                                }
                                            }
                                            Spacer(minLength: 0)
                                        }
                                    }
                                    .buttonStyle(.plain)
                                }
                            }
                        }
                    }
                }
            }
            .padding(20)
        }
        .background(Color.black.ignoresSafeArea())
        .navigationBarTitleDisplayMode(.inline)
        .toolbar {
            ToolbarItem(placement: .topBarLeading) {
                Button("Close") {
                    dismiss()
                }
                .foregroundStyle(.white)
            }
        }
        .preferredColorScheme(.dark)
    }

    private func performSearch() async {
        let trimmed = query.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            results = []
            errorMessage = nil
            return
        }

        errorMessage = nil
        isSearching = true
        defer { isSearching = false }

        do {
            results = try await appState.lookupPlaces(query: trimmed)
        } catch {
            errorMessage = "Could not search places right now."
        }
    }
}

