private struct NativeNotificationsSheet: View {
    @Environment(\.dismiss) private var dismiss
    @EnvironmentObject private var appState: NativeAppState
    @State private var notifications: [NativeNotificationItem] = []
    @State private var friendRequests: [NativeFriendRequestItem] = []
    @State private var isLoading = false
    @State private var errorMessage: String?

    private var groupedNotifications: [(title: String, items: [NativeNotificationItem])] {
        let calendar = Calendar.current
        let today = Date()
        let yesterday = calendar.date(byAdding: .day, value: -1, to: today) ?? today

        let buckets = Dictionary(grouping: notifications) { item -> String in
            guard let date = NativeAppState.date(from: item.createdAt ?? item.time) else {
                return "Earlier"
            }
            if calendar.isDate(date, inSameDayAs: today) {
                return "Today"
            }
            if calendar.isDate(date, inSameDayAs: yesterday) {
                return "Yesterday"
            }
            if calendar.isDate(date, equalTo: today, toGranularity: .weekOfYear) {
                return "This week"
            }
            return "Earlier"
        }

        let order = ["Today", "Yesterday", "This week", "Earlier"]
        return order.compactMap { key in
            guard let items = buckets[key], !items.isEmpty else { return nil }
            return (key, items)
        }
    }

    var body: some View {
        ZStack {
            Color.black.ignoresSafeArea()

            ScrollView(showsIndicators: false) {
                LazyVStack(alignment: .leading, spacing: 14) {
                    if let errorMessage {
                        NativeSurfaceCard {
                            VStack(alignment: .leading, spacing: 12) {
                                NativeInlineError(message: errorMessage)
                                Button {
                                    Task { await loadNotifications() }
                                } label: {
                                    Text("Try again")
                                        .font(nativeAppFont(size: 14, weight: .black))
                                        .foregroundStyle(.black)
                                        .frame(maxWidth: .infinity)
                                        .padding(.vertical, 12)
                                        .background(nativeAccent)
                                        .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
                                }
                                .buttonStyle(.plain)
                            }
                        }
                    }

                    if appState.currentUser == nil {
                        NativeSurfaceCard {
                            VStack(alignment: .leading, spacing: 12) {
                                Text("Log in to see your notifications.")
                                    .font(nativeAppFont(size: 18, weight: .black))
                                    .foregroundStyle(.white)
                                Button {
                                    dismiss()
                                    appState.presentAuthGate(reason: "Log in to see your notifications.")
                                } label: {
                                    Text("Go to login")
                                        .font(nativeAppFont(size: 15, weight: .black))
                                        .foregroundStyle(.black)
                                        .frame(maxWidth: .infinity)
                                        .padding(.vertical, 14)
                                        .background(nativeAccent)
                                        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
                                }
                                .buttonStyle(.plain)
                            }
                        }
                    } else if isLoading && notifications.isEmpty {
                        NativeSurfaceCard {
                            HStack(spacing: 12) {
                                ProgressView()
                                    .tint(nativeAccent)
                                Text("Loading notifications...")
                                    .font(nativeAppFont(size: 15, weight: .bold))
                                    .foregroundStyle(.white.opacity(0.8))
                            }
                        }
                    } else if notifications.isEmpty && friendRequests.isEmpty {
                        NativeSurfaceCard {
                            VStack(alignment: .leading, spacing: 10) {
                                Text("No notifications yet.")
                                    .font(nativeAppFont(size: 18, weight: .black))
                                    .foregroundStyle(.white)
                                Text("Likes, comments, follows, and invite activity will show up here.")
                                    .font(nativeAppFont(size: 14, weight: .medium))
                                    .foregroundStyle(.white.opacity(0.62))
                                    .fixedSize(horizontal: false, vertical: true)
                            }
                            .frame(maxWidth: .infinity, alignment: .leading)
                        }
                    } else {
                        if !friendRequests.isEmpty {
                            VStack(alignment: .leading, spacing: 10) {
                                Text("Friend requests")
                                    .font(nativeAppFont(size: 13, weight: .black))
                                    .foregroundStyle(.white.opacity(0.5))
                                    .textCase(.uppercase)

                                ForEach(friendRequests) { request in
                                    NativeFriendRequestRow(
                                        request: request,
                                        onAccept: {
                                            Task { await respondToFriendRequest(request, action: "accept") }
                                        },
                                        onDecline: {
                                            Task { await respondToFriendRequest(request, action: "decline") }
                                        }
                                    )
                                }
                            }
                        }

                        ForEach(groupedNotifications, id: \.title) { section in
                            VStack(alignment: .leading, spacing: 10) {
                                Text(section.title)
                                    .font(nativeAppFont(size: 13, weight: .black))
                                    .foregroundStyle(.white.opacity(0.5))
                                    .textCase(.uppercase)

                                ForEach(section.items) { notification in
                                    NativeNotificationRow(notification: notification)
                                }
                            }
                        }
                    }
                }
                .padding(.horizontal, 16)
                .padding(.top, 18)
                .padding(.bottom, 26)
            }
            .refreshable {
                await loadNotifications()
            }
        }
        .navigationTitle("Notifications")
        .navigationBarTitleDisplayMode(.inline)
        .toolbar {
            ToolbarItem(placement: .topBarTrailing) {
                Button {
                    dismiss()
                } label: {
                    Image(systemName: "xmark")
                        .font(nativeAppFont(size: 14, weight: .black))
                        .foregroundStyle(.white)
                        .frame(width: 32, height: 32)
                        .background(Color.white.opacity(0.08))
                        .clipShape(Circle())
                }
                    .foregroundStyle(nativeAccent)
            }
        }
        .task {
            await loadNotifications()
        }
    }

    private func loadNotifications() async {
        guard appState.currentUser != nil else { return }
        isLoading = true
        defer { isLoading = false }
        do {
            async let notificationsTask = appState.fetchNotifications()
            async let requestsTask = appState.fetchFriendRequests()
            notifications = try await notificationsTask
            friendRequests = try await requestsTask
            if notifications.contains(where: { $0.readAt == nil }) {
                await appState.markAllNotificationsRead()
                let nowIso = Date().ISO8601Format()
                notifications = notifications.map { item in
                    guard item.readAt == nil else { return item }
                    return NativeNotificationItem(
                        id: item.id,
                        notificationType: item.notificationType,
                        messageKind: item.messageKind,
                        targetType: item.targetType,
                        targetId: item.targetId,
                        placeTitle: item.placeTitle,
                        placeContext: item.placeContext,
                        title: item.title,
                        body: item.body,
                        time: item.time,
                        createdAt: item.createdAt,
                        readAt: nowIso,
                        actor: item.actor,
                        place: item.place,
                        traveler: item.traveler
                    )
                }
            }
            errorMessage = nil
        } catch is CancellationError {
        } catch {
            notifications = []
            friendRequests = []
            errorMessage = "Could not load notifications right now."
        }
    }

    private func respondToFriendRequest(_ request: NativeFriendRequestItem, action: String) async {
        do {
            _ = try await appState.respondToFriendRequest(requesterUserId: request.requester.id, action: action)
            friendRequests.removeAll { $0.id == request.id }
            if action == "accept" {
                nativeHaptic(.success)
            }
        } catch {
            errorMessage = "Could not update this friend request right now."
        }
    }
}

