                .focused($focusedField, equals: .otp)
                .opacity(0.01)
                .frame(height: 1)
                .onChange(of: otpCode) { value in
                    let filtered = value.filter(\.isNumber)
                    if filtered != value {
                        otpCode = filtered
                        return
