                step = appState.locationPermissionState == .authorized ? .firstPlaceEntry : .cityEntry
            }
        } catch {
            nativeLogger.error("v2 profile update failed \(nativeDescribeError(error), privacy: .public)")
            presentTransientError(error)
        }
    }

