    private static func country(_ id: String, _ name: String, _ dialCode: String) -> NativePhoneCountry {
        NativePhoneCountry(id: id, name: name, dialCode: dialCode)
    }

    private static func flagEmoji(for regionCode: String) -> String {
        let uppercased = regionCode.uppercased()
        guard uppercased.count == 2 else { return "🌍" }
        let scalars = uppercased.unicodeScalars.compactMap { scalar -> UnicodeScalar? in
            let value = scalar.value
            guard value >= 65, value <= 90 else { return nil }
            return UnicodeScalar(127397 + Int(value))
        }
        guard scalars.count == 2 else { return "🌍" }
        return String(String.UnicodeScalarView(scalars))
    }
}

private struct NativeAuthStickerStage: View {
    let visibleStickerCount: Int
    let showsLogo: Bool

    private let referenceFrame = CGSize(width: 402, height: 871)
    private let stickers: [NativeAuthStickerDescriptor] = [
        .init(assetName: "AuthStickerLayer6", originalSize: CGSize(width: 469, height: 423), x: 13, y: 0, width: 151, rotation: 0),
        .init(assetName: "AuthStickerLayer2", originalSize: CGSize(width: 396, height: 375), x: 213, y: 0, width: 137, rotation: 0),
        .init(assetName: "AuthStickerLayer4", originalSize: CGSize(width: 478, height: 547), x: -32, y: 112, width: 179, rotation: 0),
        .init(assetName: "AuthStickerLayer5", originalSize: CGSize(width: 542, height: 599), x: 0, y: 275, width: 147, rotation: 0),
        .init(assetName: "AuthStickerLayer3", originalSize: CGSize(width: 309, height: 546), x: 298, y: 80, width: 104, rotation: 0),
        .init(assetName: "AuthStickerLayer7", originalSize: CGSize(width: 533, height: 627), x: 258, y: 242, width: 166, rotation: 0),
    ]

    var body: some View {
        GeometryReader { proxy in
            let stageWidth = proxy.size.width
            let stageHeight = proxy.size.height

            ZStack {
                ForEach(Array(stickers.enumerated()), id: \.offset) { index, sticker in
                    let isVisible = visibleStickerCount > index
                    let displayedWidthInReference = sticker.width
                    let displayedHeightInReference = displayedWidthInReference * (sticker.originalSize.height / sticker.originalSize.width)
                    let targetWidth = stageWidth * (displayedWidthInReference / referenceFrame.width)
                    let targetHeight = stageHeight * (displayedHeightInReference / referenceFrame.height)
                    Image(sticker.assetName)
                        .resizable()
                        .scaledToFit()
                        .frame(width: targetWidth, height: targetHeight)
                        .rotationEffect(.degrees(sticker.rotation))
                        .shadow(color: .black.opacity(0.28), radius: 18, x: 0, y: 12)
                        .scaleEffect(isVisible ? 1 : 0.72)
                        .opacity(isVisible ? 1 : 0)
                        .position(
                            x: stageWidth * ((sticker.x + (displayedWidthInReference / 2)) / referenceFrame.width),
                            y: stageHeight * ((sticker.y + (displayedHeightInReference / 2)) / referenceFrame.height)
                        )
                }

                let iconWidthInReference: CGFloat = 61
                let wordmarkWidthInReference: CGFloat = 149
                let wordmarkHeightInReference: CGFloat = wordmarkWidthInReference * (32.0 / 357.0)

                Image("VibinnAuthLogoIcon")
                    .resizable()
                    .scaledToFit()
                    .frame(
                        width: stageWidth * (iconWidthInReference / referenceFrame.width),
                        height: stageWidth * (iconWidthInReference / referenceFrame.width)
                    )
                    .opacity(showsLogo ? 1 : 0)
                    .scaleEffect(showsLogo ? 1 : 0.9)
                    .position(
                        x: stageWidth * ((170 + (iconWidthInReference / 2)) / referenceFrame.width),
                        y: stageHeight * ((153 + (iconWidthInReference / 2)) / referenceFrame.height)
                    )

                Image("VibinnAuthWordmark")
                    .resizable()
                    .scaledToFit()
                    .frame(width: stageWidth * (wordmarkWidthInReference / referenceFrame.width))
                    .opacity(showsLogo ? 1 : 0)
                    .scaleEffect(showsLogo ? 1 : 0.9)
                    .position(
                        x: stageWidth * ((126 + (wordmarkWidthInReference / 2)) / referenceFrame.width),
                        y: stageHeight * ((231 + (wordmarkHeightInReference / 2)) / referenceFrame.height)
                    )
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .animation(.easeOut(duration: 0.24), value: showsLogo)
    }
}

private struct NativeAuthPositionDebugOverlay: View {
    private let referenceFrame = CGSize(width: 402, height: 871)
    private let markers: [NativeAuthPositionMarker] = [
        .init(label: "Logo Icon", x: 170, y: 153, width: 61, height: 61, color: .yellow),
        .init(label: "Logo Text", x: 126, y: 231, width: 149, height: 13.4, color: .green),
        .init(label: "L6", x: 13, y: 0, width: 151, height: 136.2, color: .red),
        .init(label: "L2", x: 213, y: 0, width: 137, height: 129.7, color: .orange),
        .init(label: "L4", x: -32, y: 112, width: 179, height: 204.7, color: .blue),
        .init(label: "L5", x: 0, y: 275, width: 147, height: 162.4, color: .purple),
        .init(label: "L3", x: 298, y: 80, width: 104, height: 183.6, color: .pink),
        .init(label: "L7", x: 258, y: 242, width: 166, height: 195.3, color: .cyan),
    ]

    var body: some View {
        GeometryReader { proxy in
            let stageWidth = proxy.size.width
            let stageHeight = proxy.size.height

            ZStack {
                Path { path in
                    let verticalDivisions = 4
                    let horizontalDivisions = 8
                    for index in 0...verticalDivisions {
                        let x = stageWidth * CGFloat(index) / CGFloat(verticalDivisions)
                        path.move(to: CGPoint(x: x, y: 0))
                        path.addLine(to: CGPoint(x: x, y: stageHeight))
                    }
                    for index in 0...horizontalDivisions {
                        let y = stageHeight * CGFloat(index) / CGFloat(horizontalDivisions)
                        path.move(to: CGPoint(x: 0, y: y))
                        path.addLine(to: CGPoint(x: stageWidth, y: y))
                    }
                }
                .stroke(Color.white.opacity(0.12), style: StrokeStyle(lineWidth: 1, dash: [4, 6]))

                ForEach(Array(markers.enumerated()), id: \.offset) { _, marker in
                    let rect = marker.scaledRect(in: CGSize(width: stageWidth, height: stageHeight), reference: referenceFrame)
                    ZStack(alignment: .topLeading) {
                        RoundedRectangle(cornerRadius: 12, style: .continuous)
                            .stroke(marker.color.opacity(0.9), lineWidth: 2)
                            .background(
                                RoundedRectangle(cornerRadius: 12, style: .continuous)
                                    .fill(marker.color.opacity(0.05))
                            )
                        Text("\(marker.label)\nx:\(Int(marker.x)) y:\(Int(marker.y))")
                            .font(nativeAppFont(size: 9, weight: .bold))
                            .foregroundStyle(marker.color)
                            .padding(6)
                            .background(Color.black.opacity(0.82))
                            .clipShape(RoundedRectangle(cornerRadius: 8, style: .continuous))
                            .offset(x: 4, y: 4)
                    }
                    .frame(width: rect.width, height: rect.height)
                    .position(x: rect.midX, y: rect.midY)
                }
            }
        }
    }
}

private struct NativeAuthPositionMarker {
    let label: String
    let x: CGFloat
    let y: CGFloat
    let width: CGFloat
    let height: CGFloat
    let color: Color

    func scaledRect(in stage: CGSize, reference: CGSize) -> CGRect {
        CGRect(
            x: stage.width * (x / reference.width),
            y: stage.height * (y / reference.height),
            width: stage.width * (width / reference.width),
            height: stage.height * (height / reference.height)
        )
    }
}

private struct NativeAuthStickerDescriptor {
    let assetName: String
    let originalSize: CGSize
    let x: CGFloat
    let y: CGFloat
    let width: CGFloat
    let rotation: Double
}

