            assetName: "AuthStickerLayer3",
            originalSize: CGSize(width: 309, height: 546),
            x: 327,
            y: 445,
            width: 76,
            rotation: 0
        ),
        .init(
            assetName: "AuthStickerLayer2",
            originalSize: CGSize(width: 396, height: 375),
            x: -23.44,
            y: 625.8,
            width: 92.77,
            rotation: -76
        ),
    ]

    var body: some View {
        GeometryReader { proxy in
            let stageWidth = proxy.size.width
            let stageHeight = proxy.size.height

            ZStack {
                ForEach(Array(stickers.enumerated()), id: \.offset) { _, sticker in
                    let displayedWidthInReference = sticker.width
                    let displayedHeightInReference = displayedWidthInReference * (sticker.originalSize.height / sticker.originalSize.width)
                    let targetWidth = stageWidth * (displayedWidthInReference / referenceFrame.width)
                    let targetHeight = stageHeight * (displayedHeightInReference / referenceFrame.height)
                    let centerXInReference = sticker.assetName == "AuthStickerLayer3"
                        ? sticker.x - (displayedWidthInReference / 2)
                        : sticker.x + (displayedWidthInReference / 2)

                    Image(sticker.assetName)
                        .resizable()
