                        .frame(width: targetWidth, height: targetHeight)
                        .rotationEffect(.degrees(sticker.rotation))
                        .shadow(color: .black.opacity(0.24), radius: 18, x: 0, y: 10)
                        .position(
                            x: stageWidth * (centerXInReference / referenceFrame.width),
                            y: stageHeight * ((sticker.y + (displayedHeightInReference / 2)) / referenceFrame.height)
                        )
                }
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .allowsHitTesting(false)
    }
}

private struct NativeAuthHeroPinWall: View {
    private let heroAssets = [
        "aesthetic_cafes",
        "desserts_sweet_treats",
        "street_food_casual_eats",
        "asian_comfort_food",
