private struct NativeAuthHeroTile: View {
    let assetName: String
    let width: CGFloat
    let height: CGFloat

    var body: some View {
        let tileShape = RoundedRectangle(cornerRadius: 26, style: .continuous)

        ZStack {
            tileShape
                .fill(Color.white.opacity(0.06))

            GeometryReader { geometry in
                if UIImage(named: assetName) != nil {
                    Image(assetName)
                        .resizable()
                        .scaledToFill()
                        .frame(width: geometry.size.width, height: geometry.size.height)
                        .clipped()
                } else {
                    Text("IMAGE")
                        .font(nativeAppFont(size: 10, weight: .black))
                        .foregroundStyle(.white.opacity(0.28))
                        .frame(width: geometry.size.width, height: geometry.size.height, alignment: .bottomLeading)
                        .padding(.horizontal, 10)
                        .padding(.vertical, 8)
                }
            }
            .frame(width: width, height: height)
            .clipped()
        }
        .frame(width: width)
        .frame(height: height)
        .clipped()
        .clipShape(tileShape)
        .contentShape(tileShape)
        .overlay {
            if nativeAuthHeroImageDebugMode {
                NativeDebugFrame(label: assetName, color: .red)
            }
        }
    }
}

private extension Array {
    subscript(safe index: Int) -> Element? {
        guard index >= 0 && index < count else { return nil }
        return self[index]
    }
}

private struct NativeDebugFrame: View {
    let label: String
    let color: Color

    var body: some View {
        GeometryReader { proxy in
            let frame = proxy.frame(in: .global)
            ZStack(alignment: .topLeading) {
                Rectangle()
                    .stroke(color.opacity(0.9), lineWidth: 2)

                VStack(alignment: .leading, spacing: 2) {
                    Text(label)
                    Text("minY=\(Int(frame.minY)) h=\(Int(frame.height))")
                }
                .font(nativeAppFont(size: 10, weight: .black))
                .foregroundStyle(color)
                .padding(.horizontal, 8)
                .padding(.vertical, 6)
                .background(Color.black.opacity(0.62))
                .clipShape(RoundedRectangle(cornerRadius: 10, style: .continuous))
                .padding(6)
            }
        }
        .allowsHitTesting(false)
    }
}

private struct NativeAuthLandingButton: View {
    enum IconSource {
        case none
        case system(String)
        case asset(String)
    }

    enum Style {
        case light
        case dark
    }

    let title: String
    let icon: IconSource
    let isLoading: Bool
    let style: Style
    let action: () -> Void

    var body: some View {
        Button(action: action) {
            HStack(spacing: 10) {
                if isLoading {
                    ProgressView()
                        .tint(style == .light ? .black : .white)
                } else {
                    switch icon {
                    case .none:
                        EmptyView()
                    case .system(let name):
                        Image(systemName: name)
                            .font(nativeAppFont(size: 16, weight: style == .light ? .bold : .regular))
                    case .asset(let name):
                        Image(name)
                            .resizable()
                            .interpolation(.high)
                            .frame(width: 18, height: 18)
                    }
                }
                Text(title)
                    .font(nativeAppFont(size: 15, weight: style == .light ? .bold : .regular))
            }
            .frame(maxWidth: .infinity)
            .padding(.horizontal, 18)
            .padding(.vertical, 12)
            .background(style == .light ? nativeAccent : Color.white.opacity(0.08))
            .foregroundStyle(style == .light ? Color.black : Color.white)
            .overlay(
                RoundedRectangle(cornerRadius: 22, style: .continuous)
                    .stroke(style == .light ? Color.clear : nativeBorder, lineWidth: 1)
            )
            .clipShape(RoundedRectangle(cornerRadius: 22, style: .continuous))
        }
        .buttonStyle(.plain)
    }
}

