                            .overlay(Circle().stroke(nativeBorder, lineWidth: 1))
                            .clipShape(Circle())
                    }
                }
            }
        }
        .navigationViewStyle(.stack)
    }
}

private struct NativeEmailAuthForm: View {
    @EnvironmentObject private var appState: NativeAppState
    @State private var mode: AuthMode = .login
    @State private var name = ""
    @State private var email = ""
    @State private var password = ""
    @State private var confirmPassword = ""
    @State private var isSubmitting = false
    @State private var errorMessage: String?

    private enum AuthMode: String, CaseIterable, Identifiable {
        case login = "Log in"
        case register = "Register"
        var id: String { rawValue }
    }

    var body: some View {
        ScrollView(showsIndicators: false) {
            VStack(alignment: .leading, spacing: 18) {
                Picker("Mode", selection: $mode) {
                    ForEach(AuthMode.allCases) { item in
                        Text(item.rawValue).tag(item)
                    }
                }
                .pickerStyle(.segmented)

                NativeSurfaceCard {
                    VStack(spacing: 16) {
                        if mode == .register {
                            NativeInputField(title: "Name", text: $name, keyboard: .default, secure: false)
                        }

                        NativeInputField(title: "Email", text: $email, keyboard: .emailAddress, secure: false)
                        NativeInputField(title: "Password", text: $password, keyboard: .default, secure: true)

                        if mode == .register {
                            NativeInputField(title: "Repeat password", text: $confirmPassword, keyboard: .default, secure: true)
                        }

                        if mode == .register && !confirmPassword.isEmpty && password != confirmPassword {
                            Text("Passwords need to match.")
                                .font(nativeAppFont(size: 13, weight: .bold))
                                .foregroundStyle(.red.opacity(0.9))
                                .frame(maxWidth: .infinity, alignment: .leading)
                        }

                        if let errorMessage {
                            Text(errorMessage)
                                .font(nativeAppFont(size: 14, weight: .semibold))
                                .foregroundStyle(.red.opacity(0.9))
                                .frame(maxWidth: .infinity, alignment: .leading)
                        }

                        Button {
                            Task {
                                await submit()
                            }
                        } label: {
                            HStack {
                                Spacer()
                                if isSubmitting {
                                    ProgressView().tint(.black)
                                } else {
                                    Text(mode.rawValue)
                                        .font(nativeAppFont(size: 17, weight: .black))
                                }
                                Spacer()
                            }
                            .padding(.vertical, 16)
                            .background(nativeAccent)
                            .foregroundStyle(.black)
                            .clipShape(RoundedRectangle(cornerRadius: 22, style: .continuous))
                        }
                        .buttonStyle(.plain)
                        .disabled(!canSubmit)
                    }
                }
            }
            .padding(.horizontal, 20)
            .padding(.top, 20)
            .padding(.bottom, 36)
        }
        .background(Color.black.ignoresSafeArea())
    }

    private var canSubmit: Bool {
        guard !isSubmitting else { return false }
        switch mode {
        case .login:
            return !email.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
                && !password.isEmpty
        case .register:
            return !name.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
                && !email.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
                && !password.isEmpty
                && password == confirmPassword
        }
    }

    private func submit() async {
        errorMessage = nil
        isSubmitting = true
        defer { isSubmitting = false }

        do {
            if mode == .login {
                try await appState.login(
                    email: email.trimmingCharacters(in: .whitespacesAndNewlines),
                    password: password
                )
            } else {
                try await appState.register(
                    name: name.trimmingCharacters(in: .whitespacesAndNewlines),
                    email: email.trimmingCharacters(in: .whitespacesAndNewlines),
                    password: password
                )
            }
        } catch {
            errorMessage = mode == .login
                ? "Could not log in right now."
                : "Could not create your account right now."
        }
    }
}

private struct NativeOnboardingScreen: View {
    @EnvironmentObject private var appState: NativeAppState
    @State private var step: NativeOnboardingStep = .locationPermission
    @State private var awaitingLocationPermission = false
    @State private var awaitingNotificationPermission = false
    @State private var isSubmittingPermission = false
    @State private var displayedPrimaryText = ""
    @State private var displayedSecondaryText = ""
    @State private var introTypingTask: Task<Void, Never>?

    private enum NativeOnboardingStep: Hashable {
        case introPartOne
        case introPartTwo
        case locationPermission
        case notificationPermission
    }

    var body: some View {
        ZStack {
            LinearGradient(
                colors: [Color(red: 9 / 255, green: 9 / 255, blue: 11 / 255), .black],
                startPoint: .top,
                endPoint: .bottom
            )
            .ignoresSafeArea()

            content
        }
        .onAppear {
            resolveInitialStep()
        }
        .onChange(of: appState.locationPermissionState) { newValue in
            guard awaitingLocationPermission else { return }
            guard newValue != .notDetermined else { return }
            awaitingLocationPermission = false
            isSubmittingPermission = false
            advanceFromPermissionFlow()
        }
        .onChange(of: appState.notificationPermissionState) { newValue in
            guard awaitingNotificationPermission else { return }
            guard newValue != .notDetermined else { return }
            awaitingNotificationPermission = false
            isSubmittingPermission = false
            advanceFromPermissionFlow()
        }
        .onDisappear {
            introTypingTask?.cancel()
        }
    }

    private func resolveInitialStep() {
        introTypingTask?.cancel()
        displayedPrimaryText = ""
        displayedSecondaryText = ""
        awaitingLocationPermission = false
        awaitingNotificationPermission = false
        isSubmittingPermission = false

        if appState.locationPermissionState != .authorized {
            step = .locationPermission
            return
        }

        if appState.notificationPermissionState != .authorized {
            step = .notificationPermission
            return
        }

        completeOnboarding()
    }

    @ViewBuilder
    private var content: some View {
        switch step {
        case .introPartOne:
            introPage(showIllustration: false, ctaTitle: nil, action: nil)
        case .introPartTwo:
            introPage(showIllustration: true, ctaTitle: "Continue") {
                nativeHaptic(.medium)
                advanceFromIntroPartTwo()
            }
        case .locationPermission:
            permissionPage(
                title: "Enable location",
                subtitle: "Location helps Vibinn show nearby places, accurate distance, and better place suggestions when you log a memory.",
                buttonTitle: "Continue",
                iconName: "location.fill"
            ) {
                await handleLocationPermission()
            }
        case .notificationPermission:
            permissionPage(
                title: "Enable notifications",
                subtitle: "Notifications help Vibinn send timely updates about chats, friend activity, and recommendations.",
                buttonTitle: "Continue",
                iconName: "bell.fill"
            ) {
                await handleNotificationPermission()
            }
        }
    }

    private func introPage(showIllustration: Bool, ctaTitle: String?, action: (() -> Void)?) -> some View {
        VStack(spacing: 0) {
            Spacer(minLength: 0)

            VStack(spacing: 28) {
                VStack(spacing: 10) {
                    Text(displayedPrimaryText)
                        .font(nativeAppFont(size: 38, weight: .black))
                        .multilineTextAlignment(.center)
                        .foregroundStyle(.white)
                        .frame(maxWidth: .infinity)

                    Text(displayedSecondaryText)
                        .font(nativeAppFont(size: 28, weight: .bold))
                        .multilineTextAlignment(.center)
                        .foregroundStyle(.white.opacity(0.9))
                        .frame(maxWidth: .infinity)
                }

                if showIllustration {
                    RoundedRectangle(cornerRadius: 28, style: .continuous)
                        .fill(Color.white.opacity(0.06))
                        .overlay(
                            VStack(spacing: 10) {
                                Image(systemName: "photo")
                                    .font(nativeAppFont(size: 28, weight: .bold))
                                    .foregroundStyle(.white.opacity(0.75))
                                Text("Illustration Placeholder")
                                    .font(nativeAppFont(size: 13, weight: .semibold))
                                    .foregroundStyle(.white.opacity(0.52))
                            }
                        )
                        .overlay(
                            RoundedRectangle(cornerRadius: 28, style: .continuous)
                                .stroke(Color.white.opacity(0.08), lineWidth: 1)
                        )
                        .aspectRatio(16.0 / 9.0, contentMode: .fit)
                }
            }
            .frame(maxWidth: .infinity)
            .padding(.horizontal, 28)

            Spacer(minLength: 0)

            if let ctaTitle, let action {
                Button(action: action) {
                    HStack {
                        Spacer()
                        Text(ctaTitle)
                            .font(nativeAppFont(size: 17, weight: .black))
                        Spacer()
                    }
                    .padding(.vertical, 18)
                    .background(nativeAccent)
                    .foregroundStyle(.black)
                    .clipShape(RoundedRectangle(cornerRadius: 22, style: .continuous))
                }
                .buttonStyle(.plain)
                .padding(.horizontal, 24)
                .padding(.bottom, 24)
            }
        }
    }

    private func permissionPage(
        title: String,
        subtitle: String,
        buttonTitle: String,
        iconName: String,
        action: @escaping () async -> Void
    ) -> some View {
        VStack(spacing: 0) {
            VStack(alignment: .leading, spacing: 12) {
                ZStack {
                    Circle()
                        .fill(nativeAccent)
                        .frame(width: 54, height: 54)

                    Image(systemName: iconName)
                        .font(nativeAppFont(size: 22, weight: .black))
                        .foregroundStyle(.black)
                }

                Text(title)
                    .font(nativeAppFont(size: 38, weight: .black))
                    .foregroundStyle(nativeAccent)
                    .fixedSize(horizontal: false, vertical: true)

                Text(subtitle)
                    .font(nativeAppFont(size: 20, weight: .bold))
                    .foregroundStyle(.white.opacity(0.84))
                    .fixedSize(horizontal: false, vertical: true)
            }
            .frame(maxWidth: .infinity, alignment: .leading)
            .padding(.horizontal, 24)
            .padding(.top, 36)

            Spacer(minLength: 0)

            Button {
                Task { await action() }
            } label: {
                HStack {
                    Spacer()
                    if isSubmittingPermission {
                        ProgressView().tint(.black)
                    } else {
                        Text(buttonTitle)
                            .font(nativeAppFont(size: 17, weight: .black))
                    }
                    Spacer()
                }
                .padding(.vertical, 18)
                .background(nativeAccent)
                .foregroundStyle(.black)
                .clipShape(RoundedRectangle(cornerRadius: 22, style: .continuous))
            }
            .buttonStyle(.plain)
            .disabled(isSubmittingPermission)
            .padding(.horizontal, 24)
            .padding(.bottom, 24)
        }
    }

    private func startIntroPartOne() {
        introTypingTask?.cancel()
        step = .introPartOne
        introTypingTask = Task {
            await typeIntro(
                primary: "Stop overthinking.",
                secondary: "Where we going today?"
            )
            try? await Task.sleep(nanoseconds: 3_000_000_000)
            guard !Task.isCancelled else { return }
            await MainActor.run {
                step = .introPartTwo
            }
            await typeIntro(
                primary: "We give you 3.",
                secondary: "You just pick one."
            )
        }
    }

    private func typeIntro(primary: String, secondary: String) async {
        await MainActor.run {
            displayedPrimaryText = ""
            displayedSecondaryText = ""
        }

        for character in primary {
            guard !Task.isCancelled else { return }
            await MainActor.run {
                displayedPrimaryText.append(character)
            }
            try? await Task.sleep(nanoseconds: 28_000_000)
        }

        try? await Task.sleep(nanoseconds: 180_000_000)

        for character in secondary {
            guard !Task.isCancelled else { return }
            await MainActor.run {
                displayedSecondaryText.append(character)
            }
            try? await Task.sleep(nanoseconds: 28_000_000)
        }
    }

    private func handleLocationPermission() async {
        guard !isSubmittingPermission else { return }
        isSubmittingPermission = true
        awaitingLocationPermission = true
        appState.requestLocationAuthorizationIfNeeded()

        if appState.locationPermissionState != .notDetermined {
            awaitingLocationPermission = false
            isSubmittingPermission = false
            advanceFromPermissionFlow()
        }
    }

    private func handleNotificationPermission() async {
        guard !isSubmittingPermission else { return }
        isSubmittingPermission = true
        awaitingNotificationPermission = true
        await appState.requestPushNotificationAuthorizationIfNeeded()

        if appState.notificationPermissionState != .notDetermined {
            awaitingNotificationPermission = false
            isSubmittingPermission = false
            advanceFromPermissionFlow()
        }
    }

    private func advanceFromIntroPartTwo() {
        if appState.locationPermissionState == .notDetermined {
            step = .locationPermission
            return
        }

        if appState.notificationPermissionState == .notDetermined {
            step = .notificationPermission
            return
        }

        completeOnboarding()
    }

    private func advanceFromPermissionFlow() {
        if appState.locationPermissionState == .notDetermined {
            step = .locationPermission
            return
        }

        if appState.notificationPermissionState == .notDetermined {
            step = .notificationPermission
            return
        }

        completeOnboarding()
    }

    private func completeOnboarding() {
        Task {
            await appState.completeOnboarding(
                with: appState.effectiveDecisionLocation,
                selectedInterests: appState.selectedInterests,
                selectedVibe: appState.selectedVibe,
                preserveExistingPreferences: true
            )
        }
    }
}

private struct NativeComingSoonScreen: View {
    @EnvironmentObject private var appState: NativeAppState
    @State private var email = ""
    @State private var isSubmitting = false
    @State private var hasJoinedWaitlist = false
    @State private var errorMessage: String?
    @State private var showShareSheet = false

    private var resolvedEmail: String {
        appState.currentUser?.email?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
    }

    private var activeEmail: String {
        let candidate = email.trimmingCharacters(in: .whitespacesAndNewlines)
        return candidate.isEmpty ? resolvedEmail : candidate
    }

    private var needsEmailInput: Bool {
        resolvedEmail.isEmpty
    }

    var body: some View {
        ZStack {
            LinearGradient(
                colors: [Color(red: 9 / 255, green: 9 / 255, blue: 11 / 255), .black],
                startPoint: .top,
                endPoint: .bottom
            )
            .ignoresSafeArea()

            VStack(spacing: 0) {
                Spacer(minLength: 0)

                VStack(spacing: 28) {
                    NativeComingSoonIllustration()
                        .frame(maxWidth: .infinity)
                        .aspectRatio(1.08, contentMode: .fit)

                    VStack(spacing: 12) {
                        Text("Not in your city… yet 👀")
                            .font(nativeAppFont(size: 34, weight: .black))
                            .foregroundStyle(.white)
                            .multilineTextAlignment(.center)

                        Text("We’re not in \(appState.currentUnsupportedCityLabel) just yet.\nBut we’re getting there.")
                            .font(nativeAppFont(size: 18, weight: .medium))
                            .foregroundStyle(.white.opacity(0.82))
                            .multilineTextAlignment(.center)
                    }

                    if needsEmailInput {
                        TextField("Email address", text: $email)
                            .textInputAutocapitalization(.never)
                            .keyboardType(.emailAddress)
                            .autocorrectionDisabled()
                            .font(nativeAppFont(size: 16, weight: .medium))
                            .foregroundStyle(.white)
                            .padding(.horizontal, 18)
                            .padding(.vertical, 16)
                            .background(nativeSurfaceStrong)
                            .overlay(
                                RoundedRectangle(cornerRadius: 18, style: .continuous)
                                    .stroke(nativeBorder, lineWidth: 1)
                            )
                            .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                    }

                    VStack(spacing: 12) {
                        Button {
                            Task { await joinWaitlist() }
                        } label: {
                            HStack {
                                Spacer()
                                if isSubmitting {
                                    ProgressView().tint(.black)
                                } else {
                                    Text(hasJoinedWaitlist ? "You’re on the list" : "Notify me")
                                        .font(nativeAppFont(size: 17, weight: .black))
                                }
                                Spacer()
                            }
                            .padding(.vertical, 18)
                            .background(nativeAccent)
                            .foregroundStyle(.black)
                            .clipShape(RoundedRectangle(cornerRadius: 22, style: .continuous))
                        }
                        .buttonStyle(.plain)
                        .disabled(isSubmitting || hasJoinedWaitlist)

                        Button {
                            showShareSheet = true
                        } label: {
                            HStack {
                                Spacer()
                                Text("Invite friends")
                                    .font(nativeAppFont(size: 17, weight: .black))
                                Spacer()
                            }
                            .padding(.vertical, 18)
                            .background(nativeSurface)
                            .foregroundStyle(.white)
                            .overlay(
                                RoundedRectangle(cornerRadius: 22, style: .continuous)
                                    .stroke(nativeBorder, lineWidth: 1)
                            )
                            .clipShape(RoundedRectangle(cornerRadius: 22, style: .continuous))
                        }
                        .buttonStyle(.plain)
                    }

                    if let errorMessage {
                        Text(errorMessage)
                            .font(nativeAppFont(size: 13, weight: .semibold))
                            .foregroundStyle(Color(red: 1, green: 0.55, blue: 0.55))
                            .multilineTextAlignment(.center)
                    }

                    Text("More cities coming soon")
                        .font(nativeAppFont(size: 12, weight: .semibold))
                        .foregroundStyle(.white.opacity(0.42))
                }
                .padding(.horizontal, 24)

                Spacer(minLength: 0)
            }
        }
        .preferredColorScheme(.dark)
        .onAppear {
            if email.isEmpty {
                email = resolvedEmail
            }
        }
        .sheet(isPresented: $showShareSheet) {
            NativeShareSheet(
                items: [
                    "Vibinn isn’t in \(appState.currentUnsupportedCityLabel) yet, but it’s coming soon. Join me on the waitlist."
                ]
            )
        }
    }

    private func joinWaitlist() async {
        guard !isSubmitting else { return }
        errorMessage = nil
        isSubmitting = true
        defer { isSubmitting = false }

        do {
            try await appState.joinCityWaitlist(
                email: activeEmail,
                cityLabel: appState.currentUnsupportedCityLabel
            )
            hasJoinedWaitlist = true
            nativeHaptic(.success)
        } catch {
            hasJoinedWaitlist = false
            errorMessage = error.localizedDescription
            nativeHaptic(.warning)
        }
    }
}

