private struct NativePreferenceSelectionSection: View {
    let title: String
    let subtitle: String
    @Binding var selectedInterests: [String]
    private let gridSpacing: CGFloat = 12

    private func gridCardWidth(totalWidth: CGFloat) -> CGFloat {
        floor((totalWidth - gridSpacing) / 2)
    }

    private func gridCardHeight(totalWidth: CGFloat) -> CGFloat {
        gridCardWidth(totalWidth: totalWidth) * 1.5
    }

    private func gridContentHeight(totalWidth: CGFloat) -> CGFloat {
        let rows = Int(ceil(Double(nativeInterestSwipeCards.count) / 2.0))
        let cardHeight = gridCardHeight(totalWidth: totalWidth)
        return (CGFloat(rows) * cardHeight) + (CGFloat(max(rows - 1, 0)) * gridSpacing)
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            VStack(alignment: .leading, spacing: 6) {
                Text(title)
                    .font(nativeAppFont(size: 28, weight: .black))
                    .foregroundStyle(.white)
                Text(subtitle)
                    .font(nativeAppFont(size: 13, weight: .semibold))
                    .foregroundStyle(.white.opacity(0.58))
                    .fixedSize(horizontal: false, vertical: true)
            }
            .frame(maxWidth: .infinity, alignment: .leading)
            .overlay(alignment: .topLeading) {
                if nativePreferenceLayoutDebugMode {
                    NativePreferenceDebugBadge(
                        title: "HEADER",
                        value: "spacing=6"
                    )
                    .padding(6)
                }
            }
            .overlay {
                if nativePreferenceLayoutDebugMode {
                    RoundedRectangle(cornerRadius: 14, style: .continuous)
                        .stroke(Color.blue.opacity(0.9), style: StrokeStyle(lineWidth: 1.5, dash: [6, 4]))
                }
            }

            GeometryReader { proxy in
                let totalWidth = proxy.size.width
                let cardWidth = gridCardWidth(totalWidth: totalWidth)
                let columns = [
                    GridItem(.fixed(cardWidth), spacing: gridSpacing),
                    GridItem(.fixed(cardWidth), spacing: gridSpacing),
                ]

                LazyVGrid(columns: columns, spacing: gridSpacing) {
                    ForEach(nativeInterestSwipeCards) { card in
                        NativePreferenceSelectionCard(
                            card: card,
                            cardWidth: cardWidth,
                            isSelected: selectedInterests.contains(card.id)
                        ) {
                            toggle(card.id)
                        }
                    }
                }
                .frame(maxWidth: .infinity, alignment: .leading)
                .overlay(alignment: .topLeading) {
                    if nativePreferenceLayoutDebugMode {
                        NativePreferenceDebugBadge(
                            title: "GRID",
                            value: "\(Int(totalWidth))w • \(Int(cardWidth))x\(Int(gridCardHeight(totalWidth: totalWidth)))"
                        )
                        .padding(6)
                        .allowsHitTesting(false)
                    }
                }
                .overlay {
                    if nativePreferenceLayoutDebugMode {
                        RoundedRectangle(cornerRadius: 18, style: .continuous)
                            .stroke(Color.green.opacity(0.9), style: StrokeStyle(lineWidth: 1.5, dash: [8, 5]))
                            .allowsHitTesting(false)
                    }
                }
            }
            .frame(height: gridContentHeight(totalWidth: UIScreen.main.bounds.width - 48))
        }
        .overlay(alignment: .bottomTrailing) {
            if nativePreferenceLayoutDebugMode {
                NativePreferenceDebugBadge(
                    title: "SECTION",
                    value: "\(nativeInterestSwipeCards.count) cards"
                )
                .padding(8)
            }
        }
    }

    private func toggle(_ interestId: String) {
        nativeHaptic(.selection)
        if let existingIndex = selectedInterests.firstIndex(of: interestId) {
            selectedInterests.remove(at: existingIndex)
            return
        }

        guard selectedInterests.count < 5 else {
            selectedInterests.removeFirst()
            selectedInterests.append(interestId)
            return
        }

        selectedInterests.append(interestId)
    }
}

private struct NativePreferenceSelectionCard: View {
    let card: NativePreferenceSwipeCard
    let cardWidth: CGFloat
    let isSelected: Bool
    let onTap: () -> Void

    private var cardHeight: CGFloat { cardWidth * 1.5 }

    var body: some View {
        Button(action: onTap) {
            ZStack(alignment: .topTrailing) {
                ZStack(alignment: .bottomLeading) {
                    RoundedRectangle(cornerRadius: 24, style: .continuous)
                        .fill(nativeSurfaceStrong)

                    if UIImage(named: card.imageAssetName) != nil {
                        Image(card.imageAssetName)
                            .resizable()
                            .scaledToFill()
                            .frame(width: cardWidth, height: cardHeight)
                            .clipped()
                    } else {
                        Rectangle()
                            .fill(Color.white.opacity(0.04))
                            .frame(width: cardWidth, height: cardHeight)
                    }

                    LinearGradient(
                        colors: [Color.black.opacity(0.08), Color.black.opacity(0.24), Color.black.opacity(0.84)],
                        startPoint: .top,
                        endPoint: .bottom
                    )

                    VStack(alignment: .leading, spacing: 0) {
                        HStack {
                            Image(systemName: card.symbol)
                                .font(nativeAppFont(size: 22, weight: .black))
                                .foregroundStyle(.white)
                                .shadow(color: .black.opacity(0.28), radius: 10, y: 4)
                            Spacer()
                        }
                        .padding(.top, 16)
                        .padding(.horizontal, 16)

                        Spacer(minLength: 0)

                        Text(card.title)
                            .font(nativeAppFont(size: 15, weight: .black))
                            .foregroundStyle(.white)
                            .multilineTextAlignment(.leading)
                            .lineLimit(2)
                            .frame(maxWidth: .infinity, alignment: .leading)
                            .padding(.horizontal, 16)
                            .padding(.bottom, 16)
                    }
                    .frame(width: cardWidth, height: cardHeight, alignment: .topLeading)
                }
                .frame(width: cardWidth, height: cardHeight)
                .clipShape(RoundedRectangle(cornerRadius: 24, style: .continuous))
                .overlay(
                    RoundedRectangle(cornerRadius: 24, style: .continuous)
                        .stroke(isSelected ? nativeAccent : Color.white.opacity(0.08), lineWidth: isSelected ? 2 : 1)
                )
                .overlay {
                    if nativePreferenceLayoutDebugMode {
                        RoundedRectangle(cornerRadius: 24, style: .continuous)
                            .stroke(Color.red.opacity(0.92), style: StrokeStyle(lineWidth: 1.5, dash: [7, 5]))
                            .allowsHitTesting(false)
                    }
                }
                .overlay(alignment: .bottomLeading) {
                    if nativePreferenceLayoutDebugMode {
                        GeometryReader { proxy in
                            NativePreferenceDebugBadge(
                                title: card.id,
                                value: "\(Int(proxy.size.width))x\(Int(proxy.size.height))"
                            )
                            .padding(10)
                            .allowsHitTesting(false)
                        }
                    }
                }

                ZStack {
                    Circle()
                        .fill(isSelected ? nativeAccent : Color.black.opacity(0.42))
                    Image(systemName: isSelected ? "checkmark" : "plus")
                        .font(nativeAppFont(size: 12, weight: .black))
                        .foregroundStyle(isSelected ? .black : .white.opacity(0.86))
                }
                .frame(width: 30, height: 30)
                .padding(12)
            }
            .frame(width: cardWidth, height: cardHeight, alignment: .topTrailing)
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
    }
}

private struct NativePreferenceDebugBadge: View {
    let title: String
    let value: String

    var body: some View {
        VStack(alignment: .leading, spacing: 2) {
            Text(title)
                .font(nativeAppFont(size: 9, weight: .black))
            Text(value)
                .font(nativeAppFont(size: 10, weight: .bold))
        }
        .foregroundStyle(.white)
        .padding(.horizontal, 8)
        .padding(.vertical, 6)
        .background(Color.red.opacity(0.82))
        .clipShape(RoundedRectangle(cornerRadius: 10, style: .continuous))
        .allowsHitTesting(false)
    }
}

private struct NativeMainTabView: View {
    @EnvironmentObject private var appState: NativeAppState
    @State private var isKeyboardVisible = false

    var body: some View {
        TabView(selection: $appState.activeTab) {
            NavigationView {
                NativeHomepageShellScreen()
            }
            .navigationViewStyle(.stack)
            .tabItem { Label("Home", systemImage: "house.fill") }
            .tag(NativeTab.discover)

            NavigationView {
                NativeDiaryScreen()
            }
            .navigationViewStyle(.stack)
            .tabItem { Label("Diary", systemImage: "book.closed.fill") }
            .tag(NativeTab.feed)

            NavigationView {
                NativeMainPlaceholderScreen(
                    title: "Add",
                    subtitle: "Start a new entry",
                    symbol: "plus"
                )
            }
            .navigationViewStyle(.stack)
            .tabItem { Label("Add", systemImage: "plus") }
            .tag(NativeTab.checkIn)

            NavigationView {
                NativeFeedScreen()
            }
            .navigationViewStyle(.stack)
            .tabItem { Label("Feed", systemImage: "rectangle.stack.fill") }
            .tag(NativeTab.chat)

            NavigationView {
                NativeProfileScreen()
            }
            .navigationViewStyle(.stack)
            .tabItem { Label("Profile", systemImage: "person.crop.circle.fill") }
            .tag(NativeTab.profile)
        }
        .tint(nativeAccent)
        .ignoresSafeArea(.keyboard, edges: .bottom)
        .safeAreaInset(edge: .bottom) {
            if appState.showFloatingTabBar && !isKeyboardVisible {
                NativeFloatingTabBar(activeTab: $appState.activeTab)
                    .ignoresSafeArea(.keyboard, edges: .bottom)
            }
        }
        .onAppear {
            UITabBar.appearance().isHidden = true
            Task {
                await appState.refreshChatUnreadCount()
                await appState.refreshNotificationUnreadCount()
            }
        }
        .onReceive(NotificationCenter.default.publisher(for: UIResponder.keyboardWillShowNotification)) { _ in
            isKeyboardVisible = true
        }
        .onReceive(NotificationCenter.default.publisher(for: UIResponder.keyboardWillHideNotification)) { _ in
            isKeyboardVisible = false
        }
        .onReceive(NotificationCenter.default.publisher(for: UIApplication.didBecomeActiveNotification)) { _ in
            Task {
                await appState.refreshChatUnreadCount()
                await appState.refreshNotificationUnreadCount()
            }
        }
        .task(id: appState.activeTab) {
            await appState.loadActiveTabIfNeeded()
        }
    }
}

private struct NativeDecisionHomeScreen: View {
    @EnvironmentObject private var appState: NativeAppState
    @State private var showSavedScreen = false
    @State private var showProfileSheet = false
    @State private var selectedCompanionId = nativeDecisionWithOptions[0].id
    @State private var selectedFeelingId = nativeDecisionFeelOptions[0].id
    @State private var selectedTempoId = nativeDecisionStateOptions[0].id
    @State private var selectedResultPlace: NativePlace?
    @State private var showsPostCheckInPicker = false

    private var selectedIntent: NativeDecisionIntent? {
        nativeDecisionIntentForSelection(
            withId: selectedCompanionId,
            feelId: selectedFeelingId,
            stateId: selectedTempoId
        )
    }

    private var visibleOptions: [NativeDecisionSessionOption] {
        (appState.decisionSession?.options ?? [])
            .filter { $0.isVisible && !$0.isSkipped && !$0.isSelected }
            .sorted { $0.rank < $1.rank }
    }

    private var selectedOption: NativeDecisionSessionOption? {
        appState.decisionSession?.options.first(where: \.isSelected)
    }

    private var fallbackOption: NativeDecisionSessionOption? {
        appState.decisionSession?.options.sorted { $0.rank < $1.rank }.first
    }

    private var hasCompletedSession: Bool {
        appState.decisionSession != nil && !appState.hasActiveDecisionDeck
    }

    private var latestTodayMoment: NativeMoment? {
        return appState.myMoments
            .filter { moment in
                nativeIsMomentToday(visitedAtIso: moment.visitedAtIso, visitedDate: moment.visitedDate)
            }
            .sorted {
                let lhs = NativeAppState.feedSortDate(iso: $0.visitedAtIso ?? $0.visitedDate, label: $0.visitedDate) ?? .distantPast
                let rhs = NativeAppState.feedSortDate(iso: $1.visitedAtIso ?? $1.visitedDate, label: $1.visitedDate) ?? .distantPast
                return lhs > rhs
            }
            .first
    }

    private var hasCheckedInToday: Bool {
        latestTodayMoment != nil
    }

    private var postCheckInDebugLines: [String] {
        let latest = appState.myMoments
            .sorted {
                let lhs = NativeAppState.feedSortDate(iso: $0.visitedAtIso ?? $0.visitedDate, label: $0.visitedDate) ?? .distantPast
                let rhs = NativeAppState.feedSortDate(iso: $1.visitedAtIso ?? $1.visitedDate, label: $1.visitedDate) ?? .distantPast
                return lhs > rhs
            }
            .first

        return [
            "myMoments=\(appState.myMoments.count)",
            "hasCheckedInToday=\(hasCheckedInToday)",
            "latestTodayMoment=\(latestTodayMoment?.id ?? "nil")",
            "latestMoment=\(latest?.id ?? "nil")",
            "latestVisitedDate=\(latest?.visitedDate ?? "nil")",
            "latestVisitedAtIso=\(latest?.visitedAtIso ?? "nil")",
            "latestIsToday=\(latest.map { nativeIsMomentToday(visitedAtIso: $0.visitedAtIso, visitedDate: $0.visitedDate) } ?? false)",
            "localDay=\(nativeLocalDayString())",
            "hasCompletedSession=\(hasCompletedSession)",
            "hasActiveDecisionDeck=\(appState.hasActiveDecisionDeck)"
        ]
    }

    private var isPreviewMessage: Bool {
        (appState.decisionErrorMessage ?? "").hasPrefix("Preview mode:")
    }

    var body: some View {
        GeometryReader { geometry in
            ZStack {
                Color.black
                LinearGradient(
                    colors: [
                        nativeAccent.opacity(0.16),
                        Color.clear,
                        nativeAccent.opacity(0.06),
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )

                Group {
                    if appState.hasActiveDecisionDeck {
                        NativeDecisionActiveSessionScreen(
                            intent: selectedIntent,
                            options: visibleOptions,
                            isLoading: appState.isDecisionLoading,
                            cityLabel: appState.effectiveDecisionLocation.label,
                            geometry: geometry,
                            onSwipe: { option, direction in
                                Task { await appState.swipeDecisionOption(option, direction: direction) }
                            }
                        )
                    } else {
                        VStack(spacing: 0) {
                            NativeDecisionHomeHeader(
                                cityLabel: appState.effectiveDecisionLocation.label,
                                onLeadingTap: {
                                    guard appState.currentUser != nil else {
                                        nativeHaptic(.warning)
                                        appState.presentAuthGate(reason: "Log in to view your saved places and collections.")
                                        return
                                    }
                                    nativeHaptic(.selection)
                                    showSavedScreen = true
                                },
                                onProfileTap: {
                                    nativeHaptic(.selection)
                                    showProfileSheet = true
                                }
                            )
                            .padding(.top, geometry.safeAreaInsets.top + 6)
                            .padding(.horizontal, 18)

                            Color.clear
                                .frame(height: 28)

                            if hasCompletedSession && (!hasCheckedInToday || showsPostCheckInPicker) {
                                NativeDecisionSessionResultView(
                                    selectedOption: selectedOption,
                                    fallbackOption: fallbackOption,
                                    onOpenPlace: { option in
                                        selectedResultPlace = nativeDecisionSessionPlaceAsPlace(option.place)
                                    },
                                    onGoNow: { option in
                                        openDecisionMap(for: option.place)
                                    },
                                    onCheckIn: { option in
                                        appState.trackAnalytics(
                                            .clickCheckin,
                                            properties: appState.decisionOptionAnalyticsProperties(
                                                option,
                                                source: NativeAnalyticsSource.homepagePickLocked
                                            )
                                        )
                                        appState.presentCheckInFlow(prefilledPlace: nativeDecisionSessionPlaceAsPlace(option.place))
                                    },
                                    onManualCheckInElsewhere: {
                                        appState.trackAnalytics(
                                            .clickCheckin,
                                            properties: [
                                                "source": NativeAnalyticsSource.homepagePickLocked,
                                            ]
                                        )
                                        appState.presentCheckInFlow(prefilledPlace: nil)
                                    },
                                    onReset: {
                                        nativeHaptic(.medium)
                                        appState.clearDecisionSessionState()
                                        showsPostCheckInPicker = false
                                    },
                                    onBackToTodaysDrop: hasCheckedInToday ? {
                                        showsPostCheckInPicker = false
                                        appState.clearDecisionSessionState()
                                    } : nil
                                )
                                .padding(.horizontal, 18)
                            } else if let latestTodayMoment, !showsPostCheckInPicker {
                                VStack(spacing: 12) {
                                    if nativeDecisionPostCheckInDebugMode {
                                        NativeDecisionLayoutDebugBadge(
                                            title: "POST CHECK-IN DEBUG",
                                            lines: postCheckInDebugLines
                                        )
                                    }

                                    NativeDecisionPostCheckInHomeView(
                                        moment: latestTodayMoment,
                                        onOpenPlace: {
                                            selectedResultPlace = nativePlaceApplyingMoment(latestTodayMoment)
                                        },
                                        onPickAnotherVibe: {
                                            nativeHaptic(.medium)
                                            showsPostCheckInPicker = true
                                        },
                                        onOpenTodayFeed: {
                                            nativeHaptic(.selection)
                                            appState.activeTab = .feed
                                        },
                                        onCheckInAgain: {
                                            nativeHaptic(.selection)
                                            appState.trackAnalytics(
                                                .clickCheckin,
                                                properties: [
                                                    "source": NativeAnalyticsSource.homepagePickLocked,
                                                ]
                                            )
                                            appState.presentCheckInFlow(prefilledPlace: nil)
                                        }
                                    )
                                }
                                .padding(.horizontal, 18)
                            } else {
                                VStack(spacing: 14) {
                                    if nativeDecisionPostCheckInDebugMode {
                                        NativeDecisionLayoutDebugBadge(
                                            title: "HOME DEBUG",
                                            lines: postCheckInDebugLines
                                        )
                                    }

                                    VStack(spacing: 10) {
                                        Text("Where we going?")
                                            .font(nativeAppFont(size: 32, weight: .black))
                                            .foregroundStyle(.white)
                                            .multilineTextAlignment(.center)
                                    }
                                    .padding(.top, 32)
                                    .overlay {
                                        if nativeDecisionLayoutDebugMode {
                                            RoundedRectangle(cornerRadius: 18, style: .continuous)
                                                .stroke(Color.cyan.opacity(0.9), style: StrokeStyle(lineWidth: 1.5, dash: [6, 4]))
                                        }
                                    }
                                    .overlay(alignment: .topLeading) {
                                        if nativeDecisionLayoutDebugMode {
                                            NativeDecisionLayoutDebugBadge(
                                                title: "TITLE",
                                                lines: [
                                                    "title stack=10",
                                                    "content top anchor"
                                                ]
                                            )
                                            .padding(6)
                                        }
                                    }

                                    if hasCheckedInToday {
                                        Button {
                                            nativeHaptic(.selection)
                                            showsPostCheckInPicker = false
                                        } label: {
                                            HStack(spacing: 8) {
                                                Image(systemName: "arrow.left")
                                                    .font(nativeAppFont(size: 12, weight: .black))
                                                Text("Back to Today’s drop")
                                                    .font(nativeAppFont(size: 14, weight: .bold))
                                            }
                                            .foregroundStyle(.white)
                                            .padding(.horizontal, 14)
                                            .padding(.vertical, 12)
                                            .background(nativeSurface)
                                            .overlay(
                                                Capsule()
                                                    .stroke(nativeBorder, lineWidth: 1)
                                            )
                                            .clipShape(Capsule())
                                        }
                                        .buttonStyle(.plain)
                                    }

                                    NativeDecisionMoodStrip(
                                        selectedCompanionId: $selectedCompanionId,
                                        selectedFeelingId: $selectedFeelingId,
                                        selectedTempoId: $selectedTempoId
                                    )
                                    .padding(.top, 24)

                                    if let message = appState.decisionErrorMessage, !message.isEmpty {
                                        if isPreviewMessage {
                                            NativeDecisionPreviewPill(message: message.replacingOccurrences(of: "Preview mode: ", with: ""))
                                        } else {
                                            Text(message)
                                                .font(nativeAppFont(size: 12, weight: .semibold))
                                                .foregroundStyle(Color(red: 1, green: 0.55, blue: 0.55))
                                                .multilineTextAlignment(.center)
                                                .padding(.horizontal, 10)
                                        }
                                    }

                                    Button {
                                        nativeHaptic(.medium)
                                        guard appState.canGenerateDecisionWithCurrentLocation else {
                                            appState.clearDecisionSessionState()
                                            appState.showDecisionLocationPermissionSheet = true
                                            return
                                        }
                                        appState.trackAnalytics(
                                            .generateRecommendation,
                                            properties: appState.decisionMoodAnalyticsProperties(
                                                withValue: selectedCompanionId,
                                                feelValue: selectedFeelingId,
                                                stateValue: selectedTempoId,
                                                source: hasCheckedInToday ? NativeAnalyticsSource.homepagePickLocked : NativeAnalyticsSource.homepageStandby
                                            )
                                        )
                                        Task {
                                            await appState.generateDecisionSession(
                                                withValue: selectedCompanionId,
                                                feelValue: selectedFeelingId,
                                                stateValue: selectedTempoId
                                            )
                                        }
                                    } label: {
                                        HStack(spacing: 10) {
                                            Image(systemName: "bolt.fill")
                                                .font(nativeAppFont(size: 15, weight: .black))
                                            Text("Pick for Me")
                                                .font(nativeAppFont(size: 16, weight: .bold))
                                        }
                                        .foregroundStyle(.black)
                                        .frame(maxWidth: .infinity)
                                        .padding(.vertical, 16)
                                        .background(nativeAccent)
                                        .clipShape(Capsule())
                                    }
                                    .buttonStyle(.plain)
                                    .disabled(appState.isDecisionLoading)
                                    .opacity(appState.isDecisionLoading ? 0.68 : 1)
                                    .padding(.top, 24)

                                    NativeDecisionDailyTimerPill()

                                    Button {
                                        nativeHaptic(.selection)
                                        appState.trackAnalytics(
                                            .clickCheckin,
                                            properties: [
                                                "source": NativeAnalyticsSource.homepageStandby,
                                            ]
                                        )
                                        appState.presentCheckInFlow(prefilledPlace: nil)
                                    } label: {
                                        HStack(spacing: 10) {
                                            Image(systemName: "mappin.and.ellipse")
                                                .font(nativeAppFont(size: 15, weight: .black))
                                            Text("Already somewhere?")
                                                .font(nativeAppFont(size: 16, weight: .bold))
                                        }
                                        .foregroundStyle(.white)
                                        .frame(maxWidth: .infinity)
                                        .padding(.vertical, 16)
                                        .background(nativeSurface)
                                        .overlay(
                                            Capsule()
                                                .stroke(nativeBorder, lineWidth: 1)
                                        )
                                        .clipShape(Capsule())
                                    }
                                    .buttonStyle(.plain)

                                    Spacer(minLength: 12)
                                }
                                .padding(.horizontal, 18)
                                .overlay(alignment: .topLeading) {
                                    if nativeDecisionLayoutDebugMode {
                                        NativeDecisionLayoutDebugBadge(
                                            title: "HOME",
                                            lines: [
                                                "header gap=28",
                                                "stack spacing=14",
                                                "title stack=10",
                                                "outer pad=18",
                                                "bottom spacer=12"
                                            ]
                                        )
                                        .padding(8)
                                    }
                                }
                                .overlay {
                                    if nativeDecisionLayoutDebugMode {
                                        RoundedRectangle(cornerRadius: 26, style: .continuous)
                                            .stroke(Color.red.opacity(0.82), style: StrokeStyle(lineWidth: 1.5, dash: [8, 6]))
                                    }
                                }
                            }

                            Spacer(minLength: max(8, geometry.safeAreaInsets.bottom + 8))
                        }
                        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
                    }
                }
            }
            .ignoresSafeArea()
        }
        .background(
            NavigationLink(
                destination: selectedResultPlace.map {
                    NativePlaceDetailScreen(initialPlace: $0, source: NativeAnalyticsSource.discovery)
                },
                isActive: Binding(
                    get: { selectedResultPlace != nil },
                    set: { isActive in
                        if !isActive {
                            selectedResultPlace = nil
                        }
                    }
                )
            ) {
                EmptyView()
            }
            .hidden()
        )
        .navigationBarHidden(true)
        .fullScreenCover(isPresented: $showSavedScreen) {
            NavigationView {
                NativeSavedScreen(showsDismissButton: true)
                    .environmentObject(appState)
            }
            .navigationViewStyle(.stack)
        }
        .sheet(isPresented: $showProfileSheet) {
            NavigationView {
                NativeProfileScreen()
            }
            .navigationViewStyle(.stack)
            .environmentObject(appState)
        }
        .task {
            await appState.loadDecisionCatalogIfNeeded()
            selectedCompanionId = appState.selectedDecisionWithValue
            selectedFeelingId = appState.selectedDecisionFeelValue
            selectedTempoId = appState.selectedDecisionStateValue
        }
        .onChange(of: selectedCompanionId) { newValue in
            appState.selectedDecisionWithValue = newValue
            appState.selectedDecisionIntentId = nativeDecisionDerivedIntentId(
                withId: newValue,
                feelId: selectedFeelingId,
                stateId: selectedTempoId
            )
        }
        .onChange(of: selectedFeelingId) { newValue in
            appState.selectedDecisionFeelValue = newValue
            appState.selectedDecisionIntentId = nativeDecisionDerivedIntentId(
                withId: selectedCompanionId,
                feelId: newValue,
                stateId: selectedTempoId
            )
        }
        .onChange(of: selectedTempoId) { newValue in
            appState.selectedDecisionStateValue = newValue
            appState.selectedDecisionIntentId = nativeDecisionDerivedIntentId(
                withId: selectedCompanionId,
                feelId: selectedFeelingId,
                stateId: newValue
            )
        }
        .onChange(of: appState.myMoments.count) { _ in
            if latestTodayMoment != nil {
                showsPostCheckInPicker = false
            }
        }
    }

    private func openDecisionMap(for place: NativeDecisionSessionPlace) {
        guard let url = nativeDecisionDirectionsURL(for: place) else { return }
        UIApplication.shared.open(url)
    }
}

private struct NativeProfilePlaceholderScreen: View {
    @EnvironmentObject private var appState: NativeAppState

    var body: some View {
        ScrollView(showsIndicators: false) {
            VStack(alignment: .leading, spacing: 18) {
                if let user = appState.currentUser {
                    NativeScreenHeader(
                        title: user.displayName ?? user.username,
                        subtitle: "@\(user.username)"
                    )
                } else {
                    NativeScreenHeader(
                        title: "Profile",
                        subtitle: "Not signed in"
                    )
                }

                NativeSurfaceCard {
                    VStack(alignment: .leading, spacing: 10) {
                        Text("Profile debug mode")
                            .font(nativeAppFont(size: 18, weight: .black))
                            .foregroundStyle(.white)
                        Text("This placeholder bypasses the native profile screen and skips auto profile refresh so we can isolate the crash source.")
                            .font(nativeAppFont(size: 15, weight: .medium))
                            .foregroundStyle(.white.opacity(0.68))
                            .fixedSize(horizontal: false, vertical: true)
                    }
                }
            }
            .padding(.horizontal, 20)
            .padding(.top, 16)
            .padding(.bottom, 28)
        }
        .background(Color.black.ignoresSafeArea())
        .navigationTitle("Profile")
        .navigationBarTitleDisplayMode(.inline)
        .onAppear {
            nativeLogger.log("NativeProfilePlaceholderScreen appear")
        }
    }
}

private struct NativeSavedPlaceholderScreen: View {
    @EnvironmentObject private var appState: NativeAppState

    var body: some View {
        ScrollView(showsIndicators: false) {
            VStack(alignment: .leading, spacing: 18) {
                NativeScreenHeader(
                    title: "Saved places",
                    subtitle: "Placeholder screen"
                )

                NativeSurfaceCard {
                    VStack(alignment: .leading, spacing: 10) {
                        Text("Saved debug mode")
                            .font(nativeAppFont(size: 18, weight: .black))
                            .foregroundStyle(.white)
                        Text("This placeholder bypasses the native saved screen and skips auto profile refresh so we can isolate the crash source.")
                            .font(nativeAppFont(size: 15, weight: .medium))
                            .foregroundStyle(.white.opacity(0.68))
                            .fixedSize(horizontal: false, vertical: true)
                    }
                }

                if !appState.savedPlaces.isEmpty {
                    NativeSurfaceCard {
                        VStack(alignment: .leading, spacing: 10) {
                            Text("Saved")
                                .font(nativeAppFont(size: 11, weight: .black))
                                .foregroundStyle(nativeAccent.opacity(0.92))
                                .textCase(.uppercase)
                            Text("\(appState.savedPlaces.count) places ready")
                                .font(nativeAppFont(size: 18, weight: .black))
                                .foregroundStyle(.white)
                        }
                    }
                }

                if !appState.collections.isEmpty {
                    NativeSurfaceCard {
                        VStack(alignment: .leading, spacing: 10) {
                            Text("Collections")
                                .font(nativeAppFont(size: 11, weight: .black))
                                .foregroundStyle(nativeAccent.opacity(0.92))
                                .textCase(.uppercase)
                            Text("\(appState.collections.count) lists ready")
                                .font(nativeAppFont(size: 18, weight: .black))
                                .foregroundStyle(.white)
                        }
                    }
                }
            }
            .padding(.horizontal, 20)
            .padding(.top, 16)
            .padding(.bottom, 28)
        }
        .background(Color.black.ignoresSafeArea())
        .navigationTitle("Saved places")
        .navigationBarTitleDisplayMode(.inline)
        .onAppear {
            nativeLogger.log("NativeSavedPlaceholderScreen appear saved=\(appState.savedPlaces.count, privacy: .public) collections=\(appState.collections.count, privacy: .public)")
        }
    }
}

private struct NativeFloatingTabBar: View {
    @EnvironmentObject private var appState: NativeAppState
    @Binding var activeTab: NativeTab

    private let tabs: [(tab: NativeTab, icon: String, title: String, isPrimary: Bool)] = [
        (.discover, "house.fill", "Home", false),
        (.feed, "book.closed.fill", "Diary", false),
        (.checkIn, "camera.fill", "Add", true),
        (.chat, "rectangle.stack.fill", "Feed", false),
        (.profile, "person.crop.circle.fill", "Profile", false),
    ]

    var body: some View {
        HStack(alignment: .bottom, spacing: 8) {
            ForEach(tabs, id: \.tab) { item in
                navItem(for: item)
            }
        }
        .padding(.horizontal, 12)
        .padding(.top, 10)
        .padding(.bottom, 12)
        .background(
            RoundedRectangle(cornerRadius: 28, style: .continuous)
                .fill(Color(red: 16 / 255, green: 15 / 255, blue: 13 / 255).opacity(0.96))
                .overlay(
                    RoundedRectangle(cornerRadius: 28, style: .continuous)
                        .stroke(Color.white.opacity(0.08), lineWidth: 1)
                )
        )
        .padding(.horizontal, 16)
        .padding(.bottom, 8)
    }

    @ViewBuilder
    private func navItem(for item: (tab: NativeTab, icon: String, title: String, isPrimary: Bool)) -> some View {
        Button {
            select(tab: item.tab)
        } label: {
            if item.isPrimary {
                VStack(spacing: 4) {
                    Image(systemName: item.icon)
                        .font(nativeAppFont(size: 22, weight: .black))
                        .foregroundStyle(.black)
                        .frame(width: 60, height: 60)
                        .background(nativeAccent)
                        .clipShape(Circle())
                        .overlay(
                            Circle()
                                .stroke(Color.black.opacity(0.18), lineWidth: 1)
                        )
                        .shadow(color: nativeAccent.opacity(0.28), radius: 16, x: 0, y: 8)
                        .offset(y: -18)
                        .padding(.bottom, -18)

                    Text(item.title)
                        .font(nativeAppFont(size: 11, weight: .black))
                        .foregroundStyle(activeTab == item.tab ? .white : .white.opacity(0.62))
                }
                .frame(maxWidth: .infinity, minHeight: 56, alignment: .bottom)
            } else {
                VStack(spacing: 6) {
                    Image(systemName: item.icon)
                        .font(nativeAppFont(size: 18, weight: .black))
                        .foregroundStyle(activeTab == item.tab ? .white : .white.opacity(0.62))

                    Text(item.title)
                        .font(nativeAppFont(size: 11, weight: .bold))
                        .foregroundStyle(activeTab == item.tab ? .white : .white.opacity(0.62))
                }
                .frame(maxWidth: .infinity, minHeight: 56)
                .background(
                    RoundedRectangle(cornerRadius: 22, style: .continuous)
                        .fill(activeTab == item.tab ? Color.white.opacity(0.06) : Color.clear)
                )
            }
        }
        .buttonStyle(.plain)
    }

    private func select(tab: NativeTab) {
        if tab == .checkIn {
            nativeHaptic(.selection)
            appState.presentCheckInFlow()
            return
        }
        guard activeTab != tab else {
            nativeHaptic(.light)
            return
        }
        nativeHaptic(.selection)
        activeTab = tab
    }
}

