private struct NativeChatInboxScreen: View {
    @Environment(\.dismiss) private var dismiss
    @EnvironmentObject private var appState: NativeAppState
    let showsDismissButton: Bool
    @State private var conversations: [NativeChatConversationSummary] = []
    @State private var isLoading = false
    @State private var errorMessage: String?
    @State private var selectedConversation: NativeChatConversationSummary?
    @State private var showChatRequests = false

    init(showsDismissButton: Bool = true) {
        self.showsDismissButton = showsDismissButton
    }

    var body: some View {
        ZStack {
            Color.black.ignoresSafeArea()

            VStack(spacing: 0) {
                ZStack {
                    HStack {
                        if showsDismissButton {
                            Button {
                                dismiss()
                            } label: {
                                Image(systemName: "xmark")
                                    .font(nativeAppFont(size: 12, weight: .black))
                                    .foregroundStyle(.white)
                                    .frame(width: 32, height: 32)
                                    .background(Color.white.opacity(0.08))
                                    .clipShape(Circle())
                            }
                            .buttonStyle(.plain)
                        } else {
                            Color.clear
                                .frame(width: 32, height: 32)
                        }
                        Spacer()
                    }

                    Text("Chats")
                        .font(nativePixelAccentFont(size: 12))
                        .foregroundStyle(.white)
                }
                .padding(.horizontal, 20)
                .padding(.top, 18)
                .padding(.bottom, 14)

                if let errorMessage {
                    NativeInlineError(message: errorMessage)
                        .padding(.horizontal, 20)
                        .padding(.bottom, 12)
                }

                if isLoading {
                    Spacer()
                    ProgressView()
                        .tint(nativeAccent)
                    Spacer()
                } else if conversations.isEmpty {
                    Spacer()
                    VStack(spacing: 12) {
                        Image(systemName: "message")
                            .font(nativeAppFont(size: 28, weight: .black))
                            .foregroundStyle(.white.opacity(0.5))
                        Text("No chats yet.")
                            .font(nativeAppFont(size: 18, weight: .black))
                            .foregroundStyle(.white)
                        Text("Comments on moments and messages from friends will show up here.")
                            .font(nativeAppFont(size: 14, weight: .medium))
                            .foregroundStyle(.white.opacity(0.58))
                            .multilineTextAlignment(.center)
                            .padding(.horizontal, 32)
                    }
                    Spacer()
                } else {
                    ScrollView(showsIndicators: false) {
                        VStack(spacing: 10) {
                            if !requestConversations.isEmpty {
                                Button {
                                    showChatRequests = true
                                } label: {
                                    NativeChatRequestFolderRow(
                                        requestCount: requestConversations.count,
                                        unreadCount: requestConversations.reduce(0) { $0 + max(0, $1.unreadCount) }
                                    )
                                }
                                .buttonStyle(.plain)
                            }

                            ForEach(mainConversations) { conversation in
                                Button {
                                    selectedConversation = conversation
                                } label: {
                                    NativeChatConversationRow(conversation: conversation)
                                }
                                .buttonStyle(.plain)
                            }
                        }
                        .padding(20)
                    }
                }
            }
        }
        .task {
            await loadConversations()
        }
        .onAppear {
            appState.trackAnalytics(
                .viewChatList,
                properties: [
                    "source": NativeAnalyticsSource.chatList,
                ]
            )
        }
        .sheet(item: $selectedConversation) { conversation in
            NavigationView {
                NativeChatConversationScreen(conversationSummary: conversation)
                    .environmentObject(appState)
            }
            .navigationViewStyle(.stack)
        }
        .sheet(isPresented: $showChatRequests) {
            NavigationView {
                NativeChatRequestsScreen(
                    conversations: requestConversations,
                    onSelectConversation: { conversation in
                        selectedConversation = conversation
                        showChatRequests = false
                    }
                )
                .environmentObject(appState)
            }
            .navigationViewStyle(.stack)
        }
    }

    private var requestConversations: [NativeChatConversationSummary] {
        conversations.filter(\.isRequest)
    }

    private var mainConversations: [NativeChatConversationSummary] {
        conversations.filter { !$0.isRequest }
    }

    private func loadConversations() async {
        guard !isLoading else { return }
        isLoading = true
        defer { isLoading = false }

        do {
            conversations = try await appState.fetchChatConversations()
        } catch {
            errorMessage = "Could not load chats right now."
        }
    }
}

