private struct NativeChatConversationRow: View {
    let conversation: NativeChatConversationSummary

    var body: some View {
        HStack(spacing: 12) {
            NativeAvatarCircle(
                url: conversation.otherUser?.avatarUrl,
                fallbackText: conversation.otherUser?.displayName ?? conversation.otherUser?.username ?? "Chat",
                size: 52,
                fontSize: 18
            )

            VStack(alignment: .leading, spacing: 5) {
                HStack {
                    Text(conversation.otherUser?.displayName ?? conversation.otherUser?.username ?? "Conversation")
                        .font(nativeAppFont(size: 15, weight: .black))
                        .foregroundStyle(.white)
                        .lineLimit(1)
                    Spacer(minLength: 10)
                    Text(NativeAppState.relativeLabel(from: conversation.lastMessageAt))
                        .font(nativeAppFont(size: 11, weight: .bold))
                        .foregroundStyle(.white.opacity(0.42))
                }

                Text(chatPreviewText)
                    .font(nativeAppFont(size: 13, weight: .medium))
                    .foregroundStyle(.white.opacity(0.62))
                    .lineLimit(2)
            }

            if conversation.unreadCount > 0 {
                Text("\(conversation.unreadCount)")
                    .font(nativeAppFont(size: 11, weight: .black))
                    .foregroundStyle(.black)
                    .padding(.horizontal, 8)
                    .padding(.vertical, 6)
                    .background(nativeAccent)
                    .clipShape(Capsule())
            }
        }
        .padding(14)
        .background(nativeSurface)
        .clipShape(RoundedRectangle(cornerRadius: 20, style: .continuous))
    }

    private var chatPreviewText: String {
        if let body = conversation.lastMessage?.body.trimmingCharacters(in: .whitespacesAndNewlines), !body.isEmpty {
            return body
        }
        if let preview = conversation.lastMessage?.attachments.first?.previewText, !preview.isEmpty {
            return preview
        }
        return "Open conversation"
    }
}

private struct NativeChatConversationScreen: View {
    @Environment(\.dismiss) private var dismiss
    @EnvironmentObject private var appState: NativeAppState
    let conversationSummary: NativeChatConversationSummary

    @State private var conversation: NativeChatConversationDetail?
    @State private var messages: [NativeChatMessage] = []
    @State private var draft = ""
    @State private var isLoading = false
    @State private var isSending = false
    @State private var errorMessage: String?
    @State private var selectedProfileTraveler: NativeTravelerSummary?

    var body: some View {
        ZStack {
            Color.black.ignoresSafeArea()

            VStack(spacing: 0) {
                HStack {
                    Button {
                        dismiss()
                    } label: {
                        Image(systemName: "chevron.left")
                            .font(nativeAppFont(size: 14, weight: .black))
                            .foregroundStyle(.white)
                            .frame(width: 32, height: 32)
                            .background(Color.white.opacity(0.08))
                            .clipShape(Circle())
                    }
                    .buttonStyle(.plain)

                    Button {
                        guard let traveler = otherUserTraveler else { return }
                        selectedProfileTraveler = traveler
                    } label: {
                        HStack(spacing: 10) {
                            NativeAvatarCircle(
                                url: conversation?.otherUser?.avatarUrl ?? conversationSummary.otherUser?.avatarUrl,
                                fallbackText: conversation?.otherUser?.displayName ?? conversationSummary.otherUser?.displayName ?? conversationSummary.otherUser?.username ?? "Chat",
                                size: 34,
                                fontSize: 13
                            )

                            Text(conversation?.otherUser?.displayName ?? conversationSummary.otherUser?.displayName ?? conversationSummary.otherUser?.username ?? "Chat")
                                .font(nativeAppFont(size: 18, weight: .black))
                                .foregroundStyle(.white)
                        }
                    }
                    .buttonStyle(.plain)
                    .disabled(otherUserTraveler == nil)

                    Spacer()
                }
                .padding(.horizontal, 20)
                .padding(.top, 18)
                .padding(.bottom, 14)

                if let errorMessage {
                    NativeInlineError(message: errorMessage)
                        .padding(.horizontal, 20)
                        .padding(.bottom, 10)
                }

                if isLoading {
                    Spacer()
                    ProgressView()
                        .tint(nativeAccent)
                    Spacer()
                } else {
                    ScrollViewReader { proxy in
                        ScrollView(showsIndicators: false) {
                            VStack(spacing: 10) {
                                ForEach(messages) { message in
                                    NativeChatBubble(
                                        message: message,
                                        isMine: message.sender.id == appState.currentUser?.id
                                    )
                                    .id(message.id)
                                }
                            }
                            .padding(.horizontal, 20)
                            .padding(.bottom, 14)
                        }
                        .onChange(of: messages.count) { _ in
                            guard let lastId = messages.last?.id else { return }
                            withAnimation(.easeOut(duration: 0.2)) {
                                proxy.scrollTo(lastId, anchor: .bottom)
                            }
                        }
                    }

                    HStack(alignment: .bottom, spacing: 10) {
                        nativeChatDraftField

                        Button {
                            Task { await sendMessage() }
                        } label: {
                            if isSending {
                                ProgressView()
                                    .tint(.black)
                                    .frame(width: 48, height: 48)
                            } else {
                                Image(systemName: "arrow.up")
                                    .font(nativeAppFont(size: 16, weight: .black))
                                    .foregroundStyle(.black)
                                    .frame(width: 48, height: 48)
                            }
                        }
                        .background(nativeAccent)
                        .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                        .buttonStyle(.plain)
                        .disabled(isSending || draft.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                    }
                    .padding(.horizontal, 20)
                    .padding(.top, 10)
                    .padding(.bottom, 20)
                }
            }
        }
        .task {
            await loadConversation()
        }
        .sheet(item: $selectedProfileTraveler) { traveler in
            NavigationView {
                NativeTravelerProfileScreen(initialTraveler: traveler)
                    .environmentObject(appState)
            }
            .navigationViewStyle(.stack)
        }
    }

    private var otherUserTraveler: NativeTravelerSummary? {
        let user = conversation?.otherUser ?? conversationSummary.otherUser
        guard let user else { return nil }
        return NativeTravelerSummary(
            id: user.id,
            username: user.username,
            displayName: user.displayName,
            avatar: user.avatarUrl,
            bio: nil,
            descriptor: nil,
            matchScore: nil,
            followersCount: nil,
            followingCount: nil,
            recentSavedPlaces: nil,
            recentCollections: nil,
            travelHistory: [],
            visitedPlacesCount: nil,
            savedPlacesCount: nil,
            collectionsCount: nil
        )
    }

    private func loadConversation() async {
        guard !isLoading else { return }
        isLoading = true
        defer { isLoading = false }

        do {
            let response = try await appState.fetchChatConversation(id: conversationSummary.id)
            conversation = response.conversation
            messages = response.messages
            try? await appState.markChatConversationRead(id: conversationSummary.id)
        } catch {
            errorMessage = "Could not load this chat right now."
        }
    }

    private func sendMessage() async {
        let trimmed = draft.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return }

        isSending = true
        defer { isSending = false }

        do {
            let message = try await appState.sendChatMessage(conversationId: conversationSummary.id, body: trimmed)
            draft = ""
            messages.append(message)
        } catch {
            errorMessage = "Could not send your message right now."
        }
    }

    @ViewBuilder
    private var nativeChatDraftField: some View {
        if #available(iOS 16.0, *) {
            TextField("Send a message", text: $draft, axis: .vertical)
                .font(nativeAppFont(size: 15, weight: .medium))
                .foregroundStyle(.white)
                .padding(.horizontal, 14)
                .padding(.vertical, 12)
                .background(nativeSurface)
                .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
        } else {
            TextField("Send a message", text: $draft)
                .font(nativeAppFont(size: 15, weight: .medium))
                .foregroundColor(.white)
                .padding(.horizontal, 14)
                .padding(.vertical, 12)
                .background(nativeSurface)
                .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
        }
    }
}

private struct NativeChatBubble: View {
    let message: NativeChatMessage
    let isMine: Bool

    private var myBubbleColor: Color {
        Color.white.opacity(0.12)
    }

    var body: some View {
        HStack(alignment: .bottom, spacing: 10) {
            if isMine { Spacer(minLength: 36) }

            if !isMine {
                NativeAvatarCircle(
                    url: message.sender.avatarUrl,
                    fallbackText: message.sender.displayName ?? message.sender.username,
                    size: 28,
                    fontSize: 11
                )
            }

            VStack(alignment: .leading, spacing: 8) {
                if let attachment = message.attachments.first {
                    NativeChatAttachmentCard(attachment: attachment)
                }

                if !message.body.isEmpty {
                    Text(message.body)
                        .font(nativeAppFont(size: 15, weight: .medium))
                        .foregroundStyle(.white)
                        .fixedSize(horizontal: false, vertical: true)
                }

                Text(NativeAppState.relativeLabel(from: message.createdAt))
                    .font(nativeAppFont(size: 11, weight: .bold))
                    .foregroundStyle(.white.opacity(0.45))
            }
            .padding(14)
            .background(isMine ? myBubbleColor : nativeSurface)
            .clipShape(RoundedRectangle(cornerRadius: 20, style: .continuous))

            if !isMine { Spacer(minLength: 36) }
        }
    }
}

private struct NativeChatAttachmentCard: View {
    let attachment: NativeChatAttachment

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            if let moment = attachment.moment {
                HStack(spacing: 10) {
                    NativeRemoteImage(url: moment.place.image)
                        .frame(width: 48, height: 48)
                        .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))

                    VStack(alignment: .leading, spacing: 3) {
                        Text(moment.place.name)
                            .font(nativeAppFont(size: 13, weight: .black))
                            .foregroundStyle(.white)
                            .lineLimit(1)
                        Text(moment.place.location)
                            .font(nativeAppFont(size: 12, weight: .medium))
                            .foregroundStyle(.white.opacity(0.58))
                            .lineLimit(1)
                    }
                }
            }

            if let previewText = attachment.previewText, !previewText.isEmpty {
                Text(previewText)
                    .font(nativeAppFont(size: 12, weight: .bold))
                    .foregroundStyle(.white.opacity(0.7))
            }
        }
        .padding(10)
        .background(Color.white.opacity(0.08))
        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
    }
}

