private struct NativeDecisionWheelColumn: View {
    let title: String
    let options: [NativeDecisionPickerOption]
    @Binding var selection: String

    var body: some View {
        VStack(spacing: 10) {
            Text(title)
                .font(nativePixelAccentFont(size: 8))
                .foregroundStyle(.white.opacity(0.4))

            ZStack {
                RoundedRectangle(cornerRadius: 28, style: .continuous)
                    .fill(.ultraThinMaterial)
                    .overlay(
                        RoundedRectangle(cornerRadius: 28, style: .continuous)
                            .fill(Color.white.opacity(0.04))
                    )
                    .overlay(
                        RoundedRectangle(cornerRadius: 28, style: .continuous)
                            .stroke(Color.white.opacity(0.12), lineWidth: 1)
                    )

                VStack(spacing: 0) {
                    LinearGradient(
                        colors: [Color.black.opacity(0.82), Color.black.opacity(0.0)],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                    .frame(height: 42)
                    .allowsHitTesting(false)

                    Spacer(minLength: 0)

                    LinearGradient(
                        colors: [Color.black.opacity(0.0), Color.black.opacity(0.82)],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                    .frame(height: 42)
                    .allowsHitTesting(false)
                }
                .clipShape(RoundedRectangle(cornerRadius: 28, style: .continuous))

                Picker(title, selection: $selection) {
                    ForEach(options) { option in
                        Text(option.title)
                        .font(nativeAppFont(size: 18, weight: .black))
                        .foregroundStyle(.white)
                        .tag(option.id)
                    }
                }
                .pickerStyle(.wheel)
                .labelsHidden()
                .clipped()
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .onChange(of: selection) { newValue in
            guard !newValue.isEmpty else { return }
            nativeHaptic(.selection)
        }
    }
}

private struct NativeDecisionDailyTimerPill: View {
    @State private var now = Date()

    private let timer = Timer.publish(every: 60, on: .main, in: .common).autoconnect()

    private var timeLeftText: String {
        let calendar = Calendar.current
        let nextMidnight = calendar.startOfDay(for: calendar.date(byAdding: .day, value: 1, to: now) ?? now)
        let interval = max(0, Int(nextMidnight.timeIntervalSince(now)))
        let hours = interval / 3600
        let minutes = (interval % 3600) / 60
        return "\(hours)h \(minutes)m"
    }

    var body: some View {
        HStack(spacing: 8) {
            Image(systemName: "timer")
                .font(nativeAppFont(size: 13, weight: .bold))
            Text("1 drop a day")
                .font(nativePixelAccentFont(size: 10))
            Text("refreshes in \(timeLeftText)")
                .font(nativeAppFont(size: 12, weight: .semibold))
        }
        .foregroundStyle(.white.opacity(0.88))
        .padding(.horizontal, 14)
        .padding(.vertical, 10)
        .background(nativeSurface)
        .clipShape(Capsule())
        .onReceive(timer) { value in
            now = value
        }
    }
}

