private struct NativeTodayFeedPreviewScreen: View {
    @EnvironmentObject private var appState: NativeAppState
    @State private var selectedPageIndex = 0
    @State private var showNotificationsSheet = false
    @State private var showShareSheet = false
    @State private var friendCount: Int?
    @State private var isLoadingFriendCount = false

    private let headerHeight: CGFloat = 46
    private let headerTopInset: CGFloat = 10
    private let headerToContentSpacing: CGFloat = 12
    private let contentBottomInset: CGFloat = 104
    private let contentSideInset: CGFloat = 18
    private let progressTrailingInset: CGFloat = 10
    private let progressReservedWidth: CGFloat = 14

    private var hasNoFriendsFeedState: Bool {
        guard appState.currentUser != nil else { return false }
        return (friendCount ?? 0) == 0
    }

    private var hasFriendsButNothingTodayState: Bool {
        guard appState.currentUser != nil else { return false }
        return (friendCount ?? 0) > 0 && appState.feedItems.isEmpty
    }

    private var hasCheckedInToday: Bool {
        return appState.myMoments.contains { moment in
            nativeIsMomentToday(visitedAtIso: moment.visitedAtIso, visitedDate: moment.visitedDate)
        }
    }

    private var pages: [NativeTodayFeedPage] {
        if hasNoFriendsFeedState {
            var items: [NativeTodayFeedPage] = [.intro]
            items.append(contentsOf: appState.suggestedFeedItems.prefix(3).map { .suggested($0) })
            items.append(.invite)
            return items
        }

        if hasFriendsButNothingTodayState {
            var items: [NativeTodayFeedPage] = [.friendsEmptyIntro]
            items.append(contentsOf: appState.fallbackFeedItems.prefix(3).map { .fallback($0) })
            return items
        }

        if appState.feedItems.isEmpty {
            return [.empty]
        }

        return appState.feedItems.map { .feed($0) }
    }

    var body: some View {
        GeometryReader { geometry in
            let topInset = headerTopInset
            let contentTop = topInset + headerHeight + headerToContentSpacing
            let contentHeight = max(
                geometry.size.height - contentTop - contentBottomInset,
                420
            )

            ZStack(alignment: .top) {
                header
                    .padding(.horizontal, 18)
                    .padding(.top, topInset)
                    .overlay(alignment: .topLeading) {
                        if nativeTodayFeedLayoutDebugMode {
                            NativeDecisionLayoutDebugBadge(
                                title: "TODAY HEADER",
                                lines: [
                                    "safeTop=\(Int(geometry.safeAreaInsets.top))",
                                    "headerTop=\(Int(topInset))",
                                    "headerH=\(Int(headerHeight))"
                                ]
                            )
                            .padding(.top, topInset + headerHeight + 6)
                            .padding(.leading, 18)
                        }
                    }

                ZStack {
                    NativeTodayVerticalPager(
                        pages: pages,
                        hasCheckedInToday: hasCheckedInToday,
                        onUnlockTap: {
                            nativeHaptic(.selection)
                            appState.activeTab = .discover
                        },
                        selection: $selectedPageIndex,
                        onInviteTap: {
                            nativeHaptic(.selection)
                            showShareSheet = true
                        }
                    )
                    .frame(height: contentHeight)
                    .padding(.top, contentTop)
                    .padding(.leading, contentSideInset)
                    .padding(.trailing, contentSideInset + progressReservedWidth)
                    .overlay {
                        if nativeTodayFeedLayoutDebugMode {
                            RoundedRectangle(cornerRadius: 24, style: .continuous)
                                .stroke(Color.cyan.opacity(0.82), style: StrokeStyle(lineWidth: 1.5, dash: [8, 6]))
                                .padding(.top, contentTop)
                                .padding(.leading, contentSideInset)
                                .padding(.trailing, contentSideInset + progressReservedWidth)
                        }
                    }
                    .overlay(alignment: .topLeading) {
                        if nativeTodayFeedLayoutDebugMode {
                            NativeDecisionLayoutDebugBadge(
                                title: "TODAY PAGER",
                                lines: [
                                    "contentTop=\(Int(contentTop))",
                                    "contentH=\(Int(contentHeight))",
                                    "bottomInset=\(Int(contentBottomInset))"
                                ]
                            )
                            .padding(.top, contentTop + 8)
                            .padding(.leading, 26)
                        }
                    }
                }

                VStack(spacing: 8) {
                    ForEach(Array(pages.enumerated()), id: \.offset) { index, _ in
                        Capsule()
                            .fill(index == selectedPageIndex ? nativeAccent : Color.white.opacity(0.12))
                            .frame(width: 6, height: index == selectedPageIndex ? 28 : 10)
                            .animation(.spring(response: 0.28, dampingFraction: 0.82), value: selectedPageIndex)
                    }
                }
                .padding(.trailing, progressTrailingInset)
                .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .trailing)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
            .contentShape(Rectangle())
            .simultaneousGesture(
                TapGesture().onEnded {
                    nativeDismissKeyboard()
                }
            )
        }
        .background(Color.black.ignoresSafeArea())
        .navigationBarHidden(true)
        .sheet(isPresented: $showNotificationsSheet) {
            NavigationView {
                NativeNotificationsSheet()
            }
            .navigationViewStyle(.stack)
            .environmentObject(appState)
        }
        .sheet(isPresented: $showShareSheet) {
            NativeShareSheet(items: ["https://vibinn.club"])
        }
        .task {
            await appState.refreshFeed()
            await refreshFriendCount()
        }
        .onAppear {
            appState.trackAnalytics(.viewFeed)
        }
        .onChange(of: selectedPageIndex) { _ in
            nativeHaptic(.selection)
        }
        .onChange(of: pages.count) { newCount in
            guard newCount > 0 else {
                selectedPageIndex = 0
                return
            }
            if selectedPageIndex >= newCount {
                selectedPageIndex = max(0, newCount - 1)
            }
        }
    }

    private var header: some View {
        HStack(alignment: .center, spacing: 12) {
            NavigationLink {
                NativePeopleSearchScreen()
            } label: {
                Image(systemName: "magnifyingglass")
                    .font(nativeAppFont(size: 18, weight: .bold))
                    .foregroundStyle(nativeHeaderIconTint)
                    .frame(width: 46, height: 46)
                    .background(nativeSurface)
                    .clipShape(Circle())
            }
            .buttonStyle(.plain)
            .simultaneousGesture(
                TapGesture().onEnded {
                    appState.trackAnalytics(
                        .searchFriend,
                        properties: [
                            "source": NativeAnalyticsSource.todayFeed,
                        ]
                    )
                }
            )

            Spacer(minLength: 0)

            Text("Today")
                .font(nativePixelAccentFont(size: 12))
                .foregroundStyle(.white)

            Spacer(minLength: 0)

            Button {
                nativeHaptic(.selection)
                showNotificationsSheet = true
            } label: {
                Image(systemName: "bell")
                    .font(nativeAppFont(size: 18, weight: .bold))
                    .foregroundStyle(nativeHeaderIconTint)
                    .frame(width: 46, height: 46)
                    .background(nativeSurface)
                    .clipShape(Circle())
                    .overlay(alignment: .topTrailing) {
                        if appState.notificationUnreadCount > 0 {
                            Circle()
                                .fill(nativeAccent)
                                .frame(width: 10, height: 10)
                                .overlay(
                                    Circle()
                                        .stroke(Color.black, lineWidth: 1.5)
                                )
                                .offset(x: -2, y: 2)
                        }
                    }
            }
            .buttonStyle(.plain)
        }
        .frame(height: headerHeight)
    }

    private func refreshFriendCount() async {
        guard !isLoadingFriendCount, let currentUser = appState.currentUser else { return }
        isLoadingFriendCount = true
        defer { isLoadingFriendCount = false }

        do {
            let friends = try await appState.fetchTravelerFriends(id: currentUser.id)
            friendCount = friends.count
        } catch {
            if friendCount == nil {
                friendCount = 0
            }
        }
    }
}

private func nativeDismissKeyboard() {
#if canImport(UIKit)
    UIApplication.shared.sendAction(
        #selector(UIResponder.resignFirstResponder),
        to: nil,
        from: nil,
        for: nil
    )
#endif
}

private enum NativeTodayFeedPage: Identifiable {
    case intro
    case friendsEmptyIntro
    case suggested(NativeFeedItem)
    case invite
    case feed(NativeFeedItem)
    case fallback(NativeFeedItem)
    case empty

    var id: String {
        switch self {
        case .intro:
            return "intro"
        case .friendsEmptyIntro:
            return "friends-empty-intro"
        case .invite:
            return "invite"
        case .empty:
            return "empty"
        case .suggested(let item):
            return "suggested-\(item.id)"
        case .feed(let item):
            return "feed-\(item.id)"
        case .fallback(let item):
            return "fallback-\(item.id)"
        }
    }
}

private extension NativeTodayFeedPage {
    var isUnlockableFeedContent: Bool {
        switch self {
        case .suggested, .feed, .fallback:
            return true
        default:
            return false
        }
    }
}

private struct NativeTodayVerticalPager: View {
    let pages: [NativeTodayFeedPage]
    let hasCheckedInToday: Bool
    let onUnlockTap: () -> Void
    @Binding var selection: Int
    let onInviteTap: () -> Void
    @State private var dragOffset: CGFloat = 0

    var body: some View {
        GeometryReader { geometry in
            ZStack {
                ForEach(Array(pages.enumerated()), id: \.element.id) { index, page in
                    let relativeIndex = index - selection
                    NativeTodayFeedPageCard(
                        page: page,
                        isLocked: shouldLock(pageAt: index),
                        onUnlockTap: onUnlockTap,
                        onInviteTap: onInviteTap
                    )
                    .frame(width: geometry.size.width, height: geometry.size.height)
                    .offset(y: CGFloat(relativeIndex) * geometry.size.height + (relativeIndex == 0 ? dragOffset : 0))
                    .scaleEffect(1)
                    .opacity(relativeIndex == 0 ? 1 : 0)
                    .animation(.spring(response: 0.34, dampingFraction: 0.86), value: selection)
                }
            }
            .clipped()
            .contentShape(Rectangle())
            .gesture(
                DragGesture()
                    .onChanged { value in
                        dragOffset = value.translation.height
                    }
                    .onEnded { value in
                        let threshold = geometry.size.height * 0.18
                        let translation = value.translation.height
                        if translation < -threshold {
                            moveSelection(by: 1)
                        } else if translation > threshold {
                            moveSelection(by: -1)
                        }
                        withAnimation(.spring(response: 0.32, dampingFraction: 0.84)) {
                            dragOffset = 0
                        }
                    }
            )
        }
    }

    private func moveSelection(by delta: Int) {
        let nextIndex = max(0, min(pages.count - 1, selection + delta))
        guard nextIndex != selection else { return }
        selection = nextIndex
    }

    private func shouldLock(pageAt index: Int) -> Bool {
        guard !hasCheckedInToday else { return false }
        let page = pages[index]
        guard page.isUnlockableFeedContent else { return false }

        var seenContent = 0
        for currentIndex in 0...index {
            if pages[currentIndex].isUnlockableFeedContent {
                seenContent += 1
            }
        }
        return seenContent > 1
    }
}

private struct NativeTodayFeedPageCard: View {
    let page: NativeTodayFeedPage
    let isLocked: Bool
    let onUnlockTap: () -> Void
    let onInviteTap: () -> Void

    var body: some View {
        VStack(spacing: 0) {
            Spacer(minLength: 0)

            switch page {
            case .intro:
                NativeNoFriendsFeedIntroCard(onFindFriends: onInviteTap, onInvite: onInviteTap)
            case .friendsEmptyIntro:
                NativeNoTodayFeedIntroCard()
            case .invite:
                NativeNoFriendsFeedInviteCard(onInvite: onInviteTap)
            case .empty:
                NativeSurfaceCard {
                    Text("No activity yet.")
                        .font(nativeAppFont(size: 15, weight: .medium))
                        .foregroundStyle(.white.opacity(0.6))
                }
            case .suggested(let item), .feed(let item), .fallback(let item):
                NativeTodayLiveFeedCard(item: item, showsTravelerHeader: true, isLocked: isLocked, onUnlockTap: onUnlockTap)
            }

            Spacer(minLength: 0)
        }
    }
}

private struct NativeTodayLiveFeedCard: View {
    @EnvironmentObject private var appState: NativeAppState
    let item: NativeFeedItem
    let showsTravelerHeader: Bool
    let isLocked: Bool
    let onUnlockTap: () -> Void
    var onDeletePost: ((NativeFeedItem) -> Void)? = nil
    @State private var vibed = false
    @State private var vibinCount = 0
    @State private var isTogglingVibin = false
    @State private var comments: [NativeComment] = []
    @State private var commentDraft = ""
    @State private var isCommentsLoading = false
    @State private var commentsErrorMessage: String?
    @State private var showReportPostDialog = false
    @State private var showReportAccountDialog = false
    @State private var showBlockAccountDialog = false
    @State private var showDeletePostDialog = false
    @State private var moderationAlertMessage = ""
    @State private var showModerationAlert = false

    private var isOwnPost: Bool {
        appState.currentUser?.id == item.traveler.id
    }

    private var mediaURL: String? {
        if let uploaded = item.uploadedMediaUrls?.first, !uploaded.isEmpty {
            return uploaded
        }
        if let uploaded = item.place?.userMediaUrls?.first, !uploaded.isEmpty {
            return uploaded
        }
        if let uploaded = item.place?.momentMedia?.first?.url, !uploaded.isEmpty {
            return uploaded
        }
        if let image = item.place?.image, !image.isEmpty {
            return image
        }
        if let image = item.place?.images?.first, !image.isEmpty {
            return image
        }
        return nil
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            if showsTravelerHeader {
                HStack(spacing: 12) {
                    NavigationLink {
                        NativeTravelerProfileScreen(initialTraveler: item.traveler)
                    } label: {
                        NativeAvatarCircle(
                            url: item.traveler.avatar,
                            fallbackText: item.traveler.displayName ?? item.traveler.username,
                            size: 42,
                            fontSize: 15
                        )
                    }
                    .buttonStyle(.plain)

                    VStack(alignment: .leading, spacing: 2) {
                        NavigationLink {
                            NativeTravelerProfileScreen(initialTraveler: item.traveler)
                        } label: {
                            Text(displayNameLabel)
                                .font(nativeAppFont(size: 15, weight: .black))
                                .foregroundStyle(.white)
                        }
                        .buttonStyle(.plain)

                        Text("@\(item.traveler.username) • \(item.timestampLabel)")
                            .font(nativeAppFont(size: 12, weight: .semibold))
                            .foregroundStyle(.white.opacity(0.48))
                    }

                    Spacer(minLength: 0)

                    if shouldShowPostMenu {
                        postMoreMenu
                    }
                }
            } else if shouldShowPostMenu {
                HStack {
                    Spacer(minLength: 0)
                    postMoreMenu
                }
            }

            ZStack {
                VStack(alignment: .leading, spacing: 16) {
                    if !metaPills.isEmpty {
                        VStack(alignment: .leading, spacing: 8) {
                            HStack(spacing: 8) {
                                ForEach(metaPills) { pill in
                                    NativeTodayFeedMetaPill(
                                        label: pill.label,
                                        icon: pill.icon,
                                        foreground: pill.foreground,
                                        background: pill.background
                                    )
                                }
                            }

                            if let threeWordReviewText {
                                Text(threeWordReviewText)
                                    .font(nativeAppFont(size: 16, weight: .semibold))
                                    .foregroundStyle(.white.opacity(0.9))
                                    .lineLimit(2)
                            }
                        }
                        .blur(radius: isLocked ? 8 : 0)
                        .opacity(isLocked ? 0.54 : 1)
                    }

                    GeometryReader { imageGeometry in
                        let imageWidth = imageGeometry.size.width

                        ZStack {
                            NativeRemoteImage(url: mediaURL)
                                .frame(width: imageWidth, height: imageWidth)
                                .clipShape(RoundedRectangle(cornerRadius: 24, style: .continuous))
                                .overlay(
                                    RoundedRectangle(cornerRadius: 24, style: .continuous)
                                        .stroke(Color.white.opacity(0.08), lineWidth: 1)
                                )
                                .clipped()
                                .blur(radius: isLocked ? 10 : 0)

                            if isLocked {
                                RoundedRectangle(cornerRadius: 24, style: .continuous)
                                    .fill(Color.black.opacity(0.28))

                                VStack(spacing: 12) {
                                    Text("Check in first to unlock this post")
                                        .font(nativeAppFont(size: 14, weight: .semibold))
                                        .foregroundStyle(.white.opacity(0.92))
                                        .multilineTextAlignment(.center)
                                        .padding(.horizontal, 28)

                                    Button {
                                        onUnlockTap()
                                    } label: {
                                        HStack(spacing: 8) {
                                            Image(systemName: "lock.fill")
                                                .font(nativeAppFont(size: 13, weight: .black))
