private struct NativeTodayFeedPreviewCard: View {
    @EnvironmentObject private var appState: NativeAppState
    let post: NativeTodayFeedPreviewPost
    let isLocked: Bool
    let isLiked: Bool
    let onLikeToggle: () -> Void
    let onCommentTap: () -> Void
    let onUnlockTap: () -> Void
    @State private var commentDraft = ""

    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            HStack(spacing: 12) {
                NativeAvatarCircle(
                    url: nil,
                    fallbackText: post.avatarFallback,
                    size: 42,
                    fontSize: 15
                )

                VStack(alignment: .leading, spacing: 2) {
                    Text(post.travelerName)
                        .font(nativeAppFont(size: 15, weight: .black))
                        .foregroundStyle(.white)
                    Text("@\(post.travelerUsername) • \(post.postedAtLabel)")
                        .font(nativeAppFont(size: 12, weight: .semibold))
                        .foregroundStyle(.white.opacity(0.48))
                }

                Spacer(minLength: 0)
            }

            ZStack {
                VStack(alignment: .leading, spacing: 16) {
                    VStack(alignment: .leading, spacing: 12) {
                        HStack(spacing: 8) {
                            NativeTodayFeedMetaPill(
                                label: post.moodLabel,
                                foreground: .white,
                                background: Color.white.opacity(0.08)
                            )
                            NativeTodayFeedMetaPill(
                                label: post.ratingLabel,
                                icon: "sparkles",
                                foreground: .black,
                                background: nativeAccent.opacity(0.92)
                            )
                        }

                        Text(post.threeWordReview)
                            .font(nativeAppFont(size: 15, weight: .regular))
                            .foregroundStyle(.white.opacity(0.86))
                            .lineLimit(2)
                    }

                    GeometryReader { imageGeometry in
                        let imageWidth = imageGeometry.size.width
                        let imageHeight = imageWidth

                        ZStack {
                            Image(post.imageAssetName)
                                .resizable()
                                .scaledToFill()
                                .frame(width: imageWidth, height: imageHeight)
                                .clipShape(RoundedRectangle(cornerRadius: 24, style: .continuous))
                                .clipped()
                                .blur(radius: isLocked ? 10 : 0)
                                .overlay {
                                    if isLocked {
                                        RoundedRectangle(cornerRadius: 24, style: .continuous)
                                            .fill(Color.black.opacity(0.28))
                                    }
                                }

                            if isLocked {
                                VStack(spacing: 12) {
                                    Text("Check in first to unlock this post")
                                        .font(nativeAppFont(size: 14, weight: .semibold))
                                        .foregroundStyle(.white.opacity(0.92))
                                        .multilineTextAlignment(.center)
                                        .padding(.horizontal, 28)

                                    Button {
                                        onUnlockTap()
                                    } label: {
                                        HStack(spacing: 8) {
                                            Image(systemName: "lock.fill")
                                                .font(nativeAppFont(size: 13, weight: .black))
                                            Text("Check in now")
                                                .font(nativeAppFont(size: 14, weight: .bold))
                                        }
                                        .foregroundStyle(.white)
                                        .padding(.horizontal, 16)
                                        .padding(.vertical, 11)
                                        .background(
                                            Capsule()
                                                .fill(.ultraThinMaterial)
                                                .overlay(
                                                    Capsule()
                                                        .stroke(Color.white.opacity(0.14), lineWidth: 1)
                                                )
                                        )
                                    }
                                    .buttonStyle(.plain)
                                }
                                .padding(.horizontal, 20)
                                .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .center)
                            }
                        }
                        .frame(width: imageWidth, height: imageHeight, alignment: .center)
                    }
                    .frame(maxWidth: .infinity)
                    .aspectRatio(1, contentMode: .fit)

                    HStack(alignment: .center, spacing: 12) {
                        VStack(alignment: .leading, spacing: 4) {
                            Text(post.placeName)
                                .font(nativeAppFont(size: 18, weight: .black))
                                .foregroundStyle(.white)
                                .lineLimit(2)
                            Text(post.placeLocation)
                                .font(nativeAppFont(size: 12, weight: .medium))
                                .foregroundStyle(.white.opacity(0.58))
                                .lineLimit(1)
                        }

                        Spacer(minLength: 0)

                        Button {
                            nativeHaptic(.selection)
                            appState.activeTab = .discover
                        } label: {
                            Text("Try this vibe")
                                .font(nativeAppFont(size: 12, weight: .bold))
                                .foregroundStyle(.black)
                                .padding(.horizontal, 12)
                                .padding(.vertical, 10)
                                .background(nativeAccent)
                                .clipShape(Capsule())
                        }
                        .buttonStyle(.plain)
                    }
                    .blur(radius: isLocked ? 8 : 0)
                    .disabled(isLocked)
                    .opacity(isLocked ? 0.58 : 1)

                    HStack(spacing: 10) {
                        TextField("Leave a comment", text: $commentDraft)
                            .textFieldStyle(.plain)
                            .font(nativeAppFont(size: 14, weight: .medium))
                            .foregroundStyle(.white)
                            .padding(.horizontal, 14)
                            .padding(.vertical, 12)
                            .background(Color.white.opacity(0.06))
                            .clipShape(Capsule())

                        Button(action: onCommentTap) {
                            Text("Post")
                                .font(nativeAppFont(size: 13, weight: .bold))
                                .foregroundStyle(.white.opacity(0.9))
                                .padding(.horizontal, 14)
                                .padding(.vertical, 12)
                                .background(Color.white.opacity(0.08))
                                .clipShape(Capsule())
                        }
                        .buttonStyle(.plain)

                        Button(action: onLikeToggle) {
                            HStack(spacing: 6) {
                                Image(systemName: isLiked ? "heart.fill" : "heart")
                                    .font(nativeAppFont(size: 16, weight: .bold))
                                Text("\(post.likeCount + (isLiked ? 1 : 0))")
                                    .font(nativeAppFont(size: 14, weight: .black))
                            }
                            .foregroundStyle(isLiked ? nativeAccent : .white.opacity(0.76))
                            .padding(.horizontal, 12)
                            .padding(.vertical, 12)
                            .background(Color.white.opacity(0.04))
                            .clipShape(Capsule())
                        }
                        .buttonStyle(.plain)
                    }
                    .disabled(isLocked)
                    .opacity(isLocked ? 0.52 : 1)
                }
                .padding(14)
                .background(
                    RoundedRectangle(cornerRadius: 28, style: .continuous)
                        .fill(Color(red: 18 / 255, green: 17 / 255, blue: 15 / 255))
                        .overlay(
                            RoundedRectangle(cornerRadius: 28, style: .continuous)
                            .stroke(Color.white.opacity(0.08), lineWidth: 1)
                        )
                )
            }
        }
        .overlay {
            if nativeTodayFeedLayoutDebugMode {
                RoundedRectangle(cornerRadius: 28, style: .continuous)
                    .stroke(Color.yellow.opacity(0.82), style: StrokeStyle(lineWidth: 1.5, dash: [8, 6]))
            }
        }
        .overlay(alignment: .topLeading) {
            if nativeTodayFeedLayoutDebugMode {
                NativeDecisionLayoutDebugBadge(
                    title: "POST",
                    lines: [
                        "stackSpacing=16",
                        "innerPad=14",
                        "image=3:4"
                    ]
                )
                .padding(10)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
        .scaleEffect(isLocked ? 0.988 : 1)
        .animation(.spring(response: 0.3, dampingFraction: 0.84), value: isLocked)
    }
}

