private struct NativeDecisionActiveSessionScreen: View {
    let intent: NativeDecisionIntent?
    let options: [NativeDecisionSessionOption]
    let isLoading: Bool
    let cityLabel: String
    let geometry: GeometryProxy
    let onSwipe: (NativeDecisionSessionOption, String) -> Void

    private var deckHeight: CGFloat {
        min(max(geometry.size.height * 0.7, 480), geometry.size.height - 160)
    }

    var body: some View {
        VStack(spacing: 18) {
            HStack {
                Text(cityLabel.uppercased())
                    .font(nativePixelAccentFont(size: 10))
                    .foregroundStyle(.white)

                Spacer(minLength: 0)

                Text("\(options.count) LEFT")
                    .font(nativePixelAccentFont(size: 10))
                    .foregroundStyle(nativeAccent)
            }

            Spacer(minLength: 0)

            if isLoading {
                RoundedRectangle(cornerRadius: 34, style: .continuous)
                    .fill(nativeSurface)
                    .frame(height: deckHeight)
                    .overlay(ProgressView().tint(nativeAccent))
            } else {
                NativeDecisionDeckView(
                    options: options,
                    intent: intent,
                    deckHeight: deckHeight,
                    cardHeight: deckHeight,
                    onSwipe: onSwipe
                )
            }

            Spacer(minLength: 0)
        }
        .padding(.horizontal, 16)
        .padding(.top, geometry.safeAreaInsets.top + 8)
        .padding(.bottom, max(18, geometry.safeAreaInsets.bottom + 10))
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
    }
}

private struct NativeDecisionSessionResultView: View {
    let selectedOption: NativeDecisionSessionOption?
    let fallbackOption: NativeDecisionSessionOption?
    let onOpenPlace: (NativeDecisionSessionOption) -> Void
    let onGoNow: (NativeDecisionSessionOption) -> Void
    let onCheckIn: (NativeDecisionSessionOption) -> Void
    let onManualCheckInElsewhere: () -> Void
    let onReset: () -> Void
    var onBackToTodaysDrop: (() -> Void)? = nil

    var body: some View {
        VStack(spacing: 14) {
            if let selectedOption {
                VStack(alignment: .center, spacing: 14) {
                    Text("You picked this")
                        .font(nativeAppFont(size: 32, weight: .black))
                        .foregroundStyle(.white)
                        .multilineTextAlignment(.center)
                        .frame(maxWidth: .infinity)
                        .overlay {
                            if nativeDecisionLayoutDebugMode {
                                RoundedRectangle(cornerRadius: 14, style: .continuous)
                                    .stroke(Color.cyan.opacity(0.9), style: StrokeStyle(lineWidth: 1.5, dash: [6, 4]))
                            }
                        }

                    NativeDecisionResultCard(option: selectedOption) {
                        onOpenPlace(selectedOption)
                    }

                    HStack(spacing: 12) {
                        Button {
                            nativeHaptic(.selection)
                            onCheckIn(selectedOption)
                        } label: {
                            HStack(spacing: 8) {
                                Image(systemName: "checkmark.circle.fill")
                                    .font(nativeAppFont(size: 14, weight: .bold))
                                Text("I'm here")
                                    .font(nativeAppFont(size: 15, weight: .bold))
                            }
                            .foregroundStyle(.white)
                            .frame(maxWidth: .infinity)
                            .padding(.vertical, 14)
                            .background(nativeSurface)
                            .overlay(
                                Capsule()
                                    .stroke(Color.white.opacity(0.12), lineWidth: 1)
                            )
                            .clipShape(Capsule())
                        }
                        .buttonStyle(.plain)

                        Button {
                            nativeHaptic(.success)
                            onGoNow(selectedOption)
                        } label: {
                            HStack(spacing: 8) {
                                Image(systemName: "arrow.triangle.turn.up.right.diamond.fill")
                                    .font(nativeAppFont(size: 14, weight: .bold))
                                Text("Go now")
                                    .font(nativeAppFont(size: 15, weight: .bold))
                            }
                            .foregroundStyle(.black)
                            .frame(maxWidth: .infinity)
                            .padding(.vertical, 14)
                            .background(nativeAccent)
                            .clipShape(Capsule())
                        }
                        .buttonStyle(.plain)
                    }

                    NativeDecisionLockedInResetPill()

                    if let onBackToTodaysDrop {
                        Button {
                            nativeHaptic(.selection)
                            onBackToTodaysDrop()
                        } label: {
                            HStack(spacing: 8) {
                                Image(systemName: "arrow.left")
                                    .font(nativeAppFont(size: 13, weight: .bold))
                                Text("Back to Today’s drop")
                                    .font(nativeAppFont(size: 14, weight: .bold))
                            }
                            .foregroundStyle(.white)
                            .padding(.horizontal, 14)
                            .padding(.vertical, 12)
                            .background(nativeSurface)
                            .overlay(
                                Capsule()
                                    .stroke(Color.white.opacity(0.12), lineWidth: 1)
                            )
                            .clipShape(Capsule())
                        }
                        .buttonStyle(.plain)
                    }

                    NativeDecisionFallbackActions(
                        onManualCheckInElsewhere: onManualCheckInElsewhere,
                        onReset: onReset
                    )
                }
                .overlay(alignment: .topLeading) {
                    if nativeDecisionLayoutDebugMode {
                        NativeDecisionLayoutDebugBadge(
                            title: "RESULT",
                            lines: [
                                "header gap=28",
                                "content spacing=14",
                                "outer pad=18"
                            ]
                        )
                        .padding(8)
                    }
                }
                .overlay {
                    if nativeDecisionLayoutDebugMode {
                        RoundedRectangle(cornerRadius: 26, style: .continuous)
                            .stroke(Color.red.opacity(0.82), style: StrokeStyle(lineWidth: 1.5, dash: [8, 6]))
                    }
                }
            } else {
                VStack(alignment: .center, spacing: 10) {
                    NativeDecisionNoPickIllustration()
                        .frame(width: 42, height: 42)

                    Text("No pick locked in")
                        .font(nativeAppFont(size: 32, weight: .black))
                        .foregroundStyle(.white)
                        .multilineTextAlignment(.center)
                        .frame(maxWidth: .infinity)
                        .overlay {
                            if nativeDecisionLayoutDebugMode {
                                RoundedRectangle(cornerRadius: 14, style: .continuous)
                                    .stroke(Color.cyan.opacity(0.9), style: StrokeStyle(lineWidth: 1.5, dash: [6, 4]))
                            }
                        }

                    Text("You passed on this round. Want to try again or check in somewhere else?")
                        .font(nativeAppFont(size: 15, weight: .medium))
                        .foregroundStyle(.white.opacity(0.72))
                        .multilineTextAlignment(.center)
                        .fixedSize(horizontal: false, vertical: true)
                        .padding(.horizontal, 18)

                    VStack(spacing: 12) {
                        Button {
                            nativeHaptic(.medium)
                            onReset()
                        } label: {
                            HStack(spacing: 8) {
                                Image(systemName: "arrow.clockwise")
                                    .font(nativeAppFont(size: 14, weight: .bold))
                                Text("Try again")
                                    .font(nativeAppFont(size: 14, weight: .bold))
                            }
                            .foregroundStyle(.black)
                            .frame(maxWidth: .infinity, minHeight: 52)
                            .padding(.horizontal, 12)
                            .background(nativeAccent)
                            .clipShape(Capsule())
                        }
                        .buttonStyle(.plain)

                        Button {
                            nativeHaptic(.selection)
                            onManualCheckInElsewhere()
                        } label: {
                            HStack(spacing: 8) {
                                Image(systemName: "mappin.and.ellipse")
                                    .font(nativeAppFont(size: 14, weight: .bold))
                                Text("Check in somewhere else")
                                    .font(nativeAppFont(size: 14, weight: .bold))
                                    .lineLimit(2)
                                    .multilineTextAlignment(.center)
                            }
                            .foregroundStyle(.white)
                            .frame(maxWidth: .infinity, minHeight: 52)
                            .padding(.horizontal, 12)
                            .background(nativeSurface)
                            .overlay(
                                Capsule()
                                    .stroke(Color.white.opacity(0.12), lineWidth: 1)
                            )
                            .clipShape(Capsule())
                        }
                        .buttonStyle(.plain)
                    }

                    if let fallbackOption {
                        VStack(alignment: .leading, spacing: 8) {
                            Text("One more idea")
                                .font(nativeAppFont(size: 12, weight: .semibold))
                                .foregroundStyle(.white.opacity(0.42))
                            NativeDecisionResultCard(option: fallbackOption) {
                                onOpenPlace(fallbackOption)
                            }
                            .opacity(0.88)
                        }
                    }
                }
                .padding(.top, -18)
                .overlay(alignment: .topLeading) {
                    if nativeDecisionLayoutDebugMode {
                        NativeDecisionLayoutDebugBadge(
                            title: "NO PICK",
                            lines: [
                                "header gap=28",
                                "content spacing=10",
                                "button stack spacing=12",
                                "top offset=-18",
                                "outer pad=18"
                            ]
                        )
                        .padding(8)
                    }
                }
                .overlay {
                    if nativeDecisionLayoutDebugMode {
                        RoundedRectangle(cornerRadius: 26, style: .continuous)
                            .stroke(Color.red.opacity(0.82), style: StrokeStyle(lineWidth: 1.5, dash: [8, 6]))
                    }
                }
            }
        }
        .navigationViewStyle(.stack)
    }
}

