private struct NativeDecisionPostCheckInHomeView: View {
    let moment: NativeMoment
    let onOpenPlace: () -> Void
    let onPickAnotherVibe: () -> Void
    let onOpenTodayFeed: () -> Void
    let onCheckInAgain: () -> Void

    private var mediaURL: String? {
        if let uploaded = moment.uploadedMedia?.first, !uploaded.isEmpty {
            return uploaded
        }
        if let media = moment.place.momentMedia?.first?.url, !media.isEmpty {
            return media
        }
        if let media = moment.place.userMediaUrls?.first, !media.isEmpty {
            return media
        }
        if let image = moment.place.image, !image.isEmpty {
            return image
        }
        return moment.place.images?.first
    }

    private var visitedLabel: String {
        NativeAppState.relativeLabel(from: moment.visitedAtIso ?? moment.visitedDate)
    }

    var body: some View {
        VStack(spacing: 14) {
            Button(action: onOpenPlace) {
