private struct NativeDecisionLockedInResetPill: View {
    @State private var now = Date()

    private let timer = Timer.publish(every: 60, on: .main, in: .common).autoconnect()

    private var timeLeftText: String {
        let calendar = Calendar.current
        let nextMidnight = calendar.startOfDay(for: calendar.date(byAdding: .day, value: 1, to: now) ?? now)
        let interval = max(0, Int(nextMidnight.timeIntervalSince(now)))
        let hours = interval / 3600
        let minutes = (interval % 3600) / 60
        return "\(hours)h \(minutes)m"
    }

    var body: some View {
        HStack(spacing: 8) {
            Image(systemName: "timer")
                .font(nativeAppFont(size: 13, weight: .bold))
            Text("Recommendation resets in \(timeLeftText)")
                .font(nativeAppFont(size: 13, weight: .semibold))
                .multilineTextAlignment(.center)
        }
        .foregroundStyle(.white.opacity(0.82))
        .padding(.horizontal, 14)
        .padding(.vertical, 10)
        .background(nativeSurface)
        .clipShape(Capsule())
        .onReceive(timer) { value in
            now = value
        }
    }
}

