private struct NativeDecisionHistorySheet: View {
    @EnvironmentObject private var appState: NativeAppState
    @Environment(\.dismiss) private var dismiss
    @State private var selectedMoment: NativeMoment?

    private var groupedMomentsByDay: [Date: [NativeMoment]] {
        Dictionary(grouping: appState.myMoments) { moment in
            let date = NativeAppState.date(from: moment.visitedAtIso ?? moment.visitedDate) ?? Date()
            return Calendar.current.startOfDay(for: date)
        }
    }

    private var monthStarts: [Date] {
        let calendar = Calendar.current
        let momentDates = groupedMomentsByDay.keys.sorted()
        let firstMomentDate = momentDates.first ?? Date()
        let firstMonth = calendar.date(from: calendar.dateComponents([.year, .month], from: firstMomentDate)) ?? firstMomentDate
        let currentMonth = calendar.date(from: calendar.dateComponents([.year, .month], from: Date())) ?? Date()

        var months: [Date] = []
        var cursor = firstMonth
        while cursor <= currentMonth {
            months.append(cursor)
            cursor = calendar.date(byAdding: .month, value: 1, to: cursor) ?? currentMonth
            if months.count > 24 { break }
        }
        return months.reversed()
    }

    var body: some View {
        NavigationView {
            ScrollView(showsIndicators: false) {
                VStack(alignment: .leading, spacing: 18) {
                    if appState.myMoments.isEmpty {
                        Text("No check-ins yet.")
                            .font(nativeAppFont(size: 18, weight: .black))
                            .foregroundStyle(.white)
                            .frame(maxWidth: .infinity, minHeight: 220)
                    } else {
                        VStack(alignment: .leading, spacing: 10) {
                            Text("Your moments on the calendar")
                                .font(nativeAppFont(size: 15, weight: .black))
                                .foregroundStyle(.white)
                            Text("Dates with check-ins are marked with a simple placeholder.")
                                .font(nativeAppFont(size: 13, weight: .medium))
                                .foregroundStyle(.white.opacity(0.58))
                        }

                        ForEach(monthStarts, id: \.self) { monthStart in
                            NativeDecisionHistoryMonthSection(
                                monthStart: monthStart,
                                groupedMomentsByDay: groupedMomentsByDay,
                                onMomentTap: { moment in
                                    selectedMoment = moment
                                }
                            )
                        }
                    }
                }
                .padding(.horizontal, 20)
                .padding(.vertical, 20)
            }
            .background(Color.black.ignoresSafeArea())
            .navigationTitle("Check-in history")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button("Done") { dismiss() }
                }
            }
        }
        .navigationViewStyle(.stack)
        .task {
            await appState.refreshMyMomentsOnly()
        }
        .fullScreenCover(item: $selectedMoment) { moment in
            NativeDecisionHistoryMomentFullscreen(moment: moment)
        }
    }
}

private struct NativeDecisionHistoryMonthSection: View {
    let monthStart: Date
    let groupedMomentsByDay: [Date: [NativeMoment]]
    let onMomentTap: (NativeMoment) -> Void

    private let calendar = Calendar.current
    private let columns = Array(repeating: GridItem(.flexible(), spacing: 8), count: 7)
    private let weekdaySymbols = ["S", "M", "T", "W", "T", "F", "S"]

    private var title: String {
        let formatter = DateFormatter()
        formatter.dateFormat = "MMMM yyyy"
        return formatter.string(from: monthStart)
    }

    private var days: [Date?] {
        let monthInterval = calendar.dateInterval(of: .month, for: monthStart)
        guard let monthInterval else { return [] }
        let firstDay = monthInterval.start
        let numberOfDays = calendar.range(of: .day, in: .month, for: firstDay)?.count ?? 30
        let weekday = calendar.component(.weekday, from: firstDay)
        let leadingEmpty = max(0, weekday - 1)

        var values: [Date?] = Array(repeating: nil, count: leadingEmpty)
        for dayOffset in 0..<numberOfDays {
            values.append(calendar.date(byAdding: .day, value: dayOffset, to: firstDay))
        }
        while values.count % 7 != 0 {
            values.append(nil)
        }
        return values
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            Text(title)
                .font(nativePixelAccentFont(size: 14))
                .foregroundStyle(nativeAccent)

            LazyVGrid(columns: columns, spacing: 8) {
                ForEach(weekdaySymbols, id: \.self) { symbol in
                    Text(symbol)
                        .font(nativeAppFont(size: 11, weight: .black))
                        .foregroundStyle(.white.opacity(0.38))
                        .frame(maxWidth: .infinity)
                }

                ForEach(Array(days.enumerated()), id: \.offset) { _, date in
                    NativeDecisionHistoryDayCell(
                        date: date,
                        moments: date.flatMap { groupedMomentsByDay[calendar.startOfDay(for: $0)] } ?? [],
                        onTap: onMomentTap
                    )
                }
            }
        }
        .padding(16)
        .background(
            RoundedRectangle(cornerRadius: 24, style: .continuous)
                .fill(nativeSurface)
        )
    }
}

private struct NativeDecisionHistoryDayCell: View {
    let date: Date?
    let moments: [NativeMoment]
    let onTap: (NativeMoment) -> Void

    private var dayNumber: String {
        guard let date else { return "" }
        return String(Calendar.current.component(.day, from: date))
    }

    private var placeholderIcon: String {
        if let tag = moments.first?.place.tags?.first?.lowercased() {
            if tag.contains("coffee") { return "cup.and.saucer.fill" }
            if tag.contains("dessert") || tag.contains("sweet") { return "birthday.cake.fill" }
            if tag.contains("drink") { return "wineglass.fill" }
        }
        return "photo.fill"
    }

    var body: some View {
        Group {
            if let date {
                Button {
                    if let moment = moments.first {
                        onTap(moment)
                    }
                } label: {
                    ZStack(alignment: .topLeading) {
                        RoundedRectangle(cornerRadius: 14, style: .continuous)
                            .fill(Color.white.opacity(0.04))

                        if !moments.isEmpty {
                            RoundedRectangle(cornerRadius: 14, style: .continuous)
                                .fill(
                                    LinearGradient(
                                        colors: [
                                            nativeAccent.opacity(0.34),
                                            nativeAccent.opacity(0.18)
                                        ],
                                        startPoint: .topLeading,
                                        endPoint: .bottomTrailing
                                    )
                                )
                                .overlay {
                                    VStack(spacing: 4) {
                                        Image(systemName: placeholderIcon)
                                            .font(nativeAppFont(size: 18, weight: .black))
                                            .foregroundStyle(.white.opacity(0.92))
                                        Text("Moment")
                                            .font(nativeAppFont(size: 8, weight: .black))
                                            .foregroundStyle(.white.opacity(0.78))
                                            .textCase(.uppercase)
                                    }
                                }
                        }

                        Text(dayNumber)
                            .font(nativeAppFont(size: 12, weight: .black))
                            .foregroundStyle(moments.isEmpty ? .white.opacity(0.7) : .white)
                            .padding(8)

                        if moments.count > 1 {
                            Text("\(moments.count)")
                                .font(nativeAppFont(size: 9, weight: .black))
                                .foregroundStyle(.black)
                                .padding(.horizontal, 6)
                                .padding(.vertical, 4)
                                .background(nativeAccent)
                                .clipShape(Capsule())
                                .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .bottomTrailing)
                                .padding(6)
                        }
                    }
                    .frame(maxWidth: .infinity)
                    .frame(height: 52)
                    .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
                    .overlay(
                        RoundedRectangle(cornerRadius: 14, style: .continuous)
                            .stroke(moments.isEmpty ? Color.white.opacity(0.06) : nativeAccent.opacity(0.26), lineWidth: 1)
                    )
                }
                .buttonStyle(.plain)
                .disabled(moments.isEmpty)
            } else {
                Color.clear
                    .frame(height: 52)
            }
        }
    }
}

private struct NativeDecisionHistoryMomentFullscreen: View {
    let moment: NativeMoment
    @EnvironmentObject private var appState: NativeAppState
    @Environment(\.dismiss) private var dismiss
    @State private var comments: [NativeComment] = []
    @State private var isCommentsLoading = false
    @State private var commentsErrorMessage: String?
    @State private var commentDraft = ""
    @State private var vibed = false
    @State private var vibinCount = 0
    @State private var isTogglingVibin = false
    @State private var editedMoment: NativeMoment? = nil
    @State private var selectedPlace: NativePlace? = nil
    @State private var showEditMomentSheet = false
    @State private var showDeletePostDialog = false

    private var displayedMoment: NativeMoment {
        editedMoment ?? moment
    }

    private var mediaUrl: String? {
        if let uploaded = displayedMoment.uploadedMedia?.first, !uploaded.isEmpty {
            return uploaded
        }
        if let image = displayedMoment.place.image, !image.isEmpty {
            return image
        }
        if let image = displayedMoment.place.images?.first, !image.isEmpty {
            return image
        }
        return nil
    }

    private var commentTargetType: String {
        "MOMENT"
    }

    private var commentTargetId: String {
        displayedMoment.id
    }

    private var ratingMeta: (label: String, icon: String)? {
        nativeMomentRatingMeta(label: displayedMoment.ratingLabel, fallbackRating: displayedMoment.rating)
    }

    private var shortAddress: String {
        let raw = displayedMoment.place.address?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if raw.isEmpty {
            return displayedMoment.place.location
        }
        let parts = raw
            .split(separator: ",")
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        guard let first = parts.first else { return displayedMoment.place.location }
        if CharacterSet.decimalDigits.isSuperset(of: CharacterSet(charactersIn: first)),
           parts.count > 1 {
            return "\(first) \(parts[1])"
        }
        return first
    }

    private var placeMetaLine: String {
        [displayedMoment.place.category?.trimmingCharacters(in: .whitespacesAndNewlines), shortAddress]
            .compactMap { value -> String? in
                guard let value, !value.isEmpty else { return nil }
                return value
            }
            .joined(separator: " • ")
    }

    private var commentComposerPlaceholder: String {
        "Write a comment"
    }

    var body: some View {
        NativeMomentFullscreenScaffold(
            displayName: appState.currentUser?.displayName ?? "You",
            username: appState.currentUser?.username,
            avatarURL: appState.currentUser?.avatarUrl,
            avatarFallback: appState.currentUser?.displayName ?? appState.currentUser?.username ?? "V",
            timestampLabel: NativeAppState.relativeLabel(from: displayedMoment.visitedAtIso ?? displayedMoment.visitedDate),
            ratingMeta: ratingMeta,
            reviewText: displayedMoment.caption?.trimmingCharacters(in: .whitespacesAndNewlines),
            mediaUrl: mediaUrl,
            placeName: displayedMoment.place.name,
            placeMetaLine: placeMetaLine,
            isLiked: vibed,
            likeCount: vibinCount,
            isLikeBusy: isTogglingVibin,
            comments: comments,
            isCommentsLoading: isCommentsLoading,
            commentsErrorMessage: commentsErrorMessage,
            commentComposerPlaceholder: commentComposerPlaceholder,
            menuView: AnyView(
                Menu {
                    Button("Edit details") {
                        showEditMomentSheet = true
                    }
                    Button("Delete moment", role: .destructive) {
                        showDeletePostDialog = true
                    }
                } label: {
                    Image(systemName: "ellipsis")
                        .font(nativeAppFont(size: 14, weight: .black))
                        .foregroundStyle(.white.opacity(0.72))
                        .frame(width: 32, height: 32)
                        .background(Color.white.opacity(0.06))
                        .clipShape(Circle())
                }
                .buttonStyle(.plain)
            ),
            onClose: { dismiss() },
            onPlaceTap: { selectedPlace = displayedMoment.place },
            onToggleLike: { Task { await toggleVibin() } },
            onPostComment: { Task { await postComment() } },
            commentDraft: $commentDraft
        )
            .task {
                vibed = false
                vibinCount = displayedMoment.likeCount ?? 0
                await loadComments()
            }
            .confirmationDialog("Delete moment?", isPresented: $showDeletePostDialog, titleVisibility: .visible) {
                Button("Delete moment", role: .destructive) {
                    Task {
                        do {
                            try await appState.deleteMoment(id: displayedMoment.id)
                            dismiss()
                        } catch {
                            commentsErrorMessage = "Could not delete this moment right now."
                        }
                    }
                }
                Button("Cancel", role: .cancel) {}
            } message: {
                Text("This will remove this moment from your diary.")
            }
        .sheet(isPresented: $showEditMomentSheet) {
            NativeMomentEditSheet(moment: displayedMoment) { updated in
                editedMoment = updated
                vibinCount = updated.likeCount ?? vibinCount
            }
            .environmentObject(appState)
        }
        .fullScreenCover(item: $selectedPlace) { place in
            NativePlaceDetailScreen(
                initialPlace: place,
                source: NativeAnalyticsSource.profile,
                showsExplicitBackButton: true
            )
        }
    }

    private func loadComments() async {
        isCommentsLoading = true
        commentsErrorMessage = nil
        do {
            comments = try await appState.fetchComments(targetType: commentTargetType, targetId: commentTargetId)
        } catch {
            commentsErrorMessage = "Could not load comments right now."
        }
        isCommentsLoading = false
    }

    private func postComment() async {
        let trimmed = commentDraft.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return }
        do {
            let newComment = try await appState.createComment(
                targetType: commentTargetType,
                targetId: commentTargetId,
                body: trimmed,
                momentId: displayedMoment.id
            )
            comments.insert(newComment, at: 0)
            commentDraft = ""
            commentsErrorMessage = nil
            UIApplication.shared.sendAction(#selector(UIResponder.resignFirstResponder), to: nil, from: nil, for: nil)
        } catch {
            commentsErrorMessage = "Could not post comment right now."
        }
    }

    private func toggleVibin() async {
        guard !isTogglingVibin else { return }
        guard let receiverUserId = appState.currentUser?.id, !receiverUserId.isEmpty else { return }

        isTogglingVibin = true
        defer { isTogglingVibin = false }

        do {
            let response = try await appState.toggleMomentVibin(
                targetId: displayedMoment.id,
                receiverUserId: receiverUserId,
                momentId: displayedMoment.id
            )
            vibed = response.active
            vibinCount = response.count
            nativeHaptic(.selection)
        } catch {
            commentsErrorMessage = "Could not update likes right now."
        }
    }
}

private struct NativeMomentEditSheet: View {
    let moment: NativeMoment
    let onSaved: (NativeMoment) -> Void

    @EnvironmentObject private var appState: NativeAppState
    @Environment(\.dismiss) private var dismiss
    @State private var visitedDate: Date
    @State private var ratingLabel: String
    @State private var wouldRevisit: String
    @State private var visibility: String
    @State private var reviewText: String
    @State private var isSaving = false
    @State private var errorMessage: String?

    init(moment: NativeMoment, onSaved: @escaping (NativeMoment) -> Void) {
        self.moment = moment
        self.onSaved = onSaved
        let resolvedDate = NativeAppState.date(from: moment.visitedAtIso ?? moment.visitedDate) ?? Date()
        _visitedDate = State(initialValue: resolvedDate)
        _ratingLabel = State(initialValue: nativeNormalizedMomentRatingLabel(moment.ratingLabel))
        _wouldRevisit = State(initialValue: nativeNormalizedWouldRevisit(moment.wouldRevisit))
        _visibility = State(initialValue: nativeNormalizedMomentVisibility(moment.visibility))
        _reviewText = State(initialValue: moment.caption ?? "")
    }

    var body: some View {
        NavigationView {
            ScrollView(showsIndicators: false) {
                VStack(alignment: .leading, spacing: 18) {
                    NativeSurfaceCard {
                        VStack(alignment: .leading, spacing: 14) {
                            Text("Date")
                                .font(nativeAppFont(size: 12, weight: .black))
                                .foregroundStyle(.white.opacity(0.45))
                                .textCase(.uppercase)

                            DatePicker(
                                "Visited on",
                                selection: $visitedDate,
                                displayedComponents: .date
                            )
                            .datePickerStyle(.compact)
                            .labelsHidden()
                            .tint(nativeAccent)
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)
                    }

                    NativeSurfaceCard {
                        VStack(alignment: .leading, spacing: 14) {
                            Text("How was it?")
                                .font(nativeAppFont(size: 12, weight: .black))
                                .foregroundStyle(.white.opacity(0.45))
                                .textCase(.uppercase)

                            LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 10) {
                                ForEach(NativeMomentRatingChoice.allCases) { option in
                                    Button {
                                        ratingLabel = option.rawValue
                                    } label: {
                                        HStack(spacing: 8) {
                                            Image(systemName: option.icon)
                                                .font(nativeAppFont(size: 15, weight: .black))
                                            Text(option.label)
                                                .font(nativeAppFont(size: 14, weight: .black))
                                                .lineLimit(1)
                                        }
                                        .frame(maxWidth: .infinity)
                                        .padding(.vertical, 12)
                                        .padding(.horizontal, 8)
                                        .background(ratingLabel == option.rawValue ? nativeAccent : nativeSurfaceStrong)
                                        .foregroundStyle(ratingLabel == option.rawValue ? .black : .white)
                                        .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
                                    }
                                    .buttonStyle(.plain)
                                }
                            }
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)
                    }

                    NativeSurfaceCard {
                        VStack(alignment: .leading, spacing: 14) {
                            Text("Would revisit")
                                .font(nativeAppFont(size: 12, weight: .black))
                                .foregroundStyle(.white.opacity(0.45))
                                .textCase(.uppercase)

                            HStack(spacing: 10) {
                                revisitChip("Yes", value: "yes")
                                revisitChip("Maybe", value: "maybe")
                                revisitChip("No", value: "no")
                            }
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)
                    }

                    NativeSurfaceCard {
                        VStack(alignment: .leading, spacing: 14) {
                            Text("Post visibility")
                                .font(nativeAppFont(size: 12, weight: .black))
                                .foregroundStyle(.white.opacity(0.45))
                                .textCase(.uppercase)

                            VStack(spacing: 10) {
                                visibilityChip(title: "Public", subtitle: "Visible to everyone", value: "public")
                                visibilityChip(title: "Friends", subtitle: "Only mutual follows can see it", value: "friends")
                                visibilityChip(title: "Private", subtitle: "Only visible in your diary", value: "private")
                            }
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)
                    }

                    NativeSurfaceCard {
                        VStack(alignment: .leading, spacing: 14) {
                            Text("Review")
                                .font(nativeAppFont(size: 12, weight: .black))
                                .foregroundStyle(.white.opacity(0.45))
                                .textCase(.uppercase)

                            TextField("Cozy easy solid", text: $reviewText)
                                .textInputAutocapitalization(.words)
                                .autocorrectionDisabled()
                                .font(nativeAppFont(size: 16, weight: .medium))
                                .foregroundStyle(.white)
                                .padding(.horizontal, 16)
                                .padding(.vertical, 14)
                                .background(Color.white.opacity(0.04))
                                .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)
                    }

                    if let errorMessage {
                        NativeInlineError(message: errorMessage)
                    }

                    Button {
                        Task { await save() }
                    } label: {
                        HStack {
                            Spacer()
                            if isSaving {
                                ProgressView().tint(.black)
                            } else {
                                Text("Save changes")
                                    .font(nativeAppFont(size: 16, weight: .black))
                            }
                            Spacer()
                        }
                        .padding(.vertical, 16)
                        .background(nativeAccent)
                        .foregroundStyle(.black)
                        .clipShape(RoundedRectangle(cornerRadius: 20, style: .continuous))
                    }
                    .buttonStyle(.plain)
                    .disabled(isSaving)
                }
                .padding(.horizontal, 20)
                .padding(.top, 18)
                .padding(.bottom, 24)
            }
            .background(Color.black.ignoresSafeArea())
            .navigationTitle("Edit moment")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Close") {
                        dismiss()
                    }
                    .foregroundStyle(.white)
                }
            }
        }
        .navigationViewStyle(.stack)
    }

    private func revisitChip(_ label: String, value: String) -> some View {
        Button {
            wouldRevisit = value
        } label: {
            Text(label)
                .font(nativeAppFont(size: 13, weight: .black))
                .foregroundStyle(wouldRevisit == value ? .black : .white.opacity(0.78))
                .padding(.horizontal, 14)
                .padding(.vertical, 10)
                .background(wouldRevisit == value ? nativeAccent : Color.white.opacity(0.06))
                .clipShape(Capsule())
        }
        .buttonStyle(.plain)
    }

    private func visibilityChip(title: String, subtitle: String, value: String) -> some View {
        Button {
            visibility = value
        } label: {
            HStack(spacing: 12) {
                VStack(alignment: .leading, spacing: 4) {
                    Text(title)
                        .font(nativeAppFont(size: 14, weight: .black))
                        .foregroundStyle(visibility == value ? .black : .white)
                    Text(subtitle)
                        .font(nativeAppFont(size: 12, weight: .semibold))
                        .foregroundStyle(visibility == value ? .black.opacity(0.72) : .white.opacity(0.56))
                }
                Spacer()
                Image(systemName: visibility == value ? "checkmark.circle.fill" : "circle")
                    .font(nativeAppFont(size: 16, weight: .black))
                    .foregroundStyle(visibility == value ? .black : .white.opacity(0.4))
            }
            .padding(.horizontal, 14)
            .padding(.vertical, 13)
            .background(visibility == value ? nativeAccent : Color.white.opacity(0.06))
            .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
        }
        .buttonStyle(.plain)
    }

    private func save() async {
        isSaving = true
        errorMessage = nil
        defer { isSaving = false }

        do {
            let updated = try await appState.updateMomentDetails(
                id: moment.id,
                visitedDate: NativeCheckInScreen.isoDayString(from: visitedDate),
                caption: reviewText.trimmingCharacters(in: .whitespacesAndNewlines),
                ratingLabel: ratingLabel,
                wouldRevisit: wouldRevisit,
                visibility: visibility
            )
            onSaved(updated)
            dismiss()
        } catch {
            errorMessage = "Could not update this moment right now."
        }
    }
}

