private struct NativeDecisionDeckView: View {
    @EnvironmentObject private var appState: NativeAppState
    let options: [NativeDecisionSessionOption]
    let intent: NativeDecisionIntent?
    let deckHeight: CGFloat
    let cardHeight: CGFloat
    let onSwipe: (NativeDecisionSessionOption, String) -> Void

    @State private var dragOffset: CGSize = .zero
    @State private var isAnimatingAway = false
    @State private var selectedPlace: NativePlace?
    @State private var savedPlaceIds: Set<String> = []

    private var topOption: NativeDecisionSessionOption? {
        options.first
    }

    var body: some View {
        VStack(spacing: 18) {
            ZStack {
                ForEach(Array(options.prefix(3).enumerated().reversed()), id: \.element.id) { index, option in
                    NativeDecisionPlaceCard(
                        option: option,
                        intent: intent,
                        cardsLeft: options.count - index,
                        cardHeight: cardHeight,
                        onPlaceTap: {
                            guard index == 0 else { return }
                            nativeHaptic(.selection)
                            selectedPlace = nativeDecisionSessionPlaceAsPlace(option.place)
                        }
                    )
                    .scaleEffect(index == 0 ? 1 : (index == 1 ? 0.965 : 0.93))
                    .offset(
                        x: index == 0 ? dragOffset.width : CGFloat(index * 8),
                        y: index == 0 ? dragOffset.height : CGFloat(index * 20)
                    )
                    .rotationEffect(.degrees(index == 0 ? Double(dragOffset.width / 20) : 0))
                    .opacity(index == 0 || !isAnimatingAway ? 1 : 0.98)
                    .allowsHitTesting(index == 0)
                }
            }
            .frame(height: deckHeight)
            .gesture(
                DragGesture()
                    .onChanged { value in
                        dragOffset = value.translation
                    }
                    .onEnded { value in
                        guard let topOption else { return }
                        let threshold: CGFloat = 110
                        if value.translation.width <= -threshold {
                            completeSwipe(topOption, direction: "left")
                        } else if value.translation.width >= threshold {
                            completeSwipe(topOption, direction: "right")
                        } else {
                            withAnimation(.spring(response: 0.34, dampingFraction: 0.8)) {
                                dragOffset = .zero
                            }
                        }
                }
            )

            NavigationLink(
                destination: selectedPlace.map {
                    NativePlaceDetailScreen(initialPlace: $0, source: NativeAnalyticsSource.discovery)
                },
                isActive: Binding(
                    get: { selectedPlace != nil },
                    set: { isActive in
                        if !isActive {
                            selectedPlace = nil
                        }
                    }
                )
            ) {
                EmptyView()
            }
            .hidden()

            HStack(spacing: 18) {
                NativeDecisionActionButton(
                    title: "Pass",
                    icon: "arrow.uturn.backward.circle.fill",
                    fill: Color.white.opacity(0.08),
                    foreground: .white
                ) {
                    if let topOption {
                        completeSwipe(topOption, direction: "left")
                    }
                }

                NativeDecisionActionButton(
                    title: "Go Now",
                    icon: "sparkles",
                    fill: nativeAccent,
                    foreground: .black
                ) {
                    if let topOption {
                        completeSwipe(topOption, direction: "right")
                    }
                }
            }
        }
    }

    private func completeSwipe(_ option: NativeDecisionSessionOption, direction: String) {
        guard !isAnimatingAway else { return }
        if direction == "right" {
            appState.trackAnalytics(
                .lockRecommendation,
                properties: appState.decisionOptionAnalyticsProperties(
                    option,
                    source: NativeAnalyticsSource.homepage
                )
            )
        } else if direction == "left" {
            appState.trackAnalytics(
                .passRecommendation,
                properties: appState.decisionOptionAnalyticsProperties(
                    option,
                    source: NativeAnalyticsSource.homepage
                )
            )
        }
        isAnimatingAway = true
        nativeHaptic(direction == "right" ? .success : .selection)
        withAnimation(.easeIn(duration: 0.18)) {
            dragOffset = CGSize(width: direction == "right" ? 420 : -420, height: 24)
        }
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.18) {
            onSwipe(option, direction)
            dragOffset = .zero
            isAnimatingAway = false
        }
    }
}

