private struct NativeDecisionPlaceCard: View {
    let option: NativeDecisionSessionOption
    let intent: NativeDecisionIntent?
    let cardsLeft: Int
    let cardHeight: CGFloat
    let onPlaceTap: () -> Void

    private let cornerRadius: CGFloat = 34

    var body: some View {
        ZStack {
            RoundedRectangle(cornerRadius: cornerRadius, style: .continuous)
                .fill(Color.white.opacity(0.05))

            NativeDecisionCardMedia(url: option.place.thumbnailUrl)
                .overlay(
                    LinearGradient(
                        colors: [
                            Color.black.opacity(0.06),
                            Color.black.opacity(0.18),
                            Color.black.opacity(0.86),
                        ],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )

            VStack(alignment: .leading, spacing: 0) {
                HStack(alignment: .top) {
                    VStack(alignment: .leading, spacing: 8) {
                        Text(intent?.title.uppercased() ?? "DECISION")
                            .font(nativePixelAccentFont(size: 10))
                            .foregroundStyle(nativeAccent)

                        if let topBadge = option.place.topBadge {
                            Text(topBadge)
                                .font(nativeAppFont(size: 13, weight: .black))
                                .foregroundStyle(.black)
                                .padding(.horizontal, 10)
                                .padding(.vertical, 6)
                                .background(nativeAccent)
                                .clipShape(Capsule())
                        }
                    }

                    Spacer(minLength: 0)

                    Text("\(cardsLeft)")
                        .font(nativePixelAccentFont(size: 12))
                        .foregroundStyle(.black)
                        .padding(.horizontal, 14)
                        .padding(.vertical, 10)
                        .background(Color.white.opacity(0.92))
                        .clipShape(Capsule())
                }

                Spacer(minLength: 0)

                VStack(alignment: .leading, spacing: 10) {
                    if let vibe = option.place.vibeLabel, !vibe.isEmpty {
                        Text(vibe.uppercased())
                            .font(nativePixelAccentFont(size: 10))
                            .foregroundStyle(nativeAccent)
                    }

                    Button(action: onPlaceTap) {
                        Text(option.place.name)
                            .font(nativeAppFont(size: 32, weight: .black))
                            .foregroundStyle(.white)
                            .multilineTextAlignment(.leading)
                            .lineLimit(3)
                            .frame(maxWidth: .infinity, alignment: .leading)
                    }
                    .buttonStyle(.plain)

                    HStack(spacing: 8) {
                        if let neighborhood = option.place.neighborhood, !neighborhood.isEmpty {
                            Text(neighborhood)
                        }
                        if let travelTime = option.place.travelTimeLabel, !travelTime.isEmpty {
                            Text("•")
                            Text(travelTime)
                        }
                        if let price = option.place.priceRangeLabel, !price.isEmpty {
                            Text("•")
                            Text(price)
                        }
                    }
                    .font(nativeAppFont(size: 13, weight: .bold))
                    .foregroundStyle(.white.opacity(0.74))

                    if let reason = option.place.feelEvidenceLabel ?? option.reasonLabel, !reason.isEmpty {
                        Text(reason)
                            .font(nativeAppFont(size: 15, weight: .semibold))
                            .foregroundStyle(.white.opacity(0.9))
                            .fixedSize(horizontal: false, vertical: true)
                    }

                    if let confidence = option.place.traitConfidence {
                        Text(String(format: "Trait confidence %.0f%%", max(0, min(100, confidence * 100))))
                            .font(nativeAppFont(size: 11, weight: .bold))
                            .foregroundStyle(.white.opacity(0.58))
                    }
                }
            }
            .padding(24)
        }
        .frame(maxWidth: .infinity)
        .frame(height: cardHeight)
        .clipShape(RoundedRectangle(cornerRadius: cornerRadius, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: cornerRadius, style: .continuous)
                .stroke(nativeBorder, lineWidth: 1)
        )
        .shadow(color: nativeAccent.opacity(0.18), radius: 24, y: 12)
    }
}

