            .clipped()
        }
    }
}

private struct NativeDiscoverScreen: View {
    @EnvironmentObject private var appState: NativeAppState
    @State private var showLocationSheet = false
    @State private var showNotificationsSheet = false
    @State private var showDiscoveryScoreDebug = nativeDiscoveryScoreDebugMode
    @State private var showTodayRecommendationDebug = false
    @State private var selectedDebugPlace: NativePlace?
    @State private var selectedInspirationMedia: NativeDiscoveryInspirationMedia?
    @State private var selectedDiscoveryTabId = "today"
    @State private var isLocationAccessBannerDismissed = false
    @State private var discoveryScrollOffsets: [String: CGFloat] = [:]

    private let discoveryChromeTopPadding: CGFloat = 12
    private let discoveryChromeHeaderHeight: CGFloat = 44
    private let discoveryChromeSpacing: CGFloat = 20
    private let discoveryChromeTabsHeight: CGFloat = 34
    private let discoveryChromeBottomPadding: CGFloat = 0

    private var discoveryTabs: [NativeDiscoveryCategoryTab] {
        nativeDiscoveryFilterTabs(for: appState.selectedInterests)
    }

    private var selectedDiscoveryPlaces: [NativePlace] {
        discoveryPlaces(for: selectedDiscoveryTabId)
    }

    private var discoveryScoreCounts: (yourVibe: Int, strongFit: Int, couldHit: Int, softMaybe: Int, unscored: Int) {
        selectedDiscoveryPlaces.reduce(into: (0, 0, 0, 0, 0)) { result, place in
            guard let badge = nativeCompatibilityBadge(for: place.similarityStat) else {
                result.4 += 1
                return
            }
            switch badge.label {
            case "Your vibe":
                result.0 += 1
            case "Strong fit":
                result.1 += 1
            case "Could hit":
                result.2 += 1
            default:
                result.3 += 1
            }
        }
    }

    private var discoveryExpandedChromeHeight: CGFloat {
        discoveryChromeTopPadding
            + discoveryChromeHeaderHeight
            + discoveryChromeSpacing
            + discoveryChromeTabsHeight
            + discoveryChromeBottomPadding
    }

    private var discoveryCollapsedChromeHeight: CGFloat {
        discoveryChromeTopPadding
            + discoveryChromeTabsHeight
            + discoveryChromeBottomPadding
    }

    private var activeDiscoveryScrollOffset: CGFloat {
        discoveryScrollOffsets[selectedDiscoveryTabId] ?? 0
    }

    private var discoveryChromeCollapseDistance: CGFloat {
        min(activeDiscoveryScrollOffset, discoveryChromeHeaderHeight + discoveryChromeSpacing)
    }

    private func analyticsPropertiesForDiscoveryTab(_ tabId: String) -> [String: Any] {
        let tab = discoveryTabs.first { $0.id == tabId }
        return [
            "tab_id": tabId,
            "tab_name": tab?.label ?? tabId,
        ]
    }

    var body: some View {
        GeometryReader { proxy in
            let contentWidth = proxy.size.width - 32

            ZStack(alignment: .top) {
                // Only the content pages swipe horizontally. The shared chrome
                // above stays in place, so the interaction feels like switching
                // tab content instead of changing the whole screen.
                TabView(selection: $selectedDiscoveryTabId) {
                    ForEach(discoveryTabs) { tab in
                        NativeDiscoveryTabPage(
                            tab: tab,
                            places: discoveryPlaces(for: tab.id),
                            inspirationMedia: tab.id == "all" ? appState.discoveryInspirationMedia : [],
                            contentWidth: contentWidth,
                            topInset: discoveryExpandedChromeHeight,
                            shouldShowLocationAccessCTA: appState.shouldShowLocationAccessCTA && !isLocationAccessBannerDismissed,
                            onLocationAccessTap: {
                                appState.requestLocationAccessOrOpenSettings()
                            },
                            onLocationAccessDismiss: {
                                withAnimation(.easeOut(duration: 0.2)) {
                                    isLocationAccessBannerDismissed = true
                                }
                            },
                            onPlaceDebugTap: { place in selectedDebugPlace = place },
                            onTodayDebugTap: {
                                if nativeTodayRecommendationScoreDebugMode {
                                    showTodayRecommendationDebug = true
                                }
                            },
                            onSelectTab: { tabId in
                                withAnimation(.easeOut(duration: 0.22)) {
                                    selectedDiscoveryTabId = tabId
                                }
                            },
                            onInspirationTap: { media in
                                appState.trackAnalytics(
                                    .clickForYourInspiration,
                                    properties: appState.placeAnalyticsProperties(
                                        media.place,
                                        source: NativeAnalyticsSource.discovery,
                                        extra: [
                                            "media_id": media.id,
                                            "moment_id": media.momentId ?? "",
                                            "traveler_id": media.traveler.id,
                                            "traveler_username": media.traveler.username,
                                        ]
                                    )
                                )
                                selectedInspirationMedia = media
                            },
                            onScrollOffsetChange: { offset in
                                discoveryScrollOffsets[tab.id] = offset
                            }
                        )
                        .environmentObject(appState)
                        .tag(tab.id)
                    }
                }
                .tabViewStyle(.page(indexDisplayMode: .never))

                NativeDiscoverySharedChrome(
                    locationLabel: appState.currentLocationLabelForUI,
                    tabs: discoveryTabs,
                    selectedTabId: $selectedDiscoveryTabId,
                    expandedHeight: discoveryExpandedChromeHeight,
                    collapsedHeight: discoveryCollapsedChromeHeight,
                    collapsedAmount: discoveryChromeCollapseDistance,
                    onLocationTap: {
                        guard appState.locationPermissionState != .authorized else { return }
                        showLocationSheet = true
                    },
                    onNotificationsTap: { showNotificationsSheet = true }
                )
            }
        }
        .background(Color.black.ignoresSafeArea())
        .overlay(alignment: .bottomTrailing) {
            if showDiscoveryScoreDebug {
                NativeDiscoveryScoreDebugPanel(
                    totalLoaded: appState.discoveryPlaces.count,
                    mustVisitCount: discoveryScoreCounts.yourVibe,
                    fitsYouCount: discoveryScoreCounts.strongFit,
                    worthALookCount: discoveryScoreCounts.couldHit,
                    maybeCount: discoveryScoreCounts.softMaybe,
                    unscoredCount: discoveryScoreCounts.unscored,
                    onToggle: {
                        showDiscoveryScoreDebug.toggle()
                    }
                )
                .padding(.trailing, 16)
                .padding(.bottom, appState.showFloatingTabBar ? (appState.shouldShowUnlockVibeCTA ? 184 : 100) : 22)
            } else if nativeDiscoveryScoreDebugMode {
                Button {
                    showDiscoveryScoreDebug.toggle()
                } label: {
                    Image(systemName: "ladybug.fill")
                        .font(nativeAppFont(size: 17, weight: .black))
                        .foregroundStyle(.black)
                        .frame(width: 46, height: 46)
                        .background(nativeAccent)
                        .clipShape(Circle())
                }
                .buttonStyle(.plain)
                .padding(.trailing, 16)
                .padding(.bottom, appState.showFloatingTabBar ? (appState.shouldShowUnlockVibeCTA ? 184 : 100) : 22)
            }
        }
        .safeAreaInset(edge: .bottom) {
            if appState.shouldShowUnlockVibeCTA {
                HStack {
                    Spacer()
                    Button {
                        if appState.currentUser == nil {
                            appState.presentAuthGate(
                                reason: "Log in to unlock your vibe and personalize discovery.",
                                postAuthAction: .openPreferenceSetup
                            )
                        } else {
                            appState.presentPreferenceSetup()
                        }
                    } label: {
                        HStack(spacing: 12) {
                            VStack(alignment: .leading, spacing: 3) {
                                Text("Unlock your vibe")
                                    .font(nativeAppFont(size: 15, weight: .black))
                                    .foregroundStyle(.white)
                                Text("Let AI understand your vibes & taste")
                                    .font(nativeAppFont(size: 12, weight: .semibold))
                                    .foregroundStyle(.white.opacity(0.58))
                            }
                            Spacer(minLength: 0)
                            Text("Start")
                                .font(nativeAppFont(size: 14, weight: .black))
                                .foregroundStyle(.black)
                                .padding(.horizontal, 14)
                                .padding(.vertical, 10)
                                .background(nativeAccent)
                                .clipShape(Capsule())
                        }
                        .padding(.horizontal, 16)
                        .padding(.vertical, 14)
                        .background(
                            RoundedRectangle(cornerRadius: 24, style: .continuous)
                                .fill(Color(red: 19 / 255, green: 19 / 255, blue: 22 / 255).opacity(0.96))
                                .overlay(
                                    RoundedRectangle(cornerRadius: 24, style: .continuous)
                                        .stroke(nativeBorder, lineWidth: 1)
                                )
                        )
                    }
                    .buttonStyle(.plain)
                    Spacer()
                }
                .padding(.horizontal, 16)
                .padding(.bottom, appState.showFloatingTabBar ? 96 : 18)
            }
        }
        .navigationBarHidden(true)
        .sheet(isPresented: $showLocationSheet) {
            NativeLocationPickerSheet(
                selectedLocation: appState.selectedLocation,
                availableLocations: nativeLocationOptions,
                suggestedLocations: nativeLocationOptions,
                onSelect: { location in
                    showLocationSheet = false
                    Task { await appState.updateLocation(to: location) }
                }
            )
        }
        .sheet(isPresented: $showNotificationsSheet) {
            NavigationView {
                NativeNotificationsSheet()
            }
            .navigationViewStyle(.stack)
        }
        .sheet(isPresented: $appState.showDecisionLocationPermissionSheet) {
            NativeDecisionLocationPermissionSheet(
                onTurnOnLocation: {
                    appState.showDecisionLocationPermissionSheet = false
                    appState.openSystemSettings()
                },
                onDismiss: {
                    appState.showDecisionLocationPermissionSheet = false
                }
            )
        }
        .sheet(item: $selectedDebugPlace) { place in
            NavigationView {
                NativePlaceScoreDebugSheet(place: place)
            }
            .navigationViewStyle(.stack)
        }
        .sheet(isPresented: $showTodayRecommendationDebug) {
            NavigationView {
                NativeTodayRecommendationDebugSheet()
            }
            .navigationViewStyle(.stack)
        }
        .fullScreenCover(item: $selectedInspirationMedia) { media in
            NativeDiscoveryInspirationFullscreen(media: media)
        }
        .onAppear {
            appState.trackAnalytics(
                .viewDiscovery,
                properties: analyticsPropertiesForDiscoveryTab(selectedDiscoveryTabId)
            )
        }
        .onChange(of: selectedDiscoveryTabId) { tabId in
            appState.trackAnalytics(
                .switchDiscoveryTab,
                properties: analyticsPropertiesForDiscoveryTab(tabId)
            )
        }
        .onChange(of: appState.discoveryPlaces.map(\.id)) { _ in
            if !discoveryTabs.contains(where: { $0.id == selectedDiscoveryTabId }) {
                selectedDiscoveryTabId = "today"
            }
        }
        .onChange(of: appState.selectedInterests) { _ in
            if !discoveryTabs.contains(where: { $0.id == selectedDiscoveryTabId }) {
                selectedDiscoveryTabId = "today"
            }
        }
        .onChange(of: appState.locationPermissionState) { state in
            if state == .authorized {
                isLocationAccessBannerDismissed = true
            }
        }
        .refreshable {
            await appState.refreshDiscovery()
        }
    }

    private func discoveryPlaces(for tabId: String) -> [NativePlace] {
        guard tabId != "today" else { return [] }
        guard tabId != "all" else { return appState.discoveryPlaces }
        return appState.discoveryPlaces.filter { nativePlaceMatchesDiscoveryFilter($0, filterId: tabId) }
    }
}

private struct NativeDiscoveryTabPage: View {
    @EnvironmentObject private var appState: NativeAppState
    let tab: NativeDiscoveryCategoryTab
    let places: [NativePlace]
    let inspirationMedia: [NativeDiscoveryInspirationMedia]
    let contentWidth: CGFloat
    let topInset: CGFloat
    let shouldShowLocationAccessCTA: Bool
    let onLocationAccessTap: () -> Void
    let onLocationAccessDismiss: () -> Void
    let onPlaceDebugTap: (NativePlace) -> Void
    let onTodayDebugTap: () -> Void
    let onSelectTab: (String) -> Void
    let onInspirationTap: (NativeDiscoveryInspirationMedia) -> Void
    let onScrollOffsetChange: (CGFloat) -> Void

    private var scrollCoordinateSpace: String {
        "discovery-scroll-\(tab.id)"
    }

    private var balancedColumns: (left: [NativeDiscoveryColumnItem], right: [NativeDiscoveryColumnItem]) {
        buildNativeBalancedDiscoveryColumns(places: places)
    }

    private var firstPagePlaces: [NativePlace] {
        guard !inspirationMedia.isEmpty else { return places }
        return Array(places.prefix(18))
    }

    private var remainingPlacesAfterInspiration: [NativePlace] {
        guard !inspirationMedia.isEmpty, places.count > 18 else { return [] }
        return Array(places.dropFirst(18))
    }

    private var firstPageColumns: (left: [NativeDiscoveryColumnItem], right: [NativeDiscoveryColumnItem]) {
        buildNativeBalancedDiscoveryColumns(places: firstPagePlaces)
    }

    private var remainingColumns: (left: [NativeDiscoveryColumnItem], right: [NativeDiscoveryColumnItem]) {
        buildNativeBalancedDiscoveryColumns(places: remainingPlacesAfterInspiration)
    }

    private var bottomContentSpacer: CGFloat {
        // The floating home tab bar is rendered via `safeAreaInset` at the TabView level, but SwiftUI
        // doesn't always inset nested ScrollViews the way we expect. Add an explicit spacer so the
        // last discovery tile never gets covered.
        guard appState.showFloatingTabBar else { return 28 }
        // When the Unlock Vibe CTA is present, it sits above the floating tab bar and needs extra room.
        return appState.shouldShowUnlockVibeCTA ? 220 : 120
    }

    var body: some View {
        ScrollView(showsIndicators: false) {
            LazyVStack(alignment: .leading, spacing: 16) {
                GeometryReader { proxy in
                    Color.clear.preference(
                        key: NativeDiscoveryScrollOffsetPreferenceKey.self,
                        value: [tab.id: max(0, -proxy.frame(in: .named(scrollCoordinateSpace)).minY)]
                    )
                }
                .frame(height: 0)

                Color.clear
                    .frame(height: max(topInset - 18, 0))

                if tab.id == "today" {
                    NativeTodayPickTabContent(
                        contentWidth: contentWidth,
                        onMoreLikeThis: {
                            nativeHaptic(.selection)
                            onSelectTab("all")
                        },
                        onDebugTap: onTodayDebugTap
                    )
                } else if let discoveryErrorMessage = appState.discoveryErrorMessage {
                    NativeInlineError(message: discoveryErrorMessage)
                } else if shouldShowLocationAccessCTA {
                    NativeLocationAccessCard(
                        onAllowAccess: onLocationAccessTap,
                        onDismiss: onLocationAccessDismiss
                    )
                } else if appState.isDiscoveryLoading && places.isEmpty {
                    NativeSurfaceCard {
                        VStack(alignment: .leading, spacing: 8) {
                            Text("Cooking your picks")
                                .font(nativeAppFont(size: 11, weight: .black))
                                .foregroundStyle(nativeAccent.opacity(0.9))
                                .textCase(.uppercase)
                            Text("We're cooking places for you in \(appState.selectedLocation.label).")
                                .font(nativeAppFont(size: 20, weight: .black))
                                .foregroundStyle(.white)
                            Text("Lining up the first places that fit your current taste.")
                                .font(nativeAppFont(size: 14, weight: .medium))
                                .foregroundStyle(.white.opacity(0.58))
                        }
                    }
                } else if places.isEmpty {
                    NativeSurfaceCard {
                        VStack(alignment: .leading, spacing: 8) {
                            Text(tab.id == "all" ? "No places yet for \(appState.selectedLocation.label)." : "No \(tab.label.lowercased()) spots yet in \(appState.selectedLocation.label).")
                                .font(nativeAppFont(size: 20, weight: .black))
                                .foregroundStyle(.white)
                            Text("Tap another tab to explore a different vibe.")
                                .font(nativeAppFont(size: 14, weight: .medium))
                                .foregroundStyle(.white.opacity(0.58))
                        }
                    }
                } else {
                    NativeDiscoveryMasonryView(
                        leftItems: inspirationMedia.isEmpty ? balancedColumns.left : firstPageColumns.left,
                        rightItems: inspirationMedia.isEmpty ? balancedColumns.right : firstPageColumns.right,
                        containerWidth: contentWidth,
                        onDebugTap: onPlaceDebugTap
                    )

                    if !inspirationMedia.isEmpty {
                        NativeDiscoveryInspirationSection(
                            media: inspirationMedia,
                            contentWidth: contentWidth,
                            onMediaTap: onInspirationTap
                        )
                        .padding(.top, 4)
                    }

                    if !remainingPlacesAfterInspiration.isEmpty {
                        NativeDiscoveryMasonryView(
                            leftItems: remainingColumns.left,
                            rightItems: remainingColumns.right,
                            containerWidth: contentWidth,
                            onDebugTap: onPlaceDebugTap
                        )
                    }

                    if appState.isDiscoveryLoadingMore {
                        HStack {
                            Spacer()
                            ProgressView()
                                .tint(nativeAccent)
                            Spacer()
                        }
                        .padding(.top, 8)
                    }
                }

                Color.clear
                    .frame(height: bottomContentSpacer)
            }
            .frame(width: contentWidth, alignment: .leading)
            .padding(.horizontal, 16)
            .padding(.top, 6)
            .padding(.bottom, 18)
        }
        .coordinateSpace(name: scrollCoordinateSpace)
        .background(Color.black)
        .onPreferenceChange(NativeDiscoveryScrollOffsetPreferenceKey.self) { offsets in
            if let offset = offsets[tab.id] {
                onScrollOffsetChange(offset)
            }
        }
        .refreshable {
            await appState.refreshDiscovery()
        }
    }
}

private struct NativeTodayPickTabContent: View {
    @EnvironmentObject private var appState: NativeAppState
    let contentWidth: CGFloat
    let onMoreLikeThis: () -> Void
    let onDebugTap: () -> Void
    @State private var hasLoadedInitialPick = false
    @State private var isRefining = false
    @State private var selectedFocusId = nativeTodayRefineOptions.first?.id ?? "coffee"

    var body: some View {
        VStack(alignment: .leading, spacing: 16) {
            VStack(alignment: .leading, spacing: 8) {
                Text("Today's Pick")
                    .font(nativeAppFont(size: 34, weight: .black))
                    .tracking(-1.2)
                    .foregroundStyle(.white)
                Text("One spot that fits your vibe right now.")
                    .font(nativeAppFont(size: 14, weight: .semibold))
                    .foregroundStyle(.white.opacity(0.58))
            }
            .frame(width: contentWidth, alignment: .leading)

            if appState.isTodayRecommendationLoading && appState.todayRecommendation == nil {
                NativeTodayHeroSkeletonCard(contentWidth: contentWidth)
            }

            if let message = appState.todayRecommendationErrorMessage {
                NativeInlineError(message: message)
            }

            if let recommendation = appState.todayRecommendation {
                NavigationLink {
                    NativePlaceDetailScreen(initialPlace: recommendation.place, source: NativeAnalyticsSource.todaysPick)
                } label: {
                    NativeTodayHeroPlaceCard(
                        recommendation: recommendation,
                        contentWidth: contentWidth,
                        onDebugTap: nativeTodayRecommendationScoreDebugMode ? onDebugTap : nil
                    )
                }
                .buttonStyle(.plain)
                .simultaneousGesture(TapGesture().onEnded {
                    nativeHaptic(.light)
                })

                NativeSurfaceCard {
                    VStack(alignment: .leading, spacing: 10) {
                        Text("Why this?")
                            .font(nativeAppFont(size: 18, weight: .black))
                            .foregroundStyle(.white)
                        Text(recommendation.todayReason)
                            .font(nativeAppFont(size: 14, weight: .semibold))
                            .lineSpacing(3)
                            .foregroundStyle(.white.opacity(0.72))
                            .fixedSize(horizontal: false, vertical: true)
                    }
                }
                .frame(width: contentWidth)

                HStack(spacing: 10) {
                    NativeTodayActionButton(
                        title: "Try Another",
                        icon: "shuffle",
                        isPrimary: false
                    ) {
                        nativeHaptic(.selection)
                        withAnimation(.spring(response: 0.32, dampingFraction: 0.86)) {
                            isRefining.toggle()
                        }
                    }

                    NativeTodayActionButton(
                        title: "More like this",
                        icon: "square.grid.2x2.fill",
                        isPrimary: false,
                        action: onMoreLikeThis
                    )
                }
                .frame(width: contentWidth)
            }

            if isRefining {
                VStack(alignment: .leading, spacing: 12) {
                    ScrollView(.horizontal, showsIndicators: false) {
                        HStack(spacing: 8) {
                            ForEach(nativeTodayRefineOptions) { option in
                                Button {
                                    nativeHaptic(.selection)
                                    selectedFocusId = option.id
                                } label: {
                                    HStack(spacing: 7) {
                                        Image(systemName: option.icon)
                                            .font(nativeAppFont(size: 12, weight: .black))
                                        Text(option.label)
                                            .font(nativeAppFont(size: 13, weight: .black))
                                    }
                                    .foregroundStyle(selectedFocusId == option.id ? .black : .white)
                                    .padding(.horizontal, 13)
                                    .padding(.vertical, 10)
                                    .background(selectedFocusId == option.id ? nativeAccent : Color.white.opacity(0.09))
                                    .clipShape(Capsule())
                                }
                                .buttonStyle(.plain)
                            }
                        }
                    }
                    .frame(width: contentWidth, alignment: .leading)

                    Button {
                        nativeHaptic(.medium)
                        Task {
                            await appState.loadTodayRecommendation(focus: selectedFocusId)
                        }
                    } label: {
                        HStack(spacing: 9) {
                            if appState.isTodayRecommendationLoading {
                                ProgressView()
                                    .tint(.black)
                            } else {
                                Image(systemName: "wand.and.stars")
                                    .font(nativeAppFont(size: 14, weight: .black))
                            }
                            Text("Generate")
                                .font(nativeAppFont(size: 15, weight: .black))
                        }
                        .foregroundStyle(.black)
                        .frame(maxWidth: .infinity)
                        .padding(.vertical, 14)
                        .background(nativeAccent)
                        .clipShape(Capsule())
                    }
                    .buttonStyle(.plain)
                    .disabled(appState.isTodayRecommendationLoading)
                    .opacity(appState.isTodayRecommendationLoading ? 0.72 : 1)
                }
                .frame(width: contentWidth, alignment: .leading)
                .transition(.move(edge: .top).combined(with: .opacity))
            }
        }
        .frame(width: contentWidth, alignment: .leading)
        .task {
            guard !hasLoadedInitialPick else { return }
            hasLoadedInitialPick = true
            await appState.loadTodayRecommendation()
        }
    }
}

