private struct NativeConfettiBurstView: View {
    private let pieces: [(x: CGFloat, y: CGFloat, color: Color, rotation: Double, size: CGFloat)] = [
        (0.14, 0.06, nativeAccent, -18, 9),
        (0.22, 0.12, Color.white, 28, 7),
        (0.31, 0.08, Color(red: 120 / 255, green: 1, blue: 160 / 255), -34, 8),
        (0.68, 0.07, nativeAccent.opacity(0.9), 22, 9),
        (0.76, 0.13, Color.white.opacity(0.9), -20, 7),
        (0.84, 0.09, Color(red: 120 / 255, green: 1, blue: 160 / 255), 30, 8),
    ]

    @State private var animate = false

    var body: some View {
        GeometryReader { proxy in
            ZStack {
                ForEach(Array(pieces.enumerated()), id: \.offset) { index, piece in
                    RoundedRectangle(cornerRadius: 2, style: .continuous)
                        .fill(piece.color)
                        .frame(width: piece.size, height: piece.size * 1.5)
                        .rotationEffect(.degrees(animate ? piece.rotation : 0))
                        .position(
                            x: proxy.size.width * piece.x,
                            y: proxy.size.height * (animate ? piece.y + 0.13 : piece.y)
                        )
                        .opacity(animate ? 0 : 1)
                        .animation(
                            .easeOut(duration: 0.9).delay(Double(index) * 0.03),
                            value: animate
                        )
                }
            }
            .onAppear {
                animate = false
                DispatchQueue.main.async {
                    animate = true
                }
            }
        }
        .allowsHitTesting(false)
    }
}

private struct NativeSavedScreen: View {
    @Environment(\.dismiss) private var dismiss
    @EnvironmentObject private var appState: NativeAppState
    let showsDismissButton: Bool
    @State private var now = Date()

    private let timer = Timer.publish(every: 60, on: .main, in: .common).autoconnect()

    init(showsDismissButton: Bool = false) {
        self.showsDismissButton = showsDismissButton
    }

    private var savedItems: [NativeExperimentalSavedItem] {
        appState.savedEntries.compactMap { entry in
            guard
                let savedAt = NativeAppState.date(from: entry.savedAtIso),
                let expiresAt = NativeAppState.date(from: entry.expiresAtIso),
                expiresAt > now
            else {
                return nil
            }

            return NativeExperimentalSavedItem(
                id: entry.id,
                place: entry.place,
                savedAt: savedAt,
                expiresAt: expiresAt,
                sourceLabel: entry.sourceLabel,
                previewAssetName: nil
            )
        }
        .sorted { $0.expiresAt < $1.expiresAt }
    }

    var body: some View {
        GeometryReader { geometry in
            ZStack(alignment: .top) {
                Color.black.ignoresSafeArea()

                ScrollView(showsIndicators: false) {
                    VStack(alignment: .leading, spacing: 18) {
                        header
                            .padding(.horizontal, 18)
                            .padding(.top, geometry.safeAreaInsets.top + 6)

                        savedContent
                            .padding(.horizontal, 20)
                    }
                    .frame(maxWidth: .infinity, alignment: .topLeading)
                    .padding(.bottom, 132)
                }
            }
        }
        .navigationBarHidden(true)
        .onAppear {
            appState.trackAnalytics(.viewSaved)
            if appState.savedEntries.isEmpty && appState.currentUser != nil {
                Task { await appState.refreshSavedContent() }
            }
        }
        .refreshable {
            await appState.refreshSavedContent()
        }
        .onReceive(timer) { value in
            now = value
        }
    }

    @ViewBuilder
    private var savedContent: some View {
        if appState.currentUser == nil {
            NativeGuestPromptCard(
                eyebrow: "Saved",
                title: "Save places once you're signed in.",
                message: "Log in to keep daily picks and friend drops for 48 hours.",
                cta: "Log in"
            )
        } else if let savedErrorMessage = appState.savedErrorMessage {
            NativeInlineError(message: savedErrorMessage)
        } else if savedItems.isEmpty {
            NativeSurfaceCard {
                Text("No active saved places right now.")
                    .font(nativeAppFont(size: 15, weight: .medium))
                    .foregroundStyle(.white.opacity(0.64))
            }
        } else {
            LazyVStack(spacing: 16) {
                ForEach(savedItems) { item in
                    NavigationLink {
                        NativePlaceDetailScreen(initialPlace: item.place, source: NativeAnalyticsSource.saved)
                    } label: {
                        NativeSavedDropCard(item: item, now: now)
                    }
                    .buttonStyle(.plain)
                }
            }
        }
    }

    private var header: some View {
        HStack(alignment: .center, spacing: 12) {
            if showsDismissButton {
                Button {
                    dismiss()
                } label: {
                    Image(systemName: "chevron.left")
                        .font(nativeAppFont(size: 18, weight: .bold))
                        .foregroundStyle(.white)
                        .frame(width: 46, height: 46)
                        .background(nativeSurface)
                        .clipShape(Circle())
                }
                .buttonStyle(.plain)
            } else {
                Color.clear
                    .frame(width: 46, height: 46)
            }

            Spacer(minLength: 0)

            Text("SAVED")
                .font(nativePixelAccentFont(size: 18))
                .foregroundStyle(.white)

            Spacer(minLength: 0)

            Color.clear
                .frame(width: 46, height: 46)
        }
        .frame(height: 46)
    }
}

