private struct NativeSavedDropCard: View {
    let item: NativeExperimentalSavedItem
    let now: Date

    private var remainingInterval: TimeInterval {
        max(0, item.expiresAt.timeIntervalSince(now))
    }

    private var progress: Double {
        let total: TimeInterval = 48 * 3600
        return min(max(remainingInterval / total, 0), 1)
    }

    private var progressColor: Color {
        remainingInterval <= 3 * 3600 ? Color(red: 1, green: 84/255, blue: 84/255) : nativeAccent
    }

    private var timeLeftText: String {
        let interval = Int(remainingInterval)
        let hours = interval / 3600
        let minutes = (interval % 3600) / 60
        return "\(hours)h \(minutes)m left"
    }

    private var imageUrl: String? {
        item.place.image ?? item.place.images?.first
    }

    var body: some View {
        GeometryReader { geometry in
            let cornerRadius: CGFloat = 28

            ZStack(alignment: .topLeading) {
                NativeSavedBackgroundMedia(
                    imageUrl: imageUrl,
                    fallbackAssetName: item.previewAssetName
                )
                .frame(width: geometry.size.width, height: geometry.size.height)
                .clipShape(RoundedRectangle(cornerRadius: cornerRadius, style: .continuous))
                .overlay(
                    LinearGradient(
                        colors: [
                            Color.black.opacity(0.08),
                            Color.black.opacity(0.2),
                            Color.black.opacity(0.88),
                        ],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                    .clipShape(RoundedRectangle(cornerRadius: cornerRadius, style: .continuous))
                )

                VStack(alignment: .leading, spacing: 14) {
                    HStack(alignment: .center, spacing: 10) {
                        Text(item.sourceLabel)
                            .font(nativeAppFont(size: 13, weight: .semibold))
                            .foregroundStyle(.white.opacity(0.88))
                            .lineLimit(1)

                        Spacer(minLength: 0)

                        Text(timeLeftText)
                            .font(nativeAppFont(size: 12, weight: .bold))
                            .foregroundStyle(progressColor)
                            .padding(.horizontal, 10)
                            .padding(.vertical, 8)
                            .background(Color.black.opacity(0.28))
                            .clipShape(Capsule())
                    }

                    Spacer(minLength: 0)

                    VStack(alignment: .leading, spacing: 8) {
                        if let vibe = item.place.tags?.first, !vibe.isEmpty {
                            Text(vibe.uppercased())
                                .font(nativePixelAccentFont(size: 10))
                                .foregroundStyle(nativeAccent)
                        }

                        Text(item.place.name)
                            .font(nativeAppFont(size: 28, weight: .black))
                            .foregroundStyle(.white)
                            .lineLimit(2)

                        Text(item.place.location)
                            .font(nativeAppFont(size: 13, weight: .semibold))
                            .foregroundStyle(.white.opacity(0.74))
                            .lineLimit(2)

                        if let hook = item.place.hook, !hook.isEmpty {
                            Text(hook)
                                .font(nativeAppFont(size: 14, weight: .medium))
                                .foregroundStyle(.white.opacity(0.84))
                                .lineLimit(3)
                        }
                    }
                }
                .padding(20)
                .frame(width: geometry.size.width, height: geometry.size.height, alignment: .topLeading)
            }
            .overlay(
                NativeSavedExpiryBorder(progress: progress, tint: progressColor, cornerRadius: cornerRadius)
            )
            .overlay(
                RoundedRectangle(cornerRadius: cornerRadius, style: .continuous)
                    .stroke(nativeBorder, lineWidth: 1)
            )
        }
        .aspectRatio(16.0 / 9.0, contentMode: .fit)
    }
}

private struct NativeSavedBackgroundMedia: View {
    let imageUrl: String?
    let fallbackAssetName: String?

    var body: some View {
        ZStack {
            if let fallbackAssetName, UIImage(named: fallbackAssetName) != nil {
                Image(fallbackAssetName)
                    .resizable()
                    .scaledToFill()
                    .frame(maxWidth: .infinity, maxHeight: .infinity)
            } else {
                LinearGradient(
                    colors: [
                        Color(red: 24 / 255, green: 24 / 255, blue: 28 / 255),
                        Color(red: 14 / 255, green: 14 / 255, blue: 16 / 255)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            }

            if imageUrl != nil {
                NativeRemoteImage(url: imageUrl)
                    .frame(maxWidth: .infinity, maxHeight: .infinity)
            }
        }
        .clipped()
    }
}

private struct NativeSavedExpiryBorder: View {
    let progress: Double
    let tint: Color
    let cornerRadius: CGFloat

    var body: some View {
        GeometryReader { geometry in
            let clamped = min(max(progress, 0.001), 1)
            let rect = CGRect(origin: .zero, size: geometry.size)
            let point = nativeRoundedRectProgressPoint(progress: clamped, in: rect, cornerRadius: cornerRadius)

            TimelineView(.animation) { timeline in
                let pulse = 0.78 + 0.22 * (0.5 + 0.5 * sin(timeline.date.timeIntervalSinceReferenceDate * 4.4))

                ZStack {
                    NativeRoundedRectProgressShape(cornerRadius: cornerRadius)
                        .stroke(Color.white.opacity(0.12), lineWidth: 3)

                    NativeRoundedRectProgressShape(cornerRadius: cornerRadius)
                        .trim(from: 0, to: clamped)
                        .stroke(
                            tint,
                            style: StrokeStyle(lineWidth: 4, lineCap: .round, lineJoin: .round)
                        )

                    ZStack {
                        Circle()
                            .fill(tint)
                            .frame(width: 9, height: 9)
                            .shadow(color: tint.opacity(0.95), radius: 12 * pulse)

                        Circle()
                            .fill(tint.opacity(0.48))
                            .frame(width: 24 * pulse, height: 24 * pulse)
                            .blur(radius: 3)

                        Circle()
                            .fill(tint.opacity(0.92))
                            .frame(width: 3.2, height: 3.2)
                            .offset(x: 10 * pulse, y: -8 * pulse)

                        Circle()
                            .fill(tint.opacity(0.76))
                            .frame(width: 2.4, height: 2.4)
                            .offset(x: -9 * pulse, y: -9 * pulse)

                        Circle()
                            .fill(tint.opacity(0.7))
                            .frame(width: 2.2, height: 2.2)
                            .offset(x: 8 * pulse, y: 10 * pulse)
                    }
                    .position(point)
                    .blendMode(.screen)
                    .allowsHitTesting(false)
                }
            }
        }
    }
}

private struct NativeRoundedRectProgressShape: Shape {
    let cornerRadius: CGFloat

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let radius = min(cornerRadius, min(rect.width, rect.height) / 2)
        let minX = rect.minX
        let maxX = rect.maxX
        let minY = rect.minY
        let maxY = rect.maxY
        let midX = rect.midX

        path.move(to: CGPoint(x: midX, y: minY))
        path.addLine(to: CGPoint(x: maxX - radius, y: minY))
        path.addArc(
            center: CGPoint(x: maxX - radius, y: minY + radius),
            radius: radius,
            startAngle: .degrees(-90),
            endAngle: .degrees(0),
            clockwise: false
        )
        path.addLine(to: CGPoint(x: maxX, y: maxY - radius))
        path.addArc(
            center: CGPoint(x: maxX - radius, y: maxY - radius),
            radius: radius,
            startAngle: .degrees(0),
            endAngle: .degrees(90),
            clockwise: false
        )
        path.addLine(to: CGPoint(x: minX + radius, y: maxY))
        path.addArc(
            center: CGPoint(x: minX + radius, y: maxY - radius),
            radius: radius,
            startAngle: .degrees(90),
            endAngle: .degrees(180),
            clockwise: false
        )
        path.addLine(to: CGPoint(x: minX, y: minY + radius))
        path.addArc(
            center: CGPoint(x: minX + radius, y: minY + radius),
            radius: radius,
            startAngle: .degrees(180),
            endAngle: .degrees(270),
            clockwise: false
        )
        path.addLine(to: CGPoint(x: midX, y: minY))
        return path
    }
}

private func nativeRoundedRectProgressPoint(progress: Double, in rect: CGRect, cornerRadius: CGFloat) -> CGPoint {
    let clamped = min(max(progress, 0), 1)
    let radius = min(cornerRadius, min(rect.width, rect.height) / 2)
    let topStraight = max(rect.width - (2 * radius), 0)
    let sideStraight = max(rect.height - (2 * radius), 0)
    let arc = (.pi * radius) / 2
    let total = (2 * topStraight) + (2 * sideStraight) + (4 * arc)
    var remaining = total * clamped

    let minX = rect.minX
    let maxX = rect.maxX
    let minY = rect.minY
    let maxY = rect.maxY
    let midX = rect.midX

    let topHalf = topStraight / 2
    if remaining <= topHalf {
        return CGPoint(x: midX + remaining, y: minY)
    }
    remaining -= topHalf

    if remaining <= arc {
        let angle = (-.pi / 2) + (remaining / arc) * (.pi / 2)
        return CGPoint(
            x: (maxX - radius) + cos(angle) * radius,
            y: (minY + radius) + sin(angle) * radius
        )
    }
    remaining -= arc

    if remaining <= sideStraight {
        return CGPoint(x: maxX, y: minY + radius + remaining)
    }
    remaining -= sideStraight

    if remaining <= arc {
        let angle = (remaining / arc) * (.pi / 2)
        return CGPoint(
            x: (maxX - radius) + cos(angle) * radius,
            y: (maxY - radius) + sin(angle) * radius
        )
    }
    remaining -= arc

    if remaining <= topStraight {
        return CGPoint(x: maxX - radius - remaining, y: maxY)
    }
    remaining -= topStraight

    if remaining <= arc {
        let angle = (.pi / 2) + (remaining / arc) * (.pi / 2)
        return CGPoint(
            x: (minX + radius) + cos(angle) * radius,
            y: (maxY - radius) + sin(angle) * radius
        )
    }
    remaining -= arc

    if remaining <= sideStraight {
        return CGPoint(x: minX, y: maxY - radius - remaining)
    }
    remaining -= sideStraight

    if remaining <= arc {
        let angle = .pi + (remaining / arc) * (.pi / 2)
        return CGPoint(
            x: (minX + radius) + cos(angle) * radius,
            y: (minY + radius) + sin(angle) * radius
        )
    }
    remaining -= arc

    return CGPoint(x: minX + radius + remaining, y: minY)
}

private struct NativeProfileScreen: View {
    @EnvironmentObject private var appState: NativeAppState
    @State private var showEditProfileSheet = false
    @State private var showShareSheet = false
    @State private var hasLoadedInitialProfileState = false
    @State private var blockedUsers: [NativeBlockedUser] = []
    @State private var isBlockedUsersLoading = false
    @State private var notificationSettings = NativeNotificationSettings(
        pushEnabled: true,
        emailEnabled: true,
        recommendationEnabled: true
    )
    @State private var isNotificationsLoading = false
    @State private var isUpdatingNotifications = false
    @State private var settingsErrorMessage: String?
    @State private var showDeleteAccountConfirmation = false
    @State private var isDeletingAccount = false

    private var ownIdentityPills: [String] {
        let mapped = appState.selectedInterests.compactMap { interestId in
            nativeInterestSwipeCards.first(where: { $0.id == interestId })?.title
        }
        return Array(mapped.prefix(3))
    }

    private var canManageAccount: Bool {
        appState.currentUser != nil
    }

    var body: some View {
        standardProfileBody
    }

    private var standardProfileBody: some View {
        ScrollView(showsIndicators: false) {
            VStack(alignment: .leading, spacing: 18) {
                if let user = appState.currentUser {
                    ownQuickReadIdentity(user: user)
                    ownProfileActions
                    ownProfileSettingsSections
                } else {
                    VStack(alignment: .leading, spacing: 16) {
                        NativeGuestPromptCard(
                            eyebrow: "My Profile",
                            title: "Make this profile yours.",
                            message: "Log in to save places, follow travelers, and keep your own travel graph.",
                            cta: "Log in"
                        )
                    }
                }

                if let message = settingsErrorMessage ?? appState.profileErrorMessage {
                    NativeInlineError(message: message)
                }
            }
            .padding(.bottom, 140)
            .padding(.horizontal, nativeTravelerProfileHorizontalPadding)
            .padding(.top, 20)
        }
        .background(Color.black.ignoresSafeArea())
        .navigationTitle("My Profile")
        .navigationBarTitleDisplayMode(.inline)
        .toolbar {
            ToolbarItem(placement: .topBarTrailing) {
                Button {
                    appState.trackAnalytics(
                        .shareProfile,
                        properties: [
                            "source": NativeAnalyticsSource.profile,
                        ]
                    )
                    showShareSheet = true
                } label: {
                    Image(systemName: "square.and.arrow.up")
                        .font(nativeAppFont(size: 16, weight: .bold))
                        .foregroundStyle(.white)
                }
                .buttonStyle(.plain)
            }
        }
        .sheet(isPresented: $showEditProfileSheet) {
            if let user = appState.currentUser {
                NativeEditProfileSheet(
                    user: user,
                    onClose: { showEditProfileSheet = false },
                    onDeleted: { showEditProfileSheet = false }
                )
            }
        }
        .sheet(isPresented: $showShareSheet) {
            NativeShareSheet(items: ["https://vibinn.club/u/\(appState.currentUser?.username ?? "")"])
        }
        .alert("Delete account?", isPresented: $showDeleteAccountConfirmation) {
            Button("Cancel", role: .cancel) {}
            Button("Delete", role: .destructive) {
                Task {
                    await deleteAccount()
                }
            }
        } message: {
            Text("This will remove your account identity and sign you out on this device.")
        }
        .onAppear {
            appState.trackAnalytics(.viewMyProfile)
            nativeLogger.log("NativeProfileScreen appear")
            guard !hasLoadedInitialProfileState else { return }
            hasLoadedInitialProfileState = true
            Task {
                try? await Task.sleep(nanoseconds: 250_000_000)
                guard appState.currentUser != nil else { return }
                await appState.refreshProfile()
                await loadProfileSettingsData()
            }
        }
        .onAppear {
            let appearance = UINavigationBarAppearance()
            appearance.configureWithOpaqueBackground()
            appearance.backgroundColor = UIColor(red: 16 / 255, green: 16 / 255, blue: 19 / 255, alpha: 0.98)
            appearance.titleTextAttributes = [.foregroundColor: UIColor.white]
            appearance.largeTitleTextAttributes = [.foregroundColor: UIColor.white]
            UINavigationBar.appearance().standardAppearance = appearance
            UINavigationBar.appearance().scrollEdgeAppearance = appearance
            UINavigationBar.appearance().compactAppearance = appearance
        }
        .refreshable {
            await appState.refreshProfile()
            await loadProfileSettingsData()
        }
    }

    private func ownQuickReadIdentity(user: NativeAuthUser) -> some View {
        HStack(alignment: .top, spacing: 14) {
            NativeAvatarCircle(
                url: user.avatarUrl,
                fallbackText: user.displayName ?? user.username,
                size: 68,
                fontSize: 22
            )

            VStack(alignment: .leading, spacing: 6) {
                Text(user.displayName ?? user.username)
                    .font(nativeAppFont(size: 24, weight: .black))
                    .foregroundStyle(.white)
                    .fixedSize(horizontal: false, vertical: true)

                Text("@\(user.username)")
                    .font(nativeAppFont(size: 14, weight: .bold))
                    .foregroundStyle(.white.opacity(0.55))

                if let bio = user.bio?.trimmingCharacters(in: .whitespacesAndNewlines), !bio.isEmpty {
                    Text(bio)
                        .font(nativeAppFont(size: 14, weight: .medium))
                        .foregroundStyle(.white.opacity(0.72))
                        .fixedSize(horizontal: false, vertical: true)
                }

                Text("Manage how your profile appears and how your account works.")
                    .font(nativeAppFont(size: 13, weight: .medium))
                    .foregroundStyle(.white.opacity(0.52))
                    .fixedSize(horizontal: false, vertical: true)
            }
        }
    }

    private func ownProfileStatCard(value: String, label: String) -> some View {
        VStack(alignment: .leading, spacing: 6) {
            Text(value)
                .font(nativeAppFont(size: 22, weight: .black))
                .foregroundStyle(.white)
            Text(label)
                .font(nativeAppFont(size: 11, weight: .black))
                .foregroundStyle(.white.opacity(0.45))
                .textCase(.uppercase)
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(14)
        .background(nativeSurface)
        .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
    }

    private func ownSocialMetric(title: String, value: String, subtitle: String) -> some View {
        VStack(alignment: .leading, spacing: 6) {
            Text(title)
                .font(nativeAppFont(size: 11, weight: .black))
                .foregroundStyle(.white.opacity(0.45))
                .textCase(.uppercase)
            Text(value)
                .font(nativeAppFont(size: 20, weight: .black))
                .foregroundStyle(.white)
            Text(subtitle)
                .font(nativeAppFont(size: 12, weight: .medium))
                .foregroundStyle(.white.opacity(0.58))
                .fixedSize(horizontal: false, vertical: true)
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(14)
        .background(nativeSurfaceStrong)
        .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
    }

    private var ownProfileActions: some View {
        HStack(spacing: 10) {
            Button {
                showEditProfileSheet = true
            } label: {
                HStack {
                    Spacer()
                    Text("Edit profile")
                        .font(nativeAppFont(size: 15, weight: .black))
                    Spacer()
                }
                .padding(.vertical, 14)
                .background(nativeAccent)
                .foregroundStyle(.black)
                .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
            }
            .buttonStyle(.plain)
        }
    }

    private var notificationToggleBinding: Binding<Bool> {
        Binding(
            get: { notificationSettings.pushEnabled },
            set: { newValue in
                Task {
                    await updatePushNotifications(newValue)
                }
            }
        )
    }

    private func loadProfileSettingsData() async {
        guard appState.currentUser != nil else { return }

        isBlockedUsersLoading = true
        isNotificationsLoading = true

        async let blockedUsersTask = appState.fetchBlockedUsers()
        async let notificationSettingsTask = appState.fetchNotificationSettings()

        blockedUsers = (try? await blockedUsersTask) ?? []
        notificationSettings = (try? await notificationSettingsTask) ?? notificationSettings

        isBlockedUsersLoading = false
        isNotificationsLoading = false
    }

    private func updatePushNotifications(_ enabled: Bool) async {
        guard appState.currentUser != nil else { return }
        settingsErrorMessage = nil
        isUpdatingNotifications = true
        let previousSettings = notificationSettings
        notificationSettings = NativeNotificationSettings(
            pushEnabled: enabled,
            emailEnabled: notificationSettings.emailEnabled,
            recommendationEnabled: notificationSettings.recommendationEnabled
        )

        do {
            try await appState.setPushNotificationsEnabled(enabled, currentSettings: previousSettings)
        } catch {
            notificationSettings = previousSettings
            settingsErrorMessage = "Could not update notification settings right now."
        }

        isUpdatingNotifications = false
    }

    private func deleteAccount() async {
        settingsErrorMessage = nil
        isDeletingAccount = true
        defer { isDeletingAccount = false }

        do {
            try await appState.deleteAccount()
        } catch {
            settingsErrorMessage = nativeDescribeError(error)
        }
    }

    private var ownProfileSettingsSections: some View {
        VStack(alignment: .leading, spacing: 16) {
            NativeSurfaceCard {
                VStack(alignment: .leading, spacing: 14) {
                    Text("Notifications")
                        .font(nativeAppFont(size: 15, weight: .black))
                        .foregroundStyle(.white)

                    Text("Stay up to date on follows, vibin, comments, and recommendations.")
                        .font(nativeAppFont(size: 13, weight: .medium))
                        .foregroundStyle(.white.opacity(0.62))
                        .fixedSize(horizontal: false, vertical: true)

                    HStack(spacing: 12) {
                        Image(systemName: notificationSettings.pushEnabled ? "bell.badge.fill" : "bell.slash")
                            .font(nativeAppFont(size: 15, weight: .bold))
                            .foregroundStyle(notificationSettings.pushEnabled ? nativeAccent : .white.opacity(0.58))

                        VStack(alignment: .leading, spacing: 3) {
                            Text("Push notifications")
                                .font(nativeAppFont(size: 15, weight: .black))
                                .foregroundStyle(.white)
                            Text(notificationSettings.pushEnabled ? "On" : "Off")
                                .font(nativeAppFont(size: 12, weight: .bold))
                                .foregroundStyle(.white.opacity(0.46))
                        }

                        Spacer(minLength: 0)

                        if isNotificationsLoading || isUpdatingNotifications {
                            ProgressView()
                                .tint(nativeAccent)
                        } else {
                            Toggle("", isOn: notificationToggleBinding)
                                .labelsHidden()
                                .tint(nativeAccent)
                        }
                    }
                    .padding(.horizontal, 16)
                    .padding(.vertical, 14)
                    .frame(maxWidth: .infinity)
                    .background(nativeSurfaceStrong)
                    .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                }
            }

            if canManageAccount {
                NativeSurfaceCard {
                    VStack(alignment: .leading, spacing: 14) {
                        Text("Blocked accounts")
                            .font(nativeAppFont(size: 15, weight: .black))
                            .foregroundStyle(.white)

                        if isBlockedUsersLoading {
                            HStack(spacing: 10) {
                                ProgressView().tint(nativeAccent)
                                Text("Loading blocked accounts...")
                                    .font(nativeAppFont(size: 13, weight: .medium))
                                    .foregroundStyle(.white.opacity(0.62))
                            }
                        } else if blockedUsers.isEmpty {
                            Text("No blocked accounts yet.")
                                .font(nativeAppFont(size: 13, weight: .medium))
                                .foregroundStyle(.white.opacity(0.62))
                        } else {
                            VStack(spacing: 10) {
                                ForEach(blockedUsers) { blockedUser in
                                    HStack(spacing: 12) {
                                        NativeAvatarCircle(
                                            url: blockedUser.avatar,
                                            fallbackText: blockedUser.displayName ?? blockedUser.username,
                                            size: 42,
                                            fontSize: 15
                                        )

                                        VStack(alignment: .leading, spacing: 4) {
                                            Text(blockedUser.displayName ?? blockedUser.username)
                                                .font(nativeAppFont(size: 14, weight: .black))
                                                .foregroundStyle(.white)
                                            Text("@\(blockedUser.username)")
                                                .font(nativeAppFont(size: 12, weight: .bold))
                                                .foregroundStyle(.white.opacity(0.46))
                                        }

                                        Spacer(minLength: 0)

                                        Button {
                                            Task {
                                                try? await appState.unblockUser(blockedUser.id)
                                                blockedUsers.removeAll { $0.id == blockedUser.id }
                                            }
                                        } label: {
                                            Text("Unblock")
                                                .font(nativeAppFont(size: 12, weight: .black))
                                                .foregroundStyle(nativeAccent)
                                                .padding(.horizontal, 12)
                                                .padding(.vertical, 9)
                                                .background(nativeAccent.opacity(0.12))
                                                .clipShape(Capsule())
                                        }
                                        .buttonStyle(.plain)
                                    }

                                    if blockedUser.id != blockedUsers.last?.id {
                                        Divider().background(Color.white.opacity(0.08))
                                    }
                                }
                            }
                            .frame(maxWidth: .infinity, alignment: .leading)
                        }
                    }
                }
            }

            NativeSurfaceCard {
                VStack(alignment: .leading, spacing: 14) {
                    Text("Account")
                        .font(nativeAppFont(size: 15, weight: .black))
                        .foregroundStyle(.white)

                    if let user = appState.currentUser {
                        VStack(alignment: .leading, spacing: 4) {
                            Text(user.displayName ?? user.username)
                                .font(nativeAppFont(size: 15, weight: .heavy))
                                .foregroundStyle(.white)
                            Text("@\(user.username)")
                                .font(nativeAppFont(size: 13, weight: .semibold))
                                .foregroundStyle(.white.opacity(0.6))
                        }

                        if let email = user.email, !email.isEmpty {
                            Text(email)
                                .font(nativeAppFont(size: 13, weight: .medium))
                                .foregroundStyle(.white.opacity(0.5))
                        }

                        Text("Signed in on this device.")
                            .font(nativeAppFont(size: 13, weight: .medium))
                            .foregroundStyle(.white.opacity(0.62))

                        VStack(spacing: 10) {
                            Button {
                                appState.logout()
                            } label: {
                                HStack {
                                    Image(systemName: "rectangle.portrait.and.arrow.right")
                                        .font(nativeAppFont(size: 15, weight: .bold))
                                    Text("Log out")
                                        .font(nativeAppFont(size: 15, weight: .black))
                                    Spacer()
                                }
                                .padding(.horizontal, 16)
                                .padding(.vertical, 14)
                                .frame(maxWidth: .infinity)
                                .background(Color.white.opacity(0.08))
                                .foregroundStyle(.white)
                                .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                            }
                            .buttonStyle(.plain)

                            Button {
                                showDeleteAccountConfirmation = true
                            } label: {
                                HStack {
                                    Image(systemName: "trash")
                                        .font(nativeAppFont(size: 15, weight: .bold))
                                    if isDeletingAccount {
                                        ProgressView().tint(.red)
                                    } else {
                                        Text("Delete account")
                                            .font(nativeAppFont(size: 15, weight: .black))
                                    }
                                    Spacer()
                                }
                                .padding(.horizontal, 16)
                                .padding(.vertical, 14)
                                .frame(maxWidth: .infinity)
                                .background(Color.red.opacity(0.12))
                                .foregroundStyle(Color.red.opacity(0.92))
                                .overlay(
                                    RoundedRectangle(cornerRadius: 18, style: .continuous)
                                        .stroke(Color.red.opacity(0.36), lineWidth: 1)
                                )
                                .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                            }
                            .buttonStyle(.plain)
                            .disabled(isDeletingAccount)
                        }
                    } else {
                        Text("You are currently signed out.")
                            .font(nativeAppFont(size: 13, weight: .medium))
                            .foregroundStyle(.white.opacity(0.62))

                        Button {
                            appState.presentAuthGate(reason: "Log in to personalize your profile.")
                        } label: {
                            HStack {
                                Image(systemName: "person.crop.circle.badge.plus")
                                    .font(nativeAppFont(size: 15, weight: .bold))
                                Text("Go to login")
                                    .font(nativeAppFont(size: 15, weight: .black))
                                Spacer()
                            }
                            .padding(.horizontal, 16)
                            .padding(.vertical, 14)
                            .frame(maxWidth: .infinity)
                            .background(nativeAccent.opacity(0.14))
                            .foregroundStyle(nativeAccent)
                            .overlay(
                                RoundedRectangle(cornerRadius: 18, style: .continuous)
                                    .stroke(nativeAccent.opacity(0.35), lineWidth: 1)
                            )
                            .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                        }
                        .buttonStyle(.plain)
                    }
                }
            }
        }
    }

}

