                        NativeFeedMetaPill(
                            label: nativeRevisitLabel(wouldRevisit),
                            foreground: wouldRevisit == "yes" ? nativeAccent : .white.opacity(0.82),
                            background: wouldRevisit == "yes" ? nativeAccent.opacity(0.16) : Color.white.opacity(0.08)
                        )
                    }
                    Spacer(minLength: 0)
                }

                NativeFeedPlaceAttachment(place: enrichedPlace, activityType: .visited, uploadedMediaUrls: momentUploadedMediaUrls) {
                    NativePlaceDetailScreen(initialPlace: enrichedPlace, source: NativeAnalyticsSource.profile)
                }
            }
        }
        .confirmationDialog("Delete post?", isPresented: $showDeletePostDialog, titleVisibility: .visible) {
            Button("Delete post", role: .destructive) {
                onDelete?(moment)
            }
            Button("Cancel", role: .cancel) {}
        } message: {
            Text("This will remove this check-in from your profile.")
        }
    }

	    private var enrichedPlace: NativePlace {
	        return NativePlace(
	            id: moment.place.id,
	            name: moment.place.name,
	            location: moment.place.location,
	            address: moment.place.address,
	            neighborhood: moment.place.neighborhood,
	            category: moment.place.category,
	            description: moment.place.description,
	            hook: moment.place.hook,
	            // Keep place media for the place card thumbnail. User uploads are rendered separately above.
	            image: moment.place.image,
	            images: moment.place.images,
	            momentMedia: nil,
	            placeMediaUrls: nil,
	            userMediaUrls: nil,
	            tags: moment.place.tags,
	            attitudeLabel: moment.place.attitudeLabel,
	            bestTime: moment.place.bestTime,
	            similarityStat: moment.place.similarityStat,
            whyYoullLikeIt: moment.place.whyYoullLikeIt,
            recommendationReason: moment.place.recommendationReason,
            rating: moment.place.rating,
            priceLevel: moment.place.priceLevel,
            openingHours: moment.place.openingHours,
            servesBreakfast: moment.place.servesBreakfast,
            servesLunch: moment.place.servesLunch,
            servesDinner: moment.place.servesDinner,
            servesBeer: moment.place.servesBeer,
            servesWine: moment.place.servesWine,
            servesBrunch: moment.place.servesBrunch,
            servesDessert: moment.place.servesDessert,
            servesCoffee: moment.place.servesCoffee,
            servesCocktails: moment.place.servesCocktails,
            goodForGroups: moment.place.goodForGroups,
            goodForWatchingSports: moment.place.goodForWatchingSports,
            timeZone: moment.place.timeZone,
            utcOffsetMinutes: moment.place.utcOffsetMinutes,
            outdoors: moment.place.outdoors,
            outdoorSeating: moment.place.outdoorSeating,
            mapsUrl: moment.place.mapsUrl,
            latitude: moment.place.latitude,
            longitude: moment.place.longitude,
            priceRange: moment.place.priceRange,
            priceRangeLabel: moment.place.priceRangeLabel,
            discoverySignals: moment.place.discoverySignals,
            discoveryTopRank: moment.place.discoveryTopRank,
            momentId: moment.id,
            ownerUserId: moment.place.ownerUserId,
            visitedDate: moment.visitedDate,
            visitedAtIso: moment.visitedAtIso,
            momentCaption: moment.caption,
            momentWouldRevisit: moment.wouldRevisit,
            momentRating: moment.rating,
            momentRatingLabel: moment.ratingLabel
        )
    }

    private func nativeRevisitLabel(_ value: String) -> String {
        switch value {
        case "yes":
            return "Would revisit"
        case "maybe", "not_sure":
            return "Maybe"
        case "no", "not_interested":
            return "No revisit"
        default:
            return value.replacingOccurrences(of: "_", with: " ").capitalized
        }
    }
}

private struct NativeProfileSettingsSheet: View {
    @EnvironmentObject private var appState: NativeAppState
    let onClose: () -> Void

    @State private var blockedUsers: [NativeBlockedUser] = []
    @State private var isBlockedUsersLoading = false
    @State private var notificationSettings = NativeNotificationSettings(
        pushEnabled: true,
        emailEnabled: true,
        recommendationEnabled: true
    )
    @State private var isNotificationsLoading = false
    @State private var isUpdatingNotifications = false
    @State private var settingsErrorMessage: String?
    @State private var showDeleteAccountConfirmation = false
    @State private var isDeletingAccount = false

    var body: some View {
        ZStack {
            Color.black.ignoresSafeArea()

            VStack(spacing: 0) {
                HStack {
                    Spacer()
                    Text("Settings")
                        .font(nativeAppFont(size: 18, weight: .black))
                        .foregroundStyle(.white)
                    Spacer()
                }
                .overlay(alignment: .trailing) {
                    Button {
                        onClose()
                    } label: {
                        Image(systemName: "xmark")
                            .font(nativeAppFont(size: 12, weight: .black))
                            .foregroundStyle(.white)
                            .frame(width: 32, height: 32)
                            .background(Color.white.opacity(0.08))
                            .clipShape(Circle())
                    }
                    .buttonStyle(.plain)
                }
                .padding(.horizontal, 20)
                .padding(.top, 18)
                .padding(.bottom, 18)

                ScrollView(showsIndicators: false) {
                    VStack(alignment: .leading, spacing: 18) {
                        if let settingsErrorMessage {
                            NativeInlineError(message: settingsErrorMessage)
                        }

                        NativeSurfaceCard {
                            VStack(alignment: .leading, spacing: 14) {
                                Text("Notifications")
                                    .font(nativeAppFont(size: 15, weight: .black))
                                    .foregroundStyle(.white)

                                Text("Stay up to date on follows, vibin, comments, and recommendations.")
                                    .font(nativeAppFont(size: 13, weight: .medium))
                                    .foregroundStyle(.white.opacity(0.62))
                                    .fixedSize(horizontal: false, vertical: true)

                                HStack(spacing: 12) {
                                    Image(systemName: notificationSettings.pushEnabled ? "bell.badge.fill" : "bell.slash")
                                        .font(nativeAppFont(size: 15, weight: .bold))
                                        .foregroundStyle(notificationSettings.pushEnabled ? nativeAccent : .white.opacity(0.58))

                                    VStack(alignment: .leading, spacing: 3) {
                                        Text("Push notifications")
                                            .font(nativeAppFont(size: 15, weight: .black))
                                            .foregroundStyle(.white)
                                        Text(notificationSettings.pushEnabled ? "On" : "Off")
                                            .font(nativeAppFont(size: 12, weight: .bold))
                                            .foregroundStyle(.white.opacity(0.46))
                                    }

                                    Spacer(minLength: 0)

                                    if isNotificationsLoading || isUpdatingNotifications {
                                        ProgressView()
                                            .tint(nativeAccent)
                                    } else {
                                        Toggle("", isOn: notificationToggleBinding)
                                            .labelsHidden()
                                            .tint(nativeAccent)
                                    }
                                }
                                .padding(.horizontal, 16)
                                .padding(.vertical, 14)
                                .frame(maxWidth: .infinity)
                                .background(nativeSurfaceStrong)
                                .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                            }
                        }

                        if appState.currentUser != nil {
                            NativeSurfaceCard {
                                VStack(alignment: .leading, spacing: 14) {
                                    Text("Blocked accounts")
                                        .font(nativeAppFont(size: 15, weight: .black))
                                        .foregroundStyle(.white)

                                    if isBlockedUsersLoading {
                                        HStack(spacing: 10) {
                                            ProgressView().tint(nativeAccent)
                                            Text("Loading blocked accounts...")
                                                .font(nativeAppFont(size: 13, weight: .medium))
                                                .foregroundStyle(.white.opacity(0.62))
                                        }
                                    } else if blockedUsers.isEmpty {
                                        Text("No blocked accounts yet.")
                                            .font(nativeAppFont(size: 13, weight: .medium))
                                            .foregroundStyle(.white.opacity(0.62))
                                    } else {
                                        VStack(spacing: 10) {
                                            ForEach(blockedUsers) { blockedUser in
                                                HStack(spacing: 12) {
                                                    NativeAvatarCircle(
                                                        url: blockedUser.avatar,
                                                        fallbackText: blockedUser.displayName ?? blockedUser.username,
                                                        size: 42,
                                                        fontSize: 15
                                                    )

                                                    VStack(alignment: .leading, spacing: 4) {
                                                        Text(blockedUser.displayName ?? blockedUser.username)
                                                            .font(nativeAppFont(size: 14, weight: .black))
                                                            .foregroundStyle(.white)
                                                        Text("@\(blockedUser.username)")
                                                            .font(nativeAppFont(size: 12, weight: .bold))
                                                            .foregroundStyle(.white.opacity(0.46))
                                                    }

                                                    Spacer(minLength: 0)

                                                    Button {
                                                        Task {
                                                            try? await appState.unblockUser(blockedUser.id)
                                                            blockedUsers.removeAll { $0.id == blockedUser.id }
                                                        }
                                                    } label: {
                                                        Text("Unblock")
                                                            .font(nativeAppFont(size: 12, weight: .black))
                                                            .foregroundStyle(nativeAccent)
                                                            .padding(.horizontal, 12)
                                                            .padding(.vertical, 9)
                                                            .background(nativeAccent.opacity(0.12))
                                                            .clipShape(Capsule())
                                                    }
                                                    .buttonStyle(.plain)
                                                }

                                                if blockedUser.id != blockedUsers.last?.id {
                                                    Divider().background(Color.white.opacity(0.08))
                                                }
                                            }
                                        }
                                        .frame(maxWidth: .infinity, alignment: .leading)
                                    }
                                }
                                .frame(maxWidth: .infinity, alignment: .leading)
                            }
                            .frame(maxWidth: .infinity)
                        }

                        NativeSurfaceCard {
                            VStack(alignment: .leading, spacing: 14) {
                                Text("Account")
                                    .font(nativeAppFont(size: 15, weight: .black))
                                    .foregroundStyle(.white)

                                if let user = appState.currentUser {
                                    VStack(alignment: .leading, spacing: 4) {
                                        Text(user.displayName ?? user.username)
                                            .font(nativeAppFont(size: 15, weight: .heavy))
                                            .foregroundStyle(.white)
                                        Text("@\(user.username)")
                                            .font(nativeAppFont(size: 13, weight: .semibold))
                                            .foregroundStyle(.white.opacity(0.6))
                                    }

                                    if let email = user.email, !email.isEmpty {
                                        Text(email)
                                            .font(nativeAppFont(size: 13, weight: .medium))
                                            .foregroundStyle(.white.opacity(0.5))
                                    }

                                    Text("Signed in on this device.")
                                        .font(nativeAppFont(size: 13, weight: .medium))
                                        .foregroundStyle(.white.opacity(0.62))

                                    VStack(spacing: 10) {
                                        Button {
                                            appState.logout()
                                            onClose()
                                        } label: {
                                            HStack {
                                                Image(systemName: "rectangle.portrait.and.arrow.right")
                                                    .font(nativeAppFont(size: 15, weight: .bold))
                                                Text("Log out")
                                                    .font(nativeAppFont(size: 15, weight: .black))
                                                Spacer()
                                            }
                                            .padding(.horizontal, 16)
                                            .padding(.vertical, 14)
                                            .frame(maxWidth: .infinity)
                                            .background(Color.white.opacity(0.08))
                                            .foregroundStyle(.white)
                                            .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                                        }
                                        .buttonStyle(.plain)

                                        Button {
                                            showDeleteAccountConfirmation = true
                                        } label: {
                                            HStack {
                                                Image(systemName: "trash")
                                                    .font(nativeAppFont(size: 15, weight: .bold))
                                                if isDeletingAccount {
                                                    ProgressView().tint(.red)
                                                } else {
                                                    Text("Delete account")
                                                        .font(nativeAppFont(size: 15, weight: .black))
                                                }
                                                Spacer()
                                            }
                                            .padding(.horizontal, 16)
                                            .padding(.vertical, 14)
                                            .frame(maxWidth: .infinity)
                                            .background(Color.red.opacity(0.12))
                                            .foregroundStyle(Color.red.opacity(0.92))
                                            .overlay(
                                                RoundedRectangle(cornerRadius: 18, style: .continuous)
                                                    .stroke(Color.red.opacity(0.36), lineWidth: 1)
                                            )
                                            .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                                        }
                                        .buttonStyle(.plain)
                                        .disabled(isDeletingAccount)
                                    }
                                } else {
                                    Text("You are currently signed out.")
                                        .font(nativeAppFont(size: 13, weight: .medium))
                                        .foregroundStyle(.white.opacity(0.62))

                                    Button {
                                        onClose()
                                        appState.presentAuthGate(reason: "Log in to personalize your profile.")
                                    } label: {
                                        HStack {
                                            Image(systemName: "person.crop.circle.badge.plus")
                                                .font(nativeAppFont(size: 15, weight: .bold))
                                            Text("Go to login")
                                                .font(nativeAppFont(size: 15, weight: .black))
                                            Spacer()
                                        }
                                        .padding(.horizontal, 16)
                                        .padding(.vertical, 14)
                                        .frame(maxWidth: .infinity)
                                        .background(nativeAccent.opacity(0.14))
                                        .foregroundStyle(nativeAccent)
                                        .overlay(
                                            RoundedRectangle(cornerRadius: 18, style: .continuous)
                                                .stroke(nativeAccent.opacity(0.35), lineWidth: 1)
                                        )
                                        .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                                    }
                                    .buttonStyle(.plain)
                                }
                            }
                        }
                    }
                    .padding(.horizontal, 20)
                    .padding(.bottom, 30)
                }
            }
        }
        .task {
            guard appState.currentUser != nil else { return }

            isBlockedUsersLoading = true
            isNotificationsLoading = true
            nativeLogger.log("settings sheet load start")

            async let blockedUsersTask = appState.fetchBlockedUsers()
            async let notificationSettingsTask = appState.fetchNotificationSettings()

            blockedUsers = (try? await blockedUsersTask) ?? []
            notificationSettings = (try? await notificationSettingsTask) ?? notificationSettings
            nativeLogger.log("settings sheet load success blocked=\(blockedUsers.count, privacy: .public) pushEnabled=\(notificationSettings.pushEnabled, privacy: .public)")

            isBlockedUsersLoading = false
            isNotificationsLoading = false
        }
        .alert("Delete account?", isPresented: $showDeleteAccountConfirmation) {
            Button("Cancel", role: .cancel) {}
            Button("Delete", role: .destructive) {
                Task {
                    await deleteAccount()
                }
            }
        } message: {
            Text("This will remove your account identity and sign you out on this device.")
        }
    }

    private var notificationToggleBinding: Binding<Bool> {
        Binding(
            get: { notificationSettings.pushEnabled },
            set: { newValue in
                nativeLogger.log("settings toggle tapped targetPushEnabled=\(newValue, privacy: .public)")
                Task {
                    await updatePushNotifications(newValue)
                                }
                            }
                        )
                    }

    private func updatePushNotifications(_ enabled: Bool) async {
        guard appState.currentUser != nil else { return }
        settingsErrorMessage = nil
        isUpdatingNotifications = true
        let previousSettings = notificationSettings
        nativeLogger.log("settings toggle update start current=\(previousSettings.pushEnabled, privacy: .public) target=\(enabled, privacy: .public)")
        notificationSettings = NativeNotificationSettings(
            pushEnabled: enabled,
            emailEnabled: notificationSettings.emailEnabled,
            recommendationEnabled: notificationSettings.recommendationEnabled
        )

        do {
            try await appState.setPushNotificationsEnabled(enabled, currentSettings: previousSettings)
            nativeLogger.log("settings toggle update success final=\(notificationSettings.pushEnabled, privacy: .public)")
        } catch {
            notificationSettings = previousSettings
            settingsErrorMessage = "Could not update notification settings right now."
            nativeLogger.error("settings toggle update failed: \(error.localizedDescription, privacy: .public)")
        }

        isUpdatingNotifications = false
    }

    private func deleteAccount() async {
        settingsErrorMessage = nil
        isDeletingAccount = true
        defer { isDeletingAccount = false }

        do {
            try await appState.deleteAccount()
            onClose()
        } catch {
            settingsErrorMessage = nativeDescribeError(error)
        }
    }
}

private struct NativeEditProfileSheet: View {
    @EnvironmentObject private var appState: NativeAppState

    let user: NativeAuthUser
    let onClose: () -> Void
    let onDeleted: () -> Void

    @State private var displayName: String
    @State private var username: String
    @State private var bio: String
    @State private var avatarUrl: String
    @State private var pickedAvatarImage: UIImage?
    @State private var selectedAvatarImage: UIImage?
    @State private var errorMessage: String?
    @State private var isSaving = false
    @State private var isDeleting = false
    @State private var isUploadingAvatar = false
    @State private var showDeleteConfirmation = false
    @State private var showAvatarPicker = false

    init(user: NativeAuthUser, onClose: @escaping () -> Void, onDeleted: @escaping () -> Void) {
        self.user = user
        self.onClose = onClose
        self.onDeleted = onDeleted
        _displayName = State(initialValue: user.displayName ?? "")
        _username = State(initialValue: user.username)
        _bio = State(initialValue: user.bio ?? "")
        _avatarUrl = State(initialValue: user.avatarUrl ?? "")
    }

    var body: some View {
        ZStack {
            Color.black.ignoresSafeArea()

            VStack(spacing: 0) {
                HStack {
                    Spacer()
                    Text("Edit profile")
                        .font(nativeAppFont(size: 18, weight: .black))
                        .foregroundStyle(.white)
                    Spacer()
                }
                .overlay(alignment: .trailing) {
                    Button {
                        onClose()
                    } label: {
                        Image(systemName: "xmark")
                            .font(nativeAppFont(size: 12, weight: .black))
                            .foregroundStyle(.white)
                            .frame(width: 32, height: 32)
                            .background(Color.white.opacity(0.08))
                            .clipShape(Circle())
                    }
                    .buttonStyle(.plain)
                }
                .padding(.horizontal, 20)
                .padding(.top, 18)
                .padding(.bottom, 18)

                ScrollView(showsIndicators: false) {
                    VStack(alignment: .leading, spacing: 18) {
                        NativeSurfaceCard {
                            HStack(spacing: 14) {
                                avatarPreview

                                VStack(alignment: .leading, spacing: 6) {
                                    Text(displayName.isEmpty ? user.displayName ?? user.username : displayName)
                                        .font(nativeAppFont(size: 18, weight: .black))
                                        .foregroundStyle(.white)
                                        .fixedSize(horizontal: false, vertical: true)
                                    Text("@\(username)")
                                        .font(nativeAppFont(size: 13, weight: .semibold))
                                        .foregroundStyle(.white.opacity(0.58))
                                    if let email = user.email, !email.isEmpty {
                                        Text(email)
                                            .font(nativeAppFont(size: 12, weight: .medium))
                                            .foregroundStyle(.white.opacity(0.42))
                                    }

                                    HStack(spacing: 10) {
                                        Button {
                                            showAvatarPicker = true
                                        } label: {
                                            HStack(spacing: 8) {
                                                Image(systemName: "photo.on.rectangle")
                                                    .font(nativeAppFont(size: 13, weight: .bold))
                                                Text(isUploadingAvatar ? "Uploading..." : "Choose photo")
                                                    .font(nativeAppFont(size: 12, weight: .black))
                                            }
                                            .padding(.horizontal, 12)
                                            .padding(.vertical, 10)
                                            .background(nativeSurfaceStrong)
                                            .foregroundStyle(.white)
                                            .clipShape(Capsule())
                                        }
                                        .buttonStyle(.plain)
                                        .disabled(isUploadingAvatar)

                                        if !avatarUrl.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || selectedAvatarImage != nil {
                                            Button {
                                                selectedAvatarImage = nil
                                                avatarUrl = ""
                                            } label: {
                                                Text("Remove")
                                                    .font(nativeAppFont(size: 12, weight: .black))
                                                    .foregroundStyle(.white.opacity(0.62))
                                            }
                                            .buttonStyle(.plain)
                                        }
                                    }
                                }
                            }
                        }

                        NativeSurfaceCard {
                            VStack(spacing: 16) {
                                NativeInputField(title: "Display name", text: $displayName, keyboard: .default, secure: false)
                                NativeInputField(title: "Username", text: $username, keyboard: .default, secure: false)
                                NativeMultilineInputField(title: "Bio", text: $bio, height: 108)

                                if let errorMessage {
                                    Text(errorMessage)
                                        .font(nativeAppFont(size: 13, weight: .semibold))
                                        .foregroundStyle(.red.opacity(0.92))
                                        .frame(maxWidth: .infinity, alignment: .leading)
                                }

                                Button {
                                    Task {
                                        await saveProfile()
                                    }
                                } label: {
                                    HStack {
                                        Spacer()
                                        if isSaving {
                                            ProgressView().tint(.black)
                                        } else {
                                            Text("Save changes")
                                                .font(nativeAppFont(size: 16, weight: .black))
                                        }
                                        Spacer()
                                    }
                                    .padding(.vertical, 16)
                                    .background(nativeAccent)
                                    .foregroundStyle(.black)
                                    .clipShape(RoundedRectangle(cornerRadius: 20, style: .continuous))
                                }
                                .buttonStyle(.plain)
                                .disabled(!canSave)
                            }
                        }

                        NativeSurfaceCard {
                            VStack(alignment: .leading, spacing: 12) {
                                Text("Danger zone")
                                    .font(nativeAppFont(size: 15, weight: .black))
                                    .foregroundStyle(.white)
                                Text("Deleting your account will sign you out on this device and remove your personal profile identity.")
                                    .font(nativeAppFont(size: 13, weight: .medium))
                                    .foregroundStyle(.white.opacity(0.62))
                                    .fixedSize(horizontal: false, vertical: true)

                                Button {
                                    showDeleteConfirmation = true
                                } label: {
                                    HStack {
                                        Image(systemName: "trash")
                                            .font(nativeAppFont(size: 15, weight: .bold))
                                        if isDeleting {
                                            ProgressView().tint(.red)
                                        } else {
                                            Text("Delete account")
                                                .font(nativeAppFont(size: 15, weight: .black))
                                        }
                                        Spacer()
                                    }
                                    .padding(.horizontal, 16)
                                    .padding(.vertical, 14)
                                    .frame(maxWidth: .infinity)
                                    .background(Color.red.opacity(0.12))
                                    .foregroundStyle(Color.red.opacity(0.92))
                                    .overlay(
                                        RoundedRectangle(cornerRadius: 18, style: .continuous)
                                            .stroke(Color.red.opacity(0.36), lineWidth: 1)
                                    )
                                    .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                                }
                                .buttonStyle(.plain)
                                .disabled(isDeleting)
                            }
                        }
                    }
                    .padding(.horizontal, 20)
                    .padding(.bottom, 30)
                }
            }
        }
        .alert("Delete account?", isPresented: $showDeleteConfirmation) {
            Button("Cancel", role: .cancel) {}
            Button("Delete", role: .destructive) {
                Task {
                    await deleteAccount()
                }
            }
        } message: {
            Text("This will remove your account identity and sign you out on this device.")
        }
        .sheet(isPresented: $showAvatarPicker) {
            NativeSingleImagePicker(image: $pickedAvatarImage, source: .library)
        }
        .onChange(of: pickedAvatarImage) { image in
            guard let image else { return }
            let normalized = nativeSquareCroppedImage(image)
            selectedAvatarImage = normalized
            Task {
                await uploadAvatar(normalized)
            }
        }
    }

    private var canSave: Bool {
        !isSaving
            && !isUploadingAvatar
            && !displayName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            && !username.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    @ViewBuilder
    private var avatarPreview: some View {
        if let selectedAvatarImage {
            Image(uiImage: selectedAvatarImage)
                .resizable()
                .scaledToFill()
                .frame(width: 68, height: 68)
                .clipShape(RoundedRectangle(cornerRadius: nativeAvatarCornerRadius(for: 68), style: .continuous))
                .overlay(
                    RoundedRectangle(cornerRadius: nativeAvatarCornerRadius(for: 68), style: .continuous)
                        .stroke(nativeBorder, lineWidth: 1)
                )
        } else {
            NativeAvatarCircle(
                url: avatarUrl.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? nil : avatarUrl,
                fallbackText: displayName.isEmpty ? username : displayName,
                size: 68,
                fontSize: 24
            )
        }
    }

    private func saveProfile() async {
        errorMessage = nil
        isSaving = true
        defer { isSaving = false }

        do {
            try await appState.updateProfile(
                displayName: displayName.trimmingCharacters(in: .whitespacesAndNewlines),
                username: username.trimmingCharacters(in: .whitespacesAndNewlines),
                bio: bio.trimmingCharacters(in: .whitespacesAndNewlines),
                avatarUrl: avatarUrl.trimmingCharacters(in: .whitespacesAndNewlines)
            )
            onClose()
        } catch {
            errorMessage = "Could not save your profile right now."
        }
    }

    private func deleteAccount() async {
        errorMessage = nil
        isDeleting = true
        defer { isDeleting = false }

        do {
            try await appState.deleteAccount()
            onDeleted()
        } catch {
            errorMessage = nativeDescribeError(error)
        }
    }

    private func uploadAvatar(_ image: UIImage) async {
        errorMessage = nil
        isUploadingAvatar = true
        defer {
            isUploadingAvatar = false
            pickedAvatarImage = nil
        }

        do {
            avatarUrl = try await appState.uploadAvatarImage(image)
        } catch {
            errorMessage = "Could not upload your profile photo right now."
        }
    }
}

private struct NativeFeedScreen: View {
    @EnvironmentObject private var appState: NativeAppState
    private enum FeedViewMode: String, CaseIterable, Identifiable {
        case posts = "Posts"
        case maps = "Maps"

        var id: String { rawValue }
    }

    private enum FeedMapTimeFilter: String, CaseIterable, Identifiable {
        case today = "Today"
        case thisWeek = "This week"
        case lastWeek = "Last week"
        case lastMonth = "Last month"

        var id: String { rawValue }
    }

    @State private var showShareSheet = false
    @State private var inviteSMSContact: NativeInviteContact?
    @State private var contactsAuthorizationStatus: CNAuthorizationStatus = CNContactStore.authorizationStatus(for: .contacts)
    @State private var matchedContacts: [(contact: NativeInviteContact, match: NativeMatchedFeedContact)] = []
    @State private var unmatchedContacts: [NativeInviteContact] = []
    @State private var isLoadingContacts = false
    @State private var isMatchingContacts = false
    @State private var contactsSearchText = ""
    @State private var updatingFollowContactIds = Set<String>()
    @State private var activeFeedMode: FeedViewMode = .posts
    @State private var activeFeedMapFilter: FeedMapTimeFilter = .thisWeek
    @State private var selectedFeedDetailItem: NativeFeedItem?
    @State private var feedMapRegion = MKCoordinateRegion(
        center: CLLocationCoordinate2D(latitude: 40.7128, longitude: -74.0060),
        span: MKCoordinateSpan(latitudeDelta: 0.25, longitudeDelta: 0.25)
    )

    private let contactsPageSize = 20
    private let contactsMatchBatchSize = 200

    private var hasNoFriendsFeedState: Bool {
        guard appState.currentUser != nil else { return false }
        return appState.followedTravelers.isEmpty
    }

    private var hasContactsPermission: Bool {
        contactsAuthorizationStatus == .authorized
    }

    private var normalizedContactsSearchText: String {
        contactsSearchText.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private var filteredMatchedContacts: [(contact: NativeInviteContact, match: NativeMatchedFeedContact)] {
        guard !normalizedContactsSearchText.isEmpty else { return matchedContacts }
        let query = normalizedContactsSearchText.lowercased()
        return matchedContacts.filter { item in
            item.contact.displayName.lowercased().contains(query)
                || item.match.traveler.username.lowercased().contains(query)
                || item.contact.phoneNumbers.contains(where: { $0.lowercased().contains(query) })
        }
    }

    private var filteredUnmatchedContacts: [NativeInviteContact] {
        guard !normalizedContactsSearchText.isEmpty else { return unmatchedContacts }
        let query = normalizedContactsSearchText.lowercased()
        return unmatchedContacts.filter { contact in
            contact.displayName.lowercased().contains(query)
                || contact.phoneNumbers.contains(where: { $0.lowercased().contains(query) })
        }
    }

    @State private var matchedVisibleCount = 20
    @State private var unmatchedVisibleCount = 20

    private var visibleMatchedContacts: [(contact: NativeInviteContact, match: NativeMatchedFeedContact)] {
        Array(filteredMatchedContacts.prefix(matchedVisibleCount))
    }

    private var visibleUnmatchedContacts: [NativeInviteContact] {
        Array(filteredUnmatchedContacts.prefix(unmatchedVisibleCount))
    }

    private var followedFeedItems: [NativeFeedItem] {
        appState.feedItems.sorted { $0.sortTimestamp > $1.sortTimestamp }
    }

    private var mappedFeedItems: [NativeFeedItem] {
        filteredFeedItemsByTime(activeFeedMapFilter).filter {
            $0.place?.latitude != nil && $0.place?.longitude != nil
        }
    }

