    private func requestContactsForFeed() async {
        let status = CNContactStore.authorizationStatus(for: .contacts)
        await MainActor.run {
            contactsAuthorizationStatus = status
        }

        switch status {
        case .authorized:
            await refreshFeedContactsIfPossible(force: true)
        case .notDetermined:
            let granted = await requestContactsAccessAsync()
            await MainActor.run {
                contactsAuthorizationStatus = CNContactStore.authorizationStatus(for: .contacts)
            }
            if granted {
                await refreshFeedContactsIfPossible(force: true)
            }
        case .denied, .restricted:
            break
        @unknown default:
            break
        }
    }

    private func filteredFeedItemsByTime(_ filter: FeedMapTimeFilter) -> [NativeFeedItem] {
        let calendar = Calendar.current
        let now = Date()
        let startOfToday = calendar.startOfDay(for: now)
        let startOfThisWeek = calendar.dateInterval(of: .weekOfYear, for: now)?.start ?? now
        let startOfLastWeek = calendar.date(byAdding: .weekOfYear, value: -1, to: startOfThisWeek) ?? startOfThisWeek
        let startOfThisMonth = calendar.dateInterval(of: .month, for: now)?.start ?? now
        let startOfLastMonth = calendar.date(byAdding: .month, value: -1, to: startOfThisMonth) ?? startOfThisMonth

        return followedFeedItems.filter { item in
            let date = item.sortTimestamp
            switch filter {
            case .today:
                return date >= startOfToday
            case .thisWeek:
                return date >= startOfThisWeek && date <= now
            case .lastWeek:
                return date >= startOfLastWeek && date < startOfThisWeek
            case .lastMonth:
                return date >= startOfLastMonth && date < startOfThisMonth
            }
        }
    }

    private func updateFeedMapRegion() {
        let coordinates = mappedFeedItems.compactMap { item -> CLLocationCoordinate2D? in
            guard let latitude = item.place?.latitude, let longitude = item.place?.longitude else { return nil }
            return CLLocationCoordinate2D(latitude: latitude, longitude: longitude)
        }
        guard !coordinates.isEmpty else { return }

        let latitudes = coordinates.map(\.latitude)
        let longitudes = coordinates.map(\.longitude)
        let minLat = latitudes.min() ?? 0
        let maxLat = latitudes.max() ?? 0
        let minLon = longitudes.min() ?? 0
        let maxLon = longitudes.max() ?? 0

        feedMapRegion = MKCoordinateRegion(
            center: CLLocationCoordinate2D(
                latitude: (minLat + maxLat) / 2,
                longitude: (minLon + maxLon) / 2
            ),
            span: MKCoordinateSpan(
                latitudeDelta: max((maxLat - minLat) * 1.6, 0.05),
                longitudeDelta: max((maxLon - minLon) * 1.6, 0.05)
            )
        )
    }

    private func ensureVisibleFeedMapRange() {
        guard activeFeedMode == .maps else { return }
        if !mappedFeedItems.isEmpty { return }

        let firstAvailable = FeedMapTimeFilter.allCases.first { filter in
            !filteredFeedItemsByTime(filter).filter {
                $0.place?.latitude != nil && $0.place?.longitude != nil
            }.isEmpty
        }

        if let firstAvailable {
            activeFeedMapFilter = firstAvailable
        }
    }

    private func refreshFeedContactsIfPossible(force: Bool) async {
        guard appState.currentUser != nil else { return }
        let status = CNContactStore.authorizationStatus(for: .contacts)
        await MainActor.run {
            contactsAuthorizationStatus = status
        }
        guard status == .authorized else { return }
        if !force && (!matchedContacts.isEmpty || !unmatchedContacts.isEmpty) { return }

        await MainActor.run {
            isLoadingContacts = true
            matchedContacts = []
            unmatchedContacts = []
            updatingFollowContactIds = []
            resetVisibleContactCounts()
        }

        let contacts = await loadFeedContacts()

        await MainActor.run {
            isLoadingContacts = false
            isMatchingContacts = true
        }

        do {
            var nextMatched: [(contact: NativeInviteContact, match: NativeMatchedFeedContact)] = []
            var nextUnmatched: [NativeInviteContact] = []

            for batch in contacts.chunked(into: contactsMatchBatchSize) {
                let submittedPhoneNumbers = Array(Set(batch.flatMap(\.phoneNumbers)))
                let matches = try await appState.matchContactsForFeed(phoneNumbers: submittedPhoneNumbers)
                let byPhone = Dictionary(uniqueKeysWithValues: matches.map { ($0.phoneNumber, $0) })

                let paired = batch.compactMap { contact -> (contact: NativeInviteContact, match: NativeMatchedFeedContact)? in
                    guard let match = contact.phoneNumbers.compactMap({ byPhone[$0] }).first else { return nil }
                    return (contact, match)
                }
                let matchedIds = Set(paired.map(\.contact.id))
                let unmatched = batch.filter { !matchedIds.contains($0.id) }

                nextMatched.append(contentsOf: paired)
                nextUnmatched.append(contentsOf: unmatched)

                await MainActor.run {
                    matchedContacts = nextMatched
                    unmatchedContacts = nextUnmatched
                }
            }

            await MainActor.run {
                isMatchingContacts = false
            }
        } catch {
            await MainActor.run {
                isMatchingContacts = false
            }
        }
    }

    private func loadFeedContacts() async -> [NativeInviteContact] {
        let store = CNContactStore()
        let keys: [CNKeyDescriptor] = [
            CNContactGivenNameKey as CNKeyDescriptor,
            CNContactFamilyNameKey as CNKeyDescriptor,
            CNContactPhoneNumbersKey as CNKeyDescriptor,
            CNContactThumbnailImageDataKey as CNKeyDescriptor
        ]

        var loaded: [NativeInviteContact] = []
        var seenPhoneNumbers = Set<String>()
        let request = CNContactFetchRequest(keysToFetch: keys)

        do {
            try store.enumerateContacts(with: request) { contact, _ in
                let normalizedPhoneNumbers = Array(
                    Set(
                        contact.phoneNumbers.flatMap { labeled in
                            nativeNormalizedContactPhoneCandidates(from: labeled.value.stringValue)
                        }
                    )
                ).sorted()
                guard !normalizedPhoneNumbers.isEmpty else { return }
                let dedupeKey = normalizedPhoneNumbers.joined(separator: "|")
                guard !seenPhoneNumbers.contains(dedupeKey) else { return }
                seenPhoneNumbers.insert(dedupeKey)

                let fullName = [contact.givenName, contact.familyName]
                    .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
                    .filter { !$0.isEmpty }
                    .joined(separator: " ")
                let displayName = fullName.isEmpty ? "Friend" : fullName

                loaded.append(
                    NativeInviteContact(
                        id: dedupeKey,
                        displayName: displayName,
                        phoneNumbers: normalizedPhoneNumbers,
                        avatarData: contact.thumbnailImageData
                    )
                )
            }
        } catch {
            return []
        }

        return loaded.sorted { $0.displayName.localizedCaseInsensitiveCompare($1.displayName) == .orderedAscending }
    }

    private func requestContactsAccessAsync() async -> Bool {
        await withCheckedContinuation { continuation in
            CNContactStore().requestAccess(for: .contacts) { granted, _ in
                continuation.resume(returning: granted)
            }
        }
    }

