    private func resetVisibleContactCounts() {
        matchedVisibleCount = contactsPageSize
        unmatchedVisibleCount = contactsPageSize
    }

    private func loadMoreMatchedContactsIfNeeded(currentId: String) {
        guard let lastId = visibleMatchedContacts.last?.contact.id, lastId == currentId else { return }
        guard matchedVisibleCount < filteredMatchedContacts.count else { return }
        matchedVisibleCount = min(matchedVisibleCount + contactsPageSize, filteredMatchedContacts.count)
    }

    private func loadMoreUnmatchedContactsIfNeeded(currentId: String) {
        guard let lastId = visibleUnmatchedContacts.last?.id, lastId == currentId else { return }
        guard unmatchedVisibleCount < filteredUnmatchedContacts.count else { return }
        unmatchedVisibleCount = min(unmatchedVisibleCount + contactsPageSize, filteredUnmatchedContacts.count)
    }

    private func feedMatchedContactRow(contact: NativeInviteContact, match: NativeMatchedFeedContact) -> some View {
        let isFollowing = appState.isFollowing(match.traveler.id)
        let isUpdating = updatingFollowContactIds.contains(contact.id)
        return NativeSurfaceCard {
            HStack(spacing: 12) {
                if let avatarData = contact.avatarData, let image = UIImage(data: avatarData) {
                    Image(uiImage: image)
                        .resizable()
                        .scaledToFill()
                        .frame(width: 52, height: 52)
                        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
                } else {
                    NativeAvatarPlaceholderSquare(
                        fallbackText: contact.displayName,
                        size: 52,
                        fontSize: 18
                    )
                }

                VStack(alignment: .leading, spacing: 4) {
                    Text(contact.displayName)
                        .font(nativeAppFont(size: 15, weight: .black))
                        .foregroundStyle(.white)
                        .lineLimit(1)
                    Text("@\(match.traveler.username)")
                        .font(nativeAppFont(size: 12, weight: .semibold))
                        .foregroundStyle(.white.opacity(0.52))
                        .lineLimit(1)
                    Text("In your contacts")
                        .font(nativeAppFont(size: 12, weight: .medium))
                        .foregroundStyle(.white.opacity(0.42))
                }

                Spacer(minLength: 8)

                Button {
                    Task {
                        await handleMatchedContactFollowTap(contact: contact, traveler: match.traveler)
                    }
                } label: {
                    Text(isFollowing ? "Following" : "Follow")
                        .font(nativeAppFont(size: 13, weight: .black))
                        .foregroundStyle(isFollowing ? .white : .black)
                        .padding(.horizontal, 14)
                        .padding(.vertical, 10)
                        .background(isFollowing ? Color.white.opacity(0.08) : nativeAccent)
                        .clipShape(Capsule())
                }
                .buttonStyle(.plain)
                .disabled(isUpdating)
            }
        }
    }

    private func handleMatchedContactFollowTap(contact: NativeInviteContact, traveler: NativeTravelerSummary) async {
        guard !updatingFollowContactIds.contains(contact.id) else { return }

        await MainActor.run {
            updatingFollowContactIds.insert(contact.id)
        }
        defer {
            Task { @MainActor in
                updatingFollowContactIds.remove(contact.id)
            }
        }

        do {
            _ = try await appState.toggleFollow(for: traveler, refreshFeedAfter: true)
        } catch {
            return
        }
    }

