                        }
                    }

                    if let place = item.place {
                        NativeFeedPlaceAttachment(
                            place: place,
                            activityType: item.type,
                            caption: item.caption,
                            uploadedMediaUrls: item.uploadedMediaUrls
                                ?? place.userMediaUrls
                                ?? (place.momentMedia?.map { $0.url } ?? [])
                        ) {
                            NativePlaceDetailScreen(initialPlace: place, source: NativeAnalyticsSource.feed)
                        }
                    }

                    if let collection = item.collection {
                        NavigationLink {
                            NativeCollectionDetailScreen(
                                collection: collection,
                                ownerDisplayName: item.traveler.displayName ?? item.traveler.username,
                                ownerUsername: item.traveler.username
                            )
                        } label: {
                            NativeFeedCollectionAttachment(collection: collection)
                        }
                        .buttonStyle(.plain)
                    }
                }
                }
            }
        }
        .confirmationDialog("Report post", isPresented: $showReportPostDialog, titleVisibility: .visible) {
            ForEach(NativeReportReason.allCases) { reason in
                Button(reason.rawValue) {
                    Task { await reportPost(reason) }
                }
            }
            Button("Cancel", role: .cancel) {}
        } message: {
            Text("Choose the reason that best describes this content.")
        }
        .confirmationDialog("Delete post?", isPresented: $showDeletePostDialog, titleVisibility: .visible) {
            Button("Delete post", role: .destructive) {
                onDeletePost?(item)
            }
            Button("Cancel", role: .cancel) {}
        } message: {
            Text("This will remove this check-in from your profile.")
        }
        .confirmationDialog("Report account", isPresented: $showReportAccountDialog, titleVisibility: .visible) {
            ForEach(NativeReportReason.allCases) { reason in
                Button(reason.rawValue) {
                    Task { await reportAccount(reason) }
                }
            }
            Button("Cancel", role: .cancel) {}
        } message: {
            Text("Choose the reason that best describes this account.")
        }
        .confirmationDialog("Block account?", isPresented: $showBlockAccountDialog, titleVisibility: .visible) {
            Button("Block \(item.traveler.username)", role: .destructive) {
                Task { await blockAccount() }
            }
            Button("Cancel", role: .cancel) {}
        } message: {
            Text("You will no longer see posts or profile activity from this account.")
        }
        .alert("Done", isPresented: $showModerationAlert) {
            Button("OK", role: .cancel) {}
        } message: {
            Text(moderationAlertMessage)
        }
        .sheet(isPresented: $showCommentSheet) {
            NativeCommentSheet(
                itemTitle: item.place?.name ?? item.traveler.username,
                commentDraft: $commentDraft,
                comments: $comments,
                isLoading: isCommentsLoading,
                errorMessage: commentsErrorMessage,
                onPost: {
                    Task { await postComment() }
                }
            )
        }
        .onAppear {
            vibed = item.isVibed
            vibinCount = item.vibinCount
            if item.type == .visited, comments.isEmpty, !isCommentsLoading {
                Task { await loadComments() }
            }
        }
        .contentShape(Rectangle())
        .simultaneousGesture(
            TapGesture().onEnded {
                dismissCommentComposerFocus()
            }
        )
    }

    private var activityLabel: String? {
        switch item.type {
        case .saved:
            return isOwnPost ? "You saved this place" : "Saved this place"
        case .visited:
            return nil
        case .collection:
            return isOwnPost ? "You made a collection" : "Made a collection"
        }
    }

    private var activityIcon: String {
        switch item.type {
        case .saved:
            return "bookmark"
        case .visited:
            return "mappin.and.ellipse"
        case .collection:
            return "square.stack.3d.up"
        }
    }

    private var isOwnDeletablePost: Bool {
        appState.currentUser?.id == item.traveler.id && item.place?.momentId != nil && onDeletePost != nil
    }

    private var shouldShowPostMenu: Bool {
        isOwnDeletablePost || appState.currentUser?.id != item.traveler.id
    }

    private var displayTimestampLabel: String {
        item.timestampLabel.replacingOccurrences(of: ". ago", with: " ago")
    }

    private var commentComposerPlaceholder: String {
        isOwnPost ? "Add a comment" : "Send a thought to @\(item.traveler.username)"
    }

    @ViewBuilder
    private var postMoreMenu: some View {
        Menu {
            if isOwnPost {
                Button(role: .destructive) {
                    showDeletePostDialog = true
                } label: {
                    Text("Delete post")
                }
            } else {
                Button("Report post") {
                    showReportPostDialog = true
                }
                Button("Report account") {
                    showReportAccountDialog = true
                }
                Button(role: .destructive) {
                    showBlockAccountDialog = true
                } label: {
                    Text("Block account")
                }
            }
        } label: {
            Image(systemName: "ellipsis")
                .font(nativeAppFont(size: 14, weight: .black))
                .foregroundStyle(.white.opacity(0.72))
                .frame(width: 32, height: 32)
                .background(Color.white.opacity(0.06))
                .clipShape(Circle())
        }
        .buttonStyle(.plain)
    }

    @ViewBuilder
    private func visitedFeedContent(place: NativePlace) -> some View {
        let shortAddress = nativeShortAddress(for: place)
        let ratingMeta = nativeMomentRatingMeta(label: place.momentRatingLabel, fallbackRating: place.momentRating)
        let mediaURL = item.uploadedMediaUrls?.first
            ?? place.userMediaUrls?.first
            ?? place.momentMedia?.first?.url
            ?? place.image

        NativeVisitedMomentPostCard(
            displayName: item.traveler.displayName ?? item.traveler.username,
            username: item.traveler.username,
            avatarURL: item.traveler.avatar,
            avatarFallback: item.traveler.displayName ?? item.traveler.username,
            headerLinkTraveler: item.traveler,
            ratingMeta: ratingMeta,
            wouldRevisit: place.momentWouldRevisit,
            reviewText: item.caption?.trimmingCharacters(in: .whitespacesAndNewlines),
            mediaURL: mediaURL,
            placeName: place.name,
            placeMetaLine: nativePlaceMetaLine(for: place, shortAddress: shortAddress)
        ) {
            HStack(spacing: 8) {
                Text(displayTimestampLabel)
                    .font(nativeAppFont(size: 12, weight: .bold))
                    .foregroundStyle(.white.opacity(0.58))

                if shouldShowPostMenu {
                    postMoreMenu
                }
            }
        } placeSection: {
            NavigationLink {
                NativePlaceDetailScreen(initialPlace: place, source: NativeAnalyticsSource.feed)
            } label: {
                NativeMomentPlaceInfoCard(
                    placeName: place.name,
                    metaLine: nativePlaceMetaLine(for: place, shortAddress: shortAddress)
                )
            }
            .buttonStyle(.plain)
        } actions: {
            HStack(spacing: 10) {
                HStack(spacing: 10) {
                    TextField(commentComposerPlaceholder, text: $commentDraft)
                        .font(nativeAppFont(size: 14, weight: .semibold))
                        .foregroundColor(.white)
                        .textInputAutocapitalization(.sentences)
                        .disableAutocorrection(false)
                        .focused($isCommentComposerFocused)

                    Button {
                        Task { await postComment() }
                    } label: {
                        if isCommentsLoading {
                            ProgressView()
                                .tint(.black)
                        } else {
                            Image(systemName: "arrow.up")
                                .font(nativeAppFont(size: 13, weight: .black))
                                .foregroundStyle(.black)
                        }
                    }
                    .buttonStyle(.plain)
                    .frame(width: 30, height: 30)
                    .background(commentDraft.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? Color.white.opacity(0.1) : nativeAccent)
                    .clipShape(Circle())
                    .disabled(commentDraft.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || isCommentsLoading)
                }
                .padding(.horizontal, 14)
                .frame(height: 46)
                .background(Color.white.opacity(0.06))
                .clipShape(Capsule())
                .frame(maxWidth: .infinity)

                Button {
                    guard appState.currentUser != nil else {
                        appState.presentAuthGate(reason: "Log in to comment on posts.")
                        return
                    }
                    showCommentSheet = true
                    if comments.isEmpty && !isCommentsLoading {
                        Task { await loadComments() }
                    }
                } label: {
                    HStack(spacing: 8) {
                        Image(systemName: "bubble.left")
                            .font(nativeAppFont(size: 13, weight: .black))
                        if comments.count > 0 {
                            Text("\(comments.count)")
                                .font(nativeAppFont(size: 13, weight: .black))
                        }
                    }
                    .foregroundStyle(.white.opacity(0.82))
                    .padding(.horizontal, 14)
                    .padding(.vertical, 10)
                    .frame(height: 46)
                    .background(Color.white.opacity(0.06))
                    .clipShape(Capsule())
                }
                .buttonStyle(.plain)

                Button {
                    guard appState.currentUser != nil else {
                        appState.presentAuthGate(reason: "Log in to vibin with posts.")
                        return
                    }
                    Task { await toggleVibin() }
                } label: {
                    HStack(spacing: 8) {
                        ZStack {
                            if vibinFlash {
                                Image(systemName: "heart.fill")
                                    .font(nativeAppFont(size: 14, weight: .bold))
                                    .foregroundStyle(nativeAccent.opacity(0.28))
                                    .scaleEffect(1.9)
                                    .blur(radius: 1.5)
                            }

                            Image(systemName: vibed ? "heart.fill" : "heart")
                                .font(nativeAppFont(size: 13, weight: .black))
                                .foregroundStyle(vibed ? .black : .white.opacity(0.82))
                        }
                        if vibinCount > 0 {
                            Text("\(vibinCount)")
                                .font(nativeAppFont(size: 13, weight: .black))
                                .foregroundStyle(vibed ? .black : .white.opacity(0.82))
                        }
                    }
                    .padding(.horizontal, 14)
                    .padding(.vertical, 10)
                    .frame(height: 46)
                    .background(vibed ? nativeAccent : Color.white.opacity(0.06))
                    .clipShape(Capsule())
                    .scaleEffect(vibinScale)
                    .rotationEffect(.degrees(vibinRotation))
                }
                .buttonStyle(.plain)
                .disabled(isTogglingVibin)
            }
        } commentPreview: {
            EmptyView()
        }
    }

    private func nativeRevisitLabel(_ value: String) -> String {
        switch value {
        case "yes":
            return "Would revisit"
        case "maybe", "not_sure":
            return "Maybe"
        case "no", "not_interested":
            return "No revisit"
        default:
            return value.replacingOccurrences(of: "_", with: " ").capitalized
        }
    }

    private var commentTargetType: String? {
        if item.collection != nil { return "COLLECTION" }
        guard let place = item.place else { return nil }
        return place.momentId != nil ? "MOMENT" : "PLACE"
    }

    private var commentTargetId: String? {
        if let collection = item.collection { return collection.id }
        guard let place = item.place else { return nil }
        return place.momentId ?? place.id
    }

    private func loadComments() async {
        guard let targetType = commentTargetType, let targetId = commentTargetId else { return }
        isCommentsLoading = true
        commentsErrorMessage = nil
        do {
            comments = try await appState.fetchComments(targetType: targetType, targetId: targetId)
        } catch {
            commentsErrorMessage = "Could not load comments right now."
        }
        isCommentsLoading = false
    }

    private func postComment() async {
        guard let targetType = commentTargetType, let targetId = commentTargetId else { return }
        let trimmed = commentDraft.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return }
        do {
            let newComment = try await appState.createComment(
                targetType: targetType,
                targetId: targetId,
                body: trimmed,
                momentId: item.place?.momentId
            )
            comments.insert(newComment, at: 0)
            commentDraft = ""
            commentsErrorMessage = nil
            dismissCommentComposerFocus()
        } catch {
            commentsErrorMessage = "Could not post comment right now."
        }
    }

    private func dismissCommentComposerFocus() {
        isCommentComposerFocused = false
        UIApplication.shared.sendAction(#selector(UIResponder.resignFirstResponder), to: nil, from: nil, for: nil)
    }

    private var reportPostTargetType: String? {
        if item.collection != nil { return "COLLECTION" }
        guard let place = item.place else { return nil }
        return place.momentId != nil ? "MOMENT" : "PLACE"
    }

    private var reportPostTargetId: String? {
        if let collection = item.collection { return collection.id }
        guard let place = item.place else { return nil }
        return place.momentId ?? place.id
    }

    private func reportPost(_ reason: NativeReportReason) async {
        guard let targetType = reportPostTargetType, let targetId = reportPostTargetId else { return }
        do {
            try await appState.reportTarget(
                targetType: targetType,
                targetId: targetId,
                targetUserId: item.traveler.id,
                reason: reason
            )
            moderationAlertMessage = "Thanks. This post has been reported."
            showModerationAlert = true
        } catch {
            moderationAlertMessage = "Could not report this post right now."
            showModerationAlert = true
        }
    }

    private func reportAccount(_ reason: NativeReportReason) async {
        do {
            try await appState.reportTarget(
                targetType: "PROFILE",
                targetId: item.traveler.id,
                targetUserId: item.traveler.id,
                reason: reason
            )
            moderationAlertMessage = "Thanks. This account has been reported."
            showModerationAlert = true
        } catch {
            moderationAlertMessage = "Could not report this account right now."
            showModerationAlert = true
        }
    }

    private func blockAccount() async {
        do {
            try await appState.blockTraveler(item.traveler)
            moderationAlertMessage = "This account has been blocked."
            showModerationAlert = true
        } catch {
            moderationAlertMessage = "Could not block this account right now."
            showModerationAlert = true
        }
    }

    private func toggleVibin() async {
        guard !isTogglingVibin else { return }
        guard let targetId = item.place?.momentId ?? item.place?.id, !targetId.isEmpty else { return }

        isTogglingVibin = true
        defer { isTogglingVibin = false }

        do {
            let response = try await appState.toggleMomentVibin(
                targetId: targetId,
                receiverUserId: item.traveler.id,
                momentId: item.place?.momentId
            )
            vibed = response.active
            vibinCount = response.count
            appState.updateFeedItemVibinState(itemId: item.id, isVibed: response.active, vibinCount: response.count)
            withAnimation(.spring(response: 0.22, dampingFraction: 0.52)) {
                vibinScale = 1.22
                vibinRotation = -10
                vibinFlash = true
            }
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.1) {
                withAnimation(.spring(response: 0.24, dampingFraction: 0.76)) {
                    vibinScale = 1
                    vibinRotation = 8
                }
            }
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.2) {
                withAnimation(.spring(response: 0.28, dampingFraction: 0.82)) {
                    vibinRotation = 0
                    vibinFlash = false
                }
            }
        } catch {
            commentsErrorMessage = "Could not update this vibin right now."
        }
    }
}

private struct NativeFeedMetaPill: View {
