                            .padding(.vertical, 14)
                    }
                    TextEditor(text: $commentDraft)
                        .font(nativeAppFont(size: 15, weight: .medium))
                        .foregroundColor(.white)
                        .padding(.horizontal, 10)
                        .padding(.vertical, 8)
                        .frame(minHeight: 72, maxHeight: 72)
                        .background(Color.clear)
                }
                .frame(minHeight: 72, maxHeight: 72)

                HStack {
                    Spacer()
                    Button {
                        onPost()
                    } label: {
                        Text("Post")
                            .font(nativeAppFont(size: 13, weight: .black))
                            .foregroundStyle(.black)
                            .padding(.horizontal, 16)
                            .padding(.vertical, 10)
                            .background(nativeAccent)
                            .clipShape(Capsule())
                    }
                    .buttonStyle(.plain)
                }

                Spacer(minLength: 0)
            }
            .padding(.horizontal, 20)
            .padding(.top, 20)
            .padding(.bottom, 12)
        }
    }
}

private struct NativeFeedPlaceAttachment: View {
    let place: NativePlace
    let activityType: NativeFeedActivityType
    let caption: String?
    // Explicit visited uploads (from moments). This keeps user media separate from place media (Google).
    // When provided, it becomes the single source of truth for the visited horizontal scroller.
    let uploadedMediaUrls: [String]
    let destination: () -> NativePlaceDetailScreen
    @State private var showFullscreenGallery = false
    @State private var fullscreenGalleryStartIndex = 0

    // Explicit initializer to ensure the `uploadedMediaUrls` label is always available and the trailing
    // closure is unambiguously `destination`.
    init(
        place: NativePlace,
        activityType: NativeFeedActivityType,
        caption: String? = nil,
        uploadedMediaUrls: [String] = [],
        destination: @escaping () -> NativePlaceDetailScreen
    ) {
        self.place = place
        self.activityType = activityType
        self.caption = caption
        self.uploadedMediaUrls = uploadedMediaUrls
        self.destination = destination
    }

    private var mediaUrls: [String] {
        let urls = (place.images ?? []).filter { !$0.isEmpty }
        if !urls.isEmpty { return urls }
        if let image = place.image, !image.isEmpty { return [image] }
        return []
    }

    private var thumbnailURL: String? {
        // Prefer a place photo (usually Google) for the place card thumbnail so we don't "steal" user uploads.
        let candidates = [place.image].compactMap { $0 } + (place.images ?? [])
        if let googleish = candidates.first(where: looksLikeGooglePlaceMedia) {
            return googleish
        }
        if let image = place.image, !image.isEmpty { return image }
        return (place.images ?? []).first
    }

    private var visitedUploadedUrls: [String] {
        guard activityType == .visited else { return [] }
        // For visited, ONLY render user-uploaded moment media.
        // Do not infer from place media, because place photos may also be hosted under `/uploads`
        // (for example, cached Google photos) and would incorrectly appear as "user uploads".
        let explicit = uploadedMediaUrls.filter { !$0.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty }
        return Array(NSOrderedSet(array: explicit)) as? [String] ?? explicit
    }

    private var hasVisitedUploadedMedia: Bool {
        !visitedUploadedUrls.isEmpty
    }

    private var ratingMeta: (label: String, icon: String)? {
        nativeMomentRatingMeta(label: place.momentRatingLabel, fallbackRating: place.momentRating)
    }

    private var reviewText: String? {
        let trimmed = caption?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return trimmed.isEmpty ? nil : trimmed
    }

    private var shortAddress: String {
        let raw = place.address?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if raw.isEmpty {
            return place.location
        }
        let parts = raw
            .split(separator: ",")
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        guard let first = parts.first else { return place.location }
        if CharacterSet.decimalDigits.isSuperset(of: CharacterSet(charactersIn: first)),
           parts.count > 1 {
            return "\(first) \(parts[1])"
        }
        return first
    }

    private var placeMetaLine: String {
        [place.category?.trimmingCharacters(in: .whitespacesAndNewlines), shortAddress]
            .compactMap { value -> String? in
                guard let value, !value.isEmpty else { return nil }
                return value
            }
            .joined(separator: " • ")
    }

	var body: some View {
		Group {
            switch activityType {
            case .saved:
                NavigationLink {
                    destination()
                } label: {
                    placeInfoCard(showThumbnail: true, thumbnailURL: thumbnailURL)
                }
                .buttonStyle(.plain)

            case .visited:
                VStack(alignment: .leading, spacing: 12) {
                    if let ratingMeta {
                        NativeFeedMetaPill(
                            label: ratingMeta.label,
                            icon: ratingMeta.icon,
                            foreground: .black,
                            background: nativeAccent
                        )
                    }

                    if let visitedMediaURL = visitedUploadedUrls.first ?? thumbnailURL {
                        visitedPrimaryMedia(url: visitedMediaURL)
                    }

                    if let reviewText {
                        Text(reviewText)
                            .font(nativeAppFont(size: 15, weight: .semibold))
                            .foregroundStyle(.white.opacity(0.9))
                            .fixedSize(horizontal: false, vertical: true)
                    }

                    NavigationLink {
                        destination()
                    } label: {
                        visitedPlaceInfoCard
                    }
                    .buttonStyle(.plain)
                }
                .fullScreenCover(isPresented: $showFullscreenGallery) {
                    NativeFullscreenMediaGallery(
                        urls: visitedUploadedUrls,
                        startIndex: fullscreenGalleryStartIndex
                    )
                }

            case .collection:
                NavigationLink {
                    destination()
                } label: {
                    VStack(alignment: .leading, spacing: 0) {
                        NativeFeedSingleMedia(url: thumbnailURL)
                        VStack(alignment: .leading, spacing: 10) {
                            HStack(alignment: .top, spacing: 12) {
                                VStack(alignment: .leading, spacing: 8) {
									Text(place.name)
                                        .font(nativeAppFont(size: 18, weight: .black))
                                        .foregroundStyle(.white)
                                        .fixedSize(horizontal: false, vertical: true)
                                    if let category = place.category, !category.isEmpty {
                                        Text(category.uppercased())
                                            .font(nativeAppFont(size: 10, weight: .black))
                                            .foregroundStyle(.white.opacity(0.55))
                                            .padding(.horizontal, 10)
                                            .padding(.vertical, 6)
                                            .background(Color.white.opacity(0.08))
                                            .clipShape(Capsule())
                                    }
                                }
                                Spacer(minLength: 0)
                                if let score = place.similarityStat {
                                    Text("\(score)%")
                                        .font(nativeAppFont(size: 11, weight: .black))
