                Image(systemName: "xmark")
                    .font(nativeAppFont(size: 14, weight: .black))
                    .foregroundStyle(.white.opacity(0.9))
                    .frame(width: 40, height: 40)
                    .background(Color.white.opacity(0.08))
                    .clipShape(Circle())
                    .padding(.top, 16)
                    .padding(.trailing, 16)
            }
            .buttonStyle(.plain)
        }
    }
}

