private struct NativeFlexibleRemoteImage: View {
    let url: String?

    var body: some View {
        AsyncImage(url: nativeResolvedImageURL(url).flatMap(URL.init(string:))) { phase in
            switch phase {
            case .success(let image):
                image
                    .resizable()
                    .scaledToFit()
                    .frame(maxWidth: .infinity, maxHeight: .infinity)
                    .background(Color.black)
            case .failure(_):
                fallback
            case .empty:
                ZStack {
                    fallback
                    ProgressView().tint(nativeAccent)
                }
            @unknown default:
                fallback
            }
        }
    }

    private var fallback: some View {
        LinearGradient(
            colors: [Color.white.opacity(0.08), Color.white.opacity(0.03)],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }
}

private struct NativeVideoPreview: View {
    let url: String?
    let isActive: Bool
    @State private var player: AVPlayer? = nil
    @State private var isMuted = true
    @State private var endObserver: NSObjectProtocol? = nil

    var body: some View {
        ZStack {
            if let resolved = nativeResolvedImageURL(url), let videoURL = URL(string: resolved) {
                NativeInlineVideoPlayer(player: player)
                    .aspectRatio(contentMode: .fit)
                    .frame(maxWidth: .infinity, maxHeight: .infinity)
                    .background(Color.black)
                    .onAppear {
                        if player == nil {
                            let avPlayer = AVPlayer(url: videoURL)
                            avPlayer.isMuted = isMuted
                            avPlayer.actionAtItemEnd = .none
                            endObserver = NotificationCenter.default.addObserver(
                                forName: .AVPlayerItemDidPlayToEndTime,
                                object: avPlayer.currentItem,
                                queue: .main
                            ) { _ in
                                avPlayer.seek(to: .zero)
                                avPlayer.playImmediately(atRate: 1.0)
                            }
                            if isActive {
                                avPlayer.playImmediately(atRate: 1.0)
                            }
                            player = avPlayer
                        } else {
                            player?.isMuted = isMuted
                            if isActive {
                                player?.playImmediately(atRate: 1.0)
                            } else {
                                player?.pause()
                            }
                        }
                    }
                    .onChange(of: isMuted) { newValue in
                        player?.isMuted = newValue
                    }
                    .onChange(of: isActive) { newValue in
                        if newValue {
                            player?.playImmediately(atRate: 1.0)
                        } else {
                            player?.pause()
                        }
                    }
                    .onDisappear {
                        player?.pause()
                        if let endObserver {
                            NotificationCenter.default.removeObserver(endObserver)
                            self.endObserver = nil
                        }
                    }
            } else {
                LinearGradient(
                    colors: [Color.white.opacity(0.08), Color.white.opacity(0.03)],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            }

        }
        .overlay(alignment: .bottomTrailing) {
            if player != nil {
                Button {
                    isMuted.toggle()
                } label: {
                    Image(systemName: isMuted ? "speaker.slash.fill" : "speaker.wave.2.fill")
                        .font(nativeAppFont(size: 13, weight: .black))
                        .foregroundStyle(.white)
                        .frame(width: 38, height: 38)
                        .background(Color.black.opacity(0.6))
                        .clipShape(Circle())
                }
                .buttonStyle(.plain)
                .padding(12)
            }
        }
        .clipped()
    }
}

private struct NativeInlineVideoPlayer: UIViewRepresentable {
    let player: AVPlayer?

    func makeUIView(context: Context) -> UIView {
        let container = UIView()
        container.backgroundColor = .black
        container.isUserInteractionEnabled = false

        let playerLayer = AVPlayerLayer()
        playerLayer.videoGravity = .resizeAspect
        playerLayer.player = player
        playerLayer.frame = container.bounds
        container.layer.addSublayer(playerLayer)

        context.coordinator.playerLayer = playerLayer
        return container
    }

    func updateUIView(_ uiView: UIView, context: Context) {
        context.coordinator.playerLayer?.player = player
        context.coordinator.playerLayer?.frame = uiView.bounds
    }

    func makeCoordinator() -> Coordinator {
        Coordinator()
    }

    final class Coordinator {
        var playerLayer: AVPlayerLayer?
    }
}

private struct NativeShareSheet: UIViewControllerRepresentable {
    let items: [Any]

    func makeUIViewController(context: Context) -> UIActivityViewController {
        UIActivityViewController(activityItems: items, applicationActivities: nil)
    }

    func updateUIViewController(_ uiViewController: UIActivityViewController, context: Context) {}
}

private struct NativeMessageComposer: UIViewControllerRepresentable {
    let recipients: [String]
    let body: String
    let onComplete: (Bool) -> Void

    final class Coordinator: NSObject, MFMessageComposeViewControllerDelegate {
        let onComplete: (Bool) -> Void

        init(onComplete: @escaping (Bool) -> Void) {
            self.onComplete = onComplete
        }

        func messageComposeViewController(
            _ controller: MFMessageComposeViewController,
            didFinishWith result: MessageComposeResult
        ) {
            controller.dismiss(animated: true)
            onComplete(result == .sent)
        }
    }

    func makeCoordinator() -> Coordinator {
        Coordinator(onComplete: onComplete)
    }

    func makeUIViewController(context: Context) -> MFMessageComposeViewController {
        let controller = MFMessageComposeViewController()
        controller.messageComposeDelegate = context.coordinator
        controller.recipients = recipients
        controller.body = body
        return controller
    }

    func updateUIViewController(_ uiViewController: MFMessageComposeViewController, context: Context) {}
}

