private struct NativeFollowersScreen: View {
    @EnvironmentObject private var appState: NativeAppState
    let traveler: NativeTravelerSummary
    @State private var followers: [NativeFollowerListItem] = []
    @State private var isLoading = false
    @State private var errorMessage: String?

    var body: some View {
        ScrollView(showsIndicators: false) {
            VStack(alignment: .leading, spacing: 16) {
                if let errorMessage {
                    NativeInlineError(message: errorMessage)
                }

                if isLoading && followers.isEmpty {
                    NativeSurfaceCard {
                        HStack {
                            ProgressView().tint(nativeAccent)
                            Text("Loading friends")
                                .font(nativeAppFont(size: 14, weight: .medium))
                                .foregroundStyle(.white.opacity(0.64))
                        }
                    }
                } else if followers.isEmpty {
                    NativeSurfaceCard {
                        Text("No friends visible right now.")
                            .font(nativeAppFont(size: 15, weight: .medium))
                            .foregroundStyle(.white.opacity(0.62))
                    }
                } else {
                    LazyVStack(spacing: 12) {
                        ForEach(followers) { follower in
                            NativeFollowerRow(follower: follower)
                        }
                    }
                }
            }
            .padding(.horizontal, 20)
            .padding(.top, 12)
            .padding(.bottom, 28)
        }
        .background(Color.black.ignoresSafeArea())
        .navigationTitle("Friends")
        .navigationBarTitleDisplayMode(.inline)
        .onAppear {
            appState.pushFloatingTabBarHidden()
        }
        .onDisappear {
            appState.popFloatingTabBarHidden()
        }
        .task {
            guard !isLoading else { return }
            isLoading = true
            defer { isLoading = false }

            do {
                followers = try await appState.fetchTravelerFriends(id: traveler.id)
            } catch {
                errorMessage = "Could not load friends right now."
            }
        }
    }
}

