                        .foregroundStyle(appState.isFollowing(follower.id) ? .white : .black)
                        .padding(.horizontal, 12)
                        .padding(.vertical, 9)
                        .background(appState.isFollowing(follower.id) ? Color.white.opacity(0.08) : nativeAccent)
