private struct NativeTravelerProfileScreen: View {
    @Environment(\.dismiss) private var dismiss
    @EnvironmentObject private var appState: NativeAppState
    @State private var traveler: NativeTravelerSummary
    @State private var moments: [NativeMoment] = []
    @State private var isLoading = false
    @State private var isUpdatingFollow = false
    @State private var showShareSheet = false
    @State private var selectedProfileFeedItem: NativeFeedItem?
    @State private var showReportAccountDialog = false
    @State private var showBlockAccountDialog = false
    @State private var moderationAlertMessage = ""
    @State private var showModerationAlert = false
    @State private var errorMessage: String?
    @State private var activeMode: NativeTravelerProfileContentMode = .gallery
    @State private var activeGalleryGrouping: NativeDiaryGalleryGrouping = .byDate
    @State private var activePostsCityFilter: String = "All cities"
    @State private var activeMapTimeFilter: NativeTravelerProfileMapTimeFilter = .thisWeek
    @State private var mapRegion = MKCoordinateRegion(
        center: CLLocationCoordinate2D(latitude: 40.7128, longitude: -74.0060),
        span: MKCoordinateSpan(latitudeDelta: 0.25, longitudeDelta: 0.25)
    )

    private struct GallerySection: Identifiable {
        let id: String
        let title: String
        let moments: [NativeMoment]
    }

    private enum NativeTravelerProfileContentMode: String, CaseIterable, Identifiable {
        case gallery = "Gallery"
        case posts = "Posts"
        case map = "Map"

        var id: String { rawValue }
    }

    private enum NativeTravelerProfileMapTimeFilter: String, CaseIterable, Identifiable {
        case today = "Today"
        case thisWeek = "This week"
        case lastWeek = "Last week"
        case lastMonth = "Last month"

        var id: String { rawValue }
    }

    init(initialTraveler: NativeTravelerSummary) {
        _traveler = State(initialValue: initialTraveler)
        _moments = State(initialValue: [])
    }

    var body: some View {
        ScrollView(showsIndicators: false) {
            VStack(alignment: .leading, spacing: 18) {
                travelerIdentityHeader

                if let errorMessage {
                    NativeInlineError(message: errorMessage)
                }

                travelerBioSection
                travelerStatsSection
                followAndProfileActions
                travelerModePicker
                if hasProfileMoments {
                    travelerFilterSection
                }
                travelerModeContent
            }
            .padding(.horizontal, nativeTravelerProfileHorizontalPadding)
            .padding(.top, 20)
            .padding(.bottom, 28)
        }
        .background(Color.black.ignoresSafeArea())
        .navigationTitle("@\(traveler.username)")
        .navigationBarTitleDisplayMode(.inline)
        .toolbar {
            ToolbarItem(placement: .topBarTrailing) {
                Button {
                    appState.trackAnalytics(
                        .shareProfile,
                        properties: [
                            "profile_user_id": traveler.id,
                            "profile_username": traveler.username,
                            "source": NativeAnalyticsSource.userProfile,
                        ]
                    )
                    showShareSheet = true
                } label: {
                    Image(systemName: "square.and.arrow.up")
                        .font(nativeAppFont(size: 16, weight: .bold))
                        .foregroundStyle(.white)
                }
                .buttonStyle(.plain)
            }
        }
        .task {
            await loadTravelerProfile()
            updateMapRegion()
        }
        .onAppear {
            appState.trackAnalytics(
                .visitUserProfile,
                properties: [
                    "profile_user_id": traveler.id,
                    "profile_username": traveler.username,
                    "profile_display_name": traveler.displayName ?? "",
                    "source": NativeAnalyticsSource.userProfile,
                ]
            )
            appState.pushFloatingTabBarHidden()
            let appearance = UINavigationBarAppearance()
            appearance.configureWithOpaqueBackground()
            appearance.backgroundColor = UIColor(red: 16 / 255, green: 16 / 255, blue: 19 / 255, alpha: 0.98)
            appearance.titleTextAttributes = [.foregroundColor: UIColor.white]
            appearance.largeTitleTextAttributes = [.foregroundColor: UIColor.white]
            UINavigationBar.appearance().standardAppearance = appearance
            UINavigationBar.appearance().scrollEdgeAppearance = appearance
            UINavigationBar.appearance().compactAppearance = appearance
        }
        .onDisappear {
            appState.popFloatingTabBarHidden()
        }
        .sheet(isPresented: $showShareSheet) {
            NativeShareSheet(items: ["https://vibinn.club/u/\(traveler.username)"])
        }
        .fullScreenCover(item: $selectedProfileFeedItem) { item in
            NativeFeedMomentFullscreen(item: item)
                .environmentObject(appState)
        }
        .confirmationDialog("Report account", isPresented: $showReportAccountDialog, titleVisibility: .visible) {
            ForEach(NativeReportReason.allCases) { reason in
                Button(reason.rawValue) {
                    Task { await reportAccount(reason) }
                }
            }
            Button("Cancel", role: .cancel) {}
        } message: {
            Text("Choose the reason that best describes this account.")
        }
        .confirmationDialog("Block account?", isPresented: $showBlockAccountDialog, titleVisibility: .visible) {
            Button("Block \(traveler.username)", role: .destructive) {
                Task { await blockAccount() }
            }
            Button("Cancel", role: .cancel) {}
        } message: {
            Text("You will no longer see this account or their feed activity.")
        }
        .alert("Done", isPresented: $showModerationAlert) {
            Button("OK", role: .cancel) {}
        } message: {
            Text(moderationAlertMessage)
        }
        .onChange(of: moments.count) { _ in
            normalizeProfileFilters()
            updateMapRegion()
        }
        .onChange(of: activeMapTimeFilter) { _ in
            if activeMode == .map {
                updateMapRegion()
            }
        }
        .onChange(of: activeMode) { _ in
            if activeMode == .map {
                updateMapRegion()
            }
        }
    }

    private var travelerIdentityHeader: some View {
        HStack(alignment: .top, spacing: 14) {
            NativeAvatarCircle(
                url: traveler.avatar,
                fallbackText: traveler.displayName ?? traveler.username,
                size: 68,
                fontSize: 22
            )

            VStack(alignment: .leading, spacing: 6) {
                Text(traveler.displayName ?? traveler.username)
                    .font(nativeAppFont(size: 24, weight: .black))
                    .foregroundStyle(.white)
                    .fixedSize(horizontal: false, vertical: true)

                Text("@\(traveler.username)")
                    .font(nativeAppFont(size: 14, weight: .bold))
                    .foregroundStyle(.white.opacity(0.55))

                if let cityLabel = travelerCityLabel {
                    Text(cityLabel)
                        .font(nativeAppFont(size: 13, weight: .bold))
                        .foregroundStyle(nativeAccent)
                }
            }

            Spacer(minLength: 0)
        }
    }

    @ViewBuilder
    private var travelerBioSection: some View {
        if let bio = traveler.bio?.trimmingCharacters(in: .whitespacesAndNewlines), !bio.isEmpty {
            NativeSurfaceCard {
                Text(bio)
                    .font(nativeAppFont(size: 14, weight: .medium))
                    .foregroundStyle(.white.opacity(0.78))
                    .fixedSize(horizontal: false, vertical: true)
                    .frame(maxWidth: .infinity, alignment: .leading)
            }
        }
    }

    private var followAndProfileActions: some View {
        HStack(spacing: 10) {
            if !isCurrentUser {
                Button {
                    Task { await toggleFollow() }
                } label: {
                    HStack {
                        Spacer()
                        if isUpdatingFollow {
                            ProgressView().tint(isFollowing ? .white : .black)
                        } else {
                            Text(isFollowing ? "Following" : "Follow")
                                .font(nativeAppFont(size: 15, weight: .black))
                        }
                        Spacer()
                    }
                    .padding(.vertical, 14)
                    .background(isFollowing ? Color.white.opacity(0.08) : nativeAccent)
                    .foregroundStyle(isFollowing ? .white : .black)
                    .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                }
                .buttonStyle(.plain)
                .disabled(isUpdatingFollow)
            }

            Menu {
                if appState.isBlocked(traveler.id) {
                    Button("Unblock") {
                        Task { await unblockAccount() }
                    }
                } else {
                    Button("Block", role: .destructive) {
                        showBlockAccountDialog = true
                    }
                }
                Button("Report", role: .destructive) {
                    showReportAccountDialog = true
                }
            } label: {
                Image(systemName: "ellipsis")
                    .font(nativeAppFont(size: 16, weight: .black))
                    .foregroundStyle(.white)
                    .frame(width: 48, height: 48)
                    .background(Color.white.opacity(0.08))
                    .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
            }
        }
    }

    private var travelerStatsSection: some View {
        let stats = [
            ("Places", profileUniquePlaceCount),
            ("Followers", traveler.followersCount ?? 0),
            ("Following", traveler.followingCount ?? 0),
        ]

        return LazyVGrid(columns: Array(repeating: GridItem(.flexible(), spacing: 10), count: 3), spacing: 10) {
            ForEach(Array(stats.enumerated()), id: \.offset) { _, stat in
                NativeProfileMiniStat(label: stat.0, value: "\(stat.1)")
            }
        }
    }

    private var travelerModePicker: some View {
        HStack(spacing: 0) {
            ForEach(NativeTravelerProfileContentMode.allCases) { mode in
                Button {
                    activeMode = mode
                } label: {
                    VStack(spacing: 10) {
                        HStack(spacing: 7) {
                            Image(systemName: travelerModeIconName(for: mode))
                                .font(nativeAppFont(size: 13, weight: .black))
                            Text(mode.rawValue)
                                .font(nativeAppFont(size: 14, weight: .black))
                        }
                        .foregroundStyle(activeMode == mode ? .white : .white.opacity(0.56))
                        .frame(maxWidth: .infinity)

                        Rectangle()
                            .fill(activeMode == mode ? nativeAccent : Color.white.opacity(0.12))
                            .frame(height: 3)
                    }
                    .frame(maxWidth: .infinity)
                }
                .buttonStyle(.plain)
                .frame(maxWidth: .infinity)
            }
        }
        .overlay(alignment: .bottom) {
            Rectangle()
                .fill(Color.white.opacity(0.08))
                .frame(height: 1)
        }
    }

    @ViewBuilder
    private var travelerFilterSection: some View {
        switch activeMode {
        case .gallery:
            ScrollView(.horizontal, showsIndicators: false) {
                HStack(spacing: 10) {
                    ForEach(NativeDiaryGalleryGrouping.allCases) { grouping in
                        Button {
                            activeGalleryGrouping = grouping
                        } label: {
                            Text(grouping.rawValue)
                                .font(nativeAppFont(size: 12, weight: .bold))
                                .foregroundStyle(activeGalleryGrouping == grouping ? .black : .white.opacity(0.72))
                                .padding(.horizontal, 12)
                                .padding(.vertical, 9)
                                .background(activeGalleryGrouping == grouping ? nativeAccent : Color.white.opacity(0.06))
                                .clipShape(Capsule())
                        }
                        .buttonStyle(.plain)
                    }
                }
            }
        case .posts:
            ScrollView(.horizontal, showsIndicators: false) {
                HStack(spacing: 10) {
                    ForEach(profileAvailableCities, id: \.self) { city in
                        Button {
                            activePostsCityFilter = city
                        } label: {
                            Text(city)
                                .font(nativeAppFont(size: 12, weight: .bold))
                                .foregroundStyle(activePostsCityFilter == city ? .black : .white.opacity(0.72))
                                .padding(.horizontal, 12)
                                .padding(.vertical, 9)
                                .background(activePostsCityFilter == city ? nativeAccent : Color.white.opacity(0.06))
                                .clipShape(Capsule())
                        }
                        .buttonStyle(.plain)
                    }
                }
            }
        case .map:
            ScrollView(.horizontal, showsIndicators: false) {
                HStack(spacing: 10) {
                    ForEach(NativeTravelerProfileMapTimeFilter.allCases) { filter in
                        Button {
                            activeMapTimeFilter = filter
                        } label: {
                            Text(filter.rawValue)
                                .font(nativeAppFont(size: 12, weight: .bold))
                                .foregroundStyle(activeMapTimeFilter == filter ? .black : .white.opacity(0.72))
                                .padding(.horizontal, 12)
                                .padding(.vertical, 9)
                                .background(activeMapTimeFilter == filter ? nativeAccent : Color.white.opacity(0.06))
                                .clipShape(Capsule())
                        }
                        .buttonStyle(.plain)
                    }
                }
            }
        }
    }

    @ViewBuilder
    private var travelerModeContent: some View {
        switch activeMode {
        case .posts:
            if profileFeedItems.isEmpty {
                NativeSurfaceCard {
                    Text(hasProfileMoments ? "No posts in this city yet." : "No posts yet.")
                        .font(nativeAppFont(size: 15, weight: .medium))
                        .foregroundStyle(.white.opacity(0.6))
                }
            } else {
                LazyVStack(spacing: 14) {
                    ForEach(profileFeedItems) { item in
                        NativeFeedCard(item: item)
                    }
                }
            }
        case .gallery:
            if gallerySections.isEmpty {
                NativeSurfaceCard {
                    Text(hasProfileMoments ? "No gallery memories in this section yet." : "No gallery yet.")
                        .font(nativeAppFont(size: 15, weight: .medium))
                        .foregroundStyle(.white.opacity(0.6))
                }
            } else {
                VStack(alignment: .leading, spacing: 18) {
                    ForEach(gallerySections) { section in
                        VStack(alignment: .leading, spacing: 10) {
                            Text(section.title)
                                .font(nativeAppFont(size: 15, weight: .black))
                                .foregroundStyle(.white)

                            LazyVGrid(columns: Array(repeating: GridItem(.flexible(), spacing: 8), count: 3), spacing: 8) {
                                ForEach(section.moments) { moment in
                                    Button {
                                        selectedProfileFeedItem = feedItem(for: moment)
                                    } label: {
                                        profileGalleryThumb(moment)
                                    }
                                    .buttonStyle(.plain)
                                }
                            }
                        }
                    }
                }
            }
        case .map:
            if profileMappedFeedItems.isEmpty {
                NativeSurfaceCard {
                    Text(hasProfileMoments ? "No mapped posts in this range yet." : "No mapped posts yet.")
                        .font(nativeAppFont(size: 15, weight: .medium))
                        .foregroundStyle(.white.opacity(0.6))
                }
            } else {
                VStack(alignment: .leading, spacing: 12) {
                    profileMapCard
                        .padding(.horizontal, -nativeTravelerProfileHorizontalPadding)

                    Text("\(profileMappedFeedItems.count) mapped posts")
                        .font(nativeAppFont(size: 13, weight: .semibold))
                        .foregroundStyle(.white.opacity(0.58))
                        .padding(.horizontal, 20)
                }
            }
        }
    }

    private var profileUniquePlaceCount: Int {
        Set(profileMoments.map(\.place.id)).count
    }

    private var hasProfileMoments: Bool {
        !profileMoments.isEmpty
    }

    private var isFollowing: Bool {
        appState.isFollowing(traveler.id)
    }

    private var isCurrentUser: Bool {
        appState.currentUser?.id == traveler.id
    }

    private var travelerCityLabel: String? {
        let raw = traveler.descriptor?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !raw.isEmpty, raw.count <= 32 else { return nil }
        return raw
    }

    private var profileMoments: [NativeMoment] {
        moments.sorted {
            let lhs = NativeAppState.feedSortDate(iso: $0.visitedAtIso ?? $0.visitedDate, label: $0.visitedDate) ?? .distantPast
            let rhs = NativeAppState.feedSortDate(iso: $1.visitedAtIso ?? $1.visitedDate, label: $1.visitedDate) ?? .distantPast
            return lhs > rhs
        }
    }

    private var profileAvailableCities: [String] {
        ["All cities"] + Array(Set(profileMoments.compactMap(nativeCityKey(for:)))).sorted()
    }

    private var gallerySections: [GallerySection] {
        switch activeGalleryGrouping {
        case .byDate:
            return profileGallerySectionsByDate()
        case .byCity:
            return profileGallerySectionsByCity()
        }
    }

    private var filteredPostMoments: [NativeMoment] {
        if activePostsCityFilter == "All cities" {
            return profileMoments
        }
        return profileMoments.filter { nativeCityKey(for: $0) == activePostsCityFilter }
    }

    private var profileFeedItems: [NativeFeedItem] {
        filteredPostMoments.map(feedItem(for:))
    }

    private var allProfileFeedItems: [NativeFeedItem] {
        profileMoments.map(feedItem(for:))
    }

    private var profileMappedFeedItems: [NativeFeedItem] {
        allProfileFeedItems.filter { item in
            item.place?.latitude != nil
                && item.place?.longitude != nil
                && profileMatchesMapTimeFilter(item, filter: activeMapTimeFilter)
        }
    }

