private struct NativeTravelerRecentPostsFullscreen: View {
    @EnvironmentObject private var appState: NativeAppState
    @Environment(\.dismiss) private var dismiss
    let items: [NativeFeedItem]
    let startIndex: Int
    @State private var selection: Int
    @State private var dragOffset: CGFloat = 0

    private let horizontalPadding: CGFloat = 20
    private let progressTrailingInset: CGFloat = 14
    private let progressReservedWidth: CGFloat = 14

    init(items: [NativeFeedItem], startIndex: Int) {
        self.items = items
        self.startIndex = startIndex
        _selection = State(initialValue: startIndex)
    }

    var body: some View {
        GeometryReader { geometry in
            ZStack(alignment: .top) {
                Color.black.ignoresSafeArea()

                header
                    .padding(.horizontal, 18)
                    .padding(.top, max(geometry.safeAreaInsets.top, 16))
                    .zIndex(3)

                ZStack {
                    ForEach(Array(items.enumerated()), id: \.element.id) { index, item in
                        let relativeIndex = index - selection

                        VStack(spacing: 0) {
                            Spacer(minLength: 0)

                            NativeTodayLiveFeedCard(item: item, showsTravelerHeader: false, isLocked: false, onUnlockTap: {})
                                .frame(maxWidth: min(geometry.size.width - (horizontalPadding * 2) - progressReservedWidth - 10, 520))
                                .padding(.horizontal, horizontalPadding)
                                .padding(.top, max(geometry.safeAreaInsets.top + 22, 68))
                                .padding(.bottom, 44)

                            Spacer(minLength: 0)
                        }
                        .frame(width: geometry.size.width, height: geometry.size.height)
                        .offset(y: CGFloat(relativeIndex) * geometry.size.height + (relativeIndex == 0 ? dragOffset : 0))
                        .opacity(relativeIndex == 0 ? 1 : 0)
                        .animation(.spring(response: 0.34, dampingFraction: 0.86), value: selection)
                    }
                }
                .contentShape(Rectangle())
                .gesture(
                    DragGesture()
                        .onChanged { value in
                            dragOffset = value.translation.height
                        }
                        .onEnded { value in
                            let threshold = geometry.size.height * 0.18
                            let translation = value.translation.height
                            if translation < -threshold {
                                moveSelection(by: 1)
                            } else if translation > threshold {
                                moveSelection(by: -1)
                            }
                            withAnimation(.spring(response: 0.32, dampingFraction: 0.84)) {
                                dragOffset = 0
                            }
                        }
                )

                progressBar
                    .padding(.trailing, progressTrailingInset)
                    .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .trailing)
            }
        }
        .background(Color.black.ignoresSafeArea())
        .navigationBarHidden(true)
    }

    private var header: some View {
        HStack {
            Button {
                dismiss()
            } label: {
                Image(systemName: "chevron.left")
                    .font(nativeAppFont(size: 16, weight: .black))
                    .foregroundStyle(.white)
                    .frame(width: 44, height: 44)
                    .background(nativeSurface)
                    .clipShape(Circle())
            }
            .buttonStyle(.plain)

            Spacer(minLength: 0)

            Text("@\(items[safe: selection]?.traveler.username ?? items.first?.traveler.username ?? "")")
                .font(nativeAppFont(size: 16, weight: .black))
                .foregroundStyle(.white)
                .lineLimit(1)

            Spacer(minLength: 0)

            Color.clear
                .frame(width: 44, height: 44)
        }
    }

    private var progressBar: some View {
        VStack(spacing: 8) {
            ForEach(Array(items.enumerated()), id: \.offset) { index, _ in
                Capsule()
                    .fill(index == selection ? nativeAccent : Color.white.opacity(0.12))
                    .frame(width: 6, height: index == selection ? 28 : 10)
                    .animation(.spring(response: 0.28, dampingFraction: 0.82), value: selection)
            }
        }
    }

    private func moveSelection(by delta: Int) {
        let nextIndex = max(0, min(items.count - 1, selection + delta))
        guard nextIndex != selection else { return }
        selection = nextIndex
    }
}

