    private var heroMediaItems: [NativePlaceHeroMediaItem] {
        mediaUrls.enumerated().map { index, url in
            NativePlaceHeroMediaItem(index: index, url: url)
        }
    }

    private var mediaUrls: [String] {
        let googlePhoto = [
            place.placeMediaUrls?.first,
            place.image,
            place.images?.first
        ]
        .compactMap { $0?.trimmingCharacters(in: .whitespacesAndNewlines) }
        .first(where: { !$0.isEmpty })

        let vibinnPhotos = travelerMoments
            .flatMap { $0.uploadedMedia ?? [] }
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }

        return Array(NSOrderedSet(array: [googlePhoto].compactMap { $0 } + vibinnPhotos)) as? [String] ?? []
    }

    private var compatibilityBadge: NativeCompatibilityBadgeMeta? {
        nativeCompatibilityBadge(for: place.similarityStat)
    }

    private var topTagLabel: String? {
        if let topBadgeLabel = place.topBadgeLabel?.trimmingCharacters(in: .whitespacesAndNewlines), !topBadgeLabel.isEmpty {
            return topBadgeLabel
        }
        if let topSignal = topDiscoverySignal {
            return "Top \(topSignal.rank) \(topSignal.queryText)"
        }
        if let first = place.tags?.first, !first.isEmpty { return first }
        if let attitudeLabel = place.attitudeLabel, !attitudeLabel.isEmpty { return attitudeLabel }
        if let category = place.category, !category.isEmpty { return category }
        return nil
    }

    private var topDiscoverySignal: (rank: Int, queryText: String)? {
        place.discoverySignals?
            .compactMap { signal -> (rank: Int, queryText: String)? in
                guard
                    let rank = signal.bestResultRank ?? signal.resultRank,
                    let queryText = signal.queryText?.trimmingCharacters(in: .whitespacesAndNewlines),
                    !queryText.isEmpty
                else { return nil }
                return (rank, queryText)
            }
            .sorted { lhs, rhs in lhs.rank < rhs.rank }
            .first
    }

    private var distanceLabel: String? {
        guard
            let latitude = place.latitude,
            let longitude = place.longitude,
            let origin = appState.currentCoordinate
        else { return nil }
        let destination = CLLocation(latitude: latitude, longitude: longitude)
        let source = CLLocation(latitude: origin.latitude, longitude: origin.longitude)
        let miles = source.distance(from: destination) / 1609.344
        if miles < 0.1 {
            return String(format: "%.0f ft away", source.distance(from: destination) * 3.28084)
        }
        return String(format: "%.1f mi away", miles)
    }

