    private var hasDirectionsDestination: Bool {
        mapCoordinate != nil || !(place.address?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true)
    }

    private var appleDirectionsURL: URL? {
        if let latitude = place.latitude, let longitude = place.longitude {
            let name = place.name.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? place.name
            if let origin = appState.currentCoordinate {
                return URL(string: "http://maps.apple.com/?saddr=\(origin.latitude),\(origin.longitude)&daddr=\(latitude),\(longitude)&q=\(name)&dirflg=d")
            }
            return URL(string: "http://maps.apple.com/?daddr=\(latitude),\(longitude)&q=\(name)&dirflg=d")
        }
        if let address = place.address?.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) {
            return URL(string: "http://maps.apple.com/?daddr=\(address)&dirflg=d")
        }
        return nil
    }

    private var googleDirectionsURL: URL? {
        if let latitude = place.latitude, let longitude = place.longitude {
            var components = URLComponents(string: "comgooglemaps://")
            var queryItems = [
                URLQueryItem(name: "daddr", value: "\(latitude),\(longitude)"),
                URLQueryItem(name: "directionsmode", value: "driving")
            ]
            if let origin = appState.currentCoordinate {
                queryItems.append(URLQueryItem(name: "saddr", value: "\(origin.latitude),\(origin.longitude)"))
            }
            components?.queryItems = queryItems
            return components?.url
        }
        guard let address = place.address?.trimmingCharacters(in: .whitespacesAndNewlines), !address.isEmpty else { return nil }
        var components = URLComponents(string: "comgooglemaps://")
        components?.queryItems = [
            URLQueryItem(name: "daddr", value: address),
            URLQueryItem(name: "directionsmode", value: "driving")
        ]
        return components?.url
    }

    private func openExternalMapURL(_ url: URL?) {
        guard let url else { return }
        UIApplication.shared.open(url)
    }

    private func loadLatestPlace() async {
        guard !isLoading else { return }
        if let cachedPayload = appState.cachedPlaceDetail(id: place.id) {
            applyDetailPayload(cachedPayload)
        }

        isLoading = true
        defer { isLoading = false }
        nativeLogger.log(
            "place detail load start id=\(self.place.id, privacy: .public) initialScore=\(String(describing: self.place.similarityStat), privacy: .public)"
        )

        let resolvedPayload = try? await appState.fetchPlaceDetail(id: place.id, useCache: false)

        guard let resolvedPayload else {
            nativeLogger.error(
                "place detail load failed id=\(self.place.id, privacy: .public) error=No detail payload available"
            )
            hasLoadedCanonicalDetails = true
            if place.description?.isEmpty != false && place.hook?.isEmpty != false {
                errorMessage = "Could not refresh place details right now."
            }
            return
        }

        nativeLogger.log(
            "place detail loaded id=\(self.place.id, privacy: .public) score=\(String(describing: resolvedPayload.place.similarityStat), privacy: .public)"
        )

        applyDetailPayload(resolvedPayload)
    }

    private func applyDetailPayload(_ resolvedPayload: NativePlaceDetailResponse) {
        let nextPlace = mergedPlaceRetainingPresentation(place, with: resolvedPayload.place)
        travelerMoments = resolvedPayload.travelerMoments ?? []
        place = nextPlace
        hasLoadedCanonicalDetails = true
        errorMessage = nil
        nativeLogger.log(
            "place detail final score id=\(self.place.id, privacy: .public) finalScore=\(String(describing: nextPlace.similarityStat), privacy: .public) headerPrimary=\(self.compatibilityHeaderPrimary, privacy: .public)"
        )
    }

    private func toggleBookmark() async {
        errorMessage = nil
        isTogglingBookmark = true
        defer { isTogglingBookmark = false }
        do {
            let wasBookmarked = appState.isBookmarked(place.id)
            try await appState.toggleBookmark(for: place, source: analyticsSource)
            if !wasBookmarked {
                appState.trackAnalytics(
                    .savingPlace,
                    properties: appState.placeAnalyticsProperties(place, source: analyticsSource)
                )
            }
        } catch {
            let nsError = error as NSError
            if nsError.domain == NSURLErrorDomain && nsError.code == NSURLErrorUserAuthenticationRequired {
                errorMessage = nil
            } else {
                errorMessage = error.localizedDescription
            }
        }
    }

    private func savePlaceFromCircleEmptyState() async {
        guard !isSavingFromCircleEmptyState else { return }
        isSavingFromCircleEmptyState = true
        defer { isSavingFromCircleEmptyState = false }
        do {
            try await appState.toggleBookmark(for: place, source: analyticsSource)
        } catch {
            let nsError = error as NSError
            if !(nsError.domain == NSURLErrorDomain && nsError.code == NSURLErrorUserAuthenticationRequired) {
                errorMessage = error.localizedDescription
            }
        }
    }
}

