	                                        showDeleteConfirm = false
	                                    }
	                                    dismiss()
	                                    onDelete()
	                                } label: {
	                                    HStack {
	                                        Spacer()
	                                        Text("Delete")
	                                            .font(nativeAppFont(size: 14, weight: .black))
	                                        Spacer()
	                                    }
	                                    .padding(.vertical, 12)
	                                    .background(Color.red.opacity(0.18))
	                                    .foregroundStyle(Color.red.opacity(0.95))
	                                    .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
	                                }
