    private func toggle(_ placeId: String) {
        if selectedPlaceIds.contains(placeId) {
            selectedPlaceIds.remove(placeId)
        } else {
            selectedPlaceIds.insert(placeId)
        }
    }

    private func save() async {
        guard canSave else { return }
        errorMessage = nil
        isSaving = true
        defer { isSaving = false }

        do {
            let updated = try await appState.updateCollection(
                id: collection.id,
                label: trimmedName,
                placeIds: Array(selectedPlaceIds)
            )
            onSaved(updated)
            dismiss()
        } catch {
            errorMessage = "Could not update collection right now."
        }
    }
}

private struct NativeRemoteImage: View {
    let url: String?
    @State private var loadedImage: UIImage? = nil
    @State private var isLoading = false

    var body: some View {
        Group {
            if let loadedImage {
                Image(uiImage: loadedImage)
                    .resizable()
                    .scaledToFill()
            } else if isLoading {
                ZStack {
                    fallback
                    ProgressView().tint(nativeAccent)
                }
            } else {
                fallback
            }
        }
        .task(id: nativeResolvedImageURL(url) ?? "") {
            await loadImageIfNeeded()
        }
    }

    private var fallback: some View {
        LinearGradient(
            colors: [Color.white.opacity(0.08), Color.white.opacity(0.03)],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    @MainActor
    private func loadImageIfNeeded() async {
        guard loadedImage == nil else { return }
        guard let resolved = nativeResolvedImageURL(url), let imageURL = URL(string: resolved) else { return }

        isLoading = true
        defer { isLoading = false }

        do {
            let (data, response) = try await URLSession.shared.data(from: imageURL)
            if let http = response as? HTTPURLResponse, !(200..<300).contains(http.statusCode) {
                nativeLogger.error("NativeRemoteImage HTTP failure url=\(resolved, privacy: .public) status=\(http.statusCode, privacy: .public)")
                return
            }
            guard let image = UIImage(data: data) else {
                nativeLogger.error("NativeRemoteImage decode failure url=\(resolved, privacy: .public) bytes=\(data.count, privacy: .public)")
                return
            }
            loadedImage = image
        } catch {
            nativeLogger.error("NativeRemoteImage failed url=\(resolved, privacy: .public) error=\(error.localizedDescription, privacy: .public)")
        }
    }
}

private func nativeResolvedImageURL(_ url: String?) -> String? {
    guard let raw = url?.trimmingCharacters(in: .whitespacesAndNewlines), !raw.isEmpty else {
        return nil
    }
    if raw.hasPrefix("//") {
        return "https:\(raw)"
    }
    if raw.hasPrefix("http://api.vibinn.club") {
        return raw.replacingOccurrences(of: "http://api.vibinn.club", with: "https://api.vibinn.club")
    }
    if raw.hasPrefix("http://vibinn-api-staging.onrender.com") {
        return raw.replacingOccurrences(of: "http://vibinn-api-staging.onrender.com", with: "https://vibinn-api-staging.onrender.com")
    }
    if raw.hasPrefix("https://vibecheck-api-staging.onrender.com") {
        return raw.replacingOccurrences(of: "https://vibecheck-api-staging.onrender.com", with: "https://vibinn-api-staging.onrender.com")
    }
    if raw.hasPrefix("http://vibecheck-api-staging.onrender.com") {
        return raw.replacingOccurrences(of: "http://vibecheck-api-staging.onrender.com", with: "https://vibinn-api-staging.onrender.com")
    }
    if raw.hasPrefix("http://") || raw.hasPrefix("https://") {
        return raw
    }
    let sanitized = raw.hasPrefix("/") ? raw : "/\(raw)"
    return nativeResolvedAPIBaseURL().absoluteString.trimmingCharacters(in: CharacterSet(charactersIn: "/")) + sanitized
}

private func nativeNormalizedContactPhoneCandidates(from rawValue: String) -> [String] {
    let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !trimmed.isEmpty else { return [] }

    let digitsOnly = trimmed.filter(\.isNumber)
    var candidates: [String] = []

    if trimmed.contains("+"), !digitsOnly.isEmpty {
        candidates.append("+" + digitsOnly)
    }

    if digitsOnly.count == 10 {
        candidates.append("+1" + digitsOnly)
    } else if digitsOnly.count == 11 && digitsOnly.hasPrefix("1") {
        candidates.append("+" + digitsOnly)
    } else if (8...15).contains(digitsOnly.count) {
        candidates.append("+" + digitsOnly)
    }

    if !digitsOnly.isEmpty {
        candidates.append(digitsOnly)
    }

    var seen = Set<String>()
    return candidates.filter { candidate in
        guard !candidate.isEmpty, !seen.contains(candidate) else { return false }
        seen.insert(candidate)
        return true
    }
}

private func nativeFallbackUsername(from phoneNumber: String?) -> String {
    let digits = (phoneNumber ?? "").filter(\.isNumber)
    if digits.count >= 4 {
        return "traveler\(digits.suffix(4))"
    }
    return "traveler"
}

private func nativeDistanceBetweenMiles(
    _ origin: (latitude: Double, longitude: Double),
    _ destination: (latitude: Double, longitude: Double)
) -> Double {
    let originLocation = CLLocation(latitude: origin.latitude, longitude: origin.longitude)
    let destinationLocation = CLLocation(latitude: destination.latitude, longitude: destination.longitude)
    return originLocation.distance(from: destinationLocation) / 1609.344
}

private func nativeAvatarCornerRadius(for size: CGFloat) -> CGFloat {
    min(max(size * 0.42, 14), (size / 2) - 2)
}

private enum NativeMomentRatingChoice: String, CaseIterable, Identifiable {
    case disliked
    case notBad = "not_bad"
    case liked
    case recommended

    var id: String { rawValue }

    var label: String {
        switch self {
        case .disliked: return "Disliked"
        case .notBad: return "Not bad"
        case .liked: return "Liked"
        case .recommended: return "Recommended"
        }
    }

    var icon: String {
        switch self {
        case .disliked: return "hand.thumbsdown.fill"
        case .notBad: return "face.smiling"
        case .liked: return "heart.fill"
        case .recommended: return "sparkles"
        }
    }

    var score: Int {
        switch self {
        case .disliked: return 1
        case .notBad: return 3
        case .liked: return 4
        case .recommended: return 5
        }
    }
}

private func nativeNormalizedMomentRatingLabel(_ value: String?) -> String {
    switch value {
    case "disliked", "DISLIKED":
        return NativeMomentRatingChoice.disliked.rawValue
    case "not_bad", "NOT_BAD", "notBad":
        return NativeMomentRatingChoice.notBad.rawValue
    case "recommended", "RECOMMENDED":
        return NativeMomentRatingChoice.recommended.rawValue
    default:
        return NativeMomentRatingChoice.liked.rawValue
    }
}

private func nativeMomentRatingChoice(for value: String?) -> NativeMomentRatingChoice {
    NativeMomentRatingChoice(rawValue: nativeNormalizedMomentRatingLabel(value)) ?? .liked
}

private func nativeNormalizedWouldRevisit(_ value: String?) -> String {
    switch value?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
    case "yes":
        return "yes"
    case "maybe", "not_sure":
        return "maybe"
    case "no", "not_interested":
        return "no"
    default:
        return "yes"
    }
}

private func nativeNormalizedMomentVisibility(_ value: String?) -> String {
    switch value?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
    case "friends":
        return "friends"
    case "private":
        return "private"
    default:
        return "public"
    }
}

private func nativeAvatarInitials(from raw: String) -> String {
    let tokens = raw
        .split(whereSeparator: { $0.isWhitespace || $0.isNewline })
        .map(String.init)
        .filter { !$0.isEmpty }

    if tokens.count >= 2 {
        return (String(tokens[0].prefix(1)) + String(tokens[1].prefix(1))).uppercased()
    }

    if let first = tokens.first {
        return String(first.prefix(1)).uppercased()
    }

    return "V"
}

private func nativeMomentRatingScore(for value: String?) -> Int {
    nativeMomentRatingChoice(for: value).score
}

private func nativeMomentRatingMeta(label: String?, fallbackRating: Int?) -> (label: String, icon: String)? {
    let choice: NativeMomentRatingChoice
    if let label {
        choice = nativeMomentRatingChoice(for: label)
    } else if let fallbackRating {
        if fallbackRating >= 5 {
            choice = .recommended
        } else if fallbackRating >= 4 {
            choice = .liked
        } else if fallbackRating >= 3 {
            choice = .notBad
        } else {
            choice = .disliked
        }
    } else {
        return nil
    }
    return (choice.label, choice.icon)
}

private func nativeShortAddress(for place: NativePlace) -> String {
    let raw = place.address?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
    if raw.isEmpty {
        return place.location
    }
    let parts = raw
        .split(separator: ",")
        .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
        .filter { !$0.isEmpty }
    guard let first = parts.first else { return place.location }
    if CharacterSet.decimalDigits.isSuperset(of: CharacterSet(charactersIn: first)),
       parts.count > 1 {
        return "\(first) \(parts[1])"
    }
    return first
}

private func nativePlaceMetaLine(for place: NativePlace, shortAddress: String? = nil) -> String {
    let resolvedShortAddress = shortAddress ?? nativeShortAddress(for: place)
    let segments = [place.category?.trimmingCharacters(in: .whitespacesAndNewlines), resolvedShortAddress]
        .compactMap { value -> String? in
            guard let value, !value.isEmpty else { return nil }
            return value
        }
    return segments.joined(separator: " • ")
}

