private struct NativeVisitedMomentPostCard<HeaderTrailing: View, PlaceSection: View, Actions: View, CommentPreview: View>: View {
    let displayName: String
    let username: String?
    let avatarURL: String?
    let avatarFallback: String
    var headerLinkTraveler: NativeTravelerSummary? = nil
    let ratingMeta: (label: String, icon: String)?
    let wouldRevisit: String?
    let reviewText: String?
    let mediaURL: String?
    let placeName: String
    let placeMetaLine: String
    @ViewBuilder let headerTrailing: () -> HeaderTrailing
    @ViewBuilder let placeSection: () -> PlaceSection
    @ViewBuilder let actions: () -> Actions
    @ViewBuilder let commentPreview: () -> CommentPreview

    var body: some View {
        NativeSurfaceCard {
            VStack(alignment: .leading, spacing: 14) {
                HStack(alignment: .center, spacing: 10) {
                    headerIdentityContent

                    Spacer(minLength: 8)

                    headerTrailing()
                }

                if ratingMeta != nil || wouldRevisit != nil {
                    HStack(spacing: 8) {
                        if let ratingMeta {
                            HStack(spacing: 8) {
                                Image(systemName: ratingMeta.icon)
                                    .font(nativeAppFont(size: 12, weight: .black))
                                Text(ratingMeta.label)
                                    .font(nativeAppFont(size: 12, weight: .bold))
                            }
                            .foregroundStyle(.black)
                            .padding(.horizontal, 12)
                            .padding(.vertical, 8)
                            .background(nativeAccent)
                            .clipShape(Capsule())
                        }

                        if let wouldRevisit {
                            NativeFeedMetaPill(
                                label: revisitLabel(for: wouldRevisit),
                                foreground: wouldRevisit == "yes" ? nativeAccent : .white.opacity(0.82),
                                background: wouldRevisit == "yes" ? nativeAccent.opacity(0.16) : Color.white.opacity(0.08)
                            )
                        }
                    }
                }

                if let reviewText, !reviewText.isEmpty {
                    Text(reviewText)
                        .font(nativeAppFont(size: 15, weight: .semibold))
                        .foregroundStyle(.white.opacity(0.9))
                        .lineLimit(2)
                }

                Group {
                    if let mediaURL, !mediaURL.isEmpty {
                        NativeRemoteImage(url: mediaURL)
                    } else {
                        RoundedRectangle(cornerRadius: 24, style: .continuous)
                            .fill(Color.white.opacity(0.06))
                            .overlay(
                                Image(systemName: "photo")
                                    .font(nativeAppFont(size: 22, weight: .black))
                                    .foregroundStyle(.white.opacity(0.3))
                            )
                    }
                }
                .frame(maxWidth: .infinity)
                .aspectRatio(1, contentMode: .fit)
                .clipShape(RoundedRectangle(cornerRadius: 24, style: .continuous))
                .overlay(
                    RoundedRectangle(cornerRadius: 24, style: .continuous)
                        .stroke(Color.white.opacity(0.08), lineWidth: 1)
                )

                placeSection()

                actions()

                commentPreview()
            }
        }
    }

    @ViewBuilder
    private var headerIdentityContent: some View {
        if let headerLinkTraveler {
            NavigationLink {
                NativeTravelerProfileScreen(initialTraveler: headerLinkTraveler)
            } label: {
                identityRow
                    .contentShape(Rectangle())
            }
            .buttonStyle(.plain)
        } else {
            identityRow
        }
    }

    private var identityRow: some View {
        HStack(alignment: .center, spacing: 10) {
            avatarSquare(size: 42)

            VStack(alignment: .leading, spacing: 2) {
                Text(displayName)
                    .font(nativeAppFont(size: 15, weight: .black))
                    .foregroundStyle(.white)

                if let username, !username.isEmpty {
                    Text("@\(username)")
                        .font(nativeAppFont(size: 12, weight: .semibold))
                        .foregroundStyle(.white.opacity(0.48))
                }
            }
        }
    }

    private func avatarSquare(size: CGFloat) -> some View {
        ZStack {
            if let avatarURL, !avatarURL.isEmpty {
                NativeRemoteImage(url: avatarURL)
            } else {
                RoundedRectangle(cornerRadius: 14, style: .continuous)
                    .fill(Color.white.opacity(0.08))
                    .overlay(
                        Text(nativeAvatarInitials(from: avatarFallback))
                            .font(nativeAppFont(size: 15, weight: .black))
                            .foregroundStyle(.white)
                    )
            }
        }
        .frame(width: size, height: size)
        .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: 14, style: .continuous)
                .stroke(Color.white.opacity(0.06), lineWidth: 1)
        )
    }

    private func revisitLabel(for value: String) -> String {
        switch value.lowercased() {
        case "yes":
            return "Would revisit"
        case "maybe":
            return "Maybe"
        case "no":
            return "No revisit"
        default:
            return value
        }
    }
}

private struct NativeMomentFullscreenScaffold: View {
    let displayName: String
    let username: String?
    let avatarURL: String?
    let avatarFallback: String
    let timestampLabel: String
    let ratingMeta: (label: String, icon: String)?
    let reviewText: String?
    let mediaUrl: String?
    let placeName: String?
    let placeMetaLine: String?
    let isLiked: Bool
    let likeCount: Int
    let isLikeBusy: Bool
    let comments: [NativeComment]
    let isCommentsLoading: Bool
    let commentsErrorMessage: String?
