        .frame(width: size, height: size)
        .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: 14, style: .continuous)
                .stroke(Color.white.opacity(0.06), lineWidth: 1)
        )
    }
}

private struct NativeFeedMomentFullscreen: View {
    @EnvironmentObject private var appState: NativeAppState
    @Environment(\.dismiss) private var dismiss
    let item: NativeFeedItem
    @State private var comments: [NativeComment] = []
    @State private var isCommentsLoading = false
    @State private var commentsErrorMessage: String?
    @State private var commentDraft = ""
    @State private var vibed = false
    @State private var vibinCount = 0
    @State private var isTogglingVibin = false
    @State private var selectedPlace: NativePlace? = nil
    @State private var showReportPostDialog = false
    @State private var showReportAccountDialog = false
    @State private var showBlockAccountDialog = false
    @State private var showDeletePostDialog = false
    @State private var moderationAlertMessage = ""
    @State private var showModerationAlert = false

    private var mediaUrl: String? {
        if let uploaded = item.uploadedMediaUrls?.first, !uploaded.isEmpty {
            return uploaded
        }
        if let uploaded = item.place?.userMediaUrls?.first, !uploaded.isEmpty {
            return uploaded
        }
        if let uploaded = item.place?.momentMedia?.first?.url, !uploaded.isEmpty {
            return uploaded
        }
        if let image = item.place?.image, !image.isEmpty {
            return image
        }
        if let image = item.place?.images?.first, !image.isEmpty {
            return image
        }
        return nil
    }

    private var commentTargetType: String? {
        guard let place = item.place else { return nil }
        return place.momentId != nil ? "MOMENT" : "PLACE"
    }

    private var commentTargetId: String? {
        guard let place = item.place else { return nil }
        return place.momentId ?? place.id
    }

    private var ratingMeta: (label: String, icon: String)? {
        guard let place = item.place else { return nil }
        return nativeMomentRatingMeta(label: place.momentRatingLabel, fallbackRating: place.momentRating)
    }

    private var shortAddress: String {
        guard let place = item.place else { return "" }
        return nativeShortAddress(for: place)
    }

    private var placeMetaLine: String {
        guard let place = item.place else { return "" }
        return nativePlaceMetaLine(for: place, shortAddress: shortAddress)
    }

    private var commentComposerPlaceholder: String {
        "Write a comment"
    }

    private var isOwnPost: Bool {
        appState.currentUser?.id == item.traveler.id
    }

    private var shouldShowPostMenu: Bool {
        item.place?.momentId != nil
    }

    var body: some View {
        NativeMomentFullscreenScaffold(
            displayName: item.traveler.displayName ?? item.traveler.username,
            username: item.traveler.username,
            avatarURL: item.traveler.avatar,
            avatarFallback: item.traveler.displayName ?? item.traveler.username,
            timestampLabel: item.timestampLabel.replacingOccurrences(of: ". ago", with: " ago"),
            ratingMeta: ratingMeta,
            reviewText: item.caption?.trimmingCharacters(in: .whitespacesAndNewlines),
            mediaUrl: mediaUrl,
            placeName: item.place?.name,
            placeMetaLine: placeMetaLine.isEmpty ? nil : placeMetaLine,
            isLiked: vibed,
            likeCount: vibinCount,
            isLikeBusy: isTogglingVibin,
            comments: comments,
            isCommentsLoading: isCommentsLoading,
            commentsErrorMessage: commentsErrorMessage,
            commentComposerPlaceholder: commentComposerPlaceholder,
            menuView: shouldShowPostMenu ? AnyView(feedPostMoreMenu) : nil,
            onClose: { dismiss() },
            onPlaceTap: item.place.map { place in { selectedPlace = place } },
            onToggleLike: { Task { await toggleVibin() } },
            onPostComment: { Task { await postComment() } },
            commentDraft: $commentDraft
        )
            .task {
                vibed = item.isVibed
                vibinCount = item.vibinCount
                await loadComments()
            }
            .confirmationDialog("Delete post?", isPresented: $showDeletePostDialog, titleVisibility: .visible) {
                Button("Delete post", role: .destructive) {
                    Task {
                        do {
                            if let momentId = item.place?.momentId {
                                try await appState.deleteMoment(id: momentId)
                            }
                            dismiss()
                        } catch {
                            commentsErrorMessage = "Could not delete this post right now."
                        }
                    }
                }
                Button("Cancel", role: .cancel) {}
            } message: {
                Text("This will remove this post from your profile.")
            }
            .confirmationDialog("Report post", isPresented: $showReportPostDialog, titleVisibility: .visible) {
                ForEach(NativeReportReason.allCases) { reason in
                    Button(reason.rawValue) {
                        Task { await reportPost(reason) }
                    }
                }
                Button("Cancel", role: .cancel) {}
            } message: {
                Text("Choose the reason that best describes this content.")
            }
            .confirmationDialog("Report account", isPresented: $showReportAccountDialog, titleVisibility: .visible) {
                ForEach(NativeReportReason.allCases) { reason in
                    Button(reason.rawValue) {
                        Task { await reportAccount(reason) }
                    }
                }
                Button("Cancel", role: .cancel) {}
            } message: {
                Text("Choose the reason that best describes this account.")
            }
            .confirmationDialog("Block account?", isPresented: $showBlockAccountDialog, titleVisibility: .visible) {
                Button("Block \(item.traveler.username)", role: .destructive) {
                    Task { await blockAccount() }
                }
                Button("Cancel", role: .cancel) {}
            } message: {
                Text("You will no longer see posts or profile activity from this account.")
            }
            .alert("Done", isPresented: $showModerationAlert) {
                Button("OK", role: .cancel) {}
            } message: {
                Text(moderationAlertMessage)
            }
        .fullScreenCover(item: $selectedPlace) { place in
            NativePlaceDetailScreen(
                initialPlace: place,
                source: NativeAnalyticsSource.feed,
                showsExplicitBackButton: true
            )
        }
    }

    private var feedPostMoreMenu: some View {
        Menu {
            if isOwnPost {
                Button(role: .destructive) {
                    showDeletePostDialog = true
                } label: {
                    Text("Delete post")
                }
            } else {
                Button("Report post") {
                    showReportPostDialog = true
                }
                Button("Report account") {
                    showReportAccountDialog = true
                }
                Button(role: .destructive) {
                    showBlockAccountDialog = true
                } label: {
                    Text("Block account")
                }
            }
        } label: {
            Image(systemName: "ellipsis")
                .font(nativeAppFont(size: 14, weight: .black))
                .foregroundStyle(.white.opacity(0.72))
                .frame(width: 32, height: 32)
                .background(Color.white.opacity(0.06))
                .clipShape(Circle())
        }
        .buttonStyle(.plain)
    }

    private func loadComments() async {
        guard let targetType = commentTargetType, let targetId = commentTargetId else { return }
        isCommentsLoading = true
        commentsErrorMessage = nil
        do {
            comments = try await appState.fetchComments(targetType: targetType, targetId: targetId)
        } catch {
            commentsErrorMessage = "Could not load comments right now."
        }
        isCommentsLoading = false
    }

    private func postComment() async {
        guard let targetType = commentTargetType, let targetId = commentTargetId else { return }
        let trimmed = commentDraft.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return }
        do {
            let newComment = try await appState.createComment(
                targetType: targetType,
                targetId: targetId,
                body: trimmed,
                momentId: item.place?.momentId
            )
            comments.insert(newComment, at: 0)
            commentDraft = ""
            commentsErrorMessage = nil
            UIApplication.shared.sendAction(#selector(UIResponder.resignFirstResponder), to: nil, from: nil, for: nil)
        } catch {
            commentsErrorMessage = "Could not post comment right now."
        }
    }

    private func toggleVibin() async {
        guard !isTogglingVibin else { return }
        guard let targetId = item.place?.momentId ?? item.place?.id, !targetId.isEmpty else { return }

        isTogglingVibin = true
        defer { isTogglingVibin = false }

        do {
            let response = try await appState.toggleMomentVibin(
                targetId: targetId,
                receiverUserId: item.traveler.id,
                momentId: item.place?.momentId
            )
            vibed = response.active
            vibinCount = response.count
            appState.updateFeedItemVibinState(itemId: item.id, isVibed: response.active, vibinCount: response.count)
        } catch {
            commentsErrorMessage = "Could not update this like right now."
        }
    }

    private func reportPost(_ reason: NativeReportReason) async {
        guard let targetType = commentTargetType, let targetId = commentTargetId else { return }
        do {
            try await appState.reportTarget(
                targetType: targetType,
                targetId: targetId,
                targetUserId: item.traveler.id,
                reason: reason
            )
            moderationAlertMessage = "Thanks. This post has been reported."
            showModerationAlert = true
        } catch {
            moderationAlertMessage = "Could not report this post right now."
            showModerationAlert = true
        }
    }

    private func reportAccount(_ reason: NativeReportReason) async {
        do {
            try await appState.reportTarget(
                targetType: "PROFILE",
                targetId: item.traveler.id,
                targetUserId: item.traveler.id,
                reason: reason
            )
            moderationAlertMessage = "Thanks. This account has been reported."
            showModerationAlert = true
        } catch {
            moderationAlertMessage = "Could not report this account right now."
            showModerationAlert = true
        }
    }

    private func blockAccount() async {
        do {
            try await appState.blockTraveler(item.traveler)
            moderationAlertMessage = "This account has been blocked."
            showModerationAlert = true
        } catch {
            moderationAlertMessage = "Could not block this account right now."
            showModerationAlert = true
        }
    }

    private func revisitLabel(for value: String) -> String {
        switch value.lowercased() {
        case "yes":
            return "Would revisit"
        case "maybe":
            return "Maybe"
        case "no":
            return "No revisit"
        default:
            return value
        }
    }
}

private func nativeDebugListLabel(_ values: [String]) -> String {
    let joined = values.joined(separator: ", ")
    return joined.isEmpty ? "none" : joined
}

private struct NativeCheckInScreen: View {
    private enum Step: Int {
        case media = 1
        case place = 2
        case review = 3
    }

    @EnvironmentObject private var appState: NativeAppState
    @Environment(\.dismiss) private var dismiss
    @FocusState private var isSearchFieldFocused: Bool
    @FocusState private var isReviewFieldFocused: Bool
    let prefilledPlace: NativePlace?
    let prefilledPhotoAsset: NativePickedPhotoAsset?
    let prefilledImage: UIImage?
    let prefilledVisitedDate: String?

    @State private var step: Step = .media
    @State private var photoAuthorizationStatus: PHAuthorizationStatus = PHPhotoLibrary.authorizationStatus(for: .readWrite)
    @State private var recentGalleryPreviews: [UIImage] = []
    @State private var query = ""
    @State private var results: [NativePlace] = []
    @State private var placeCandidates: [NativePlace] = []
    @State private var selectedPlace: NativePlace?
    @State private var reviewText = ""
    @State private var ratingLabel = NativeMomentRatingChoice.liked.rawValue
    @State private var wouldRevisit = "yes"
    @State private var visibility = "public"
    @State private var selectedImage: UIImage?
    @State private var selectedPhotoAsset: NativePickedPhotoAsset?
    @State private var activeMediaPicker: NativeCheckInMediaPickerSource?
    @State private var pendingLibrarySelectionAnalysis = false
    @StateObject private var inlineCamera = NativeInlineCameraController()
    @State private var reviewWordLimitMessage: String?
    @State private var isSearching = false
    @State private var isAnalyzingPlace = false
    @State private var isSubmitting = false
    @State private var errorMessage: String?
    @State private var showCloseConfirmation = false
    @State private var searchTask: Task<Void, Never>?
    @State private var autocompleteSessionToken = UUID().uuidString

    init(
        prefilledPlace: NativePlace? = nil,
        prefilledPhotoAsset: NativePickedPhotoAsset? = nil,
        prefilledImage: UIImage? = nil,
        prefilledVisitedDate: String? = nil
    ) {
        self.prefilledPlace = prefilledPlace
        self.prefilledPhotoAsset = prefilledPhotoAsset
        self.prefilledImage = prefilledImage
        self.prefilledVisitedDate = prefilledVisitedDate
    }

    private var resolvedVisitedDate: String {
        if let prefilledVisitedDate, !prefilledVisitedDate.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            return prefilledVisitedDate
        }
        return Self.isoDayString(from: Date())
    }

    private var nextButtonDisabled: Bool {
        selectedPlace == nil
    }

    private var submitButtonDisabled: Bool {
        selectedPlace == nil || isSubmitting
    }

    var body: some View {
        NavigationView {
            ScrollView(showsIndicators: false) {
                VStack(alignment: .leading, spacing: 18) {
                    header

                    if step == .media {
                        mediaStep
                    } else if step == .place {
                        placeStep
                    } else {
                        reviewStep
                    }

                    if let errorMessage {
                        NativeInlineError(message: errorMessage)
                    }
                }
                .padding(.horizontal, 20)
                .padding(.top, 16)
                .padding(.bottom, 28)
            }
            .contentShape(Rectangle())
            .onTapGesture {
                dismissKeyboardFocus()
            }
            .background(Color.black.ignoresSafeArea())
            .navigationBarHidden(true)
        }
        .navigationViewStyle(.stack)
        .preferredColorScheme(.dark)
        .safeAreaInset(edge: .bottom) {
            if step != .media {
                VStack(spacing: 0) {
                    if step == .place {
                        Button {
                            withAnimation(.spring(response: 0.28, dampingFraction: 0.9)) {
                                step = .review
                            }
                        } label: {
                            Text("Continue")
                                .font(nativeAppFont(size: 16, weight: .black))
                                .foregroundStyle(.black)
                                .frame(maxWidth: .infinity)
                                .padding(.vertical, 16)
                                .background(nativeAccent)
                                .clipShape(RoundedRectangle(cornerRadius: 20, style: .continuous))
                        }
                        .buttonStyle(.plain)
                        .disabled(nextButtonDisabled || isAnalyzingPlace)
                    } else {
                        Button {
                            Task {
                                await submitCheckIn()
                            }
                        } label: {
                            HStack(spacing: 10) {
                                if isSubmitting {
                                    ProgressView().tint(.black)
                                }
                                Text("Submit")
                                    .font(nativeAppFont(size: 16, weight: .black))
                            }
                            .foregroundStyle(.black)
                            .frame(maxWidth: .infinity)
                            .padding(.vertical, 16)
                            .background(nativeAccent)
                            .clipShape(RoundedRectangle(cornerRadius: 20, style: .continuous))
                        }
                        .buttonStyle(.plain)
                        .disabled(submitButtonDisabled)
                    }
                }
                .padding(.horizontal, 20)
                .padding(.top, 10)
                .padding(.bottom, 12)
                .background(Color.black.opacity(0.92))
            }
        }
        .onAppear {
            if let prefilledPhotoAsset {
                selectedPhotoAsset = prefilledPhotoAsset
                selectedImage = prefilledPhotoAsset.image
                step = .media
                inlineCamera.stopSession()
                Task { @MainActor in
                    await analyzeSelectedCheckInPhoto()
                }
            } else if let prefilledPlace {
                selectedPlace = prefilledPlace
                if let prefilledImage {
                    let normalized = nativeSquareCroppedImage(prefilledImage)
                    selectedPhotoAsset = NativePickedPhotoAsset(
                        image: normalized,
                        latitude: nil,
                        longitude: nil,
                        capturedAt: nil
                    )
                    selectedImage = normalized
                }
                step = prefilledImage == nil ? .media : .review
                inlineCamera.prepareIfNeeded()
            } else {
                step = .media
                autocompleteSessionToken = UUID().uuidString
                inlineCamera.prepareIfNeeded()
            }
            refreshCheckInGalleryPreviewIfNeeded()
        }
        .onChange(of: query) { _ in
            searchTask?.cancel()
            let trimmed = query.trimmingCharacters(in: .whitespacesAndNewlines)
            guard step == .place else { return }
            guard trimmed.count >= 3 else {
                results = []
                errorMessage = nil
                autocompleteSessionToken = UUID().uuidString
                return
            }
            searchTask = Task {
                try? await Task.sleep(nanoseconds: 450_000_000)
                guard !Task.isCancelled else { return }
                await performSearch()
            }
        }
        .onChange(of: step) { newValue in
            if newValue == .media, selectedPhotoAsset == nil {
                inlineCamera.prepareIfNeeded()
            } else if newValue == .place {
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.15) {
                    isSearchFieldFocused = placeCandidates.isEmpty
                }
            } else {
                inlineCamera.stopSession()
            }
        }
        .onChange(of: selectedPhotoAsset) { newValue in
            selectedImage = newValue?.image
            if newValue == nil, step == .media {
                inlineCamera.prepareIfNeeded()
            } else {
                inlineCamera.stopSession()
            }
            guard let _ = newValue else { return }
            if pendingLibrarySelectionAnalysis || activeMediaPicker == .library {
                pendingLibrarySelectionAnalysis = false
                activeMediaPicker = nil
                Task { @MainActor in
                    try? await Task.sleep(nanoseconds: 180_000_000)
                    await analyzeSelectedCheckInPhoto()
                }
            }
        }
        .onChange(of: photoAuthorizationStatus) { _ in
            refreshCheckInGalleryPreviewIfNeeded()
        }
        .onDisappear {
            inlineCamera.stopSession()
        }
        .sheet(item: $activeMediaPicker) { source in
            switch source {
            case .library:
                NativeSingleMetadataImagePicker(selection: $selectedPhotoAsset)
            case .camera:
                NativeSingleImagePicker(
                    image: Binding(
                        get: { selectedImage },
                        set: { selectedImage = $0.map(nativeSquareCroppedImage) }
                    ),
                    source: source
                )
            }
        }
        .confirmationDialog(
            "Cancel check-in?",
            isPresented: $showCloseConfirmation,
            titleVisibility: .visible
        ) {
            Button("Discard check-in", role: .destructive) {
                closeSheet()
            }
            Button("Keep editing", role: .cancel) {}
        } message: {
            Text("Your current check-in progress will be lost.")
        }
    }

    private var header: some View {
        HStack(alignment: .top) {
            VStack(alignment: .leading, spacing: 10) {
                NativeCheckInProgressBar(currentStep: step.rawValue)
                    .frame(maxWidth: .infinity, alignment: .leading)
            }
            Spacer()
            if step != .media {
                Button {
                    withAnimation(.spring(response: 0.28, dampingFraction: 0.9)) {
                        step = step == .review ? .place : .media
                    }
                } label: {
                    Image(systemName: "chevron.left")
                        .font(nativeAppFont(size: 15, weight: .bold))
                        .foregroundStyle(.white.opacity(0.8))
                        .frame(width: 38, height: 38)
                        .background(nativeSurface)
                        .overlay(Circle().stroke(nativeBorder, lineWidth: 1))
                        .clipShape(Circle())
                }
                .buttonStyle(.plain)
            }
            Button {
                showCloseConfirmation = true
            } label: {
                Image(systemName: "xmark")
                    .font(nativeAppFont(size: 15, weight: .bold))
                    .foregroundStyle(.white.opacity(0.8))
                    .frame(width: 38, height: 38)
                    .background(nativeSurface)
                    .overlay(Circle().stroke(nativeBorder, lineWidth: 1))
                    .clipShape(Circle())
            }
            .buttonStyle(.plain)
        }
    }

    private var placeStep: some View {
        VStack(alignment: .leading, spacing: 16) {
            Text(placeCandidates.isEmpty ? "Choose the place" : "Confirm the place")
                .font(nativeAppFont(size: 24, weight: .black))
                .foregroundStyle(.white)

            if let selectedPhotoAsset {
                NativeSurfaceCard {
                    HStack(spacing: 14) {
                        Image(uiImage: selectedPhotoAsset.image)
                            .resizable()
                            .scaledToFill()
                            .frame(width: 64, height: 64)
                            .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))

                        VStack(alignment: .leading, spacing: 6) {
                            Text(selectedMomentDateLabel)
                                .font(nativeAppFont(size: 15, weight: .black))
                                .foregroundStyle(.white)
                                .fixedSize(horizontal: false, vertical: true)
                        }
                    }
                    .frame(maxWidth: .infinity, alignment: .leading)
                }
            }

            if isAnalyzingPlace {
                NativeSurfaceCard {
                    HStack(spacing: 12) {
                        ProgressView().tint(nativeAccent)
                        Text("Analyzing your photo...")
                            .font(nativeAppFont(size: 15, weight: .medium))
                            .foregroundStyle(.white.opacity(0.72))
                    }
                }
                .frame(maxWidth: .infinity, alignment: .leading)
            }

            NativeSurfaceCard {
                VStack(alignment: .leading, spacing: 12) {
                    TextField("Search places", text: $query)
                        .textInputAutocapitalization(.words)
                        .autocorrectionDisabled()
                        .focused($isSearchFieldFocused)
                        .font(nativeAppFont(size: 17, weight: .medium))
                        .padding(.horizontal, 16)
                        .padding(.vertical, 15)
                        .background(nativeSurfaceStrong)
                        .overlay(
                            RoundedRectangle(cornerRadius: 18, style: .continuous)
                                .stroke(nativeBorder, lineWidth: 1)
                        )
                        .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))

                    if query.trimmingCharacters(in: .whitespacesAndNewlines).count > 0 && query.trimmingCharacters(in: .whitespacesAndNewlines).count < 3 {
                        Text("Type at least 3 letters to search places.")
                            .font(nativeAppFont(size: 14, weight: .medium))
                            .foregroundStyle(.white.opacity(0.58))
                    }
                }
            }

            if !placeCandidates.isEmpty {
                NativeSectionTitle("Suggested places")
                LazyVStack(spacing: 12) {
                    ForEach(placeCandidates) { place in
                        Button {
                            selectedPlace = place
                            errorMessage = nil
                        } label: {
                            NativeCheckInPlaceRow(place: place, isSelected: selectedPlace?.id == place.id)
                        }
                        .buttonStyle(.plain)
                    }
                }
            }

            if isSearching {
                NativeSurfaceCard {
                    HStack(spacing: 12) {
                        ProgressView().tint(nativeAccent)
                        Text("Searching places...")
                            .font(nativeAppFont(size: 15, weight: .medium))
                            .foregroundStyle(.white.opacity(0.72))
                    }
                }
                .frame(maxWidth: .infinity, alignment: .leading)
            } else if query.trimmingCharacters(in: .whitespacesAndNewlines).count >= 3 && results.isEmpty {
                Text("No places found.")
                    .font(nativeAppFont(size: 14, weight: .medium))
                    .foregroundStyle(.white.opacity(0.58))
            }

            if !results.isEmpty {
                NativeSectionTitle("Results")
                LazyVStack(spacing: 12) {
                    ForEach(results) { place in
                        Button {
                            selectedPlace = place
                            errorMessage = nil
                        } label: {
                            NativeCheckInPlaceRow(place: place, isSelected: selectedPlace?.id == place.id)
                        }
                        .buttonStyle(.plain)
                    }
                }
            }
        }
    }

    private var mediaStep: some View {
        VStack(alignment: .leading, spacing: 16) {
            Text("Add a log")
                .font(nativeAppFont(size: 24, weight: .black))
                .foregroundStyle(.white)

            NativeSurfaceCard {
                VStack(alignment: .leading, spacing: 16) {
                    Text("Photo")
                        .font(nativeAppFont(size: 12, weight: .black))
                        .foregroundStyle(.white.opacity(0.45))
                        .textCase(.uppercase)

                    ZStack {
                        RoundedRectangle(cornerRadius: 28, style: .continuous)
                            .fill(nativeSurfaceStrong)

                        if let selectedImage {
                            Image(uiImage: selectedImage)
                                .resizable()
                                .scaledToFill()
                                .blur(radius: isAnalyzingPlace ? 12 : 0)
                                .overlay {
                                    if isAnalyzingPlace {
                                        Color.black.opacity(0.28)
                                    }
                                }
                        } else if inlineCamera.authorizationStatus == .authorized, inlineCamera.isConfigured {
                            NativeInlineCameraPreview(session: inlineCamera.session)
                                .overlay(alignment: .bottom) {
                                    LinearGradient(
                                        colors: [
                                            Color.black.opacity(0),
                                            Color.black.opacity(0.52),
                                        ],
                                        startPoint: .top,
                                        endPoint: .bottom
                                    )
                                    .frame(height: 96)
                                    .clipShape(RoundedRectangle(cornerRadius: 28, style: .continuous))
                                }
                        } else {
                            VStack(spacing: 10) {
                                Image(systemName: inlineCamera.authorizationStatus == .denied ? "camera.slash" : "camera.viewfinder")
                                    .font(nativeAppFont(size: 30, weight: .bold))
                                    .foregroundStyle(.white.opacity(0.5))
                                Text(inlineCamera.inlineMessage)
                                    .font(nativeAppFont(size: 14, weight: .semibold))
                                    .foregroundStyle(.white.opacity(0.5))
                                    .multilineTextAlignment(.center)
                                    .padding(.horizontal, 28)
                                if inlineCamera.authorizationStatus == .denied || inlineCamera.authorizationStatus == .restricted {
                                    Button {
                                        guard let settingsURL = URL(string: UIApplication.openSettingsURLString) else { return }
                                        UIApplication.shared.open(settingsURL)
                                    } label: {
                                        Text("Allow camera")
                                            .font(nativeAppFont(size: 14, weight: .bold))
                                            .foregroundStyle(.white)
                                            .padding(.horizontal, 18)
                                            .padding(.vertical, 10)
                                            .background(nativeSurface)
                                            .overlay(
                                                Capsule()
                                                    .stroke(nativeBorder, lineWidth: 1)
                                            )
                                            .clipShape(Capsule())
                                    }
                                    .buttonStyle(.plain)
                                    .padding(.top, 2)
                                }
                            }
                        }

                        if isAnalyzingPlace, selectedImage != nil {
                            VStack(spacing: 12) {
                                ProgressView()
                                    .tint(nativeAccent)
                                    .scaleEffect(1.12)

                                Text("Reading your photo")
                                    .font(nativeAppFont(size: 15, weight: .black))
                                    .foregroundStyle(.white)
                            }
                            .padding(.horizontal, 22)
                            .padding(.vertical, 16)
                            .background(Color.black.opacity(0.42))
                            .overlay(
                                RoundedRectangle(cornerRadius: 18, style: .continuous)
                                    .stroke(Color.white.opacity(0.08), lineWidth: 1)
                            )
                            .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                        }
                    }
                    .frame(maxWidth: .infinity)
                    .aspectRatio(1, contentMode: .fit)
                    .clipShape(RoundedRectangle(cornerRadius: 28, style: .continuous))
                    .overlay(alignment: .center) {
                        RoundedRectangle(cornerRadius: 28, style: .continuous)
                            .stroke(Color.white.opacity(0.1), lineWidth: 1)
                    }

                    if isAnalyzingPlace {
                        EmptyView()
                    } else if selectedPhotoAsset == nil {
                        ZStack {
                            HStack {
                                Button {
                                    pendingLibrarySelectionAnalysis = true
                                    activeMediaPicker = .library
                                } label: {
                                    checkInGalleryPreviewStack
                                }
                                .buttonStyle(.plain)

                                Spacer()

                                Button {
                                    inlineCamera.toggleCameraPosition()
                                } label: {
                                    Image(systemName: "arrow.triangle.2.circlepath.camera")
                                        .font(nativeAppFont(size: 20, weight: .bold))
                                        .foregroundStyle(.white)
                                        .frame(width: 58, height: 58)
                                        .background(nativeSurface)
                                        .overlay(Circle().stroke(nativeBorder, lineWidth: 1))
                                        .clipShape(Circle())
                                }
                                .buttonStyle(.plain)
                                .disabled(!(inlineCamera.authorizationStatus == .authorized && inlineCamera.isConfigured))
                            }

                            Button {
                                inlineCamera.capturePhoto { image in
                                    if let image {
                                        let normalized = nativeSquareCroppedImage(image)
                                        let coordinate = appState.currentCoordinate
                                        Task { @MainActor in
                                            selectedPhotoAsset = NativePickedPhotoAsset(
                                                image: normalized,
                                                latitude: coordinate?.latitude,
                                                longitude: coordinate?.longitude,
                                                capturedAt: Date()
                                            )
                                            nativeHaptic(.success)
                                            await analyzeSelectedCheckInPhoto()
                                        }
                                    }
                                }
                            } label: {
                                ZStack {
                                    Circle()
                                        .fill(nativeAccent)
                                        .frame(width: 78, height: 78)
                                    Image(systemName: "camera.fill")
                                        .font(nativeAppFont(size: 24, weight: .black))
                                        .foregroundStyle(.black)
                                }
                            }
                            .buttonStyle(.plain)
                            .disabled(!(inlineCamera.authorizationStatus == .authorized && inlineCamera.isConfigured))
                        }
                    } else {
                        HStack(spacing: 12) {
                            Button {
                                resetSelectedCheckInPhoto()
                            } label: {
                                HStack(spacing: 8) {
                                    Image(systemName: "arrow.counterclockwise")
                                    Text("Retake")
                                }
                                .font(nativeAppFont(size: 14, weight: .bold))
                                .foregroundStyle(.white)
                                .frame(maxWidth: .infinity)
                                .padding(.vertical, 14)
                                .background(nativeSurface)
                                .overlay(Capsule().stroke(nativeBorder, lineWidth: 1))
                                .clipShape(Capsule())
                            }
                            .buttonStyle(.plain)

                            Button {
                                pendingLibrarySelectionAnalysis = true
                                activeMediaPicker = .library
                            } label: {
                                HStack(spacing: 8) {
                                    Image(systemName: "photo.on.rectangle")
                                    Text("Change image")
                                }
                                .font(nativeAppFont(size: 14, weight: .bold))
                                .foregroundStyle(.white)
                                .frame(maxWidth: .infinity)
                                .padding(.vertical, 14)
                                .background(nativeSurface)
                                .overlay(Capsule().stroke(nativeBorder, lineWidth: 1))
                                .clipShape(Capsule())
                            }
                            .buttonStyle(.plain)
                        }
                    }
                }
                .frame(maxWidth: .infinity, alignment: .leading)
            }
        }
    }

    private var reviewStep: some View {
        VStack(alignment: .leading, spacing: 16) {
            if let selectedPlace {
                selectedPlaceSummary(place: selectedPlace, showsMomentThumbnail: true)
            }

            NativeSurfaceCard {
                VStack(alignment: .leading, spacing: 14) {
                    Text("How was it?")
                        .font(nativeAppFont(size: 12, weight: .black))
                        .foregroundStyle(.white.opacity(0.45))
                        .textCase(.uppercase)

                    LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 10) {
                        ForEach(NativeMomentRatingChoice.allCases) { option in
                            Button {
                                ratingLabel = option.rawValue
                            } label: {
                                HStack(spacing: 8) {
                                    Image(systemName: option.icon)
                                        .font(nativeAppFont(size: 15, weight: .black))
                                    Text(option.label)
                                        .font(nativeAppFont(size: 14, weight: .black))
                                        .lineLimit(1)
                                        .minimumScaleFactor(0.82)
                                }
                                    .frame(maxWidth: .infinity)
                                    .padding(.vertical, 12)
                                    .padding(.horizontal, 8)
                                    .background(ratingLabel == option.rawValue ? nativeAccent : nativeSurfaceStrong)
                                    .foregroundStyle(ratingLabel == option.rawValue ? .black : .white)
                                    .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
                            }
                            .buttonStyle(.plain)
                        }
                    }
                }
                .frame(maxWidth: .infinity, alignment: .leading)
            }

            NativeSurfaceCard {
                VStack(alignment: .leading, spacing: 14) {
                    Text("3-words review")
                        .font(nativeAppFont(size: 12, weight: .black))
                        .foregroundStyle(.white.opacity(0.45))
                        .textCase(.uppercase)
                    ZStack(alignment: .leading) {
                        RoundedRectangle(cornerRadius: 18, style: .continuous)
                            .fill(nativeSurfaceStrong)
                        if reviewText.isEmpty {
