    private func refreshCheckInGalleryPreviewIfNeeded() {
        photoAuthorizationStatus = PHPhotoLibrary.authorizationStatus(for: .readWrite)
        guard hasCheckInGalleryAccess else {
            recentGalleryPreviews = []
            return
        }

        let fetchOptions = PHFetchOptions()
        fetchOptions.sortDescriptors = [NSSortDescriptor(key: "creationDate", ascending: false)]
        fetchOptions.fetchLimit = 3
        let assets = PHAsset.fetchAssets(with: .image, options: fetchOptions)
        guard assets.count > 0 else {
            recentGalleryPreviews = []
            return
        }

        var previews: [UIImage?] = Array(repeating: nil, count: min(assets.count, 3))
        let manager = PHCachingImageManager()
        let targetSize = CGSize(width: 96, height: 96)
        let options = PHImageRequestOptions()
        options.deliveryMode = .highQualityFormat
        options.resizeMode = .fast
        options.isSynchronous = false

        let group = DispatchGroup()
        for index in 0..<min(assets.count, 3) {
            group.enter()
            manager.requestImage(
                for: assets.object(at: index),
                targetSize: targetSize,
                contentMode: .aspectFill,
                options: options
            ) { image, _ in
                previews[index] = image
                group.leave()
            }
        }

        group.notify(queue: .main) {
            self.recentGalleryPreviews = previews.compactMap { $0 }
        }
    }

    private func submitCheckIn() async {
        guard let currentPlace = selectedPlace else { return }
        errorMessage = nil
        isSubmitting = true
        defer { isSubmitting = false }

        do {
            let images = selectedImage.map { [$0] } ?? []
            nativeLogger.log("submitCheckIn sheet start place=\(currentPlace.id, privacy: .public) images=\(images.count, privacy: .public)")
            let uploadedMedia = try await appState.uploadCheckInImages(images)
            nativeLogger.log("submitCheckIn sheet upload success media=\(uploadedMedia.count, privacy: .public)")
            selectedImage = nil
            try await appState.submitCheckIn(
                place: currentPlace,
                visitedDate: resolvedVisitedDate,
                ratingLabel: ratingLabel,
                wouldRevisit: wouldRevisit,
                visibility: visibility,
                note: reviewText,
                uploadedMedia: uploadedMedia
            )
            nativeHaptic(.success)
            nativeLogger.log("submitCheckIn sheet appState success")
            closeSheet()
            nativeLogger.log("submitCheckIn sheet closed")
        } catch {
            let nsError = error as NSError
            if nsError.domain == NSURLErrorDomain && nsError.code == NSURLErrorUserAuthenticationRequired {
                errorMessage = nil
            } else {
                errorMessage = "Could not save this check-in."
            }
        }
    }

    private func updateReviewText(_ newValue: String) {
        let normalized = newValue.replacingOccurrences(of: "\n", with: " ")
        let leadingTrimmed = normalized.replacingOccurrences(of: "^\\s+", with: "", options: .regularExpression)
        let wordCount = leadingTrimmed.split(separator: " ", omittingEmptySubsequences: true).count

        if wordCount <= 3 {
            reviewText = leadingTrimmed
            reviewWordLimitMessage = nil
            return
        }

        let limited = leadingTrimmed
            .split(separator: " ", omittingEmptySubsequences: true)
            .prefix(3)
            .joined(separator: " ")
        reviewText = limited
        reviewWordLimitMessage = "Easy there, just 3 words."
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.6) {
            if self.reviewWordLimitMessage == "Easy there, just 3 words." {
                self.reviewWordLimitMessage = nil
            }
        }
    }

    static func isoDayString(from date: Date) -> String {
        let formatter = DateFormatter()
        formatter.calendar = Calendar(identifier: .gregorian)
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.timeZone = .current
        formatter.dateFormat = "yyyy-MM-dd"
        return formatter.string(from: date)
    }

    static func dateFromISODateString(_ value: String) -> Date? {
        let formatter = DateFormatter()
        formatter.calendar = Calendar(identifier: .gregorian)
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.timeZone = .current
        formatter.dateFormat = "yyyy-MM-dd"
        return formatter.date(from: String(value.prefix(10)))
    }
}

private func nativeSquareCroppedImage(_ image: UIImage) -> UIImage {
    let normalized = nativeNormalizedUIImage(image)
    let size = normalized.size
    let edge = min(size.width, size.height)
    let origin = CGPoint(
        x: (size.width - edge) / 2,
        y: (size.height - edge) / 2
    )
    let rect = CGRect(origin: origin, size: CGSize(width: edge, height: edge))

    guard
        let cgImage = normalized.cgImage?.cropping(to: CGRect(
            x: rect.origin.x * normalized.scale,
            y: rect.origin.y * normalized.scale,
            width: rect.width * normalized.scale,
            height: rect.height * normalized.scale
        ))
    else {
        return normalized
    }

    return UIImage(cgImage: cgImage, scale: normalized.scale, orientation: .up)
}

private func nativeNormalizedUIImage(_ image: UIImage) -> UIImage {
    guard image.imageOrientation != .up else { return image }
    let renderer = UIGraphicsImageRenderer(size: image.size)
    return renderer.image { _ in
        image.draw(in: CGRect(origin: .zero, size: image.size))
    }
}

