private final class NativeInlineCameraController: NSObject, ObservableObject, AVCapturePhotoCaptureDelegate {
    enum CameraPosition {
        case front
        case back

        var avPosition: AVCaptureDevice.Position {
            switch self {
            case .front:
                return .front
            case .back:
                return .back
            }
        }
    }

    @Published private(set) var authorizationStatus: AVAuthorizationStatus = AVCaptureDevice.authorizationStatus(for: .video)
    @Published private(set) var isConfigured = false
    @Published private(set) var isRunning = false
    @Published private(set) var errorMessage: String?
    @Published private(set) var cameraPosition: CameraPosition = .back

    let session = AVCaptureSession()

    private let sessionQueue = DispatchQueue(label: "club.vibinn.inline-camera")
    private let photoOutput = AVCapturePhotoOutput()
    private var activeInput: AVCaptureDeviceInput?
    private var captureCompletion: ((UIImage?) -> Void)?
    private var isConfiguring = false

    var inlineMessage: String {
        switch authorizationStatus {
        case .authorized:
            return errorMessage ?? "Frame your moment in a square crop."
        case .denied, .restricted:
            return "Allow camera access to capture here, or pick from gallery."
        case .notDetermined:
            return "We’ll ask for camera access so you can capture here."
        @unknown default:
            return "Camera is not ready yet."
        }
    }

    func prepareIfNeeded() {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        DispatchQueue.main.async {
            self.authorizationStatus = status
        }

        switch status {
        case .authorized:
            configureIfNeededAndStart()
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { granted in
                DispatchQueue.main.async {
                    self.authorizationStatus = granted ? .authorized : .denied
                }
                if granted {
                    self.configureIfNeededAndStart()
                }
            }
        case .denied, .restricted:
            stopSession()
        @unknown default:
            stopSession()
        }
    }

    func stopSession() {
        sessionQueue.async {
            guard self.session.isRunning else { return }
            self.session.stopRunning()
            DispatchQueue.main.async {
                self.isRunning = false
            }
        }
    }

    func capturePhoto(completion: @escaping (UIImage?) -> Void) {
        guard authorizationStatus == .authorized, isConfigured else {
            completion(nil)
            return
        }

        sessionQueue.async {
            let settings = AVCapturePhotoSettings()
            settings.isHighResolutionPhotoEnabled = true
            settings.flashMode = .off
            if let connection = self.photoOutput.connection(with: .video), connection.isVideoOrientationSupported {
                connection.videoOrientation = .portrait
            }
            self.captureCompletion = completion
            self.photoOutput.capturePhoto(with: settings, delegate: self)
        }
    }

    func toggleCameraPosition() {
        guard authorizationStatus == .authorized else { return }
        let nextPosition: CameraPosition = cameraPosition == .back ? .front : .back

        sessionQueue.async {
            guard let device = AVCaptureDevice.default(.builtInWideAngleCamera, for: .video, position: nextPosition.avPosition) else {
                return
            }

            do {
                let input = try AVCaptureDeviceInput(device: device)
                self.session.beginConfiguration()
                if let activeInput = self.activeInput {
                    self.session.removeInput(activeInput)
                }
                guard self.session.canAddInput(input) else {
                    self.session.commitConfiguration()
                    if let activeInput = self.activeInput, self.session.canAddInput(activeInput) {
                        self.session.addInput(activeInput)
                    }
                    return
                }
                self.session.addInput(input)
                self.activeInput = input
                self.session.commitConfiguration()

                DispatchQueue.main.async {
                    self.cameraPosition = nextPosition
                    self.errorMessage = nil
                }
            } catch {
                DispatchQueue.main.async {
                    self.errorMessage = "Could not switch camera."
                }
            }
        }
    }

    private func configureIfNeededAndStart() {
        sessionQueue.async {
            if self.isConfigured {
                self.startSessionIfNeeded()
                return
            }
            guard !self.isConfiguring else { return }
            self.isConfiguring = true
            var shouldStartSession = false

            self.session.beginConfiguration()
            self.session.sessionPreset = .photo

            defer {
                self.session.commitConfiguration()
                self.isConfiguring = false
                if shouldStartSession {
                    self.startSessionIfNeeded()
                }
            }

            do {
                let device = AVCaptureDevice.default(.builtInWideAngleCamera, for: .video, position: self.cameraPosition.avPosition)
                    ?? AVCaptureDevice.default(for: .video)

                guard let device else {
                    DispatchQueue.main.async {
                        self.errorMessage = "Camera is unavailable on this device."
                    }
                    return
                }

                let input = try AVCaptureDeviceInput(device: device)
                if self.session.canAddInput(input) {
                    self.session.addInput(input)
                    self.activeInput = input
                }

                if self.session.canAddOutput(self.photoOutput) {
                    self.session.addOutput(self.photoOutput)
                    self.photoOutput.isHighResolutionCaptureEnabled = true
                }

                DispatchQueue.main.async {
                    self.isConfigured = true
                    self.errorMessage = nil
                }
                shouldStartSession = true
            } catch {
                DispatchQueue.main.async {
                    self.errorMessage = "Could not start camera."
                }
            }
        }
    }

    private func startSessionIfNeeded() {
        guard isConfigured || session.inputs.contains(where: { $0 === self.activeInput }) else { return }
        guard !session.isRunning else {
            DispatchQueue.main.async {
                self.isRunning = true
            }
            return
        }

        session.startRunning()
        DispatchQueue.main.async {
            self.isRunning = true
        }
    }

    func photoOutput(_ output: AVCapturePhotoOutput, didFinishProcessingPhoto photo: AVCapturePhoto, error: Error?) {
        guard error == nil, let data = photo.fileDataRepresentation(), let image = UIImage(data: data) else {
            DispatchQueue.main.async {
                self.captureCompletion?(nil)
                self.captureCompletion = nil
            }
            return
        }

        DispatchQueue.main.async {
            self.captureCompletion?(image)
            self.captureCompletion = nil
        }
    }
}

