private struct NativePlainTextView: UIViewRepresentable {
    @Binding var text: String

    func makeUIView(context: Context) -> UITextView {
        let textView = UITextView()
        textView.backgroundColor = .clear
        textView.textColor = .white
        textView.font = nativeAppUIFont(size: 16, weight: .medium)
        textView.isScrollEnabled = true
        textView.textContainerInset = .zero
        textView.textContainer.lineFragmentPadding = 0
        textView.keyboardAppearance = .dark
        textView.autocorrectionType = .no
        textView.autocapitalizationType = .sentences
        textView.delegate = context.coordinator
        return textView
    }

    func updateUIView(_ uiView: UITextView, context: Context) {
        if uiView.text != text {
            uiView.text = text
        }
        uiView.font = nativeAppUIFont(size: 16, weight: .medium)
        uiView.textColor = .white
        uiView.backgroundColor = .clear
    }

    func makeCoordinator() -> Coordinator {
        Coordinator(text: $text)
    }

    final class Coordinator: NSObject, UITextViewDelegate {
        @Binding var text: String

        init(text: Binding<String>) {
            _text = text
        }

        func textViewDidChange(_ textView: UITextView) {
            text = textView.text
        }
    }
}

private struct NativeCheckInPlaceRow: View {
    let place: NativePlace
    var isSelected: Bool = false

    private var placeTypeLabel: String? {
        let trimmed = place.category?.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let trimmed, !trimmed.isEmpty else { return nil }
        return trimmed
            .replacingOccurrences(of: "_", with: " ")
            .replacingOccurrences(of: "-", with: " ")
            .capitalized
    }

    private var shortAddressLabel: String? {
        let normalizedName = place.name
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        let parts = (place.address ?? place.location)
            .split(separator: ",")
            .map { String($0).trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
            .filter { part in
                let normalizedPart = part.lowercased()
                guard !normalizedName.isEmpty else { return true }
                if normalizedPart == normalizedName { return false }
                if normalizedPart.contains(normalizedName) { return false }
                return true
            }

        if parts.isEmpty {
            let fallbackParts = place.location
                .split(separator: ",")
                .map { String($0).trimmingCharacters(in: .whitespacesAndNewlines) }
                .filter { !$0.isEmpty }
            guard !fallbackParts.isEmpty else { return nil }
            return Array(fallbackParts.prefix(2)).joined(separator: ", ")
        }

        return Array(parts.prefix(2)).joined(separator: ", ")
    }

    private var tertiaryLine: String? {
        let resolvedShortAddress: String? = {
            if let shortAddressLabel, !shortAddressLabel.isEmpty {
                return shortAddressLabel
            }
            let fallbackLocation = place.location.trimmingCharacters(in: .whitespacesAndNewlines)
            return fallbackLocation.isEmpty ? nil : fallbackLocation
        }()

        switch (distanceLabel, resolvedShortAddress) {
        case let (distance?, address?) where !address.isEmpty:
            return "\(distance) • \(address)"
        case let (distance?, _):
            return distance
        case let (_, address?) where !address.isEmpty:
            return address
        default:
            return nil
        }
    }

    private var distanceLabel: String? {
        guard let distanceMeters = place.distanceMeters, distanceMeters > 0 else { return nil }
        if distanceMeters < 160.934 {
            let feet = distanceMeters * 3.28084
            return String(format: "%.0f ft away", feet)
        }
        let miles = distanceMeters / 1609.344
        return String(format: "%.1f mi away", miles)
    }

    var body: some View {
        HStack(alignment: .center, spacing: 12) {
            VStack(alignment: .leading, spacing: 4) {
                Text(place.name)
                    .font(nativeAppFont(size: 17, weight: .black))
                    .foregroundStyle(.white)
                    .frame(maxWidth: .infinity, alignment: .leading)
                if let placeTypeLabel {
                    Text(placeTypeLabel)
                        .font(nativeAppFont(size: 13, weight: .medium))
                        .foregroundStyle(.white.opacity(0.72))
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .lineLimit(1)
                }
                if let tertiaryLine {
                    Text(tertiaryLine)
                        .font(nativeAppFont(size: 12, weight: .medium))
                        .foregroundStyle(.white.opacity(0.52))
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .lineLimit(1)
                }
            }
            if isSelected {
                Image(systemName: "checkmark.circle.fill")
                    .font(nativeAppFont(size: 20, weight: .bold))
                    .foregroundStyle(nativeAccent)
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(16)
        .background(
            RoundedRectangle(cornerRadius: 20, style: .continuous)
                .fill(isSelected ? nativeAccent.opacity(0.16) : nativeSurface)
                .overlay(
                    RoundedRectangle(cornerRadius: 20, style: .continuous)
                        .stroke(isSelected ? nativeAccent.opacity(0.55) : nativeBorder, lineWidth: 1)
                )
        )
    }
}

private struct NativeMultiImagePicker: UIViewControllerRepresentable {
    @Environment(\.dismiss) private var dismiss
    @Binding var images: [UIImage]
    let selectionLimit: Int

    func makeCoordinator() -> Coordinator {
        Coordinator(images: $images)
    }

    func makeUIViewController(context: Context) -> PHPickerViewController {
        var configuration = PHPickerConfiguration(photoLibrary: .shared())
        configuration.filter = .images
        configuration.selectionLimit = selectionLimit
        let controller = PHPickerViewController(configuration: configuration)
        controller.delegate = context.coordinator
        return controller
    }

    func updateUIViewController(_ uiViewController: PHPickerViewController, context: Context) {}

    final class Coordinator: NSObject, PHPickerViewControllerDelegate {
        @Binding private var images: [UIImage]
        private let maxImportedPixelSize: CGFloat = 1600

        init(images: Binding<[UIImage]>) {
            self._images = images
        }

        func picker(_ picker: PHPickerViewController, didFinishPicking results: [PHPickerResult]) {
            picker.dismiss(animated: true)
            guard !results.isEmpty else { return }

            Task {
                var loaded: [UIImage] = []
                for result in results {
                    guard result.itemProvider.hasItemConformingToTypeIdentifier("public.image") else { continue }
                    let image = try? await withCheckedThrowingContinuation { (continuation: CheckedContinuation<UIImage, Error>) in
                        result.itemProvider.loadFileRepresentation(forTypeIdentifier: "public.image") { url, error in
                            if let error {
                                continuation.resume(throwing: error)
                            } else if let url {
                                let temporaryURL = FileManager.default.temporaryDirectory
                                    .appendingPathComponent(UUID().uuidString)
                                    .appendingPathExtension(url.pathExtension.isEmpty ? "jpg" : url.pathExtension)
                                do {
                                    if FileManager.default.fileExists(atPath: temporaryURL.path) {
                                        try FileManager.default.removeItem(at: temporaryURL)
                                    }
                                    try FileManager.default.copyItem(at: url, to: temporaryURL)
                                    let image = try Self.downsampleImage(
                                        at: temporaryURL,
                                        maxPixelSize: self.maxImportedPixelSize
                                    )
                                    try? FileManager.default.removeItem(at: temporaryURL)
                                    continuation.resume(returning: image)
                                } catch {
                                    try? FileManager.default.removeItem(at: temporaryURL)
                                    continuation.resume(throwing: error)
                                }
                            } else {
                                continuation.resume(throwing: NSError(domain: "NativeImagePicker", code: 1, userInfo: nil))
                            }
                        }
                    }
                    if let image {
                        loaded.append(image)
                    }
                }
                await MainActor.run {
                    self.images = loaded
                }
            }
        }

        private static func downsampleImage(at url: URL, maxPixelSize: CGFloat) throws -> UIImage {
            let options: [CFString: Any] = [
                kCGImageSourceShouldCache: false,
            ]

            guard let source = CGImageSourceCreateWithURL(url as CFURL, options as CFDictionary) else {
                throw NSError(domain: "NativeImagePicker", code: 2, userInfo: [NSLocalizedDescriptionKey: "Could not read image source."])
            }

            let downsampleOptions: [CFString: Any] = [
                kCGImageSourceCreateThumbnailFromImageAlways: true,
                kCGImageSourceShouldCacheImmediately: true,
                kCGImageSourceCreateThumbnailWithTransform: true,
                kCGImageSourceThumbnailMaxPixelSize: maxPixelSize,
            ]

            guard let cgImage = CGImageSourceCreateThumbnailAtIndex(source, 0, downsampleOptions as CFDictionary) else {
                throw NSError(domain: "NativeImagePicker", code: 3, userInfo: [NSLocalizedDescriptionKey: "Could not downsample image."])
            }

            return UIImage(cgImage: cgImage)
        }
    }
}

private struct NativeSingleMetadataImagePicker: UIViewControllerRepresentable {
    @Environment(\.dismiss) private var dismiss
    @Binding var selection: NativePickedPhotoAsset?

    func makeCoordinator() -> Coordinator {
        Coordinator(selection: $selection) {
            self.dismiss()
        }
    }

    func makeUIViewController(context: Context) -> PHPickerViewController {
        var configuration = PHPickerConfiguration(photoLibrary: .shared())
        configuration.filter = .images
        configuration.selectionLimit = 1
        let controller = PHPickerViewController(configuration: configuration)
        controller.delegate = context.coordinator
        return controller
    }

    func updateUIViewController(_ uiViewController: PHPickerViewController, context: Context) {}

    final class Coordinator: NSObject, PHPickerViewControllerDelegate {
        @Binding private var selection: NativePickedPhotoAsset?
        private let onFinish: @MainActor () -> Void
        private let maxImportedPixelSize: CGFloat = 1800

        init(
            selection: Binding<NativePickedPhotoAsset?>,
            onFinish: @escaping @MainActor () -> Void
        ) {
            self._selection = selection
            self.onFinish = onFinish
        }

        func picker(_ picker: PHPickerViewController, didFinishPicking results: [PHPickerResult]) {
            guard let result = results.first else {
                Task { @MainActor in
                    self.onFinish()
                }
                return
            }
            guard result.itemProvider.hasItemConformingToTypeIdentifier("public.image") else {
                Task { @MainActor in
                    self.onFinish()
                }
                return
            }

            Task {
                let pickedPhoto = try? await withCheckedThrowingContinuation { (continuation: CheckedContinuation<NativePickedPhotoAsset, Error>) in
                    result.itemProvider.loadFileRepresentation(forTypeIdentifier: "public.image") { url, error in
                        if let error {
                            continuation.resume(throwing: error)
                            return
                        }

                        guard let url else {
                            continuation.resume(throwing: NSError(domain: "NativeMetadataImagePicker", code: 1))
                            return
                        }

                        let temporaryURL = FileManager.default.temporaryDirectory
                            .appendingPathComponent(UUID().uuidString)
                            .appendingPathExtension(url.pathExtension.isEmpty ? "jpg" : url.pathExtension)

                        do {
                            if FileManager.default.fileExists(atPath: temporaryURL.path) {
                                try FileManager.default.removeItem(at: temporaryURL)
                            }
                            try FileManager.default.copyItem(at: url, to: temporaryURL)
                            let image = try Self.downsampleImage(at: temporaryURL, maxPixelSize: self.maxImportedPixelSize)
                            let metadata = try Self.extractMetadata(from: temporaryURL)
                            try? FileManager.default.removeItem(at: temporaryURL)
                            continuation.resume(returning: NativePickedPhotoAsset(
                                image: nativeSquareCroppedImage(image),
                                latitude: metadata.latitude,
                                longitude: metadata.longitude,
                                capturedAt: metadata.capturedAt
                            ))
                        } catch {
                            try? FileManager.default.removeItem(at: temporaryURL)
                            continuation.resume(throwing: error)
                        }
                    }
                }

                if let pickedPhoto {
                    await MainActor.run {
                        self.selection = pickedPhoto
                        self.onFinish()
                    }
                } else {
                    await MainActor.run {
                        self.onFinish()
                    }
                }
            }
        }

        private static func downsampleImage(at url: URL, maxPixelSize: CGFloat) throws -> UIImage {
            let options: [CFString: Any] = [
                kCGImageSourceShouldCache: false,
            ]

            guard let source = CGImageSourceCreateWithURL(url as CFURL, options as CFDictionary) else {
                throw NSError(domain: "NativeMetadataImagePicker", code: 2)
            }

            let downsampleOptions: [CFString: Any] = [
                kCGImageSourceCreateThumbnailFromImageAlways: true,
                kCGImageSourceShouldCacheImmediately: true,
                kCGImageSourceCreateThumbnailWithTransform: true,
                kCGImageSourceThumbnailMaxPixelSize: maxPixelSize,
            ]

            guard let cgImage = CGImageSourceCreateThumbnailAtIndex(source, 0, downsampleOptions as CFDictionary) else {
                throw NSError(domain: "NativeMetadataImagePicker", code: 3)
            }

            return UIImage(cgImage: cgImage)
        }

        private static func extractMetadata(from url: URL) throws -> (latitude: Double?, longitude: Double?, capturedAt: Date?) {
            guard let source = CGImageSourceCreateWithURL(url as CFURL, nil),
                  let properties = CGImageSourceCopyPropertiesAtIndex(source, 0, nil) as? [CFString: Any] else {
                throw NSError(domain: "NativeMetadataImagePicker", code: 4)
            }

            let gps = properties[kCGImagePropertyGPSDictionary] as? [CFString: Any]
            let exif = properties[kCGImagePropertyExifDictionary] as? [CFString: Any]
            let tiff = properties[kCGImagePropertyTIFFDictionary] as? [CFString: Any]

            var latitude = (gps?[kCGImagePropertyGPSLatitude] as? NSNumber)?.doubleValue
            var longitude = (gps?[kCGImagePropertyGPSLongitude] as? NSNumber)?.doubleValue
            let latitudeRef = gps?[kCGImagePropertyGPSLatitudeRef] as? String
            let longitudeRef = gps?[kCGImagePropertyGPSLongitudeRef] as? String

            if latitudeRef == "S", let resolvedLatitude = latitude {
                latitude = -abs(resolvedLatitude)
            }
            if longitudeRef == "W", let resolvedLongitude = longitude {
                longitude = -abs(resolvedLongitude)
            }

            let rawDate =
                (exif?[kCGImagePropertyExifDateTimeOriginal] as? String)
                ?? (tiff?[kCGImagePropertyTIFFDateTime] as? String)
            let formatter = DateFormatter()
            formatter.locale = Locale(identifier: "en_US_POSIX")
            formatter.dateFormat = "yyyy:MM:dd HH:mm:ss"
            let capturedAt = rawDate.flatMap { formatter.date(from: $0) }

            return (latitude, longitude, capturedAt)
        }
    }
}

private struct NativeSingleImagePicker: UIViewControllerRepresentable {
    @Environment(\.dismiss) private var dismiss
    @Binding var image: UIImage?
    let source: NativeCheckInMediaPickerSource

    func makeCoordinator() -> Coordinator {
        Coordinator(image: $image)
    }

    func makeUIViewController(context: Context) -> UIImagePickerController {
        let controller = UIImagePickerController()
        controller.delegate = context.coordinator
        controller.sourceType = source.uiSourceType
        controller.modalPresentationStyle = .fullScreen
        controller.allowsEditing = true
        return controller
    }

    func updateUIViewController(_ uiViewController: UIImagePickerController, context: Context) {}

    final class Coordinator: NSObject, UINavigationControllerDelegate, UIImagePickerControllerDelegate {
        @Binding private var image: UIImage?

        init(image: Binding<UIImage?>) {
            self._image = image
        }

        func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
            picker.dismiss(animated: true)
        }

        func imagePickerController(
            _ picker: UIImagePickerController,
            didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey : Any]
        ) {
            let selected = (info[.editedImage] ?? info[.originalImage]) as? UIImage
            image = selected
            picker.dismiss(animated: true)
        }
    }
}

private struct NativeInputField: View {
    let title: String
    @Binding var text: String
    let keyboard: UIKeyboardType
    let secure: Bool

    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            Text(title)
                .font(nativeAppFont(size: 12, weight: .black))
                .foregroundStyle(.white.opacity(0.45))
                .textCase(.uppercase)
            if secure {
                SecureField(title, text: $text)
                    .textInputAutocapitalization(.never)
                    .autocorrectionDisabled()
                    .font(nativeAppFont(size: 17, weight: .medium))
                    .padding(.horizontal, 16)
                    .padding(.vertical, 16)
                    .background(nativeSurfaceStrong)
                    .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                    .keyboardType(keyboard)
            } else {
                TextField(title, text: $text)
                    .textInputAutocapitalization(.never)
                    .autocorrectionDisabled()
                    .font(nativeAppFont(size: 17, weight: .medium))
                    .padding(.horizontal, 16)
                    .padding(.vertical, 16)
                    .background(nativeSurfaceStrong)
                    .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                    .keyboardType(keyboard)
            }
        }
    }
}

private struct NativeMultilineInputField: View {
    let title: String
    @Binding var text: String
    let height: CGFloat

    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            Text(title)
                .font(nativeAppFont(size: 12, weight: .black))
                .foregroundStyle(.white.opacity(0.45))
                .textCase(.uppercase)

            NativeWrappedTextView(text: $text)
                .frame(height: height)
                .padding(.horizontal, 12)
                .padding(.vertical, 12)
                .background(nativeSurfaceStrong)
                .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
        }
    }
}

private struct NativeWrappedTextView: UIViewRepresentable {
    @Binding var text: String

    func makeCoordinator() -> Coordinator {
        Coordinator(text: $text)
    }

    func makeUIView(context: Context) -> UITextView {
        let textView = UITextView()
        textView.delegate = context.coordinator
        textView.backgroundColor = .clear
        textView.textColor = .white
        textView.font = .systemFont(ofSize: 16, weight: .medium)
        textView.autocorrectionType = .no
        textView.autocapitalizationType = .sentences
        textView.textContainerInset = .zero
        textView.textContainer.lineFragmentPadding = 0
        textView.showsVerticalScrollIndicator = false
        textView.keyboardAppearance = .dark
        return textView
    }

    func updateUIView(_ uiView: UITextView, context: Context) {
        if uiView.text != text {
            uiView.text = text
        }
    }

    final class Coordinator: NSObject, UITextViewDelegate {
        @Binding private var text: String

        init(text: Binding<String>) {
            self._text = text
        }

        func textViewDidChange(_ textView: UITextView) {
            text = textView.text
        }
    }
}

